// How long the two-stage delete (× → ✓) stays armed before auto-disarming.
// Long enough for a deliberate confirmation click, short enough that the armed
// state doesn't linger and cause accidents on a later sidebar return visit.
const DELETE_CONFIRM_WINDOW_MS = 3500;

// How long a pointer must be held on any chat-delete button before the
// "Delete all chats?" armed-all state takes over. Tuned so a normal click
// can't cross the threshold accidentally, but an intentional press-and-hold
// resolves without feeling like a ritual. Must stay in sync with the CSS
// transition duration on `.conversationDelete[data-holding="true"]` so the
// visual morph completes at the same instant the JS timer fires.
const DELETE_ALL_HOLD_MS = 900;

// Sentinel for the chat-header delete button, which has no chat id of its own
// (it always targets the currently open chat).
const HEADER_DELETE_KEY = "__header__";

// Sentinel for the "delete every chat" armed state, reached by holding any
// chat × / Delete button past DELETE_ALL_HOLD_MS. Reuses the single
// `pendingDeleteKey` slot so the existing auto-disarm / outside-click /
// Escape behaviour applies to it without any extra wiring.
const DELETE_ALL_KEY = "__delete_all__";
const DELETE_ALL_COFFEE_SESSIONS_KEY = "__delete_all_coffee_sessions__";
/** Single Coffee Group delete — opens the same centered confirm modal as bulk deletes. */
const DELETE_COFFEE_GROUP_KEY_PREFIX = "__delete_coffee_group__:";

function coffeeGroupDeleteKey(groupId: string): string {
  return `${DELETE_COFFEE_GROUP_KEY_PREFIX}${groupId}`;
}

function parseCoffeeGroupDeleteKey(key: string | null): string | null {
  if (key == null || !key.startsWith(DELETE_COFFEE_GROUP_KEY_PREFIX)) return null;
  const id = key.slice(DELETE_COFFEE_GROUP_KEY_PREFIX.length).trim();
  return id.length > 0 ? id : null;
}

function ZenPersonaTransitionChoiceControl({
  value,
  onChange,
  compact = false,
}: {
  value: ZenPersonaTransitionChoice;
  onChange: (next: ZenPersonaTransitionChoice) => void;
  compact?: boolean;
}): React.JSX.Element {
  const labels: Record<ZenPersonaTransitionChoice, string> = {
    random: "Random",
    "new-speaks": "New",
    "previous-introduces": "Intro",
    off: "Off",
  };
  return (
    <div
      className={styles.zenPersonaTransitionControl}
      data-compact={compact ? "true" : undefined}
      role="radiogroup"
      aria-label="Facet transition style"
      onMouseDown={(event) => event.preventDefault()}
    >
      <span className={styles.zenPersonaTransitionLabelWithInfo}>
        <span className={styles.zenPersonaTransitionControlLabel}>Switch</span>
        <PanelSectionInfo
          id={`zen-persona-transition-switch-info-${compact ? "compact" : "full"}`}
          label="About Facet switching"
          variant="control"
          icon="help"
        >
          Controls the handoff when you change Facets after Zen has started: Random chooses
          between Off, New, and Intro. Off switches silently.
        </PanelSectionInfo>
      </span>
      <div className={styles.zenPersonaTransitionSegments}>
        {ZEN_PERSONA_TRANSITION_CHOICES.map((choice) => (
          <button
            key={choice}
            type="button"
            className={styles.zenPersonaTransitionSegmentButton}
            data-active={value === choice ? "true" : undefined}
            role="radio"
            aria-checked={value === choice}
            onClick={() => onChange(choice)}
          >
            {labels[choice]}
          </button>
        ))}
      </div>
    </div>
  );
}

function normalizeZenPersonaTransitionChoice(
  value: unknown,
  fallback: ZenPersonaTransitionChoice = "random"
): ZenPersonaTransitionChoice {
  return typeof value === "string" &&
    (ZEN_PERSONA_TRANSITION_CHOICES as readonly string[]).includes(value)
    ? (value as ZenPersonaTransitionChoice)
    : fallback;
}
