function countPromptTagMatches(prompt: string, tags: readonly string[]): number {
  let score = 0;
  for (const tag of tags) {
    if (prompt.includes(tag)) {
      score += 1;
    }
  }
  return score;
}

function inferImageGenerationVariantFromPrompt(promptRaw: string): ImageGenerationVariant {
  const prompt = promptRaw.toLowerCase();
  const portraitScore = countPromptTagMatches(prompt, IMAGE_VARIANT_TAGS.portrait);
  const letterboxScore = countPromptTagMatches(prompt, IMAGE_VARIANT_TAGS.letterbox);
  const landscapeScore = countPromptTagMatches(prompt, IMAGE_VARIANT_TAGS.landscape);
  if (portraitScore === 0 && letterboxScore === 0 && landscapeScore === 0) {
    return "letterbox";
  }
  if (portraitScore >= landscapeScore && portraitScore >= letterboxScore) {
    return "portrait";
  }
  if (landscapeScore >= portraitScore && landscapeScore >= letterboxScore) {
    return "landscape";
  }
  return "letterbox";
}

function composeImagePromptWithKeywordDirectives(args: {
  basePrompt: string;
  positiveKeywords: readonly string[];
  negativeKeywords: readonly string[];
}): string {
  const base = args.basePrompt.trim();
  const positive = args.positiveKeywords
    .map((keyword) => keyword.trim())
    .filter((keyword) => keyword.length > 0);
  const negative = args.negativeKeywords
    .map((keyword) => keyword.trim())
    .filter((keyword) => keyword.length > 0);
  if (positive.length === 0 && negative.length === 0) return base;
  const directives: string[] = [];
  if (positive.length > 0) directives.push(`Positive keywords: ${positive.join(", ")}`);
  if (negative.length > 0) directives.push(`Negative keywords: ${negative.join(", ")}`);
  return `${base}\n\n${directives.join("\n")}`;
}

/** Groups overlapping `/api/images/generate` calls so each directory/bot can load independently. */
function imageGenerationScopeKey(
  conversationId: string | null | undefined,
  scopeBotId: string | null
): string {
  return `${conversationId ?? ""}\u0000${scopeBotId ?? ""}`;
}

/** Inverse of `imageGenerationScopeKey` for routing the Images panel to an in-flight request. */
function parseImageGenerationScopeKey(key: string): {
  conversationId: string;
  botId: string | null;
} {
  const sep = "\u0000";
  const idx = key.indexOf(sep);
  if (idx < 0) {
    return { conversationId: key, botId: null };
  }
  const tail = key.slice(idx + sep.length);
  return {
    conversationId: key.slice(0, idx),
    botId: tail.length > 0 ? tail : null,
  };
}

