async function withBotAvatarSaveTimeout<T>(
  operation: (signal: AbortSignal) => Promise<T>
): Promise<T> {
  const controller = new AbortController();
  let timedOut = false;
  const timeout = window.setTimeout(() => {
    timedOut = true;
    controller.abort();
  }, BOT_AVATAR_SAVE_TIMEOUT_MS);
  try {
    return await operation(controller.signal);
  } catch (err) {
    if (timedOut && isAbortLikeError(err)) {
      throw new Error("Avatar save took too long. Please try again.");
    }
    throw err;
  } finally {
    window.clearTimeout(timeout);
  }
}

function readZenLiveBotAvatarPosition(): ZenLiveBotAvatarPosition | null {
  if (typeof window === "undefined") return null;
  try {
    const raw = window.localStorage.getItem(
      PRISM_ZEN_LIVE_BOT_AVATAR_POSITION_STORAGE_KEY
    );
    if (!raw) return null;
    const parsed = JSON.parse(raw) as Partial<ZenLiveBotAvatarPosition> | null;
    if (
      parsed &&
      typeof parsed.x === "number" &&
      Number.isFinite(parsed.x) &&
      typeof parsed.y === "number" &&
      Number.isFinite(parsed.y)
    ) {
      return { x: parsed.x, y: parsed.y };
    }
  } catch {
    // localStorage can throw (privacy mode, quota); non-fatal.
  }
  return null;
}

function persistZenLiveBotAvatarPosition(position: ZenLiveBotAvatarPosition): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      PRISM_ZEN_LIVE_BOT_AVATAR_POSITION_STORAGE_KEY,
      JSON.stringify(position)
    );
  } catch {
    // localStorage can throw (privacy mode, quota); non-fatal.
  }
}

function measureZenLiveBotAvatarBounds(node: HTMLElement): ZenLiveBotAvatarBounds {
  const rootRect = node.getBoundingClientRect();
  let left = 0;
  let top = 0;
  let right = Math.max(1, rootRect.width);
  let bottom = Math.max(1, rootRect.height);
  node
    .querySelectorAll<HTMLElement>(
      [
        "[data-zen-live-bot-body-layer='true']",
        "[data-zen-live-bot-body-frame='true']",
        "[data-zen-live-bot-face-rig='true']",
      ].join(", ")
    )
    .forEach((child) => {
      const childRect = child.getBoundingClientRect();
      left = Math.min(left, childRect.left - rootRect.left);
      top = Math.min(top, childRect.top - rootRect.top);
      right = Math.max(right, childRect.right - rootRect.left);
      bottom = Math.max(bottom, childRect.bottom - rootRect.top);
    });
  return {
    offsetX: left,
    offsetY: top,
    width: Math.max(1, right - left),
    height: Math.max(1, bottom - top),
  };
}

function zenLiveBotRectFromEdges(
  left: number,
  top: number,
  right: number,
  bottom: number
): ZenLiveBotAvatarRect {
  const normalizedLeft = Math.min(left, right);
  const normalizedRight = Math.max(left, right);
  const normalizedTop = Math.min(top, bottom);
  const normalizedBottom = Math.max(top, bottom);
  const width = Math.max(0, normalizedRight - normalizedLeft);
  const height = Math.max(0, normalizedBottom - normalizedTop);
  return {
    left: normalizedLeft,
    top: normalizedTop,
    right: normalizedRight,
    bottom: normalizedBottom,
    width,
    height,
    centerX: normalizedLeft + width / 2,
    centerY: normalizedTop + height / 2,
  };
}

function zenLiveBotAvatarRectForPosition(
  position: ZenLiveBotAvatarPosition,
  bounds: ZenLiveBotAvatarBounds
): ZenLiveBotAvatarRect {
  return zenLiveBotRectFromEdges(
    position.x + bounds.offsetX,
    position.y + bounds.offsetY,
    position.x + bounds.offsetX + bounds.width,
    position.y + bounds.offsetY + bounds.height
  );
}

function zenLiveBotRectsOverlap(
  first: ZenLiveBotAvatarRect,
  second: ZenLiveBotAvatarRect
): boolean {
  return (
    first.left < second.right &&
    first.right > second.left &&
    first.top < second.bottom &&
    first.bottom > second.top
  );
}

function zenLiveBotRectOverlapArea(
  first: ZenLiveBotAvatarRect,
  second: ZenLiveBotAvatarRect
): number {
  const width = Math.max(0, Math.min(first.right, second.right) - Math.max(first.left, second.left));
  const height = Math.max(0, Math.min(first.bottom, second.bottom) - Math.max(first.top, second.top));
  return width * height;
}

function collectZenLiveBotProseHillRect(
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS
): ZenLiveBotProseHillRect | null {
  if (typeof document === "undefined") return null;
  const safeTop = safeAreaInsets.top;
  const safeBottom = viewportHeight - safeAreaInsets.bottom;
  let left = Number.POSITIVE_INFINITY;
  let top = Number.POSITIVE_INFINITY;
  let right = Number.NEGATIVE_INFINITY;
  let bottom = Number.NEGATIVE_INFINITY;

  document
    .querySelectorAll<HTMLElement>(ZEN_LIVE_BOT_PROSE_HILL_SELECTOR)
    .forEach((target) => {
      const rect = target.getBoundingClientRect();
      if (rect.width <= 0 || rect.height <= 0) return;
      if (
        rect.bottom <= safeTop ||
        rect.top >= safeBottom ||
        rect.right <= 0 ||
        rect.left >= viewportWidth
      ) {
        return;
      }
      left = Math.min(left, Math.max(0, rect.left));
      top = Math.min(top, Math.max(safeTop, rect.top));
      right = Math.max(right, Math.min(viewportWidth, rect.right));
      bottom = Math.max(bottom, Math.min(safeBottom, rect.bottom));
    });

  if (
    !Number.isFinite(left) ||
    !Number.isFinite(top) ||
    !Number.isFinite(right) ||
    !Number.isFinite(bottom) ||
    right <= left ||
    bottom <= top
  ) {
    return null;
  }
  return zenLiveBotRectFromEdges(left, top, right, bottom);
}

function zenLiveBotGrabGeometryFromElement(element: Element): ZenLiveBotGrabGeometry | null {
  const rect = element.getBoundingClientRect();
  if (rect.width <= 0 || rect.height <= 0) return null;
  return {
    centerX: rect.left + rect.width / 2,
    centerY: rect.top + rect.height / 2,
    radiusX: rect.width / 2,
    radiusY: rect.height / 2,
  };
}

function measureZenLiveBotGrabGeometries(node: HTMLElement): ZenLiveBotGrabGeometry[] {
  const hitTargetGeometries = Array.from(
    node.querySelectorAll("[data-zen-live-bot-body-hit-target='true']")
  ).flatMap((target) => {
    const geometry = zenLiveBotGrabGeometryFromElement(target);
    return geometry ? [geometry] : [];
  });
  if (hitTargetGeometries.length > 0) return hitTargetGeometries;

  const body =
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-frame='true']") ??
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-layer='true']") ??
    node;
  const geometry = zenLiveBotGrabGeometryFromElement(body);
  return geometry ? [geometry] : [];
}

function measureZenLiveBotGrabGeometry(node: HTMLElement): ZenLiveBotGrabGeometry | null {
  return measureZenLiveBotGrabGeometries(node)[0] ?? null;
}

function zenLiveBotGrabGeometryContainsPointer(
  geometry: ZenLiveBotGrabGeometry | null,
  clientX: number,
  clientY: number
): boolean {
  if (!geometry) return false;
  if (geometry.radiusX <= 0 || geometry.radiusY <= 0) return false;
  const normalizedX = (clientX - geometry.centerX) / geometry.radiusX;
  const normalizedY = (clientY - geometry.centerY) / geometry.radiusY;
  return normalizedX * normalizedX + normalizedY * normalizedY <= 1;
}

function zenLiveBotAvatarPointerIsInsideBody(
  node: HTMLElement,
  clientX: number,
  clientY: number
): boolean {
  return measureZenLiveBotGrabGeometries(node).some((geometry) =>
    zenLiveBotGrabGeometryContainsPointer(geometry, clientX, clientY)
  );
}

function zenLiveBotAvatarPointMatchesSelector(
  clientX: number,
  clientY: number,
  selector: string
): boolean {
  if (typeof document === "undefined") return false;
  return document.elementsFromPoint(clientX, clientY).some((element) =>
    element.closest(selector)
  );
}

function zenLiveBotAvatarSurfaceCanStartGrab(
  target: EventTarget | null | undefined,
  clientX: number,
  clientY: number
): boolean {
  if (!(target instanceof Element)) return false;
  if (!target.isConnected) return false;
  if (!target.closest(ZEN_LIVE_BOT_AVATAR_SURFACE_SELECTOR)) return false;
  if (target.closest(ZEN_LIVE_BOT_AVATAR_DRAG_BLOCKED_SELECTOR)) return false;
  if (target.closest(ZEN_LIVE_BOT_AVATAR_DRAG_INTERACTIVE_SELECTOR)) return false;
  if (
    zenLiveBotAvatarPointMatchesSelector(
      clientX,
      clientY,
      ZEN_LIVE_BOT_AVATAR_DRAG_BLOCKED_SELECTOR
    )
  ) {
    return false;
  }
  if (
    zenLiveBotAvatarPointMatchesSelector(
      clientX,
      clientY,
      ZEN_LIVE_BOT_AVATAR_DRAG_INTERACTIVE_SELECTOR
    )
  ) {
    return false;
  }
  return true;
}

function zenLiveBotAvatarPointerCanStartGrab(
  node: HTMLElement,
  clientX: number,
  clientY: number,
  options: ZenLiveBotAvatarGrabStartOptions = {}
): boolean {
  if (zenLiveBotAvatarPointerIsInsideBody(node, clientX, clientY)) return true;
  if (!options.allowSurfaceDrag) return false;
  return zenLiveBotAvatarSurfaceCanStartGrab(
    options.eventTarget,
    clientX,
    clientY
  );
}

function PrismAppCursor(): React.JSX.Element | null {
  const [mounted, setMounted] = useState(false);
  const activeGrabPointerIdRef = useRef<number | null>(null);

  const clearGrabCursor = useCallback((): void => {
    activeGrabPointerIdRef.current = null;
    if (typeof document === "undefined") return;
    document.body.classList.remove(PRISM_APP_CURSOR_GRABBING_BODY_CLASS);
  }, []);

  useEffect(() => {
    setMounted(true);
    return () => {
      if (typeof document === "undefined") return;
      document.body.classList.remove(PRISM_APP_CURSOR_BODY_CLASS);
      document.body.classList.remove(PRISM_APP_CURSOR_DARK_BODY_CLASS);
      document.body.classList.remove(PRISM_APP_CURSOR_LIGHT_BODY_CLASS);
      document.body.classList.remove(PRISM_APP_CURSOR_GRABBING_BODY_CLASS);
    };
  }, []);

  useEffect(() => {
    if (!mounted || typeof document === "undefined") return;
    const applyCursorTheme = (): void => {
      const theme = document.body.dataset.prismTheme === "light" ? "light" : "dark";
      document.body.classList.toggle(PRISM_APP_CURSOR_DARK_BODY_CLASS, theme === "dark");
      document.body.classList.toggle(PRISM_APP_CURSOR_LIGHT_BODY_CLASS, theme === "light");
    };
    applyCursorTheme();
    const observer = new MutationObserver(applyCursorTheme);
    observer.observe(document.body, {
      attributeFilter: ["data-prism-theme"],
      attributes: true,
    });
    return () => {
      observer.disconnect();
      document.body.classList.remove(PRISM_APP_CURSOR_DARK_BODY_CLASS);
      document.body.classList.remove(PRISM_APP_CURSOR_LIGHT_BODY_CLASS);
    };
  }, [mounted]);

  useEffect(() => {
    if (!mounted || typeof window === "undefined") return;

    document.body.classList.add(PRISM_APP_CURSOR_BODY_CLASS);

    const startGrabCursor = (event: PointerEvent): void => {
      if (event.pointerType && event.pointerType !== "mouse") {
        clearGrabCursor();
        return;
      }
      if (event.button !== 0) return;
      if (!(event.target instanceof Element)) return;
      if (!event.target.closest(PRISM_APP_CURSOR_GRAB_SELECTOR)) return;
      activeGrabPointerIdRef.current = event.pointerId;
      document.body.classList.add(PRISM_APP_CURSOR_GRABBING_BODY_CLASS);
    };
    const finishGrabCursor = (event: PointerEvent): void => {
      if (activeGrabPointerIdRef.current === event.pointerId) {
        clearGrabCursor();
      }
    };
    const handlePointerOut = (event: PointerEvent): void => {
      if (event.relatedTarget) return;
      clearGrabCursor();
    };

    window.addEventListener("pointerdown", startGrabCursor, true);
    window.addEventListener("pointerup", finishGrabCursor, true);
    window.addEventListener("pointercancel", finishGrabCursor, true);
    window.addEventListener("pointerout", handlePointerOut, true);
    window.addEventListener("blur", clearGrabCursor);
    return () => {
      window.removeEventListener("pointerdown", startGrabCursor, true);
      window.removeEventListener("pointerup", finishGrabCursor, true);
      window.removeEventListener("pointercancel", finishGrabCursor, true);
      window.removeEventListener("pointerout", handlePointerOut, true);
      window.removeEventListener("blur", clearGrabCursor);
      clearGrabCursor();
      document.body.classList.remove(PRISM_APP_CURSOR_BODY_CLASS);
      document.body.classList.remove(PRISM_APP_CURSOR_DARK_BODY_CLASS);
      document.body.classList.remove(PRISM_APP_CURSOR_LIGHT_BODY_CLASS);
    };
  }, [clearGrabCursor, mounted]);

  if (!mounted || typeof document === "undefined") return null;

  return createPortal(<style>{PRISM_APP_CURSOR_GLOBAL_STYLE}</style>, document.body);
}

function resolveZenLiveBotActionCopyPlacement(
  node: HTMLElement,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS
): ZenLiveBotActionCopyPlacement {
  const copy = node.querySelector<HTMLElement>(
    "[data-zen-live-bot-action-copy-measure='true']"
  );
  const body =
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-layer='true']") ??
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-frame='true']") ??
    node;
  const bodyRect = body.getBoundingClientRect();
  const copyRect = copy?.getBoundingClientRect();
  const copyWidth = copyRect?.width || 156;
  const copyHeight = copyRect?.height || 56;
  const margin = ZEN_LIVE_BOT_AVATAR_VIEWPORT_MARGIN_PX;
  const safeLeft = safeAreaInsets.left + margin;
  const safeTop = safeAreaInsets.top + margin;
  const safeRight = viewportWidth - safeAreaInsets.right - margin;
  const safeBottom = viewportHeight - safeAreaInsets.bottom - margin;
  const spaceBelow = safeBottom - bodyRect.bottom;
  const spaceAbove = bodyRect.top - safeTop;
  const spaceLeft = bodyRect.left - safeLeft;
  const spaceRight = safeRight - bodyRect.right;
  const bodyGap = Math.max(
    8,
    Math.min(12, Math.min(bodyRect.width, bodyRect.height) * 0.07)
  );
  const verticalNeed = copyHeight + bodyGap;
  const horizontalNeed = copyWidth + margin;
  const topFits = spaceAbove >= verticalNeed;
  const bottomFits = spaceBelow >= verticalNeed;

  if (topFits || bottomFits) {
    if (topFits && bottomFits) {
      const bodyCenterY = bodyRect.top + bodyRect.height / 2;
      const safeCenterY = safeTop + (safeBottom - safeTop) / 2;
      return bodyCenterY > safeCenterY ? "top" : "bottom";
    }
    return topFits ? "top" : "bottom";
  }

  const proseHillRect = collectZenLiveBotProseHillRect(
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );

  if (proseHillRect) {
    const proseGap = Math.max(12, ZEN_LIVE_BOT_PROSE_HILL_CLEARANCE_PX * 0.5);
    const rightCopyLeft = clampZenLiveBotActionCopyAnchor(
      bodyRect.right,
      safeLeft,
      safeRight - copyWidth
    );
    if (
      bodyRect.left >= proseHillRect.right &&
      rightCopyLeft >= proseHillRect.right + proseGap
    ) {
      return "right";
    }

    const leftCopyRight = clampZenLiveBotActionCopyAnchor(
      bodyRect.left,
      safeLeft + copyWidth,
      safeRight
    );
    if (
      bodyRect.right <= proseHillRect.left &&
      leftCopyRight <= proseHillRect.left - proseGap
    ) {
      return "left";
    }
  }

  if (spaceRight >= horizontalNeed || spaceLeft >= horizontalNeed) {
    return spaceRight >= spaceLeft ? "right" : "left";
  }
  return spaceAbove > spaceBelow ? "top" : "bottom";
}

function resolveZenLiveBotActionCopyOffsetX(
  node: HTMLElement,
  position: ZenLiveBotAvatarPosition,
  viewportWidth: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS,
  placement: ZenLiveBotActionCopyPlacement = "bottom"
): number {
  if (placement === "left" || placement === "right") return 0;
  const copy = node.querySelector<HTMLElement>(
    "[data-zen-live-bot-action-copy-measure='true']"
  );
  if (!copy) return 0;
  const rootRect = node.getBoundingClientRect();
  const copyRect = copy.getBoundingClientRect();
  const copyWidth = copyRect.width || 320;
  const computedStyle = window.getComputedStyle(node);
  const bodyXRaw = computedStyle.getPropertyValue("--zen-live-bot-body-x").trim();
  const copyCenterAnchorRaw = computedStyle
    .getPropertyValue("--zen-live-bot-copy-center-anchor")
    .trim();
  const bodyXAnchor = bodyXRaw.endsWith("%")
    ? (Number.parseFloat(bodyXRaw) / 100) * rootRect.width
    : Number.isFinite(Number.parseFloat(bodyXRaw))
      ? Number.parseFloat(bodyXRaw)
      : rootRect.width / 2;
  const copyCenterAnchor = Number.isFinite(Number.parseFloat(copyCenterAnchorRaw))
    ? Number.parseFloat(copyCenterAnchorRaw)
    : 0;
  const defaultCopyLeft =
    position.x + bodyXAnchor + copyCenterAnchor - copyWidth / 2;
  const margin = ZEN_LIVE_BOT_AVATAR_VIEWPORT_MARGIN_PX;
  const safeLeftCandidate = safeAreaInsets.left + margin;
  const safeRightCandidate = viewportWidth - safeAreaInsets.right - margin;
  const safeLeft =
    safeRightCandidate > safeLeftCandidate ? safeLeftCandidate : margin;
  const safeRight =
    safeRightCandidate > safeLeftCandidate ? safeRightCandidate : viewportWidth - margin;
  const rightOverflow = defaultCopyLeft + copyWidth - safeRight;
  const leftOverflow = safeLeft - defaultCopyLeft;
  if (leftOverflow > 0) return Math.ceil(leftOverflow);
  if (rightOverflow > 0) return -Math.ceil(rightOverflow);
  return 0;
}

function clampZenLiveBotActionCopyAnchor(
  value: number,
  min: number,
  max: number
): number {
  if (max < min) return value;
  return Math.max(min, Math.min(max, value));
}

function resolveZenLiveBotActionCopyAnchor(
  node: HTMLElement,
  placement: ZenLiveBotActionCopyPlacement,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS
): Omit<ZenLiveBotActionCopyAnchor, "key"> {
  const copy = node.querySelector<HTMLElement>(
    "[data-zen-live-bot-action-copy-measure='true']"
  );
  const body =
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-layer='true']") ??
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-frame='true']") ??
    node;
  const bodyRect = body.getBoundingClientRect();
  const copyRect = copy?.getBoundingClientRect();
  const copyWidth = copyRect?.width || 260;
  const copyHeight = copyRect?.height || 48;
  const margin = ZEN_LIVE_BOT_AVATAR_VIEWPORT_MARGIN_PX;
  const safeLeft = safeAreaInsets.left + margin;
  const safeTop = safeAreaInsets.top + margin;
  const safeRight = viewportWidth - safeAreaInsets.right - margin;
  const safeBottom = viewportHeight - safeAreaInsets.bottom - margin;
  const bodyGap = Math.max(
    8,
    Math.min(12, Math.min(bodyRect.width, bodyRect.height) * 0.07)
  );
  const centerX = bodyRect.left + bodyRect.width / 2;
  const centerY = bodyRect.top + bodyRect.height / 2;

  if (placement === "top") {
    return {
      placement,
      x: clampZenLiveBotActionCopyAnchor(
        centerX,
        safeLeft + copyWidth / 2,
        safeRight - copyWidth / 2
      ),
      y: clampZenLiveBotActionCopyAnchor(
        bodyRect.top - bodyGap,
        safeTop + copyHeight,
        safeBottom
      ),
    };
  }

  if (placement === "right") {
    return {
      placement,
      x: clampZenLiveBotActionCopyAnchor(
        bodyRect.right + bodyGap,
        safeLeft,
        safeRight - copyWidth
      ),
      y: clampZenLiveBotActionCopyAnchor(
        centerY,
        safeTop + copyHeight / 2,
        safeBottom - copyHeight / 2
      ),
    };
  }

  if (placement === "left") {
    return {
      placement,
      x: clampZenLiveBotActionCopyAnchor(
        bodyRect.left - bodyGap,
        safeLeft + copyWidth,
        safeRight
      ),
      y: clampZenLiveBotActionCopyAnchor(
        centerY,
        safeTop + copyHeight / 2,
        safeBottom - copyHeight / 2
      ),
    };
  }

  return {
    placement,
    x: clampZenLiveBotActionCopyAnchor(
      centerX,
      safeLeft + copyWidth / 2,
      safeRight - copyWidth / 2
    ),
    y: clampZenLiveBotActionCopyAnchor(
      bodyRect.bottom + bodyGap,
      safeTop,
      safeBottom - copyHeight
    ),
  };
}

function zenLiveBotAvatarPositionLimits(
  bounds: ZenLiveBotAvatarBounds,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS
): { minX: number; maxX: number; minY: number; maxY: number } {
  const minUnionPosition = clampDevPanelPositionToSafeArea({
    x: Number.NEGATIVE_INFINITY,
    y: Number.NEGATIVE_INFINITY,
    panelWidth: bounds.width,
    panelHeight: bounds.height,
    viewportWidth,
    viewportHeight,
    margin: ZEN_LIVE_BOT_AVATAR_VIEWPORT_MARGIN_PX,
    safeAreaInsets,
  });
  const maxUnionPosition = clampDevPanelPositionToSafeArea({
    x: Number.MAX_SAFE_INTEGER,
    y: Number.MAX_SAFE_INTEGER,
    panelWidth: bounds.width,
    panelHeight: bounds.height,
    viewportWidth,
    viewportHeight,
    margin: ZEN_LIVE_BOT_AVATAR_VIEWPORT_MARGIN_PX,
    safeAreaInsets,
  });
  const minX = minUnionPosition.x - bounds.offsetX;
  const minY = minUnionPosition.y - bounds.offsetY;
  const maxX = Math.max(minX, maxUnionPosition.x - bounds.offsetX);
  const maxY = Math.max(minY, maxUnionPosition.y - bounds.offsetY);
  return { minX, maxX, minY, maxY };
}

function clampZenLiveBotAvatarPosition(
  position: ZenLiveBotAvatarPosition,
  bounds: ZenLiveBotAvatarBounds,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS
): ZenLiveBotAvatarPosition {
  const { minX, maxX, minY, maxY } = zenLiveBotAvatarPositionLimits(
    bounds,
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );
  return {
    x: Math.max(minX, Math.min(maxX, position.x)),
    y: Math.max(minY, Math.min(maxY, position.y)),
  };
}

function resolveZenLiveBotAvatarProseHillPosition(
  position: ZenLiveBotAvatarPosition,
  bounds: ZenLiveBotAvatarBounds,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS,
  velocity: ZenLiveBotAvatarVelocity = { x: 0, y: 0 }
): ZenLiveBotAvatarPosition {
  const proseHillRect = collectZenLiveBotProseHillRect(
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );
  if (!proseHillRect) return position;

  const horizontalClearance = Math.max(
    ZEN_LIVE_BOT_PROSE_HILL_CLEARANCE_PX,
    Math.min(320, bounds.width * 1.18)
  );
  const inflatedHillRect = zenLiveBotRectFromEdges(
    proseHillRect.left - horizontalClearance,
    proseHillRect.top - ZEN_LIVE_BOT_PROSE_HILL_VERTICAL_CLEARANCE_PX,
    proseHillRect.right + horizontalClearance,
    proseHillRect.bottom + ZEN_LIVE_BOT_PROSE_HILL_VERTICAL_CLEARANCE_PX
  );
  const currentRect = zenLiveBotAvatarRectForPosition(position, bounds);
  if (!zenLiveBotRectsOverlap(currentRect, inflatedHillRect)) return position;

  const { minX, maxX } = zenLiveBotAvatarPositionLimits(
    bounds,
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );
  const leftPosition = clampZenLiveBotAvatarPosition(
    {
      x: inflatedHillRect.left - bounds.width - bounds.offsetX,
      y: position.y,
    },
    bounds,
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );
  const rightPosition = clampZenLiveBotAvatarPosition(
    {
      x: inflatedHillRect.right - bounds.offsetX,
      y: position.y,
    },
    bounds,
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );
  const leftFreeSpace = Math.max(0, proseHillRect.left - minX);
  const rightFreeSpace = Math.max(
    0,
    maxX + bounds.offsetX + bounds.width - proseHillRect.right
  );
  const preferredSide =
    Math.abs(velocity.x) > 42
      ? velocity.x < 0
        ? "left"
        : "right"
      : currentRect.centerX < proseHillRect.centerX
        ? "left"
        : currentRect.centerX > proseHillRect.centerX
          ? "right"
          : rightFreeSpace >= leftFreeSpace
            ? "right"
            : "left";
  const candidates: Array<{
    side: "left" | "right";
    position: ZenLiveBotAvatarPosition;
  }> = [
    { side: "left", position: leftPosition },
    { side: "right", position: rightPosition },
  ];

  return candidates
    .map((candidate) => {
      const candidateRect = zenLiveBotAvatarRectForPosition(
        candidate.position,
        bounds
      );
      const overlapArea = zenLiveBotRectOverlapArea(
        candidateRect,
        inflatedHillRect
      );
      const distance = Math.hypot(
        candidate.position.x - position.x,
        candidate.position.y - position.y
      );
      const sidePenalty = candidate.side === preferredSide ? 0 : 24;
      return {
        ...candidate,
        score: overlapArea * 100 + distance + sidePenalty,
      };
    })
    .sort((first, second) => first.score - second.score)[0]!.position;
}

function resolveZenLiveBotAvatarProseHillMotion(
  position: ZenLiveBotAvatarPosition,
  velocity: ZenLiveBotAvatarVelocity,
  bounds: ZenLiveBotAvatarBounds,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets = DEV_PANEL_SAFE_AREA_DEFAULT_INSETS,
  dtSeconds = 1 / 60
): { velocity: ZenLiveBotAvatarVelocity; affected: boolean } {
  const target = resolveZenLiveBotAvatarProseHillPosition(
    position,
    bounds,
    viewportWidth,
    viewportHeight,
    safeAreaInsets,
    velocity
  );
  const deltaX = target.x - position.x;
  if (Math.abs(deltaX) < 0.75) {
    return { velocity, affected: false };
  }

  const direction = Math.sign(deltaX);
  const distanceRatio = Math.min(1, Math.abs(deltaX) / Math.max(1, bounds.width * 1.15));
  const hillStrength = Math.max(0.22, distanceRatio);
  const acceleration =
    ZEN_LIVE_BOT_PROSE_HILL_ACCELERATION_PX_PER_SEC * hillStrength;
  const inertiaDamping = Math.pow(
    ZEN_LIVE_BOT_PROSE_HILL_INERTIA_DAMPING_PER_FRAME,
    dtSeconds * 60
  );
  const verticalDamping = Math.pow(
    ZEN_LIVE_BOT_PROSE_HILL_VERTICAL_DAMPING_PER_FRAME,
    dtSeconds * 60
  );
  const speedTowardSide = velocity.x * direction * inertiaDamping;
  const acceleratedSpeedTowardSide =
    speedTowardSide + acceleration * Math.max(0.001, dtSeconds);
  const nextSpeedTowardSide = Math.min(
    ZEN_LIVE_BOT_PROSE_HILL_MAX_SIDE_SPEED,
    Math.max(
      -ZEN_LIVE_BOT_PROSE_HILL_MAX_SIDE_SPEED * 0.42,
      acceleratedSpeedTowardSide
    )
  );

  return {
    velocity: {
      x: direction * nextSpeedTowardSide,
      y: velocity.y * verticalDamping,
    },
    affected: true,
  };
}

function resolveDefaultZenLiveBotAvatarPosition(
  node: HTMLElement,
  viewportWidth: number,
  viewportHeight: number,
  safeAreaInsets: DevPanelSafeAreaInsets
): ZenLiveBotAvatarPosition {
  const bounds = measureZenLiveBotAvatarBounds(node);
  const rootRect = node.getBoundingClientRect();
  const body =
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-layer='true']") ??
    node.querySelector<HTMLElement>("[data-zen-live-bot-body-frame='true']") ??
    node;
  const bodyRect = body.getBoundingClientRect();
  const bodyCenterOffsetX = bodyRect.left - rootRect.left + bodyRect.width / 2;
  const bodyCenterOffsetY = bodyRect.top - rootRect.top + bodyRect.height / 2;
  const leftSafe = safeAreaInsets.left + ZEN_LIVE_BOT_AVATAR_VIEWPORT_MARGIN_PX;
  const desiredBodyCenterX = Math.max(
    leftSafe + Math.min(bodyRect.width, bodyRect.height) * 0.62,
    Math.min(viewportWidth * 0.18, 220)
  );
  const desiredBodyCenterY = Math.max(
    safeAreaInsets.top + Math.min(bodyRect.width, bodyRect.height),
    Math.min(viewportHeight * 0.44, viewportHeight - safeAreaInsets.bottom - bodyRect.height)
  );
  return clampZenLiveBotAvatarPosition(
    {
      x: desiredBodyCenterX - bodyCenterOffsetX,
      y: desiredBodyCenterY - bodyCenterOffsetY,
    },
    bounds,
    viewportWidth,
    viewportHeight,
    safeAreaInsets
  );
}

function sampleZenLiveBotAvatarDragVelocity(
  dragState: ZenLiveBotAvatarDragState,
  clientX: number,
  clientY: number,
  timeMs: number
): void {
  const dtSeconds = Math.max(
    0.008,
    (timeMs - dragState.lastTimeMs) / 1000 || 0.016
  );
  const sampleVelocityX = (clientX - dragState.lastClientX) / dtSeconds;
  const sampleVelocityY = (clientY - dragState.lastClientY) / dtSeconds;
  dragState.velocityX = dragState.velocityX * 0.36 + sampleVelocityX * 0.64;
  dragState.velocityY = dragState.velocityY * 0.36 + sampleVelocityY * 0.64;
  dragState.lastClientX = clientX;
  dragState.lastClientY = clientY;
  dragState.lastTimeMs = timeMs;
}

function resolveZenLiveBotAvatarReleaseVelocity(
  dragState: ZenLiveBotAvatarDragState
): ZenLiveBotAvatarVelocity {
  const sampledVelocity = {
    x: dragState.velocityX,
    y: dragState.velocityY,
  };
  if (
    Math.hypot(sampledVelocity.x, sampledVelocity.y) >=
    ZEN_LIVE_BOT_AVATAR_FLING_MIN_SPEED
  ) {
    return sampledVelocity;
  }

  const dx = dragState.lastClientX - dragState.startClientX;
  const dy = dragState.lastClientY - dragState.startClientY;
  const distance = Math.hypot(dx, dy);
  const elapsedSeconds = Math.max(
    0.016,
    (dragState.lastTimeMs - dragState.startTimeMs) / 1000 || 0.016
  );
  if (distance < 56 || elapsedSeconds > 0.48) {
    return sampledVelocity;
  }

  const fallbackSpeed = Math.min(
    ZEN_LIVE_BOT_AVATAR_FLING_MAX_SPEED,
    Math.max(ZEN_LIVE_BOT_AVATAR_FLING_MIN_SPEED * 1.1, distance / elapsedSeconds)
  );
  return {
    x: (dx / distance) * fallbackSpeed,
    y: (dy / distance) * fallbackSpeed,
  };
}

function advanceZenLiveBotAvatarMetalRotationDegrees(
  currentDegrees: number,
  previousPosition: ZenLiveBotAvatarPosition | null,
  nextPosition: ZenLiveBotAvatarPosition
): number {
  if (!previousPosition) return currentDegrees;
  const horizontalDeltaPx = nextPosition.x - previousPosition.x;
  if (Math.abs(horizontalDeltaPx) < 0.05) return currentDegrees;
  const rotationDelta = Math.sign(horizontalDeltaPx) * Math.min(
    Math.abs(horizontalDeltaPx) * ZEN_LIVE_BOT_AVATAR_METAL_DEGREES_PER_PX,
    ZEN_LIVE_BOT_AVATAR_METAL_MAX_ROTATION_STEP_DEGREES
  );
  return currentDegrees + rotationDelta;
}

function resolveZenLiveBotScreenGlareState(
  position: ZenLiveBotAvatarPosition,
  avatarWidthPx: number,
  viewportWidth: number,
  viewportHeight: number
): ZenLiveBotScreenGlareState {
  const safeViewportWidth = Math.max(1, viewportWidth);
  const safeViewportHeight = Math.max(1, viewportHeight);
  const centerX = position.x + avatarWidthPx / 2;
  const centerY = position.y + avatarWidthPx / 2;
  const lightX = safeViewportWidth * ZEN_LIVE_BOT_SCREEN_GLARE_LIGHT_X_RATIO;
  const lightY = safeViewportHeight * ZEN_LIVE_BOT_SCREEN_GLARE_LIGHT_Y_RATIO;
  const normalizedX = (lightX - centerX) / safeViewportWidth;
  const normalizedY = (lightY - centerY) / safeViewportHeight;
  const xPct = Math.max(
    ZEN_LIVE_BOT_SCREEN_GLARE_X_MIN_PCT,
    Math.min(
      ZEN_LIVE_BOT_SCREEN_GLARE_X_MAX_PCT,
      50 + normalizedX * ZEN_LIVE_BOT_SCREEN_GLARE_X_GAIN
    )
  );
  const yPct = Math.max(
    ZEN_LIVE_BOT_SCREEN_GLARE_Y_MIN_PCT,
    Math.min(
      ZEN_LIVE_BOT_SCREEN_GLARE_Y_MAX_PCT,
      42 + normalizedY * ZEN_LIVE_BOT_SCREEN_GLARE_Y_GAIN
    )
  );
  const angleDeg =
    Math.atan2(
      normalizedY * ZEN_LIVE_BOT_SCREEN_GLARE_ANGLE_Y_WEIGHT,
      normalizedX
    ) *
      (180 / Math.PI) +
    96;
  const distance = Math.min(1, Math.hypot(normalizedX, normalizedY) * 1.7);
  return {
    xPct,
    yPct,
    angleDeg,
    opacity: 0.38 + distance * 0.16,
  };
}

function resolveMemoryBubbleCollisionsPx(
  positionsPx: Record<string, MemoryBubblePositionPx>,
  radiiPx: Record<string, number>,
  boundsPx: { minX: number; maxX: number; minY: number; maxY: number },
  draggedId: string
): Set<string> {
  const ids = Object.keys(positionsPx);
  const touched = new Set<string>([draggedId]);
  const active = new Set<string>([draggedId]);

  // Localized propagation: resolve collisions from dragged bubble outward
  // instead of running O(n^2) over the full cloud on every pointer frame.
  for (let iter = 0; iter < 8; iter += 1) {
    const frontier = Array.from(active);
    active.clear();
    let anyOverlap = false;
    for (const aId of frontier) {
      const a = positionsPx[aId];
      const aRadius = radiiPx[aId] ?? 0;
      if (!a) continue;
      for (const bId of ids) {
        if (aId === bId) continue;
        const b = positionsPx[bId];
        const bRadius = radiiPx[bId] ?? 0;
        if (!b) continue;
        const dx = b.x - a.x;
        const dy = b.y - a.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 0.0001;
        const minDist = aRadius + bRadius + 3.6;
        if (dist >= minDist) continue;
        anyOverlap = true;
        const nx = dx / dist;
        const ny = dy / dist;
        const overlap = minDist - dist;

        if (aId === draggedId) {
          b.x += nx * overlap;
          b.y += ny * overlap;
          touched.add(bId);
          active.add(bId);
        } else if (bId === draggedId) {
          a.x -= nx * overlap;
          a.y -= ny * overlap;
          touched.add(aId);
          active.add(aId);
        } else {
          const half = overlap * 0.5;
          a.x -= nx * half;
          a.y -= ny * half;
          b.x += nx * half;
          b.y += ny * half;
          touched.add(aId);
          touched.add(bId);
          active.add(aId);
          active.add(bId);
        }
      }
    }

    for (const id of touched) {
      const p = positionsPx[id];
      const radius = radiiPx[id] ?? 0;
      p.x = Math.max(boundsPx.minX + radius, Math.min(boundsPx.maxX - radius, p.x));
      p.y = Math.max(boundsPx.minY + radius, Math.min(boundsPx.maxY - radius, p.y));
    }
    if (!anyOverlap) break;
  }

  return touched;
}

function memoryBubblePositionsPxToPctMap(
  dragState: Pick<MemoryBubbleDragState, "positionsPx" | "cloudWidth" | "cloudHeight">
): Record<string, MemoryBubblePositionPct> {
  const next: Record<string, MemoryBubblePositionPct> = {};
  for (const [id, pos] of Object.entries(dragState.positionsPx)) {
    next[id] = {
      xPct: Math.max(0, Math.min(100, (pos.x / dragState.cloudWidth) * 100)),
      yPct: Math.max(0, Math.min(100, (pos.y / dragState.cloudHeight) * 100)),
    };
  }
  return next;
}

interface PrismWordmarkProps {
  className?: string;
}

function PrismWordmark({ className }: PrismWordmarkProps): React.JSX.Element {
  const colors = PRISM_WORDMARK_PALETTE;

  return (
    <svg
      className={className}
      viewBox="0 0 610 72"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label="Prism"
    >
      {/* Shared stroke geometry lives on the <g>; only the per-letter
          stroke colors vary, which keeps the letterforms consistent
          while preserving the canonical Prism palette mapping. */}
      <g
        fill="none"
        strokeLinecap="round"
        strokeLinejoin="round"
        strokeWidth="12"
      >
        {/* P */}
        <path
          stroke={colors[0]}
          d="M6,66V6h50c10.67,0,16,5.33,16,16s-5.33,16-16,16H18"
        />
        {/* R — two subpaths grouped so both subpaths inherit the same
            fixed color from a single <g stroke>. */}
        <g stroke={colors[1]}>
          <path d="M134,66V6h50c10.67,0,16,5.33,16,16s-5.33,16-16,16h-38" />
          <path d="M162,38l44,28" />
        </g>
        {/* I */}
        <path stroke={colors[2]} d="M282,6v60" />
        {/* S */}
        <path
          stroke={colors[3]}
          d="M430,6h-48c-10.67,0-16,5.33-16,16,0,8,4,12.67,12,14l52,2c9.33,1.33,14,6,14,14,0,9.33-5.33,14-16,14h-48"
        />
        {/* M — three subpaths (two uprights + the central chevron). */}
        <g stroke={colors[4]}>
          <path d="M508,66V6" />
          <path d="M508,6l48,48,48-48" />
          <path d="M604,6v60" />
        </g>
      </g>
    </svg>
  );
}

interface PrismWordmarkWithVersionProps {
  /** Class applied to the wordmark SVG (e.g. brandWordmark / hubHomeWordmark). */
  className?: string;
  /**
   * Visual scale of the version pill.
   *  - "lg" matches the 30px brandWordmark (Hub card, auth, gated screen)
   *  - "sm" matches the 20px hubHomeWordmark (chat/sandbox header back button)
   */
  size?: "lg" | "sm";
  /** Optional override applied to the lockup row span. */
  rowClassName?: string;
  /** Optional override applied to the pill span. */
  pillClassName?: string;
  /** Optional test-id passthrough on the pill (auth screen relies on this). */
  pillTestId?: string;
}

/**
 * Lockup that renders the Prism wordmark with the app version pill aligned
 * to its baseline. Single component so the chip stays visually consistent
 * everywhere the wordmark appears.
 */
function PrismWordmarkWithVersion({
  className,
  size = "lg",
  rowClassName,
  pillClassName,
  pillTestId,
}: PrismWordmarkWithVersionProps): React.JSX.Element {
  const rowClasses = [
    styles.wordmarkLockup,
    size === "sm" ? styles.wordmarkLockupSm : null,
    rowClassName,
  ]
    .filter(Boolean)
    .join(" ");
  const pillClasses = [
    styles.wordmarkVersionPill,
    size === "sm" ? styles.wordmarkVersionPillSm : null,
    pillClassName,
  ]
    .filter(Boolean)
    .join(" ");
  return (
    <span className={rowClasses}>
      <PrismWordmark className={className} />
      <span className={pillClasses} data-testid={pillTestId}>
        {PRISM_APP_VERSION}
      </span>
    </span>
  );
}

interface AppletLabelProps {
  appletId: PrismAppletId;
  className?: string;
  versionClassName?: string;
}

function AppletLabel({
  appletId,
  className,
  versionClassName,
}: AppletLabelProps): React.JSX.Element {
  const applet = PRISM_APPLETS[appletId];
  const labelClasses = [styles.appletLabel, className].filter(Boolean).join(" ");
  const versionClasses = [styles.appletVersion, versionClassName].filter(Boolean).join(" ");
  return (
    <span className={labelClasses} aria-label={`${applet.name} ${prismAppletVersionLabel(appletId)}`}>
      <span>{applet.name}</span>
      <span className={versionClasses}>{prismAppletVersionLabel(appletId)}</span>
    </span>
  );
}

function AppletHeaderLabel({ appletId }: { appletId: PrismAppletId }): React.JSX.Element {
  return (
    <AppletLabel
      appletId={appletId}
      className={styles.appletHeaderLabel}
      versionClassName={styles.appletHeaderVersion}
    />
  );
}

interface PrismTriangleMarkProps {
  className?: string;
}

function PrismTriangleMark({ className }: PrismTriangleMarkProps): React.JSX.Element {
  return (
    <svg
      className={className}
      viewBox="0 0 56 56"
      xmlns="http://www.w3.org/2000/svg"
      fill="none"
      aria-hidden="true"
      focusable="false"
    >
      <path
        d="M28 6L48 43H8L28 6Z"
        stroke="currentColor"
        strokeLinecap="butt"
        strokeLinejoin="miter"
        strokeMiterlimit="10"
        strokeWidth="7"
      />
    </svg>
  );
}

// ── Chat-mode picker geometry ────────────────────────────────────────
// Adaptive sizing for the start-of-chat bot picker. As the user's bot
// library grows, individual tiles shrink so the whole picker stays
// inside the empty-state column without ever pushing the composer off-
// screen. Low counts stay capped so a single bot reads as a card, not a
// wall; at the other extreme (~hundreds of bots)
// it collapses into a dense palette wall.
//
// The math is intentionally piecewise rather than a smooth log curve —
// each step lands on a rounded pixel size that pairs cleanly with stroke
// widths and gap so adjacent tiles never look jittery. Mirrored CSS
// custom properties (--tile-size / --tile-gap / --tile-hover-scale) are
// what actually drive the layout; this function is the single source of
// truth for that triple.

interface PickerGeometry {
  /** Width of the picker frame, in pixels. Mobile keeps this equal to height. */
  pickerWidth: number;
  /** Height of the picker frame, in pixels. */
  pickerHeight: number;
  /** Edge length of each square tile, in pixels. */
  tileSize: number;
  /** BotGlyph SVG `size` prop — tracks ~50% of the tile so the mark fills the avatar without crowding. */
  glyphSize: number;
  /** SVG stroke width — slightly thinner on big glyphs so heavy lines don't dominate at scale. */
  glyphStroke: number;
  /** Multiplier the hovered tile scales TO. Smaller for big base sizes so the magnified tile doesn't burst out of the picker. */
  hoverScale: number;
  /** Gap between tiles — proportional to tile size so the row's negative space stays balanced visually. */
  tileGap: number;
  /** Column count the grid renders with, biased toward the frame aspect ratio. */
  gridCols: number;
  /** Row count occupied inside the picker frame. */
  gridRows: number;
  /** Blank cells used to keep incomplete final rows from changing the grid footprint. */
  fillerCells: number;
  /** True when the picker is presenting a single featured bot card. */
  singleBot: boolean;
  /** True when three bots use the narrow/mobile pyramid composition. */
  threeBotStack: boolean;
  /** True when mobile low/mid counts use a taller compact column layout. */
  mobileColumnStack: boolean;
  /** True when an odd-count balancing cell should lead the bot buttons. */
  leadingFillerCell: boolean;
  /** True for the bridge stage: flat Stage-2-style tiles that still keep names. */
  namedFlatTile: boolean;
  /** True when mobile density should let the picker replace the hero copy. */
  suppressMobileHeroCopy: boolean;
  /** True from the icon-only flat stage onward. */
  flattenTile: boolean;
  /** True from level 3 onward: increase the glyph-to-container ratio. */
  enlargeGlyph: boolean;
  /** True from level 4 onward: hide the bot glyph inside the tile. */
  hideGlyphByDefault: boolean;
  /** True late in level 2 onward: use a crosshair cursor for denser picking. */
  crosshairCursor: boolean;
  /** True shortly after crosshair in level 2: use a dot cursor before glyphs disappear. */
  dotCursor: boolean;
  /**
   * Level 5: tiny pixel swatches with no border and no rounded corners.
   */
  solidSwatch: boolean;
  /**
   * Level 5: very large bot libraries render as a flat, gapless pixel grid.
   */
  compactPixelGrid: boolean;
  /**
   * Level 5 onward: selected glyph simplifies to an inverted dot.
   */
  selectedDotGlyph: boolean;
  /**
   * Level 6: fully dense picker collapses into a radial rainbow field.
   */
  radialRainbowGradient: boolean;
}

type PickerDensityStageId = 1 | 1.5 | 2 | 3 | 4 | 5 | 6;

interface PickerDensityBreakpoints {
  namedFlatTileCountMin: number;
  flatTileCountMin: number;
  largeGlyphTileCountMin: number;
  crosshairTileCountMin: number;
  dotTileCountMin: number;
  glyphlessCardCountMin: number;
  compactPixelGridCountMin: number;
  radialRainbowCountMin: number;
}

interface PickerDensityStageTarget {
  id: PickerDensityStageId;
  label: string;
  description: string;
  targetCount: number;
}

/**
 * Density breakpoints for the start-of-chat picker.
 *
 * Counts are viewport-scaled below; stage 2 intentionally starts early so
 * the larger glyph-to-box treatment appears before the grid feels crowded.
 * Later stages simplify more slowly: remove glyph, then card chrome, then
 * collapse into the pixel-grid states.
 */
const PICKER_MOBILE_MAX_SQUARE_SIZE = 320;
const PICKER_LOW_COUNT_MAX = 10;
const PICKER_ICON_ONLY_FLAT_COUNT = PICKER_LOW_COUNT_MAX + 1;
const PICKER_MOBILE_LOW_COUNT_MAX_SIZE = 260;
const PICKER_MOBILE_COLUMN_STACK_MAX_HEIGHT = 340;
const PICKER_DESKTOP_LOW_COUNT_MAX_WIDTH = 460;
const PICKER_DESKTOP_MAX_WIDTH = 1280;
const PICKER_DESKTOP_MAX_HEIGHT = 260;
const PICKER_DESKTOP_ASPECT_RATIO = 16 / 9;
const PICKER_MAX_TILE_SIZE = 220;
const PICKER_SINGLE_BOT_TILE_SIZE_MOBILE = 168;
/** Larger than legacy 128 — single-bot reads as an intentional hero tile on widescreen */
const PICKER_SINGLE_BOT_TILE_SIZE_DESKTOP = 168;
const PICKER_FEW_BOT_TILE_SIZE_MOBILE = 124;
const PICKER_FEW_BOT_TILE_SIZE_DESKTOP = 104;
const PICKER_LOW_COUNT_TILE_SIZE_MOBILE = 72;
const PICKER_LOW_COUNT_TILE_SIZE_DESKTOP = 76;
const PICKER_TILE_NAME_MIN_SIZE = PICKER_LOW_COUNT_TILE_SIZE_MOBILE;
const PICKER_TILE_COMPACT_NAME_MAX_SIZE = 92;
const PICKER_LOW_COUNT_FRAME_VERTICAL_PAD = 24;
const PICKER_THREE_STACK_TILE_SIZE_MOBILE = 128;
const PICKER_DEFAULT_GLYPH_RATIO = 0.5;
const PICKER_STAGE_TWO_GLYPH_RATIO = 0.82;
const PICKER_PIXEL_GLYPH_RATIO = 0.86;
const PICKER_PIXEL_GLYPH_MIN_SIZE = 9;
const PICKER_PIXEL_GLYPH_STROKE = 0.9;
const PICKER_CROSSHAIR_STAGE_TWO_PROGRESS = 0;
const PICKER_DOT_STAGE_TWO_PROGRESS = 0.2;
const PICKER_REFERENCE_SIZE = 480;
const PICKER_MIN_AVAILABLE_WIDTH = 180;
const PICKER_MIN_AVAILABLE_HEIGHT = 180;
const PICKER_BREAKPOINT_SCALE_EXPONENT = 1.2;
const PICKER_BREAKPOINT_SCALE_MIN = 0.45;
const PICKER_BREAKPOINT_SCALE_MAX = 2.5;
const PICKER_MOBILE_BREAKPOINT = 720;
const DESKTOP_SIDEBAR_WIDTH = 280;
const DESKTOP_MESSAGES_PADDING_X = 40;
/** Sidebar drawer (single-column shell) through this width. */
const SIDEBAR_DRAWER_BREAKPOINT = 1080;
const APP_SIDEBAR_NAVIGATION_ID = "prism-sidebar-navigation";
/**
 * Phone-only shell: fixed ☰ + floating wrench + compact header. Wider than
 * this (up to `PICKER_MOBILE_BREAKPOINT`) uses the › sidebar handle + looser
 * gutters — see `page.module.css` letterbox rules.
 */
const PHONE_MENU_BREAKPOINT = 560;
const MOBILE_LETTERBOX_MIN_WIDTH = PHONE_MENU_BREAKPOINT + 1;

/** Total L+R messages/compose horizontal padding for empty-state picker math. */
function mobileMessagesHorizontalPaddingTotal(viewportWidth: number): number {
  if (viewportWidth > PICKER_MOBILE_BREAKPOINT) {
    return DESKTOP_MESSAGES_PADDING_X;
  }
  if (viewportWidth >= MOBILE_LETTERBOX_MIN_WIDTH) {
    /* `--chat-inline-gutter` ≈ 20px each side (561–720px band). */
    return 40;
  }
  /* Phone `--chat-inline-gutter` ≈ 60px each side (≤560px). */
  return 120;
}
const PICKER_SIDE_GUTTER = 48;
const PICKER_NAMED_FLAT_MOBILE_COUNT = 5;
const PICKER_NAMED_FLAT_DESKTOP_COUNT = 8;
const LARGE_GLYPH_BASE_COUNT = 180;
const GLYPHLESS_CARD_BASE_COUNT = 360;
const COMPACT_PIXEL_GRID_BASE_COUNT = 480;
const RADIAL_RAINBOW_BASE_COUNT = 720;
const PICKER_PARALLAX_X = 3;
const PICKER_PARALLAX_Y = 2;
const CHAT_HEADER_HEIGHT_ESTIMATE = 64;
const COMPOSE_HEIGHT_ESTIMATE = 138;
const EMPTY_STATE_CHROME_HEIGHT_ESTIMATE = 220;

const subscribeViewportWidth = (onStoreChange: () => void): (() => void) => {
  window.addEventListener("resize", onStoreChange);
  return () => window.removeEventListener("resize", onStoreChange);
};

const getViewportWidthSnapshot = (): number =>
  typeof window === "undefined" ? PICKER_REFERENCE_SIZE : window.innerWidth;

const getViewportHeightSnapshot = (): number =>
  typeof window === "undefined" ? 900 : window.innerHeight;

const getServerViewportWidthSnapshot = (): number => PICKER_REFERENCE_SIZE;
const getServerViewportHeightSnapshot = (): number => 900;

function useViewportWidth(): number {
  return useSyncExternalStore(
    subscribeViewportWidth,
    getViewportWidthSnapshot,
    getServerViewportWidthSnapshot
  );
}

function useViewportHeight(): number {
  return useSyncExternalStore(
    subscribeViewportWidth,
    getViewportHeightSnapshot,
    getServerViewportHeightSnapshot
  );
}

function pickerAvailableWidth(viewportWidth: number): number {
  const isMobile = viewportWidth <= PICKER_MOBILE_BREAKPOINT;
  const chatPaneWidth = isMobile
    ? viewportWidth
    : Math.max(PICKER_MIN_AVAILABLE_WIDTH, viewportWidth - DESKTOP_SIDEBAR_WIDTH);
  const messagesPadding = isMobile
    ? mobileMessagesHorizontalPaddingTotal(viewportWidth)
    : DESKTOP_MESSAGES_PADDING_X;
  const availableWidth = chatPaneWidth - messagesPadding - PICKER_SIDE_GUTTER;

  return Math.max(
    PICKER_MIN_AVAILABLE_WIDTH,
    Math.min(
      isMobile ? PICKER_MOBILE_MAX_SQUARE_SIZE : PICKER_DESKTOP_MAX_WIDTH,
      availableWidth
    )
  );
}

function pickerAvailableHeight(viewportHeight: number): number {
  return Math.max(
    PICKER_MIN_AVAILABLE_HEIGHT,
    viewportHeight -
      CHAT_HEADER_HEIGHT_ESTIMATE -
      COMPOSE_HEIGHT_ESTIMATE -
      EMPTY_STATE_CHROME_HEIGHT_ESTIMATE
  );
}

function pickerFrameSize(
  viewportWidth: number,
  viewportHeight: number
): { width: number; height: number } {
  const isMobile = viewportWidth <= PICKER_MOBILE_BREAKPOINT;
  const availableWidth = pickerAvailableWidth(viewportWidth);
  const availableHeight = pickerAvailableHeight(viewportHeight);

  if (isMobile) {
    const squareSize = Math.max(
      PICKER_MIN_AVAILABLE_WIDTH,
      Math.min(PICKER_MOBILE_MAX_SQUARE_SIZE, availableWidth, availableHeight)
    );

    return { width: squareSize, height: squareSize };
  }

  const width = Math.max(PICKER_MIN_AVAILABLE_WIDTH, availableWidth);
  const height = Math.max(
    PICKER_MIN_AVAILABLE_HEIGHT,
    Math.min(
      availableHeight,
      PICKER_DESKTOP_MAX_HEIGHT,
      width / PICKER_DESKTOP_ASPECT_RATIO
    )
  );

  return { width, height };
}

function lowCountPickerFrameSize(
  totalTiles: number,
  viewportWidth: number,
  viewportHeight: number,
  baseFrame: { width: number; height: number }
): { width: number; height: number } {
  if (totalTiles > PICKER_LOW_COUNT_MAX) return baseFrame;

  const isDesktop = viewportWidth > PICKER_MOBILE_BREAKPOINT;
  const availableHeight = pickerAvailableHeight(viewportHeight);

  if (isDesktop) {
    const width = Math.min(baseFrame.width, PICKER_DESKTOP_LOW_COUNT_MAX_WIDTH);
    const height = Math.max(
      PICKER_MIN_AVAILABLE_HEIGHT,
      Math.min(
        availableHeight,
        PICKER_DESKTOP_MAX_HEIGHT,
        width / PICKER_DESKTOP_ASPECT_RATIO
      )
    );

    return { width, height };
  }

  const width = Math.min(baseFrame.width, PICKER_MOBILE_LOW_COUNT_MAX_SIZE);
  const height =
    totalTiles >= 5
      ? Math.min(availableHeight, PICKER_MOBILE_COLUMN_STACK_MAX_HEIGHT)
      : width;

  return { width, height };
}

function pickerMaxTileSize(totalTiles: number, isDesktop: boolean): number {
  if (totalTiles > PICKER_LOW_COUNT_MAX) return PICKER_MAX_TILE_SIZE;
  if (totalTiles === 1) {
    return isDesktop
      ? PICKER_SINGLE_BOT_TILE_SIZE_DESKTOP
      : PICKER_SINGLE_BOT_TILE_SIZE_MOBILE;
  }
  if (totalTiles <= 4) {
    return isDesktop
      ? PICKER_FEW_BOT_TILE_SIZE_DESKTOP
      : PICKER_FEW_BOT_TILE_SIZE_MOBILE;
  }

  return isDesktop
    ? PICKER_LOW_COUNT_TILE_SIZE_DESKTOP
    : PICKER_LOW_COUNT_TILE_SIZE_MOBILE;
}

function lowCountPickerContentHeight(
  totalTiles: number,
  pickerHeight: number,
  gridRows: number,
  tileSize: number,
  tileGap: number
): number {
  if (totalTiles > PICKER_LOW_COUNT_MAX) return pickerHeight;

  const contentHeight = gridRows * tileSize + Math.max(0, gridRows - 1) * tileGap;
  return Math.min(
    pickerHeight,
    Math.ceil(contentHeight + PICKER_LOW_COUNT_FRAME_VERTICAL_PAD)
  );
}

function scaledPickerBreakpoint(baseCount: number, pickerWidth: number): number {
  const linearScale = pickerWidth / PICKER_REFERENCE_SIZE;
  const scale = Math.max(
    PICKER_BREAKPOINT_SCALE_MIN,
    Math.min(
      PICKER_BREAKPOINT_SCALE_MAX,
      Math.pow(linearScale, PICKER_BREAKPOINT_SCALE_EXPONENT)
    )
  );
  return Math.max(1, Math.round(baseCount * scale));
}

function pickerStageBreakpoint(
  baseCount: number,
  pickerWidth: number,
  isDesktop: boolean
): number {
  const scaled = scaledPickerBreakpoint(baseCount, pickerWidth);
  return isDesktop ? Math.max(1, scaled) : scaled;
}

function pickerDensityBreakpoints(
  viewportWidth: number,
  viewportHeight: number
): PickerDensityBreakpoints {
  const { width: pickerWidth, height: pickerHeight } = pickerFrameSize(
    viewportWidth,
    viewportHeight
  );
  const isDesktop = viewportWidth > PICKER_MOBILE_BREAKPOINT;
  const densityWidth =
    isDesktop
      ? Math.min(pickerWidth, pickerHeight * PICKER_DESKTOP_ASPECT_RATIO)
      : pickerWidth;
  const namedFlatTileCountMin = isDesktop
    ? PICKER_NAMED_FLAT_DESKTOP_COUNT
    : PICKER_NAMED_FLAT_MOBILE_COUNT;
  const flatTileCountMin = PICKER_ICON_ONLY_FLAT_COUNT;
  const largeGlyphTileCountMin = pickerStageBreakpoint(
    LARGE_GLYPH_BASE_COUNT,
    densityWidth,
    isDesktop
  );
  const crosshairTileCountMin =
    flatTileCountMin +
    Math.round(
      (largeGlyphTileCountMin - flatTileCountMin) *
        PICKER_CROSSHAIR_STAGE_TWO_PROGRESS
    );
  const dotTileCountMin =
    flatTileCountMin +
    Math.round(
      (largeGlyphTileCountMin - flatTileCountMin) *
        PICKER_DOT_STAGE_TWO_PROGRESS
    );
  const glyphlessCardCountMin = pickerStageBreakpoint(
    GLYPHLESS_CARD_BASE_COUNT,
    densityWidth,
    isDesktop
  );
  const compactPixelGridCountMin = pickerStageBreakpoint(
    COMPACT_PIXEL_GRID_BASE_COUNT,
    densityWidth,
    isDesktop
  );
  const radialRainbowCountMin = pickerStageBreakpoint(
    RADIAL_RAINBOW_BASE_COUNT,
    densityWidth,
    isDesktop
  );

  return {
    namedFlatTileCountMin,
    flatTileCountMin,
    largeGlyphTileCountMin,
    crosshairTileCountMin,
    dotTileCountMin,
    glyphlessCardCountMin,
    compactPixelGridCountMin,
    radialRainbowCountMin,
  };
}

function pickerDensityStageTargets(
  viewportWidth: number,
  viewportHeight: number
): PickerDensityStageTarget[] {
  const breakpoints = pickerDensityBreakpoints(viewportWidth, viewportHeight);

  return [
    {
      id: 1,
      label: "Stage 1",
      description: "full cards",
      targetCount: Math.max(1, breakpoints.namedFlatTileCountMin - 1),
    },
    {
      id: 1.5,
      label: "Stage 1.5",
      description: "named flat cards",
      targetCount: breakpoints.namedFlatTileCountMin,
    },
    {
      id: 2,
      label: "Stage 2",
      description: "flat cards",
      targetCount: breakpoints.flatTileCountMin,
    },
    {
      id: 3,
      label: "Stage 3",
      description: "larger glyphs",
      targetCount: breakpoints.largeGlyphTileCountMin,
    },
    {
      id: 4,
      label: "Stage 4",
      description: "glyphless cards",
      targetCount: breakpoints.glyphlessCardCountMin,
    },
    {
      id: 5,
      label: "Stage 5",
      description: "pixel grid + dot",
      targetCount: breakpoints.compactPixelGridCountMin,
    },
    {
      id: 6,
      label: "Stage 6",
      description: "radial rainbow",
      targetCount: breakpoints.radialRainbowCountMin,
    },
  ];
}

/**
 * Trim a bot's system_prompt down to a compact preview suitable for the
 * empty-state / conversation-intro hint. Preserves the first paragraph
 * (treats `\n\n+` as a hard break), collapses intra-paragraph newlines,
 * and truncates at a word boundary if the result would exceed
 * `maxChars`. Empty input returns an empty string so the caller can
 * decide whether to render a fallback hint or nothing at all.
 */
function firstLinesOf(text: string | null | undefined, maxChars = 140): string {
  const raw =
    typeof text === "string" ? stripBotProfileMetaSuffix(text).trim() : "";
  if (!raw) return "";
  const firstPara = raw.split(/\n\n+/)[0]?.replace(/\n/g, " ").trim() ?? "";
  if (firstPara.length <= maxChars) return firstPara;
  const sliced = firstPara.slice(0, maxChars);
  const lastSpace = sliced.lastIndexOf(" ");
  // Only snap back to the last space if it lands reasonably far from
  // the start — otherwise mid-word truncation is better than a silly
  // one-or-two-word preview.
  const cut = lastSpace > maxChars * 0.6 ? sliced.slice(0, lastSpace) : sliced;
  return `${cut.trim()}\u2026`;
}

function formatBotHeroSentence(value: string): string {
  return value.replace(
    /^(I am [^,]+,\s+)(A|An|The)\b/u,
    (_match, prefix: string, article: string) =>
      `${prefix}${article.toLocaleLowerCase()}`
  );
}

function botHeroPreview(text: string | null | undefined, maxChars = 220): string {
  const raw =
    typeof text === "string" ? stripBotProfileMetaSuffix(text).trim() : "";
  if (!raw) return "";
  const purposeMatch = raw.match(/(?:^|\n)Purpose:\s*\n\s*(You are .+?)(?:\n\n|$)/i);
  const purpose = purposeMatch?.[1]?.trim();
  const source = purpose || firstLinesOf(raw, maxChars);
  const firstPerson = formatBotHeroSentence(
    source.replace(/^You are\b/i, "I am")
  );
  if (firstPerson.length <= maxChars) return firstPerson;
  const sliced = firstPerson.slice(0, maxChars);
  const lastSpace = sliced.lastIndexOf(" ");
  const cut = lastSpace > maxChars * 0.6 ? sliced.slice(0, lastSpace) : sliced;
  return `${cut.trim()}\u2026`;
}

/**
 * Geometry for the Chat-mode bot picker.
 *
 * Strategy:
 *   1. Claim a stable frame from the available viewport space.
 *   2. Pick a grid shape that follows the frame's aspect ratio.
 *   3. Fit each bot tile into that grid, shrinking tiles as count grows.
 *
 * Example outcomes:
 *   N=1  → 1×1, one capped tile centered inside the frame.
 *   Mobile N=9  → 3×3.
 *   Desktop N=10 → 5×2-ish widescreen rows.
 */
function pickerGridShape(
  totalTiles: number,
  pickerWidth: number,
  pickerHeight: number,
  preferredRows?: number,
  preferredCols?: number
): { cols: number; rows: number } {
  if (totalTiles <= 1) return { cols: 1, rows: 1 };
  if (preferredRows && preferredCols && totalTiles <= preferredRows * preferredCols) {
    return {
      cols: preferredCols,
      rows: preferredRows,
    };
  }
  if (preferredRows && totalTiles > preferredRows) {
    return {
      cols: Math.ceil(totalTiles / preferredRows),
      rows: preferredRows,
    };
  }
  const aspectRatio = Math.max(1, pickerWidth / Math.max(1, pickerHeight));
  if (aspectRatio > 1.2 && totalTiles <= 4) {
    return { cols: totalTiles, rows: 1 };
  }
  if (totalTiles === 3) {
    return { cols: 2, rows: 2 };
  }
  if (aspectRatio <= 1.2 && totalTiles >= 7 && totalTiles <= 9) {
    return { cols: 3, rows: Math.ceil(totalTiles / 3) };
  }
  if (aspectRatio <= 1.2 && totalTiles === 10) {
    return { cols: 4, rows: 3 };
  }
  if (aspectRatio <= 1.2 && totalTiles >= 5 && totalTiles <= 10) {
    return { cols: 2, rows: Math.ceil(totalTiles / 2) };
  }
  if (totalTiles <= 4) {
    const side = Math.ceil(Math.sqrt(totalTiles));
    return { cols: side, rows: side };
  }
  const cols = Math.max(1, Math.ceil(Math.sqrt(totalTiles * aspectRatio)));
  const rows = Math.max(1, Math.ceil(totalTiles / cols));
  return { cols, rows };
}

function pickerFormationCells<T>(
  items: T[],
  geom: PickerGeometry
): Array<T | null> {
  const cells = Array<T | null>(geom.gridCols * geom.gridRows).fill(null);
  let cellIndex = geom.leadingFillerCell ? 1 : 0;

  for (const item of items) {
    cells[cellIndex] = item;
    cellIndex += 1;
    if (cellIndex >= cells.length) break;
  }

  return cells;
}

interface PickerGeometryOptions {
  balanceOddRows?: boolean;
  preferredRows?: number;
  preferredCols?: number;
}

function pickerGeometry(
  totalTiles: number,
  viewportWidth: number,
  viewportHeight: number,
  options: PickerGeometryOptions = {}
): PickerGeometry {
  // Mobile owns the old square frame; desktop owns a widescreen frame whose
  // width scales with the available viewport. Density thresholds use the
  // viewport-derived width on desktop so short windows don't prematurely
  // collapse the visual treatment into later stages.
  const baseFrame = pickerFrameSize(
    viewportWidth,
    viewportHeight
  );
  const { width: pickerWidth, height: basePickerHeight } = lowCountPickerFrameSize(
    totalTiles,
    viewportWidth,
    viewportHeight,
    baseFrame
  );
  const isDesktop = viewportWidth > PICKER_MOBILE_BREAKPOINT;
  const pickerHeight =
    !isDesktop && totalTiles >= 5 && totalTiles <= 10
      ? Math.min(
          pickerAvailableHeight(viewportHeight),
          PICKER_MOBILE_COLUMN_STACK_MAX_HEIGHT
        )
      : basePickerHeight;
  const {
    namedFlatTileCountMin,
    flatTileCountMin,
    largeGlyphTileCountMin,
    crosshairTileCountMin,
    dotTileCountMin,
    glyphlessCardCountMin,
    compactPixelGridCountMin,
    radialRainbowCountMin,
  } = pickerDensityBreakpoints(viewportWidth, viewportHeight);
  const enlargeGlyph = totalTiles >= largeGlyphTileCountMin;
  const hideGlyphByDefault = totalTiles >= glyphlessCardCountMin;
  const isCompactPixelGrid = totalTiles >= compactPixelGridCountMin;
  const selectedDotGlyph = isCompactPixelGrid;
  const radialRainbowGradient =
    isCompactPixelGrid && totalTiles >= radialRainbowCountMin;
  const isSolidSwatch = isCompactPixelGrid;
  if (totalTiles <= 0) {
    return {
      pickerWidth,
      pickerHeight,
      tileSize: 192,
      glyphSize: 96,
      glyphStroke: 1.6,
      hoverScale: 1.06,
      tileGap: 14,
      gridCols: 1,
      gridRows: 1,
      fillerCells: 0,
      singleBot: false,
      threeBotStack: false,
      mobileColumnStack: false,
      leadingFillerCell: false,
      namedFlatTile: false,
      suppressMobileHeroCopy: false,
      flattenTile: false,
      enlargeGlyph: false,
      hideGlyphByDefault: false,
      crosshairCursor: false,
      dotCursor: false,
      solidSwatch: false,
      compactPixelGrid: false,
      selectedDotGlyph: false,
      radialRainbowGradient: false,
    };
  }

  // Breakpoints scale with available width. The ladder now removes one
  // visual affordance at a time: gradient, then larger glyphs, then glyphs,
  // then card chrome/pixel gaps, then the fully abstract rainbow field.
  const balanceOddRows = options.balanceOddRows ?? true;
  const leadingFillerCell =
    balanceOddRows && totalTiles > 10 && totalTiles % 2 === 1;
  const namedFlatTile =
    totalTiles >= namedFlatTileCountMin && totalTiles < flatTileCountMin;
  const gridOccupancyCount = totalTiles + (leadingFillerCell ? 1 : 0);
  const { cols, rows } = pickerGridShape(
    gridOccupancyCount,
    pickerWidth,
    pickerHeight,
    options.preferredRows,
    options.preferredCols
  );
  const fillerCells = cols * rows - gridOccupancyCount;
  const gap = isCompactPixelGrid
    ? 0
    : Math.max(
        isSolidSwatch ? 2 : 4,
        Math.min(
          14,
          Math.round(
            Math.min(
              pickerWidth * 0.018,
              rows > 1 ? pickerHeight * 0.012 : pickerWidth * 0.018
            )
          )
        )
      );
  const baseMaxTileSize = pickerMaxTileSize(totalTiles, isDesktop);
  const maxTileSize =
    !isDesktop && totalTiles === 3
      ? Math.min(PICKER_THREE_STACK_TILE_SIZE_MOBILE, baseMaxTileSize)
      : isDesktop && totalTiles > 1 && totalTiles <= 4
        ? Math.min(
            baseMaxTileSize,
            Math.floor((pickerWidth - (cols - 1) * gap) / cols)
          )
        : baseMaxTileSize;
  const tileSize = Math.min(
    maxTileSize,
    Math.floor(
      Math.min(
        (pickerWidth - (cols - 1) * gap) / cols,
        (pickerHeight - (rows - 1) * gap) / rows
      )
    )
  );
  const contentAlignedPickerHeight = lowCountPickerContentHeight(
    totalTiles,
    pickerHeight,
    rows,
    tileSize,
    gap
  );

  const glyphRatio = hideGlyphByDefault || isSolidSwatch
    ? 0
    : enlargeGlyph
      ? PICKER_STAGE_TWO_GLYPH_RATIO
      : PICKER_DEFAULT_GLYPH_RATIO;
  const glyphSize = Math.max(14, Math.round(tileSize * glyphRatio));
  const glyphStroke = botGlyphStrokeForSize(glyphSize);
  // Magnification target: dramatic on tiny tiles (where the small pop
  // still reads as a satisfying nudge), restrained on giant tiles (where
  // the same multiplier would pop the tile clear out of the empty-state
  // column). Break-points scale alongside the tile ladder: tiles sized
  // for 1-4 bots land in the 120+ "restrained" band, 5-16 bots sit in
  // the 80+ "medium" band, and denser packings get the strongest pop.
  // Values were halved (relative to "amount over 1.0") to soften the
  // first-stage zoom while keeping the relative shape across the ladder.
  const hoverScale = isCompactPixelGrid
    ? 1
    : tileSize >= 120
      ? 1.06
      : tileSize >= 80
        ? 1.1
        : 1.16;

  return {
    pickerWidth,
    pickerHeight: contentAlignedPickerHeight,
    tileSize,
    glyphSize,
    glyphStroke,
    hoverScale,
    tileGap: gap,
    gridCols: cols,
    gridRows: rows,
    fillerCells,
    singleBot: totalTiles === 1,
    threeBotStack: !isDesktop && totalTiles === 3,
    mobileColumnStack: !isDesktop && totalTiles >= 5 && totalTiles <= 10,
    leadingFillerCell,
    namedFlatTile,
    suppressMobileHeroCopy: false,
    flattenTile: totalTiles >= flatTileCountMin,
    enlargeGlyph,
    hideGlyphByDefault,
    crosshairCursor: totalTiles >= crosshairTileCountMin,
    dotCursor: totalTiles >= dotTileCountMin,
    solidSwatch: isSolidSwatch,
    compactPixelGrid: isCompactPixelGrid,
    selectedDotGlyph,
    radialRainbowGradient,
  };
}

function pickerGridOuterHeight(geom: PickerGeometry): number {
  const hoverPadding = Math.max(
    8,
    geom.tileSize * (geom.hoverScale - 1) * 0.5 + 2
  );
  return (
    geom.gridRows * geom.tileSize +
    Math.max(0, geom.gridRows - 1) * geom.tileGap +
    hoverPadding * 2
  );
}

function coffeeCanvasPickerPreferredRows(
  totalTiles: number,
  viewportWidth: number,
  viewportHeight: number
): number | undefined {
  if (viewportWidth > PICKER_MOBILE_BREAKPOINT || totalTiles <= 0) return undefined;

  const targetGridHeight = Math.max(96, Math.min(170, viewportHeight * 0.2));
  const maxRowsToTry = Math.min(totalTiles, Math.max(6, Math.ceil(Math.sqrt(totalTiles))));
  let best: { rows: number; tileSize: number; height: number } | null = null;

  for (let rows = 1; rows <= maxRowsToTry; rows += 1) {
    const geom = pickerGeometry(totalTiles, viewportWidth, viewportHeight, {
      balanceOddRows: false,
      preferredRows: rows,
    });
    const height = pickerGridOuterHeight(geom);
    if (height > targetGridHeight) continue;
    if (
      !best ||
      geom.tileSize > best.tileSize ||
      (geom.tileSize === best.tileSize && height > best.height)
    ) {
      best = { rows, tileSize: geom.tileSize, height };
    }
  }

  return best?.rows;
}

function pickerUsesHueNavigation(geom: PickerGeometry, viewportWidth: number): boolean {
  const mobileLargeGrid =
    viewportWidth <= PICKER_MOBILE_BREAKPOINT && geom.enlargeGlyph;
  return mobileLargeGrid || geom.hideGlyphByDefault || geom.solidSwatch || geom.compactPixelGrid;
}

function updatePickerParallax(
  event: React.PointerEvent<HTMLButtonElement>
): void {
  if (event.pointerType !== "mouse") return;

  const picker = event.currentTarget.closest("[data-bot-picker-frame='true']");
  if (!(picker instanceof HTMLDivElement)) return;

  const rect = picker.getBoundingClientRect();
  const normalizedX = (event.clientX - rect.left) / rect.width - 0.5;
  const normalizedY = (event.clientY - rect.top) / rect.height - 0.5;
  const x = normalizedX * -2 * PICKER_PARALLAX_X;
  const y = normalizedY * -2 * PICKER_PARALLAX_Y;

  picker.style.setProperty(
    "--picker-parallax-x",
    `${x.toFixed(2)}px`
  );
  picker.style.setProperty(
    "--picker-parallax-y",
    `${y.toFixed(2)}px`
  );
}

function resetPickerParallax(element: HTMLDivElement): void {
  element.style.setProperty("--picker-parallax-x", "0px");
  element.style.setProperty("--picker-parallax-y", "0px");
}

// Hit-test the picker grid at a viewport coordinate and return the bot id
// of the tile under that point. Each tile button carries `data-bot-id`
// (set in the JSX) so we can reuse the existing element layout instead
// of recomputing grid coordinates against filler cells or the optional
// leading filler. Returns null when the point misses every tile (e.g.
// finger is over a placeholder, gap, or off the picker entirely) so
// callers can park the preview in a "no target" state.
function findBotIdAtPoint(x: number, y: number): string | null {
  if (typeof document === "undefined") return null;
  const target = document.elementFromPoint(x, y);
  if (!(target instanceof Element)) return null;
  const tile = target.closest("[data-bot-id]");
  if (!(tile instanceof HTMLElement)) return null;
  return tile.dataset.botId ?? null;
}

// ── Color math for the bot color wheel ────────────────────────────────
// The wheel paints a HSL hue ring via conic-gradient with a white-centered
// radial for saturation; these helpers map clicks on the wheel to/from hex.

function randomHexSeed(seedIndex?: number): string {
  // Seed from five PRISM wordmark hue families, not five exact hexes.
  // This keeps the library constrained to P/R/I/S/M while preserving the
  // subtle spectrum that makes large swatch grids readable.
  const safeSeedIndex =
    typeof seedIndex === "number"
      ? Math.max(0, Math.min(PRISM_WORDMARK_PALETTE.length - 1, seedIndex))
      : Math.floor(Math.random() * PRISM_WORDMARK_PALETTE.length);
  const seed = PRISM_WORDMARK_PALETTE[safeSeedIndex];
  const { h } = hexToHsl(seed);
  const hue =
    (h -
      PRISM_BOT_SEED_HUE_SPREAD_DEG / 2 +
      Math.random() * PRISM_BOT_SEED_HUE_SPREAD_DEG +
      360) %
    360;
  const saturation =
    PRISM_BOT_SEED_SATURATION_MIN +
    Math.random() * (PRISM_BOT_SEED_SATURATION_MAX - PRISM_BOT_SEED_SATURATION_MIN);
  const lightness =
    PRISM_BOT_SEED_LIGHTNESS_MIN +
    Math.random() * (PRISM_BOT_SEED_LIGHTNESS_MAX - PRISM_BOT_SEED_LIGHTNESS_MIN);
  return hslToHex(hue, saturation, lightness);
}

function botColorDistanceScore(aHex: string, bHex: string): number {
  const a = hexToHsl(aHex);
  const b = hexToHsl(bHex);
  const hueDistance = circularHueDistance(a.h, b.h) / 180;
  const saturationDistance = Math.abs(a.s - b.s) / 100;
  const lightnessDistance = Math.abs(a.l - b.l) / 100;
  return hueDistance * 0.68 + saturationDistance * 0.2 + lightnessDistance * 0.12;
}

function randomHex(existingHexes: readonly string[] = []): string {
  const existing = existingHexes
    .map((hex) => hex.trim())
    .filter((hex) => hexChannels(hex) !== null);
  if (existing.length === 0) return randomHexSeed();
  const normalizedExisting = existing.map((hex) => normalizeAccentForTheme(hex, "dark"));
  const segmentCounts = new Array<number>(PRISM_WORDMARK_PALETTE.length).fill(0);
  for (const hex of normalizedExisting) {
    const { h } = hexToHsl(hex);
    segmentCounts[hueLensSegmentIndexForHue(h)] += 1;
  }
  const prioritizedSegments = segmentCounts
    .map((count, segment) => ({ count, segment }))
    .sort((a, b) => a.count - b.count)
    .map((entry) => entry.segment);

  let bestCandidate = randomHexSeed(prioritizedSegments[0]);
  let bestMinDistance = -1;

  for (let attempt = 0; attempt < BOT_COLOR_DIVERSITY_SAMPLE_ATTEMPTS; attempt += 1) {
    const segment = prioritizedSegments[attempt % prioritizedSegments.length];
    const candidate = randomHexSeed(segment);
    const normalizedCandidate = normalizeAccentForTheme(candidate, "dark");
    let minDistance = Number.POSITIVE_INFINITY;
    for (const existingHex of normalizedExisting) {
      minDistance = Math.min(
        minDistance,
        botColorDistanceScore(normalizedCandidate, existingHex)
      );
    }
    if (minDistance > bestMinDistance) {
      bestMinDistance = minDistance;
      bestCandidate = candidate;
    }
    if (minDistance >= BOT_COLOR_DIVERSITY_MIN_DISTANCE) {
      return candidate;
    }
  }

  return bestCandidate;
}

function hslToHex(h: number, s: number, l: number): string {
  const sNorm = s / 100;
  const lNorm = l / 100;
  const k = (n: number) => (n + h / 30) % 12;
  const a = sNorm * Math.min(lNorm, 1 - lNorm);
  const f = (n: number) =>
    lNorm - a * Math.max(-1, Math.min(k(n) - 3, Math.min(9 - k(n), 1)));
  const toHex = (v: number) =>
    Math.round(v * 255)
      .toString(16)
      .padStart(2, "0");
  return `#${toHex(f(0))}${toHex(f(8))}${toHex(f(4))}`;
}

function hexToHsl(hex: string): { h: number; s: number; l: number } {
  const clean = hex.replace(/^#/, "");
  if (clean.length !== 6) return { h: 0, s: 0, l: 50 };
  const r = parseInt(clean.substring(0, 2), 16) / 255;
  const g = parseInt(clean.substring(2, 4), 16) / 255;
  const b = parseInt(clean.substring(4, 6), 16) / 255;
  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  const l = (max + min) / 2;
  let s = 0;
  let h = 0;
  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    if (max === r) h = (g - b) / d + (g < b ? 6 : 0);
    else if (max === g) h = (b - r) / d + 2;
    else h = (r - g) / d + 4;
    h *= 60;
  }
  return { h, s: s * 100, l: l * 100 };
}

// WCAG 2 color helpers, duplicated here so the frontend doesn't need to
// pull in the @localai/shared package at runtime. Mirrored in
// packages/shared/src/color.ts, which is where the unit tests live —
// keep these in sync if you tweak the math.

function hexChannels(hex: string): [number, number, number] | null {
  const clean = hex.replace(/^#/, "").trim();
  if (clean.length !== 6 || !/^[0-9a-fA-F]{6}$/.test(clean)) return null;
  return [
    parseInt(clean.substring(0, 2), 16),
    parseInt(clean.substring(2, 4), 16),
    parseInt(clean.substring(4, 6), 16),
  ];
}

function relativeLuminance(hex: string): number {
  const parsed = hexChannels(hex);
  if (!parsed) return 0;
  const toLinear = (channel: number): number => {
    const n = channel / 255;
    return n <= 0.03928 ? n / 12.92 : Math.pow((n + 0.055) / 1.055, 2.4);
  };
  const [r, g, b] = parsed;
  return 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
}

function pickReadableText(hex: string): string {
  // WCAG threshold: anything brighter than ~0.179 gets a higher contrast
  // ratio with near-black text than with white text. Bright limes and
  // yellows sit well above this; deep reds and blues sit well below.
  return relativeLuminance(hex) > 0.179 ? "#0b0b0d" : "#ffffff";
}

function contrastRatio(a: string, b: string): number {
  const la = relativeLuminance(a);
  const lb = relativeLuminance(b);
  const lighter = Math.max(la, lb);
  const darker = Math.min(la, lb);
  return (lighter + 0.05) / (darker + 0.05);
}

function hexChannelToByte(value: number): string {
  return Math.max(0, Math.min(255, Math.round(value))).toString(16).padStart(2, "0");
}

function mixHex(a: string, b: string, amount: number): string {
  const pa = hexChannels(a);
  const pb = hexChannels(b);
  if (!pa || !pb) return a;
  const t = Math.max(0, Math.min(1, amount));
  return `#${hexChannelToByte(pa[0] + (pb[0] - pa[0]) * t)}${hexChannelToByte(
    pa[1] + (pb[1] - pa[1]) * t
  )}${hexChannelToByte(pa[2] + (pb[2] - pa[2]) * t)}`;
}

// Darken/lighten a color toward black or white until it meets the target
// contrast ratio against `background`. Keeps the original hue recognisable
// as long as possible.
function ensureContrast(foreground: string, background: string, targetRatio = 4.5): string {
  if (contrastRatio(foreground, background) >= targetRatio) return foreground;
  const anchor = relativeLuminance(background) > 0.5 ? "#000000" : "#ffffff";
  let lo = 0;
  let hi = 1;
  let best: string = anchor;
  for (let i = 0; i < 20; i++) {
    const mid = (lo + hi) / 2;
    const blended = mixHex(foreground, anchor, mid);
    if (contrastRatio(blended, background) >= targetRatio) {
      best = blended;
      hi = mid;
    } else {
      lo = mid;
    }
  }
  return best;
}

// Theme-specific baseline backgrounds. Kept as named constants so any
// helper that needs to reason about "what does --bg evaluate to right
// now?" doesn't have to duplicate literals. Mirrored in page.module.css
// under .themeDark / .themeLight — keep these in sync.
const THEME_BG: Record<"light" | "dark", string> = {
  light: "#f4f2ee",
  dark: "#0b0a09",
};

// HSL lightness alone underestimates perceived brightness for warm yellows
// and oranges on the light theme's ivory surface. After hue-preserving HSL
// clamping, cap WCAG luminance so bot glyphs/tiles keep enough edge contrast.
const ACCENT_LUMINANCE_MAX_LIGHT = 0.42;
const ACCENT_LUMINANCE_MAX_LIGHT_YELLOW = 0.3;
const YELLOW_HUE_MIN = 40;
const YELLOW_HUE_MAX = 75;

// Clamp a color's luminance into [min, max] by blending toward black (to
// lower) or white (to raise). Used so light mode can't display eye-searing
// bright accents and dark mode can't display ink-black accents that
// disappear into the background.
function clampLuminance(hex: string, opts: { min?: number; max?: number }): string {
  const lum = relativeLuminance(hex);
  const runBinarySearch = (anchor: "#000000" | "#ffffff", target: number): string => {
    let lo = 0;
    let hi = 1;
    let best: string = anchor;
    for (let i = 0; i < 20; i++) {
      const mid = (lo + hi) / 2;
      const blended = mixHex(hex, anchor, mid);
      const l = relativeLuminance(blended);
      const satisfies = anchor === "#000000" ? l <= target : l >= target;
      if (satisfies) {
        best = blended;
        hi = mid;
      } else {
        lo = mid;
      }
    }
    return best;
  };
  if (opts.max !== undefined && lum > opts.max) {
    return runBinarySearch("#000000", opts.max);
  }
  if (opts.min !== undefined && lum < opts.min) {
    return runBinarySearch("#ffffff", opts.min);
  }
  return hex;
}

// Build the --accent / --accent-text / --accent-ink triad for a given raw
// hex against the active theme background. Shared between the Sandbox
// bot-color override and the Chat-mode P-color pinning so both code paths
// apply the same clamp + contrast treatment.
function deriveAccentStyle(
  rawHex: string,
  resolvedTheme: "light" | "dark"
): React.CSSProperties {
  const themeBg = THEME_BG[resolvedTheme];
  const accent =
    resolvedTheme === "light"
      ? clampLuminance(rawHex, { max: 0.55 })
      : clampLuminance(rawHex, { min: 0.1 });
  const accentText = pickReadableText(accent);
  const accentInk = ensureContrast(accent, themeBg, 4.5);
  return {
    ["--accent" as string]: accent,
    ["--accent-text" as string]: accentText,
    ["--accent-ink" as string]: accentInk,
  } as React.CSSProperties;
}

// HSL-lightness band the color picker is allowed to produce. Clamping
// both ends (not just one) means bot colors never go dark enough to
// vanish into the dark-mode shell nor pale enough to wash out against
// the light-mode shell, while preserving shade variation in the middle.
//
// The "_DARK" pair compresses both ends 8 units toward L=50 so deep
// picks (pure blue, deep red) don't disappear against `#0b0a09` and
// pale picks don't glare — saturation stays identical, only L moves.
//
// Kept in lockstep with `ACCENT_LIGHTNESS_*` constants in
// packages/shared/src/color.ts. The picker math, the render-time
// clamp, and the CSS gradient overlays all key off these numbers — if
// you nudge the band, nudge all three places (here, the shared module,
// and the `.colorSquare` overlay alpha in page.module.css).
const ACCENT_LIGHTNESS_MIN = 30;
const ACCENT_LIGHTNESS_MAX = 70;
const ACCENT_LIGHTNESS_MIN_DARK = 38;
const ACCENT_LIGHTNESS_MAX_DARK = 62;

function accentLightnessBand(
  theme?: "light" | "dark"
): { min: number; max: number } {
  if (theme === "dark") {
    return { min: ACCENT_LIGHTNESS_MIN_DARK, max: ACCENT_LIGHTNESS_MAX_DARK };
  }
  return { min: ACCENT_LIGHTNESS_MIN, max: ACCENT_LIGHTNESS_MAX };
}

// Pull a color's HSL lightness into the safe band, preserving hue and
// saturation. The canonical normalizer for any surface painting a user-
// chosen bot color (bot card bar, glyph tile, message bubble, inline
// name glyph, swatch button, shell --accent triad). Unlike the older
// "pin to 50%" approach this keeps the shade a user picked whenever it
// already sits in-range, so two bots that differ only slightly in
// lightness still read as distinct colors — they just can't both race
// to near-white or near-black.
//
// Pass `theme: "dark"` to apply the tighter dark-mode band so the same
// user-chosen hex renders readable on both theme shells — a deep navy
// that sits at L=30 in light mode lifts to L=38 against the dark shell.
//
// Mirrors `clampAccentLightness` in packages/shared/src/color.ts — keep
// the two implementations in sync.
function clampAccentLightness(
  hex: string,
  theme?: "light" | "dark"
): string {
  const { h, s, l } = hexToHsl(hex);
  const { min, max } = accentLightnessBand(theme);
  const clamped = Math.max(min, Math.min(max, l));
  return hslToHex(h, s, clamped);
}

// Mirrors `normalizeAccentForTheme` in packages/shared/src/color.ts — keep
// the two implementations in sync. This is the canonical render-time bot
// accent normalizer for surfaces that paint user-chosen colors.
function normalizeAccentForTheme(hex: string, theme?: "light" | "dark"): string {
  const lightnessClamped = clampAccentLightness(hex, theme);
  if (theme === "dark") return lightnessClamped;
  const { h } = hexToHsl(lightnessClamped);
  const max = h >= YELLOW_HUE_MIN && h <= YELLOW_HUE_MAX
    ? ACCENT_LUMINANCE_MAX_LIGHT_YELLOW
    : ACCENT_LUMINANCE_MAX_LIGHT;
  return clampLuminance(lightnessClamped, { max });
}

function resolveZenUserMessageColor(
  personaInkSegment: { color: string; variant: "persona" | "default" } | null,
  prismColor: ZenUserMessagePrismColor | undefined,
  resolvedTheme: "light" | "dark"
): string | undefined {
  if (personaInkSegment?.variant === "persona") {
    const rawPersonaColor = personaInkSegment.color.trim();
    if (/^#[0-9a-f]{6}$/i.test(rawPersonaColor)) {
      return deriveThemedAccentTextTone(
        normalizeAccentForTheme(rawPersonaColor, resolvedTheme),
        resolvedTheme,
        "strong"
      );
    }
  }
  if (!prismColor) return undefined;
  return deriveThemedAccentTextTone(
    resolvedTheme === "light" ? prismColor.dark : prismColor.bright,
    resolvedTheme,
    "strong"
  );
}

function coffeeBotTranscriptTextColor(
  rawHex: string | null | undefined,
  resolvedTheme: "light" | "dark"
): string | undefined {
  if (!rawHex) return undefined;
  const normalized = normalizeAccentForTheme(rawHex, resolvedTheme);
  const { h, s, l } = hexToHsl(normalized);
  const desaturated = hslToHex(h, s * 0.28, l);
  return ensureContrast(desaturated, THEME_BG[resolvedTheme], 4.5);
}

// --bg-surface hex per theme. Mirrored from .themeDark / .themeLight in
// page.module.css so the swatch-border compensator can reason about what
// surface the swatch actually sits on.
const THEME_SURFACE_BG: Record<"light" | "dark", string> = {
  light: "#fffdf8",
  dark: "#151311",
};
const COMPOSE_BOT_LIGHT_INK_CONTRAST_RATIO = 5.8;
const PRIVATE_MODE_ACCENT_SATURATION_MULTIPLIER = 0.62;

function privateModeAccentHex(
  rawHex: string | null | undefined,
  resolvedTheme: "light" | "dark"
): string | null {
  const raw = rawHex?.trim();
  if (!raw) return null;
  const normalized = normalizeAccentForTheme(raw, resolvedTheme);
  const { h, s, l } = hexToHsl(normalized);
  const muted = hslToHex(h, s * PRIVATE_MODE_ACCENT_SATURATION_MULTIPLIER, l);
  const neutralAnchor = resolvedTheme === "dark" ? "#d7cfc3" : "#332d27";
  const neutralized = mixHex(
    muted,
    neutralAnchor,
    resolvedTheme === "dark" ? 0.14 : 0.1
  );
  return ensureContrast(neutralized, THEME_BG[resolvedTheme], 4.5);
}

function displayAccentForMode(
  rawHex: string | null | undefined,
  resolvedTheme: "light" | "dark",
  privateMode: boolean
): string | null {
  const raw = rawHex?.trim();
  if (!raw) return null;
  return privateMode
    ? privateModeAccentHex(raw, resolvedTheme)
    : normalizeAccentForTheme(raw, resolvedTheme);
}

function deriveThemedAccentTextTone(
  normalizedAccent: string,
  resolvedTheme: "light" | "dark",
  strength: "subtle" | "strong"
): string {
  const anchor = resolvedTheme === "light" ? "#0b0a09" : "#fffdf8";
  const amount =
    strength === "strong"
      ? resolvedTheme === "light" ? 0.48 : 0.42
      : resolvedTheme === "light" ? 0.18 : 0.16;
  const contrastTarget = strength === "strong" ? 5.2 : 3.1;
  return ensureContrast(
    mixHex(normalizedAccent, anchor, amount),
    THEME_BG[resolvedTheme],
    contrastTarget
  );
}

function botAccentStyle(
  rawHex: string | null | undefined,
  resolvedTheme: "light" | "dark"
): React.CSSProperties | undefined {
  const raw = rawHex?.trim();
  if (!raw) return undefined;
  const accent = normalizeAccentForTheme(raw, resolvedTheme);
  const ink = ensureContrast(accent, THEME_SURFACE_BG[resolvedTheme], 4.5);
  return {
    ["--bot-color" as string]: accent,
    ["--bot-ink" as string]: ink,
  } as React.CSSProperties;
}

// Sidebar conversation row border shade compensation. Emits a 0..100
// integer percent so the consumer can apply the blend in CSS
// (`color-mix(var(--row-color), var(--fg) X%)`). Keeping the computation
// off the CSS side gives us control over easing without shipping a bigger
// CSS expression per row.
//
// Semantics: a conversation tile fill is ~22% of the bot color over the
// theme surface. When the bot color is bright on a light theme (or dark
// on a dark theme), the effective fill reads very close to the surface
// and the row border needs to lean toward --fg for visibility. When the
// fill has healthy contrast already (mid-band pinks, teals, oranges),
// the border stays close to the bot color itself so the row keeps its
// brand identity.
function rowBorderMixPercent(
  fillHex: string,
  resolvedTheme: "light" | "dark"
): number {
  const surface = THEME_SURFACE_BG[resolvedTheme];
  const ratio = contrastRatio(fillHex, surface);
  // Mid-band bot colors get a gentle nudge toward --fg too — keeps the
  // border readable over the actual 22% tint rather than the raw color.
  const START = 2.5;
  const END = 1.05;
  const raw = Math.max(0, Math.min(1, (START - ratio) / (START - END)));
  const eased = raw < 0.5 ? 2 * raw * raw : 1 - Math.pow(-2 * raw + 2, 2) / 2;
  return Math.round(eased * 100);
}

function selectedRowTextColor(
  rowAccent: string,
  resolvedTheme: "light" | "dark"
): string {
  const selectedFill = mixHex(rowAccent, THEME_SURFACE_BG[resolvedTheme], 0.72);
  return ensureContrast(rowAccent, selectedFill, 4.5);
}

type Provider = "local" | "openai" | "anthropic";
function isProvider(value: unknown): value is Provider {
  return value === "local" || value === "openai" || value === "anthropic";
}
function responseModeShortLabel(mode: ResponseMode): string {
  return mode === "local" ? "LOCAL" : "ONLINE";
}
function responseModeDisplayLabel(mode: ResponseMode): string {
  return mode === "local" ? "Local" : "Online";
}
function providerDisplayLabel(provider: Provider): string {
  if (provider === "local") return "Local";
  if (provider === "anthropic") return "Anthropic";
  return "OpenAI";
}
type Theme = "dark" | "light" | "system";
type PanelView =
  | null
  | "settings"
  | "bots"
  | "images"
  | "memories"
  | "usage"
  | "command-center";
type MemoryPanelScope = "bot" | "default" | "session" | "all";
type ClientAccessState = "checking" | "allowed" | "blocked";
const AUTO_TITLE_REFRESH_DELAYS_MS = [1500, 4000, 8000] as const;
const VIEW_SWITCH_OVERLAY_MIN_VISIBLE_MS = 320;
const VIEW_SWITCH_OVERLAY_FADE_OUT_MS = 280;
// Which post-auth surface is currently rendered. Product Chat owns the
// immersive Hub canvas (`chat`); `sandbox` is retained as a compatibility
// branch for stale in-memory navigation and developer links.
type View = PrismSurfaceView;

function isZenSurfaceView(view: View): boolean {
  return view === "chat";
}

function isChatSurfaceView(view: View): boolean {
  return view === "sandbox";
}

function chatRequestModeForView(view: View): "zen" | "chat" | "sandbox" {
  if (isZenSurfaceView(view)) return "zen";
  if (isChatSurfaceView(view)) return "chat";
  return "sandbox";
}

type ChatLikeSummaryMode = "zen" | "chat" | "sandbox";

function summaryModeForView(view: View): ChatLikeSummaryMode {
  return chatRequestModeForView(view);
}

const USAGE_RANGE_OPTIONS: Array<{ value: UsageRange; label: string }> = [
  { value: "24h", label: "24h" },
  { value: "7d", label: "7d" },
  { value: "30d", label: "30d" },
  { value: "all", label: "All" },
];

const usageCompactNumberFormat = new Intl.NumberFormat(undefined, {
  notation: "compact",
  maximumFractionDigits: 1,
});
const usageWholeNumberFormat = new Intl.NumberFormat(undefined);
const usageUsdFormat = new Intl.NumberFormat(undefined, {
  style: "currency",
  currency: "USD",
  minimumFractionDigits: 2,
  maximumFractionDigits: 2,
});

function formatUsageNumber(value: number | null | undefined): string {
  const safe = typeof value === "number" && Number.isFinite(value) ? value : 0;
  return safe >= 10000
    ? usageCompactNumberFormat.format(safe)
    : usageWholeNumberFormat.format(Math.round(safe));
}

function formatUsageCost(microUsd: number | null | undefined): string {
  const micro = typeof microUsd === "number" && Number.isFinite(microUsd) ? microUsd : 0;
  if (micro <= 0) return "$0.00";
  return usageUsdFormat.format(micro / 1_000_000);
}

function formatUsageDate(value: string | null | undefined): string {
  if (!value) return "Never";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString([], {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function usagePurposeLabel(value: string): string {
  return value
    .split("_")
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function usageEventLabel(event: UsageRecentEvent): string {
  if (event.eventType === "image") {
    const imageCount = event.imageCount ?? 1;
    const suffix = event.imageSize ? ` · ${event.imageSize}` : "";
    return `${imageCount} image${imageCount === 1 ? "" : "s"}${suffix}`;
  }
  return `${formatUsageNumber(event.totalTokens ?? 0)} tokens`;
}

type UsageCsvCell = string | number | boolean | null | undefined;

const USAGE_CSV_HEADERS = [
  "section",
  "group",
  "key",
  "label",
  "provider",
  "model",
  "purpose",
  "event_type",
  "created_at",
  "surface",
  "mode",
  "input_tokens",
  "output_tokens",
  "total_tokens",
  "local_tokens",
  "online_tokens",
  "image_count",
  "estimated_cost_usd",
  "token_count_source",
  "cost_estimated",
  "unpriced",
  "image_size",
  "image_quality",
  "notes",
] as const;

function usageCsvCell(value: UsageCsvCell): string {
  if (value == null) return "";
  const text = String(value);
  return /[",\n\r]/.test(text) ? `"${text.replace(/"/g, '""')}"` : text;
}

function usageCostCsvValue(microUsd: number | null | undefined): string {
  if (typeof microUsd !== "number" || !Number.isFinite(microUsd)) return "";
  return (microUsd / 1_000_000).toFixed(6).replace(/0+$/u, "").replace(/\.$/u, "");
}

function usageCsvRow(
  cells: Partial<Record<(typeof USAGE_CSV_HEADERS)[number], UsageCsvCell>>
): string {
  return USAGE_CSV_HEADERS.map((header) => usageCsvCell(cells[header])).join(",");
}

function buildUsageCsv(report: UsageResponse): string {
  const rows = [USAGE_CSV_HEADERS.join(",")];
  const addRow = (
    cells: Partial<Record<(typeof USAGE_CSV_HEADERS)[number], UsageCsvCell>>
  ): void => {
    rows.push(usageCsvRow(cells));
  };
  const addTotalRow = (
    section: string,
    group: string,
    key: string,
    label: string,
    totals: UsageResponse["totals"]
  ): void => {
    addRow({
      section,
      group,
      key,
      label,
      input_tokens: totals.inputTokens,
      output_tokens: totals.outputTokens,
      total_tokens: totals.totalTokens,
      local_tokens: totals.localTokens,
      online_tokens: totals.onlineTokens,
      image_count: totals.imageCount,
      estimated_cost_usd: usageCostCsvValue(totals.estimatedCostMicroUsd),
      cost_estimated: totals.estimatedCostMicroUsd > 0,
      unpriced: totals.unpricedOnlineEvents > 0,
      notes: `${totals.eventCount} events; ${totals.providerReportedEvents} provider reported; ${totals.estimatedTokenEvents} estimated token events; ${totals.unpricedOnlineEvents} unpriced online events`,
    });
  };
  const addBreakdownRows = (
    group: "provider" | "model" | "purpose",
    items: UsageBreakdownItem[]
  ): void => {
    items.forEach((item) => {
      addRow({
        section: "breakdown",
        group,
        key: item.key,
        label: item.label,
        provider: item.provider,
        model: item.model,
        purpose: item.purpose,
        input_tokens: item.inputTokens,
        output_tokens: item.outputTokens,
        total_tokens: item.totalTokens,
        local_tokens: item.localTokens,
        online_tokens: item.onlineTokens,
        image_count: item.imageCount,
        estimated_cost_usd: usageCostCsvValue(item.estimatedCostMicroUsd),
        cost_estimated: item.estimatedCostMicroUsd > 0,
        unpriced: item.unpricedOnlineEvents > 0,
        notes: `${item.eventCount} events`,
      });
    });
  };

  addRow({ section: "metadata", key: "exported_at", label: "Exported at", notes: new Date().toISOString() });
  addRow({ section: "metadata", key: "generated_at", label: "Report generated at", notes: report.generatedAt });
  addRow({ section: "metadata", key: "range", label: "Range", notes: report.range });
  addRow({ section: "metadata", key: "range_start", label: "Range start", notes: report.rangeStart });
  addRow({
    section: "metadata",
    key: "scope",
    label: "Scope",
    notes: report.conversationScoped ? "conversation" : "all",
  });
  addRow({
    section: "metadata",
    key: "tracking_started_at",
    label: "Tracking started at",
    notes: report.trackingStartedAt,
  });
  addRow({
    section: "metadata",
    key: "has_untracked_history",
    label: "Has untracked history",
    notes: report.hasUntrackedHistory,
  });
  addRow({
    section: "metadata",
    key: "privacy_note",
    label: "Privacy note",
    notes: "Private/incognito usage is included in totals only, not recent activity rows.",
  });
  addTotalRow("summary", "totals", "all", "All tracked usage", report.totals);
  addBreakdownRows("purpose", report.byPurpose);
  addBreakdownRows("model", report.byModel);
  addBreakdownRows("provider", report.byProvider);
  report.recentEvents.forEach((event) => {
    addRow({
      section: "recent_event",
      key: event.id,
      label: usagePurposeLabel(event.purpose),
      provider: event.provider,
      model: event.model,
      purpose: event.purpose,
      event_type: event.eventType,
      created_at: event.createdAt,
      surface: event.surface,
      mode: event.mode,
      input_tokens: event.inputTokens,
      output_tokens: event.outputTokens,
      total_tokens: event.totalTokens,
      image_count: event.imageCount,
      estimated_cost_usd: usageCostCsvValue(event.estimatedCostMicroUsd),
      token_count_source: event.tokenCountSource,
      cost_estimated: event.costEstimated,
      unpriced: event.unpriced,
      image_size: event.imageSize,
      image_quality: event.imageQuality,
    });
  });
  return `${rows.join("\r\n")}\r\n`;
}

function usageExportFileName(report: UsageResponse): string {
  const scope = report.conversationScoped ? "thread" : "all";
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  return `prism-usage-${report.range}-${scope}-${stamp}.csv`;
}
