type ParsedGlobalClearCommand =
  | { kind: "none" }
  | { kind: "ok" }
  | { kind: "error"; error: string };

function parseGlobalClearCommand(text: string): ParsedGlobalClearCommand {
  const trimmed = normalizeComposerSlashCommandLine(text).trim();
  const match = /^\/(?:clear|cls)(?:\s|$)/i.exec(trimmed);
  if (!match) return { kind: "none" };
  const rest = trimmed.slice(match[0].length).trim();
  if (rest.length > 0) {
    return { kind: "error", error: `Use \`${match[0].trim().toLowerCase()}\` without extra arguments.` };
  }
  return { kind: "ok" };
}

const PRISM_COMMAND_MENTION_LEGACY_PROTOCOL = "prism-command://";
const PRISM_COMMAND_MENTION_HASH_PREFIX = "#prism-command:";

function parsePrismCommandMentionHref(href?: string | null): string | null {
  if (!href) return null;
  const lowered = href.toLowerCase();
  const encodedWithMeta = lowered.startsWith(PRISM_COMMAND_MENTION_LEGACY_PROTOCOL)
    ? href.slice(PRISM_COMMAND_MENTION_LEGACY_PROTOCOL.length).trim()
    : lowered.startsWith(PRISM_COMMAND_MENTION_HASH_PREFIX)
      ? href.slice(PRISM_COMMAND_MENTION_HASH_PREFIX.length).trim()
      : "";
  const encoded = encodedWithMeta.split("?")[0]?.trim() ?? "";
  if (!encoded) return null;
  try {
    const decoded = decodeURIComponent(encoded);
    return decoded.trim() || null;
  } catch {
    return encoded || null;
  }
}

function parsePrismCommandMentionSourceStart(href?: string | null): number | null {
  if (!href) return null;
  const metadataStart = href.indexOf("?");
  if (metadataStart < 0) return null;
  const params = new URLSearchParams(href.slice(metadataStart + 1));
  const rawStart = params.get("start");
  if (!rawStart) return null;
  const start = Number(rawStart);
  return Number.isInteger(start) && start >= 0 ? start : null;
}

function prismCommandMentionHref(commandId: string, sourceStart?: number): string {
  const metadata =
    typeof sourceStart === "number" && Number.isInteger(sourceStart) && sourceStart >= 0
      ? `?start=${sourceStart}`
      : "";
  return `${PRISM_COMMAND_MENTION_HASH_PREFIX}${encodeURIComponent(commandId)}${metadata}`;
}

/**
 * User line from a post-`POST /api/coffee/turn` payload: prefer the user message before a
 * trailing assistant reply; otherwise the last user message in the array.
 */
function extractCoffeeUserLineFromTurnMessages(
  messages: readonly CoffeeConversationMessage[]
): string | null {
  if (messages.length === 0) return null;
  const last = messages[messages.length - 1];
  if (last.role === "assistant") {
    for (let i = messages.length - 2; i >= 0; i -= 1) {
      const m = messages[i];
      if (m.role === "user") {
        return m.content.trim().length > 0 ? coffeeTableDisplayText(m.content) : null;
      }
    }
    return null;
  }
  for (let i = messages.length - 1; i >= 0; i -= 1) {
    const m = messages[i];
    if (m.role === "user") {
      return m.content.trim().length > 0 ? coffeeTableDisplayText(m.content) : null;
    }
  }
  return null;
}

function clampCoffeeTableText(text: string): string {
  return text;
}

function stripCoffeeVisibleQuoteMarks(text: string): string {
  return text
    .replace(/[“”"]/g, "")
    .replace(/\s+([,.!?;:])/gu, "$1")
    .replace(/\s{2,}/g, " ")
    .trim();
}

function coffeeTableDisplayText(text: string): string {
  return stripCoffeeVisibleQuoteMarks(extractStageDirections(clampCoffeeTableText(text)).mainText);
}

function mergeCoffeeTranscriptMessageSources(
  fullHistory: readonly CoffeeConversationMessage[] | undefined,
  liveMessages: readonly CoffeeConversationMessage[]
): CoffeeConversationMessage[] {
  if (!fullHistory) return [...liveMessages];
  const seenMessageIds = new Set(fullHistory.map((message) => message.id));
  return [
    ...fullHistory,
    ...liveMessages.filter((message) => !seenMessageIds.has(message.id)),
  ];
}

function normalizeCoffeeSeatActionBadgeText(
  raw: string,
  bot?: Pick<Bot, "name" | "system_prompt" | "glyph"> | null
): string {
  const collapsed = stripCoffeeVisibleQuoteMarks(raw.replace(/\s+/g, " ").trim());
  if (!collapsed) return "";
  let text = sanitizeCoffeeActionForBot(
    collapsed
      .replace(/^\*+|\*+$/g, "")
      .replace(/^\[[^\]\n]+\]\(prism-bot:\/\/[^)\n]+\)\s*,?\s*/i, "")
      .replace(/^[\p{Lu}][\p{L}'-]+(?:\s+[\p{Lu}][\p{L}'-]+){0,3},\s+/u, "")
      .replace(/^[“”"]+|[“”"]+$/g, "")
      .replace(/[.!?;:,\s]+$/u, "")
      .replace(/^[“”"]+|[“”"]+$/g, "")
      .trim(),
    bot
      ? {
          name: bot.name,
          systemPrompt: bot.system_prompt,
          glyph: bot.glyph,
        }
      : null
  );
  if (!text) return "";
  if (text.length <= COFFEE_SEAT_ACTION_BADGE_MAX_CHARS) return text;

  const firstClause = text
    .split(/[.!?;:]\s+/u)
    .map((segment) => segment.trim())
    .find(
      (segment) =>
        segment.length >= COFFEE_SEAT_ACTION_BADGE_MIN_CLAUSE_CHARS &&
        segment.length <= COFFEE_SEAT_ACTION_BADGE_MAX_CHARS
    );
  if (firstClause) return firstClause;

  const sliced = text.slice(0, COFFEE_SEAT_ACTION_BADGE_MAX_CHARS).trimEnd();
  const lastSpace = sliced.lastIndexOf(" ");
  const cut =
    lastSpace > COFFEE_SEAT_ACTION_BADGE_MAX_CHARS * 0.6
      ? sliced.slice(0, lastSpace).trimEnd()
      : sliced;
  text = cut.length > 0 ? cut : sliced;
  return text.replace(/[.!?;:,\s]+$/u, "");
}

function coffeeMessageHasTableText(
  message: CoffeeConversationMessage | null | undefined
): boolean {
  if (!message) return false;
  return coffeeTableDisplayText(message.content).trim().length > 0;
}

function coffeeConversationHasSessionSynopsis(
  conversation: CoffeeConversationState | null | undefined
): boolean {
  return Boolean(
    conversation?.messages.some(
      (message) =>
        message.role === "system" &&
        coffeeSystemSynopsisIsDisplayable(message.content)
    )
  );
}

function coffeeReplayMessageKey(message: CoffeeConversationMessage, index: number): string {
  return message.id || `${index}:${message.createdAt}:${message.role}:${message.botName ?? ""}`;
}

function coffeeReplayDisplayLengthForMessage(message: CoffeeConversationMessage): number {
  if (!coffeeMessageHasTableText(message)) {
    return coffeeReplayMessageHasStateEvent(message) ? 12 : 0;
  }
  return getBotMentionDisplayLength(coffeeTableDisplayText(message.content));
}

