interface ConversationStarterPromptState {
  conversationId: string;
  prompts: string[];
  assistantMessageId: string | null;
}

function messageCreatedAtMs(message: Pick<Message, "createdAt">): number | null {
  const ms = Date.parse(message.createdAt);
  return Number.isFinite(ms) ? ms : null;
}

function getLatestAssistantMessageId(messages: readonly Message[]): string | null {
  for (let i = messages.length - 1; i >= 0; i -= 1) {
    const message = messages[i];
    if (message?.role === "assistant") return message.id;
  }
  return null;
}

function findConversationStarterAnchorMessage(
  messages: readonly Message[],
  assistantMessageId: string | null | undefined
): Message | undefined {
  if (assistantMessageId) {
    return messages.find(
      (message) => message.id === assistantMessageId && message.role === "assistant"
    );
  }
  return [...messages].reverse().find((message) => message.role === "assistant");
}

function hasUserReplyAfterMessage(
  messages: readonly Message[],
  messageId: string | null | undefined
): boolean {
  if (!messageId) return false;
  const messageIndex = messages.findIndex((message) => message.id === messageId);
  if (messageIndex < 0) return false;
  return messages.slice(messageIndex + 1).some((message) => message.role === "user");
}

function formatZenSessionGapDuration(gapMs: number): string {
  const safeGapMs = Number.isFinite(gapMs) ? Math.max(0, gapMs) : 0;
  const totalMinutes = Math.round(safeGapMs / (60 * 1000));
  if (totalMinutes < 2) return "A moment later";
  if (totalMinutes < 60) return `${totalMinutes} minutes later`;
  const hours = Math.floor(totalMinutes / 60);
  const minutes = totalMinutes % 60;
  if (minutes === 0) return `${hours} ${hours === 1 ? "hour" : "hours"} later`;
  return `${hours}h ${minutes}m later`;
}

function formatZenSessionBoundaryDateLabel(ms: number): string {
  const date = new Date(ms);
  const includeYear = date.getFullYear() !== new Date().getFullYear();
  return date.toLocaleDateString([], {
    month: "short",
    day: "numeric",
    ...(includeYear ? { year: "numeric" } : {}),
  });
}

function formatZenSessionBoundaryLabel(
  gapMs: number,
  previousActiveAt?: string | null
): string {
  const safeGapMs = Number.isFinite(gapMs) ? Math.max(0, gapMs) : 0;
  const previousMs = previousActiveAt ? Date.parse(previousActiveAt) : NaN;
  const labelMs = Number.isFinite(previousMs) ? previousMs : Date.now() - safeGapMs;
  if (safeGapMs >= ZEN_SESSION_BOUNDARY_DATE_GAP_MS) {
    return `Last session ${formatZenSessionBoundaryDateLabel(labelMs)}`;
  }
  return formatZenSessionGapDuration(safeGapMs);
}

function formatZenEraBoundaryLabel(
  previousMessage: Pick<Message, "createdAt">,
  currentMessage: Pick<Message, "createdAt">
): string {
  const previousMs = messageCreatedAtMs(previousMessage);
  const currentMs = messageCreatedAtMs(currentMessage);
  if (previousMs === null || currentMs === null) return "A new stretch begins";
  return formatZenSessionBoundaryLabel(
    Math.max(0, currentMs - previousMs),
    previousMessage.createdAt
  );
}

function clampZenSessionSummary(text: string | null | undefined): string | null {
  const normalized = text?.replace(/\s+/g, " ").trim() ?? "";
  if (!normalized) return null;
  if (normalized.length <= 360) return normalized;
  return `${normalized.slice(0, 357).trimEnd()}...`;
}

function formatZenSessionAwayLabel(
  gapMs: number,
  previousActiveAt?: string | null
): string {
  return formatZenSessionBoundaryLabel(gapMs, previousActiveAt);
}

function effectiveZenSessionBreakGapMs(
  sessionBreak: Pick<ZenSessionBreakState, "previousActiveAt" | "simulatedIdleMs">,
  nowMs = Date.now()
): number {
  const previousMs = sessionBreak.previousActiveAt
    ? Date.parse(sessionBreak.previousActiveAt)
    : NaN;
  const realGapMs = Number.isFinite(previousMs) ? Math.max(0, nowMs - previousMs) : 0;
  return Math.max(sessionBreak.simulatedIdleMs, realGapMs);
}

function displayZenSessionBreakGapMs(
  sessionBreak: Pick<ZenSessionBreakState, "previousActiveAt" | "simulatedIdleMs">,
  nowMs = Date.now()
): number {
  const previousMs = sessionBreak.previousActiveAt
    ? Date.parse(sessionBreak.previousActiveAt)
    : NaN;
  if (Number.isFinite(previousMs)) return Math.max(0, nowMs - previousMs);
  return Math.max(0, sessionBreak.simulatedIdleMs);
}

function zenSessionBreakUsesFreshStart(
  gapMs: number,
  freshStartGapMs = ZEN_LONG_SESSION_GAP_MS
): boolean {
  return gapMs >= normalizeZenFreshStartGapSetting(freshStartGapMs);
}

function normalizeZenSessionBreakState(raw: unknown): ZenSessionBreakState | null {
  if (!raw || typeof raw !== "object") return null;
  const record = raw as Partial<ZenSessionBreakState>;
  if (record.schema !== ZEN_SESSION_BREAK_SCHEMA) return null;
  const conversationId =
    typeof record.conversationId === "string" ? record.conversationId.trim() : "";
  if (!conversationId) return null;
  const createdAt =
    typeof record.createdAt === "string" && Number.isFinite(Date.parse(record.createdAt))
      ? record.createdAt
      : new Date().toISOString();
  const previousActiveAt =
    typeof record.previousActiveAt === "string" &&
    Number.isFinite(Date.parse(record.previousActiveAt))
      ? record.previousActiveAt
      : null;
  const simulatedIdleMs =
    typeof record.simulatedIdleMs === "number" && Number.isFinite(record.simulatedIdleMs)
      ? Math.max(0, record.simulatedIdleMs)
      : ZEN_IDLE_ERA_GAP_MS;
  return {
    schema: ZEN_SESSION_BREAK_SCHEMA,
    userId: typeof record.userId === "string" ? record.userId : null,
    conversationId,
    anchorMessageId:
      typeof record.anchorMessageId === "string" && record.anchorMessageId.trim()
        ? record.anchorMessageId.trim()
        : null,
    anchorMessageCount:
      typeof record.anchorMessageCount === "number" && Number.isFinite(record.anchorMessageCount)
        ? Math.max(0, Math.floor(record.anchorMessageCount))
        : 0,
    displaySummary: clampZenSessionSummary(record.displaySummary),
    internalSummary: clampZenSessionSummary(record.internalSummary),
    createdAt,
    previousActiveAt,
    simulatedIdleMs,
    source: record.source === "dev" ? "dev" : "idle",
    resumeHintConsumed: record.resumeHintConsumed === true,
  };
}

function readStoredZenSessionBreak(userId: string | null | undefined): ZenSessionBreakState | null {
  if (typeof window === "undefined") return null;
  try {
    const parsed = normalizeZenSessionBreakState(
      JSON.parse(window.localStorage.getItem(PRISM_ZEN_SESSION_BREAK_STORAGE_KEY) ?? "null")
    );
    if (!parsed) return null;
    if (parsed.userId && userId && parsed.userId !== userId) return null;
    return parsed;
  } catch {
    return null;
  }
}

function persistZenSessionBreak(state: ZenSessionBreakState | null): void {
  if (typeof window === "undefined") return;
  try {
    if (!state) {
      window.localStorage.removeItem(PRISM_ZEN_SESSION_BREAK_STORAGE_KEY);
      return;
    }
    window.localStorage.setItem(
      PRISM_ZEN_SESSION_BREAK_STORAGE_KEY,
      JSON.stringify(state)
    );
  } catch {
    // Private mode / quota: the in-memory marker still works for this tab.
  }
}

function latestMessageActivityAt(messages: readonly Message[]): string | null {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const candidate = messages[index]?.createdAt;
    if (candidate && Number.isFinite(Date.parse(candidate))) return candidate;
  }
  return null;
}

function createZenSessionBreakState(args: {
  userId: string | null;
  conversationId: string;
  messages: readonly Message[];
  displaySummary?: string | null;
  internalSummary?: string | null;
  source: "idle" | "dev";
  idleMs: number;
  sessionIdleGapMs?: number;
  freshStartGapMs?: number;
}): ZenSessionBreakState {
  const lastMessage = args.messages.at(-1) ?? null;
  const createdAt = new Date().toISOString();
  const sessionIdleGapMs = normalizeZenSessionIdleGapSetting(
    args.sessionIdleGapMs
  );
  const previousActiveAt =
    latestMessageActivityAt(args.messages) ??
    new Date(Date.now() - Math.max(args.idleMs, sessionIdleGapMs)).toISOString();
  const keepResumeSummary = !zenSessionBreakUsesFreshStart(
    args.idleMs,
    args.freshStartGapMs
  );
  return {
    schema: ZEN_SESSION_BREAK_SCHEMA,
    userId: args.userId,
    conversationId: args.conversationId,
    anchorMessageId: lastMessage?.id ?? null,
    anchorMessageCount: args.messages.length,
    displaySummary: keepResumeSummary ? clampZenSessionSummary(args.displaySummary) : null,
    internalSummary: keepResumeSummary ? clampZenSessionSummary(args.internalSummary) : null,
    createdAt,
    previousActiveAt,
    simulatedIdleMs: Math.max(args.idleMs, 0),
    source: args.source,
    resumeHintConsumed: false,
  };
}

function createSessionResumeContextFromZenBreak(
  sessionBreak: ZenSessionBreakState
): SessionResumeContext {
  const summary = sessionBreak.displaySummary ?? sessionBreak.internalSummary ?? undefined;
  return {
    ...(summary ? { summary } : {}),
    resumedAt: new Date().toISOString(),
    ...(sessionBreak.previousActiveAt
      ? { previousActiveAt: sessionBreak.previousActiveAt }
      : {}),
    gapMs: effectiveZenSessionBreakGapMs(sessionBreak),
    source: sessionBreak.source,
  };
}

function collectGeneratedImageIds(messages: readonly Message[]): string[] {
  const ids: string[] = [];
  for (const message of messages) {
    const imageId = message.sentGeneratedImage?.imageId?.trim();
    if (!imageId) continue;
    ids.push(imageId);
  }
  return ids;
}

/** How many typewriter characters advance before moving to the next Zen mouth phase. */
const COFFEE_SEAT_MOUTH_CHARS_PER_PHASE = 3;
const COFFEE_SEAT_MOOD_PULSE_MS = 8_000;

function coffeeSeatStableHash(text: string): number {
  let hash = 2_166_136_261;
  for (let index = 0; index < text.length; index += 1) {
    hash ^= text.charCodeAt(index);
    hash = Math.imul(hash, 16_777_619);
  }
  return hash >>> 0;
}

function coffeeSeatMouthShapeFromVisibleLength(
  visibleLength: number,
  speechSeedText: string
): ZenLiveBotMouthShape {
  if (visibleLength <= 0) return "closed";
  return zenLiveBotMouthShapeFromSpeechPhase({
    speechSeedText,
    phaseIndex: Math.floor(
      Math.max(0, visibleLength) / COFFEE_SEAT_MOUTH_CHARS_PER_PHASE
    ),
  });
}

function lastCoffeeAssistantMoodKeyForBotName(
  threadMessages: readonly CoffeeConversationMessage[],
  botName: string
): BotMoodKey | undefined {
  for (let i = threadMessages.length - 1; i >= 0; i--) {
    const row = threadMessages[i];
    if (row?.role === "assistant" && row.botName === botName && row.moodKey) {
      return row.moodKey;
    }
  }
  return undefined;
}

/**
 * Coffee threads do not always include Prism mood on rows yet; social metrics
 * provide a lightweight table "temperature" until the API mirrors chat moods.
 */
function coffeeSeatSocialHeuristicMood(
  social: CoffeeBotSocialSnapshot | undefined
): BotMoodKey | undefined {
  if (!social) return undefined;
  return derivePrismMoodKey(coffeeSocialSnapshotToPrismMoodState(social));
}

function coffeeSeatLiveMood({
  baseMood,
  social,
  botId,
  nowMs,
  isSpeaking,
  sessionLive,
}: {
  baseMood: BotMoodKey;
  social: CoffeeBotSocialSnapshot | undefined;
  botId: string;
  nowMs: number;
  isSpeaking: boolean;
  sessionLive: boolean;
}): BotMoodKey {
  if (!sessionLive || isSpeaking) return baseMood;

  const botOffsetMs = coffeeSeatStableHash(`${botId}:mood-offset`) % COFFEE_SEAT_MOOD_PULSE_MS;
  const pulseIndex = Math.floor((Math.max(0, nowMs) + botOffsetMs) / COFFEE_SEAT_MOOD_PULSE_MS);
  const roll = coffeeSeatStableHash(`${botId}:${pulseIndex}:${baseMood}`) % 100;
  const valuesFriction = social?.valuesFriction ?? 0.32;
  const leavePressure = social?.leavePressure ?? 0.18;
  const disposition = social?.disposition ?? 0.52;
  const engagement = social?.engagement ?? 0.5;

  switch (baseMood) {
    case "joyful":
      return roll < 22 ? "warm" : "joyful";
    case "warm":
      if (valuesFriction > 0.5 && roll < 24) return "guarded";
      if (disposition > 0.62 && engagement > 0.58 && roll < 42) return "joyful";
      return roll < 18 ? "neutral" : "warm";
    case "guarded":
      if (leavePressure > 0.58 && roll < 36) return "strained";
      if (disposition > 0.56 && roll < 24) return "neutral";
      return roll < 26 ? "neutral" : "guarded";
    case "strained":
      return roll < 24 ? "guarded" : "strained";
    case "neutral":
    default:
      if (leavePressure > 0.48 && roll < 30) return "strained";
      if (valuesFriction > 0.42 && roll < 38) return "guarded";
      if (disposition > 0.54 && engagement > 0.56 && roll < 38) return "warm";
      return roll < 16 ? "warm" : "neutral";
  }
}

function coffeeSeatFallbackSaturationForMood(mood: BotMoodKey): number {
  switch (mood) {
    case "joyful":
      return 1.32;
    case "warm":
      return 1.12;
    case "guarded":
      return 1;
    case "strained":
      return 1;
    case "neutral":
    default:
      return 1;
  }
}

function coffeeSeatMoodVisualMetrics(
  mood: BotMoodKey,
  social: CoffeeBotSocialSnapshot | undefined
): {
  saturation: number;
  grayscale: number;
  contrast: number;
  brightness: number;
} {
  const rawSaturation = social
    ? coffeeMoodSaturationFromSocial(social)
    : coffeeSeatFallbackSaturationForMood(mood);
  const nearDesaturated =
    social != null && coffeeSocialSnapshotIsNearDesaturated(social);
  const saturation = nearDesaturated
    ? Math.min(rawSaturation, COFFEE_NEAR_DESATURATED_SATURATION)
    : Math.max(rawSaturation, 0.54);
  const belowNeutral = Math.max(0, 1 - Math.min(1, saturation));
  const aboveNeutral = Math.max(0, saturation - 1);
  const grayscaleLimit = nearDesaturated ? 0.86 : 0.38;
  const grayscaleWeight = nearDesaturated ? 0.9 : 0.55;
  return {
    saturation: Number(saturation.toFixed(3)),
    grayscale: Number(Math.min(grayscaleLimit, belowNeutral * grayscaleWeight).toFixed(3)),
    contrast: Number((1 + Math.min(0.08, aboveNeutral * 0.16) - belowNeutral * 0.06).toFixed(3)),
    brightness: Number((1 + Math.min(0.08, aboveNeutral * 0.14) - belowNeutral * 0.1).toFixed(3)),
  };
}

function coffeeSeatEmojiMoodFromPrism(mood: BotMoodKey): CoffeeSeatEmojiMood {
  switch (mood) {
    case "joyful":
      return "happy";
    case "warm":
      return "warm";
    case "neutral":
      return "neutral";
    case "strained":
      return "sad";
    case "guarded":
      return "angry";
    default:
      return "neutral";
  }
}


