function modelChoiceSupportsReasoningEffort(
  provider: Provider,
  modelChoice: string
): boolean {
  return (
    provider === "openai" &&
    modelChoice !== AUTO_MODEL_CHOICE &&
    modelChoice !== DISABLED_MODEL_CHOICE &&
    openAiModelSupportsReasoningEffort(modelChoice)
  );
}

function reasoningEffortSliderPosition(value: ReasoningEffort): number {
  const sliderValue = REASONING_EFFORT_SLIDER_VALUES.includes(
    value as (typeof REASONING_EFFORT_SLIDER_VALUES)[number]
  )
    ? (value as (typeof REASONING_EFFORT_SLIDER_VALUES)[number])
    : DEFAULT_MANUAL_REASONING_EFFORT;
  const index = REASONING_EFFORT_SLIDER_VALUES.indexOf(sliderValue);
  const safeIndex = Math.max(0, index);
  return (safeIndex / (REASONING_EFFORT_SLIDER_VALUES.length - 1)) *
    REASONING_EFFORT_SLIDER_MAX;
}

function reasoningEffortFromSliderPosition(position: number): ReasoningEffort {
  const normalized = Number.isFinite(position) ? position : 0;
  const clamped = Math.min(
    REASONING_EFFORT_SLIDER_MAX,
    Math.max(0, normalized)
  );
  const index = Math.round(
    (clamped / REASONING_EFFORT_SLIDER_MAX) *
      (REASONING_EFFORT_SLIDER_VALUES.length - 1)
  );
  return REASONING_EFFORT_SLIDER_VALUES[index] ?? DEFAULT_MANUAL_REASONING_EFFORT;
}

function normalizeZenModeSettingsFields(
  settings: Partial<ZenModeSettingsFields> | null | undefined
): ZenModeSettingsFields {
  const zenSessionIdleGapMs = normalizeZenSessionIdleGapSetting(
    settings?.zenSessionIdleGapMs
  );
  const zenMessageFontMinPx = normalizeZenMessageFontMinPxSetting(
    settings?.zenMessageFontMinPx
  );
  return {
    zenWallpaperOpacity: normalizeZenWallpaperOpacitySetting(
      settings?.zenWallpaperOpacity
    ),
    zenWallpaperTextMaskEnabled: normalizeZenWallpaperTextMaskSetting(
      settings?.zenWallpaperTextMaskEnabled
    ),
    zenWallpaperGrayscaleEnabled: normalizeZenWallpaperGrayscaleSetting(
      settings?.zenWallpaperGrayscaleEnabled
    ),
    zenWallpaperBlurredEdgesEnabled: normalizeZenWallpaperBlurredEdgesSetting(
      settings?.zenWallpaperBlurredEdgesEnabled
    ),
    zenWallpaperStyleNotes: resolveZenWallpaperStyleOptionNotes(
      settings?.zenWallpaperStyleNotes
    ),
    zenSessionIdleGapMs,
    zenFreshStartGapMs: normalizeZenFreshStartGapSetting(
      settings?.zenFreshStartGapMs,
      zenSessionIdleGapMs
    ),
    zenRecentContextMessages: normalizeZenRecentContextMessagesSetting(
      settings?.zenRecentContextMessages
    ),
    zenWallpaperRegenMessageInterval:
      normalizeZenWallpaperRegenMessageIntervalSetting(
        settings?.zenWallpaperRegenMessageInterval
      ),
    zenMoodSensitivity: normalizeZenMoodSensitivitySetting(
      settings?.zenMoodSensitivity
    ),
    zenCanvasTypingSpeed: normalizeZenCanvasTypingSpeedSetting(
      settings?.zenCanvasTypingSpeed
    ),
    zenMessageFontMinPx,
    zenMessageFontMaxPx: normalizeZenMessageFontMaxPxSetting(
      settings?.zenMessageFontMaxPx,
      zenMessageFontMinPx
    ),
    zenAskQuestionPatienceEnabled:
      normalizeZenAskQuestionPatienceEnabledSetting(
        settings?.zenAskQuestionPatienceEnabled
      ),
    zenAskQuestionPatienceMs: normalizeZenAskQuestionPatienceMsSetting(
      settings?.zenAskQuestionPatienceMs
    ),
    zenAutonomyEnabled: normalizeZenAutonomyEnabledSetting(
      settings?.zenAutonomyEnabled
    ),
  };
}

function formatZenDuration(value: unknown, kind: "idle" | "fresh" = "idle"): string {
  const ms =
    kind === "fresh"
      ? normalizeZenFreshStartGapSetting(value)
      : normalizeZenSessionIdleGapSetting(value);
  const hours = ms / (60 * 60 * 1000);
  if (hours < 24) return `${Math.round(hours * 10) / 10}h`;
  const days = ms / (24 * 60 * 60 * 1000);
  return `${Math.round(days * 10) / 10}d`;
}

function formatZenSessionMemoryExpiry(expiresAt: string): string {
  const expiresMs = Date.parse(expiresAt);
  if (!Number.isFinite(expiresMs)) return "expires soon";
  const remainingMs = expiresMs - Date.now();
  if (remainingMs <= 0) return "expired";
  const hours = remainingMs / (60 * 60 * 1000);
  if (hours < 1) {
    return "expires in under 1 hour";
  }
  if (hours < 24) {
    const roundedHours = Math.max(1, Math.round(hours));
    return `expires in ${roundedHours} hour${roundedHours === 1 ? "" : "s"}`;
  }
  const days = Math.ceil(hours / 24);
  return `expires in ${days} day${days === 1 ? "" : "s"}`;
}

function parseCommandCenterModelChoice(
  value: string
): { provider: Provider; modelId: string } | null {
  const normalized = normalizeModelChoice(value);
  if (normalized === AUTO_MODEL_CHOICE) return null;
  if (normalized === DISABLED_MODEL_CHOICE) return null;
  const separatorIndex = normalized.indexOf(":");
  if (separatorIndex <= 0) return null;
  const providerRaw = normalized.slice(0, separatorIndex).trim().toLowerCase();
  const modelId = normalized.slice(separatorIndex + 1).trim();
  if (!modelId) return null;
  if (providerRaw !== "local") return null;
  return {
    provider: "local",
    modelId,
  };
}

function normalizeCommandCenterPreferredModelChoice(value: string | null | undefined): string {
  const normalized = normalizeModelChoice(value);
  if (normalized === AUTO_MODEL_CHOICE) return AUTO_MODEL_CHOICE;
  if (normalized === DISABLED_MODEL_CHOICE) return DISABLED_MODEL_CHOICE;
  const parsed = parseCommandCenterModelChoice(normalized);
  return parsed ? `local:${parsed.modelId}` : AUTO_MODEL_CHOICE;
}

function commandCenterAuxiliaryModelId(settings: UserSettings | null): string {
  const accountOverride = settings?.prismDefaultLlmModel?.trim() ?? "";
  if (accountOverride.length > 0 && !modelChoiceIsDisabled(accountOverride)) {
    return accountOverride;
  }
  const serverAuxiliary = settings?.ollamaAuxiliaryModel?.trim() ?? "";
  return serverAuxiliary.length > 0 ? serverAuxiliary : "llama3.2";
}

function resolveCommandCenterModelChoiceForSend(
  value: string,
  settings: UserSettings | null,
  catalog: ModelCatalog | null
): string {
  const normalized = normalizeCommandCenterPreferredModelChoice(value);
  if (normalized === DISABLED_MODEL_CHOICE) return DISABLED_MODEL_CHOICE;
  const parsed = parseCommandCenterModelChoice(normalized);
  if (parsed) {
    const visibleChoice = visibleModelChoiceForProvider(
      catalog,
      settings,
      "local",
      parsed.modelId
    );
    if (visibleChoice !== AUTO_MODEL_CHOICE) {
      return `local:${visibleChoice}`;
    }
  }
  return `local:${commandCenterAuxiliaryModelId(settings)}`;
}

/** Row to badge in chat model menus: the concrete id saved in Settings (no badge when Auto). */
function chatSettingsSavedDefaultModelId(
  settings: UserSettings | null,
  provider: Provider | "online"
): string | null {
  if (!settings) return null;
  const raw =
    provider === "local" ? settings.preferredLocalModel : settings.preferredOnlineModel;
  const normalized = normalizeModelChoice(raw);
  return normalized === AUTO_MODEL_CHOICE || normalized === DISABLED_MODEL_CHOICE
    ? null
    : normalized;
}

/** Row to badge in image model menus from Settings image preferences. */
function imageSettingsSavedDefaultModelId(
  settings: UserSettings | null,
  provider: Provider
): string | null {
  if (!settings) return null;
  if (provider === "local") {
    const n = normalizeModelChoice(settings.preferredLocalImageModel);
    return n === AUTO_MODEL_CHOICE || n === DISABLED_MODEL_CHOICE ? null : n;
  }
  const trimmed = settings.preferredOpenAiImageModel?.trim() ?? "";
  if (trimmed.length === 0) return null;
  if (modelChoiceIsDisabled(trimmed)) return null;
  return isAllowedOpenAiImageModelId(trimmed) || isElevenLabsImageModelId(trimmed)
    ? trimmed
    : null;
}

const SECONDARY_OLLAMA_MODEL_PREFIX = "ollama-secondary:";
const REQUIRED_PRIMARY_LOCAL_MODEL_ID = "llama3.2";

function titleCaseModelToken(token: string): string {
  const lower = token.toLowerCase();
  const known: Record<string, string> = {
    api: "API",
    b: "B",
    chatgpt: "ChatGPT",
    code: "Code",
    codellama: "Code Llama",
    codex: "Codex",
    deepseek: "DeepSeek",
    distill: "Distill",
    flux: "FLUX",
    gemma: "Gemma",
    gpt: "GPT",
    instruct: "Instruct",
    llama: "Llama",
    llava: "LLaVA",
    mini: "Mini",
    mistral: "Mistral",
    mixtral: "Mixtral",
    nano: "Nano",
    opus: "Opus",
    phi: "Phi",
    pro: "Pro",
    qwen: "Qwen",
    r1: "R1",
    search: "Search",
    sonnet: "Sonnet",
    tinyllama: "TinyLlama",
    vl: "VL",
  };
  if (known[lower]) return known[lower];
  if (/^\d+(?:\.\d+)?b$/i.test(token)) return token.toUpperCase();
  if (/^o\d/.test(lower)) return lower;
  const alphaNumber = token.match(/^([a-z]+)(\d+(?:\.\d+)?)$/i);
  if (alphaNumber) return `${titleCaseModelToken(alphaNumber[1]!)} ${alphaNumber[2]}`;
  return token.toUpperCase() === token
    ? token
    : `${token.slice(0, 1).toUpperCase()}${token.slice(1)}`;
}

function modelSnapshotSuffix(datePart: string | undefined): string {
  if (!datePart) return "";
  const isoDate = datePart.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (isoDate) return ` (${isoDate[1]}-${isoDate[2]}-${isoDate[3]})`;
  const compactDate = datePart.match(/^(\d{4})(\d{2})(\d{2})$/);
  if (compactDate) return ` (${compactDate[1]}-${compactDate[2]}-${compactDate[3]})`;
  return ` (${datePart})`;
}

function openAiTextModelLabelFromId(id: string): string | null {
  const normalized = id.trim().toLowerCase();
  if (!normalized) return null;
  if (normalized === "chatgpt-4o-latest") return "ChatGPT-4o";
  const oSeries = normalized.match(/^(o\d)(?:-(mini))?$/);
  if (oSeries) return [oSeries[1], oSeries[2] ? "Mini" : ""].filter(Boolean).join(" ");
  const codex = normalized.match(/^gpt-(\d+(?:\.\d+)?)-codex(?:-(max|mini))?$/);
  if (codex) {
    return [`GPT-${codex[1]}`, "Codex", codex[2] ? titleCaseModelToken(codex[2]) : ""]
      .filter(Boolean)
      .join(" ");
  }
  const search = normalized.match(/^gpt-(\d+(?:\.\d+)?)-search-api(?:-(\d{4}-\d{2}-\d{2}))?$/);
  if (search) return `GPT-${search[1]} Search${modelSnapshotSuffix(search[2])}`;
  const chatLatest = normalized.match(/^gpt-(\d+(?:\.\d+)?)-chat-latest$/);
  if (chatLatest) return `GPT-${chatLatest[1]}`;
  const versioned = normalized.match(
    /^gpt-(\d+(?:\.\d+)?)(?:-(mini|nano|pro))?(?:-(\d{4}-\d{2}-\d{2}))?$/
  );
  if (versioned) {
    return [`GPT-${versioned[1]}`, versioned[2] ? titleCaseModelToken(versioned[2]) : ""]
      .filter(Boolean)
      .join(" ") + modelSnapshotSuffix(versioned[3]);
  }
  return null;
}

function anthropicTextModelLabelFromId(id: string): string | null {
  const normalized = id.trim().toLowerCase();
  if (!normalized.startsWith("claude-")) return null;
  const latest = normalized.match(/^claude-(\d)-(\d)-(sonnet|haiku)-latest$/);
  if (latest) return `${latest[1]}.${latest[2]} ${titleCaseModelToken(latest[3]!)}`;
  const named = normalized.match(
    /^claude-(opus|sonnet|haiku)-(\d+)(?:-(\d+))?(?:-(\d{8}))?$/
  );
  if (named) {
    const version = named[3] ? `${named[2]}.${named[3]}` : named[2]!;
    return `${titleCaseModelToken(named[1]!)} ${version}${modelSnapshotSuffix(named[4])}`;
  }
  return null;
}

function modelLabelFromId(id: string): string {
  const providerLabel = openAiTextModelLabelFromId(id) ?? anthropicTextModelLabelFromId(id);
  if (providerLabel) return providerLabel;
  const parts = id
    .replace(SECONDARY_OLLAMA_MODEL_PREFIX, "")
    .split(/[-_:]/)
    .filter(Boolean)
    .filter((part, index, allParts) =>
      !(index === allParts.length - 1 && part.toLowerCase() === "latest")
    );
  const displayParts = parts.length > 0 ? parts : [id];
  return displayParts.map(titleCaseModelToken).join(" ");
}

function isRequiredPrimaryLocalModel(model: ModelCatalogEntry): boolean {
  return (
    model.provider === "local" &&
    model.localHost !== "secondary" &&
    model.id === REQUIRED_PRIMARY_LOCAL_MODEL_ID
  );
}

function normalizeApiKeySource(value: unknown, hasSavedKey: boolean): ApiKeySource {
  return value === "saved" || value === "server" || value === "none"
    ? value
    : hasSavedKey
      ? "saved"
      : "none";
}

function apiKeySourceAvailable(source: ApiKeySource | null | undefined): boolean {
  return source === "saved" || source === "server";
}

function onlineProviderApiKeySource(
  settings: UserSettings | null,
  provider: Provider
): ApiKeySource | null {
  if (!settings) return null;
  if (provider === "openai") return settings.openAiApiKeySource;
  if (provider === "anthropic") return settings.anthropicApiKeySource;
  return null;
}

function onlineProviderHasConfiguredKey(
  settings: UserSettings | null,
  provider: Provider
): boolean {
  return apiKeySourceAvailable(onlineProviderApiKeySource(settings, provider));
}

function apiKeySourceModelGroupMeta(source: ApiKeySource): string {
  return source === "server" ? "Server key connected" : "Saved key connected";
}

function normalizeSavedApiKeySettingsState(
  state: Partial<SavedApiKeySettingsState>
): SavedApiKeySettingsState {
  const hasOpenAiApiKey = state.hasOpenAiApiKey === true;
  const hasAnthropicApiKey = state.hasAnthropicApiKey === true;
  const hasElevenLabsApiKey = state.hasElevenLabsApiKey === true;
  return {
    hasOpenAiApiKey,
    hasAnthropicApiKey,
    hasElevenLabsApiKey,
    openAiApiKeySource: normalizeApiKeySource(
      state.openAiApiKeySource,
      hasOpenAiApiKey
    ),
    anthropicApiKeySource: normalizeApiKeySource(
      state.anthropicApiKeySource,
      hasAnthropicApiKey
    ),
    elevenLabsApiKeySource: normalizeApiKeySource(
      state.elevenLabsApiKeySource,
      hasElevenLabsApiKey
    ),
  };
}

function apiKeySourceStatusLabel(providerLabel: string, source: ApiKeySource): string {
  if (source === "saved") return `${providerLabel} saved`;
  if (source === "server") return `${providerLabel} server key`;
  return `${providerLabel} unset`;
}

function createApiKeyDraftValidationMap(): ApiKeyDraftValidationMap {
  return {
    openai: { value: "", status: "idle", detail: null },
    anthropic: { value: "", status: "idle", detail: null },
    elevenlabs: { value: "", status: "idle", detail: null },
  };
}

function apiKeyConnectionDisplay(
  providerLabel: string,
  source: ApiKeySource,
  draft: ApiKeyDraftValidation
): ApiKeyConnectionDisplay {
  if (draft.value.length > 0) {
    if (draft.status === "connected") {
      return {
        overviewStatus: "connected",
        overviewText: `${providerLabel} connected`,
        fieldStatus: "connected",
        fieldText: "Connected",
        detail: draft.detail,
      };
    }
    if (draft.status === "error") {
      return {
        overviewStatus: "error",
        overviewText: `${providerLabel} invalid`,
        fieldStatus: "error",
        fieldText: "Invalid",
        detail: draft.detail,
      };
    }
    return {
      overviewStatus: "checking",
      overviewText: `${providerLabel} checking...`,
      fieldStatus: "checking",
      fieldText: "Checking...",
      detail: draft.detail,
    };
  }

  if (source !== "none") {
    return {
      overviewStatus: "ready",
      overviewText: apiKeySourceStatusLabel(providerLabel, source),
      fieldStatus: "connected",
      fieldText: source === "server" ? "Server key" : "Saved",
      detail: null,
    };
  }

  return {
    overviewStatus: "idle",
    overviewText: apiKeySourceStatusLabel(providerLabel, source),
    fieldStatus: "idle",
    fieldText: "Optional",
    detail: null,
  };
}

function onlineProviderCanPreserveModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): boolean {
  return (
    (catalog?.online ?? []).some((model) => model.provider === provider) ||
    onlineProviderHasConfiguredKey(settings, provider)
  );
}

function isHiddenBotModelId(
  settings: UserSettings | null,
  modelId: string | null | undefined
): boolean {
  const normalized = modelId?.trim() ?? "";
  if (!normalized) return false;
  return (settings?.hiddenBotModelIds ?? []).includes(normalized);
}

function modelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  if (provider === "local") {
    const fallbackId = settings?.ollamaModel?.trim() || "Local default";
    return catalog?.local.length
      ? catalog.local
      : [{
          id: fallbackId,
          label: fallbackId,
          provider: "local",
          isDefault: true,
          hostLabel: "Primary host",
        }];
  }
  const onlineOptions = (catalog?.online ?? []).filter(
    (model) => model.provider === provider
  );
  if (onlineOptions.length > 0) {
    return onlineOptions.map((model) => ({
      ...model,
      hostLabel: model.hostLabel ?? providerDisplayLabel(provider),
    }));
  }
  return [];
}

function fallbackChatModelOptionsForProvider(
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  // Keep chat menus usable while online model discovery is still catching up.
  if (!isOnlineProvider(provider) || !onlineProviderHasConfiguredKey(settings, provider)) {
    return [];
  }
  return fallbackOnlineModelIdsForProvider(
    provider,
    settings?.preferredOnlineModel
  ).map((id, index) => ({
    id,
    label: modelLabelFromId(id),
    provider,
    hostLabel: providerDisplayLabel(provider),
    isDefault: index === 0,
  }));
}

function chatModelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  const visibleCatalogOptions = filterVisibleModelOptions(
    modelOptionsForProvider(catalog, settings, provider),
    settings?.hiddenBotModelIds ?? []
  );
  if (visibleCatalogOptions.length > 0 || provider === "local") {
    return visibleCatalogOptions;
  }
  return filterVisibleModelOptions(
    fallbackChatModelOptionsForProvider(settings, provider),
    settings?.hiddenBotModelIds ?? []
  );
}

function botCustomizerModelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  return chatModelOptionsForProvider(catalog, settings, provider);
}

function availableModelOptionsForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): ModelCatalogEntry[] {
  return modelOptionsForProvider(catalog, settings, provider);
}

function defaultModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider
): string {
  const options = chatModelOptionsForProvider(catalog, settings, provider).filter(
    (model) => !model.disabledReason
  );
  return options.find((model) => model.isDefault)?.id ?? options[0]?.id ?? AUTO_MODEL_CHOICE;
}

function visibleConcreteModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === DISABLED_MODEL_CHOICE) {
    return DISABLED_MODEL_CHOICE;
  }
  if (visibleChoice === AUTO_MODEL_CHOICE) {
    return defaultModelChoiceForProvider(catalog, settings, provider);
  }
  return chatModelOptionsForProvider(catalog, settings, provider).some(
    (model) => model.id === visibleChoice
  )
    ? visibleChoice
    : defaultModelChoiceForProvider(catalog, settings, provider);
}

function defaultOnlineModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null
): string {
  const options = onlineModelOptionsForPicker(catalog, settings).filter(
    (model) => !model.disabledReason
  );
  return options.find((model) => model.isDefault)?.id ?? options[0]?.id ?? AUTO_MODEL_CHOICE;
}

function visibleConcreteOnlineModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === DISABLED_MODEL_CHOICE) {
    return DISABLED_MODEL_CHOICE;
  }
  if (visibleChoice === AUTO_MODEL_CHOICE) {
    return defaultOnlineModelChoice(catalog, settings);
  }
  if (isHiddenBotModelId(settings, visibleChoice)) {
    return defaultOnlineModelChoice(catalog, settings);
  }
  const options = onlineModelOptionsForPicker(catalog, settings);
  const provider = inferOnlineProviderForModelId(visibleChoice);
  return options.some((model) => model.id === visibleChoice) ||
    onlineProviderCanPreserveModelChoice(catalog, settings, provider)
    ? visibleChoice
    : defaultOnlineModelChoice(catalog, settings);
}

function visibleModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === DISABLED_MODEL_CHOICE) return DISABLED_MODEL_CHOICE;
  if (visibleChoice === AUTO_MODEL_CHOICE) {
    return visibleChoice;
  }
  return chatModelOptionsForProvider(catalog, settings, provider).some(
    (model) => model.id === visibleChoice
  ) ||
    (provider !== "local" &&
      !isHiddenBotModelId(settings, visibleChoice) &&
      onlineProviderCanPreserveModelChoice(catalog, settings, provider))
    ? visibleChoice
    : AUTO_MODEL_CHOICE;
}

function visibleOptionalModelChoiceForProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  provider: Provider,
  choice: string | null | undefined
): string {
  const visibleChoice = choice?.trim() ?? "";
  if (!visibleChoice) return "";
  return chatModelOptionsForProvider(catalog, settings, provider).some(
    (model) => model.id === visibleChoice
  ) ||
    (provider !== "local" &&
      !isHiddenBotModelId(settings, visibleChoice) &&
      onlineProviderCanPreserveModelChoice(catalog, settings, provider))
    ? visibleChoice
    : "";
}

function visiblePreferredOnlineModelChoice(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  choice: string | null | undefined
): string {
  const visibleChoice = normalizeModelChoice(choice);
  if (visibleChoice === DISABLED_MODEL_CHOICE) return DISABLED_MODEL_CHOICE;
  if (visibleChoice === AUTO_MODEL_CHOICE) return AUTO_MODEL_CHOICE;
  if (isHiddenBotModelId(settings, visibleChoice)) return AUTO_MODEL_CHOICE;
  const provider = inferOnlineProviderForModelId(visibleChoice);
  return onlineProviderCanPreserveModelChoice(catalog, settings, provider)
    ? visibleChoice
    : AUTO_MODEL_CHOICE;
}

function visibleModelChoicesByProvider(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  choices: Record<Provider, string>
): Record<Provider, string> {
  return {
    local: visibleModelChoiceForProvider(catalog, settings, "local", choices.local),
    openai: visibleModelChoiceForProvider(catalog, settings, "openai", choices.openai),
    anthropic: visibleModelChoiceForProvider(
      catalog,
      settings,
      "anthropic",
      choices.anthropic
    ),
  };
}

function onlineModelOptionsForPicker(
  catalog: ModelCatalog | null,
  settings: UserSettings | null
): ModelCatalogEntry[] {
  return withOnlineProviderHostLabels(combinedOnlineModelOptions(
    chatModelOptionsForProvider(catalog, settings, "openai"),
    chatModelOptionsForProvider(catalog, settings, "anthropic")
  ));
}

function withOnlineProviderHostLabels(options: ModelCatalogEntry[]): ModelCatalogEntry[] {
  return options.map((model) => ({
    ...model,
    hostLabel: model.hostLabel ?? providerDisplayLabel(model.provider),
  }));
}

function modelOptionsForResponseMode(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  responseMode: ResponseMode
): ModelCatalogEntry[] {
  return responseMode === "local"
    ? chatModelOptionsForProvider(catalog, settings, "local")
    : onlineModelOptionsForPicker(catalog, settings);
}

function includeSelectedModelOption(
  options: ModelCatalogEntry[],
  choice: string,
  provider: Provider
): ModelCatalogEntry[] {
  const normalizedChoice = choice.trim();
  if (
    !normalizedChoice ||
    normalizedChoice === AUTO_MODEL_CHOICE ||
    normalizedChoice === DISABLED_MODEL_CHOICE ||
    options.some((model) => model.id === normalizedChoice)
  ) {
    return options;
  }
  return [
    ...options,
    { id: normalizedChoice, label: normalizedChoice, provider },
  ];
}

function includeSelectedOnlineModelOption(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  options: ModelCatalogEntry[],
  choice: string
): ModelCatalogEntry[] {
  const normalizedChoice = normalizeModelChoice(choice);
  if (
    normalizedChoice === AUTO_MODEL_CHOICE ||
    normalizedChoice === DISABLED_MODEL_CHOICE ||
    options.some((model) => model.id === normalizedChoice)
  ) {
    return options;
  }
  if (isHiddenBotModelId(settings, normalizedChoice)) return options;
  const provider = inferOnlineProviderForModelId(normalizedChoice);
  return onlineProviderCanPreserveModelChoice(catalog, settings, provider)
    ? includeSelectedModelOption(options, normalizedChoice, provider)
    : options;
}

function includeSelectedResponseModeModelOption(
  catalog: ModelCatalog | null,
  settings: UserSettings | null,
  responseMode: ResponseMode,
  options: ModelCatalogEntry[],
  choice: string,
  provider: Provider
): ModelCatalogEntry[] {
  return responseMode === "online"
    ? includeSelectedOnlineModelOption(catalog, settings, options, choice)
    : isHiddenBotModelId(settings, choice)
      ? options
      : includeSelectedModelOption(options, choice, provider);
}

function visibleLocalImageModelSelectValue(value: string | null | undefined): string {
  const trimmed = value?.trim() ?? "";
  if (modelChoiceIsDisabled(trimmed)) return DISABLED_MODEL_CHOICE;
  return isComfyUiModelId(trimmed) ? "" : trimmed;
}

function includeSelectedLocalImageModelOption(
  options: ModelCatalogEntry[],
  choice: string | null | undefined
): ModelCatalogEntry[] {
  return includeSelectedModelOption(
    options,
    visibleLocalImageModelSelectValue(choice),
    "local"
  );
}

function uniqueModelOptions(options: ModelCatalogEntry[]): ModelCatalogEntry[] {
  const seen = new Set<string>();
  return options.filter((model) => {
    const key = `${model.provider}:${model.id}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

type SettingsModelEligibilityGroupId = "ollama" | "openai" | "anthropic" | "elevenlabs";

interface SettingsModelEligibilityGroup {
  id: SettingsModelEligibilityGroupId;
  label: string;
  meta: string;
  models: ModelCatalogEntry[];
  notice?: string;
  pending?: boolean;
}

function settingsModelGroupOptions(options: ModelCatalogEntry[]): ModelCatalogEntry[] {
  const seen = new Set<string>();
  return options.filter((model) => {
    const id = model.id.trim();
    if (!id || seen.has(id)) return false;
    seen.add(id);
    return true;
  });
}

function settingsOllamaGroupMeta(models: ModelCatalogEntry[]): string {
  const hasSecondaryHost = models.some((model) => model.localHost === "secondary");
  if (!hasSecondaryHost) return "Local Ollama host";
  const hostCount = new Set(
    models.map((model) => model.localHost ?? model.hostLabel ?? "primary")
  ).size;
  return `${hostCount} connected Ollama hosts`;
}

function settingsModelDiscoveryNotice(
  providerLabel: string,
  status: ModelCatalogRefreshStatus
): string {
  if (status === "checking" || status === "idle") {
    return `${providerLabel} chat models are still being checked. They may appear in a moment.`;
  }
  if (status === "error") {
    return `${providerLabel} chat models could not be refreshed. Prism is keeping this provider visible and will try again when models refresh.`;
  }
  return `${providerLabel} chat models have not appeared yet. If the provider is still warming up, they may appear after the next refresh.`;
}

function settingsModelEligibilityGroups(args: {
  catalog: ModelCatalog | null;
  settings: UserSettings;
  openAiImageModels: ModelCatalogEntry[];
  elevenLabsImageModels: ModelCatalogEntry[];
  modelCatalogStatus: ModelCatalogRefreshStatus;
}): SettingsModelEligibilityGroup[] {
  const groups: SettingsModelEligibilityGroup[] = [];
  const ollama = settingsModelGroupOptions(
    modelOptionsForProvider(args.catalog, args.settings, "local")
  );
  if (ollama.length > 0) {
    groups.push({
      id: "ollama",
      label: "Ollama",
      meta: settingsOllamaGroupMeta(ollama),
      models: ollama,
    });
  }

  if (apiKeySourceAvailable(args.settings.openAiApiKeySource)) {
    const openAiChat = settingsModelGroupOptions(
      modelOptionsForProvider(args.catalog, args.settings, "openai")
    );
    const openAi = settingsModelGroupOptions([...openAiChat, ...args.openAiImageModels]);
    if (openAi.length > 0) {
      const chatPending = openAiChat.length === 0;
      groups.push({
        id: "openai",
        label: "OpenAI",
        meta: `${apiKeySourceModelGroupMeta(args.settings.openAiApiKeySource)} - ${
          chatPending ? "Image models visible, chat pending" : "Chat and image"
        }`,
        models: openAi,
        notice: chatPending
          ? settingsModelDiscoveryNotice("OpenAI", args.modelCatalogStatus)
          : undefined,
        pending: chatPending,
      });
    }
  }

  if (apiKeySourceAvailable(args.settings.anthropicApiKeySource)) {
    const anthropic = settingsModelGroupOptions(
      modelOptionsForProvider(args.catalog, args.settings, "anthropic")
    );
    if (anthropic.length > 0) {
      groups.push({
        id: "anthropic",
        label: "Anthropic",
        meta: `${apiKeySourceModelGroupMeta(args.settings.anthropicApiKeySource)} - Chat`,
        models: anthropic,
      });
    } else {
      groups.push({
        id: "anthropic",
        label: "Anthropic",
        meta: `${apiKeySourceModelGroupMeta(args.settings.anthropicApiKeySource)} - Chat pending`,
        models: [],
        notice: settingsModelDiscoveryNotice("Anthropic", args.modelCatalogStatus),
        pending: true,
      });
    }
  }

  if (apiKeySourceAvailable(args.settings.elevenLabsApiKeySource)) {
    const elevenLabs = settingsModelGroupOptions(args.elevenLabsImageModels);
    if (elevenLabs.length > 0) {
      groups.push({
        id: "elevenlabs",
        label: "ElevenLabs",
        meta: `${apiKeySourceModelGroupMeta(args.settings.elevenLabsApiKeySource)} - Image & Video`,
        models: elevenLabs,
      });
    }
  }

  return groups;
}

function settingsModelToggleMeta(
  groupId: SettingsModelEligibilityGroupId,
  model: ModelCatalogEntry,
  required: boolean
): string {
  if (required) return "Required";
  if (groupId === "ollama") {
    return `Offline${model.hostLabel ? ` - ${model.hostLabel}` : ""}`;
  }
  if (groupId === "anthropic") return "Chat";
  if (groupId === "elevenlabs") return "Image & Video";
  const id = model.id.toLowerCase();
  return id.includes("image") || id.startsWith("dall-e") ? "Image" : "Chat";
}

function inferOnlineProviderForModelId(modelId: string): Provider {
  return modelId.trim().toLowerCase().startsWith("claude-") ? "anthropic" : "openai";
}

function blendToward(value: number, target: number, amount: number): number {
  return value + (target - value) * amount;
}

function botColorFamilyGroup(hue: number): number {
  if (hue < 15 || hue >= 345) return 0; // red
  if (hue < 45) return 1; // orange
  if (hue < 75) return 2; // yellow
  if (hue < 110) return 3; // lime
  if (hue < 155) return 4; // green
  if (hue < 240) return 5; // cyan/blue
  if (hue < 275) return 7; // indigo
  if (hue < 315) return 8; // violet
  return 9; // magenta
}

function botHueSortValue(hue: number): number {
  return hue >= 345 ? hue - 360 : hue;
}

// Smallest angular distance between two hues on the 360° wheel. Both
// inputs are normalized into [0, 360) first so callers don't have to
// pre-clamp slider values that drift slightly outside the range.
function circularHueDistance(a: number, b: number): number {
  const wrap = (value: number): number => {
    const mod = value % 360;
    return mod < 0 ? mod + 360 : mod;
  };
  const diff = Math.abs(wrap(a) - wrap(b));
  return Math.min(diff, 360 - diff);
}

// True when a bot has a usable, non-grayscale color the hue lens can
// match against. Uncolored or near-grayscale bots intentionally fall
// out of the filter so the lens reads as "show me bots in this hue
// band" rather than "show me everything tinted at all".
function botHasFilterableColor(bot: Bot): boolean {
  const raw = bot.color?.trim();
  if (!raw || !hexChannels(raw)) return false;
  const { s } = hexToHsl(raw);
  return s > BOT_COLOR_SORT_GRAYSCALE_SATURATION_MAX;
}

// Hue availability buckets — the lens slider's gradient and the dense
// color-map's snap behavior both need a histogram of which hue families
// the user actually owns. Twelve 30° buckets keep adjacent families
// (red/orange/yellow) visually distinct on the slider while still being
// coarse enough that snapping to a region doesn't feel jittery near a
// boundary.
const HUE_BUCKET_COUNT = 12;
const HUE_BUCKET_WIDTH_DEG = 360 / HUE_BUCKET_COUNT;

interface HueBucket {
  /** Hue (degrees) at the center of this bucket. */
  center: number;
  /** Number of filterable bots whose color falls in this bucket. */
  count: number;
}

interface HueLensTrackSegment {
  prismIndex: number;
  color: string;
}

const EMPTY_HUE_LENS_TRACK_SEGMENTS: readonly HueLensTrackSegment[] = [];
const PRISM_HUE_LENS_TRACK_SEGMENTS: readonly HueLensTrackSegment[] =
  PRISM_WORDMARK_PALETTE.map((color, prismIndex) => ({ prismIndex, color }));

function hueBucketIndex(hue: number): number {
  const wrapped = ((hue % 360) + 360) % 360;
  return Math.min(
    HUE_BUCKET_COUNT - 1,
    Math.floor(wrapped / HUE_BUCKET_WIDTH_DEG)
  );
}

function hueBucketCenter(index: number): number {
  return index * HUE_BUCKET_WIDTH_DEG + HUE_BUCKET_WIDTH_DEG / 2;
}

// Tally bot hues into a fixed-width bucket histogram, ignoring
// uncolored/grayscale bots so the lens reflects only the population it
// can actually filter against.
function computeHueBuckets(bots: readonly Bot[]): HueBucket[] {
  const counts = new Array<number>(HUE_BUCKET_COUNT).fill(0);
  for (const bot of bots) {
    if (!botHasFilterableColor(bot)) continue;
    const { h } = hexToHsl(bot.color!.trim());
    counts[hueBucketIndex(h)] += 1;
  }
  return counts.map((count, i) => ({ center: hueBucketCenter(i), count }));
}

function hueLensSegmentIndexForHue(hue: number): number {
  const prismHues = PRISM_WORDMARK_PALETTE.map((color) => hexToHsl(color).h);
  let segmentIndex = 0;
  let bestDistance = Infinity;
  for (let i = 0; i < prismHues.length; i += 1) {
    const distance = circularHueDistance(prismHues[i], hue);
    if (distance < bestDistance) {
      bestDistance = distance;
      segmentIndex = i;
    }
  }
  return segmentIndex;
}

function hueLensPositionForHue(hue: number): number {
  const prismHues = PRISM_WORDMARK_PALETTE.map((color) => hexToHsl(color).h);
  const segmentIndex = hueLensSegmentIndexForHue(hue);
  const segmentWidth = 360 / prismHues.length;
  const center = segmentIndex * segmentWidth + segmentWidth / 2;
  const signedHueOffset =
    (((hue - prismHues[segmentIndex] + 540) % 360) - 180) /
    (PRISM_BOT_SEED_HUE_SPREAD_DEG / 2);
  const maxOffset = segmentWidth / 2 - 1;
  const offset = Math.max(-maxOffset, Math.min(maxOffset, signedHueOffset * maxOffset));
  return Math.max(0, Math.min(359, center + offset));
}

function computeHueLensTrackSegments(bots: readonly Bot[]): HueLensTrackSegment[] {
  const populatedSegments = new Array<boolean>(PRISM_WORDMARK_PALETTE.length).fill(false);
  for (const bot of bots) {
    if (!botHasFilterableColor(bot)) continue;
    const { h } = hexToHsl(bot.color!.trim());
    populatedSegments[hueLensSegmentIndexForHue(h)] = true;
  }
  return populatedSegments.flatMap((populated, prismIndex) =>
    populated
      ? [{ prismIndex, color: PRISM_WORDMARK_PALETTE[prismIndex] }]
      : []
  );
}

// Build the lens track from the bot colors that actually exist. Populated
// families expand to fill the whole rail, so a one-green-bot library paints
// one full-width green bar instead of a green island with empty gaps.
function hueLensGradient(
  segments: readonly HueLensTrackSegment[],
  theme: "light" | "dark"
): string {
  if (segments.length === 0) {
    return "linear-gradient(to right, transparent 0%, transparent 100%)";
  }
  const stops: string[] = [];
  for (let i = 0; i < segments.length; i += 1) {
    const color = normalizeAccentForTheme(segments[i].color, theme);
    const start = (i / segments.length) * 100;
    const end = ((i + 1) / segments.length) * 100;
    stops.push(`${color} ${start.toFixed(2)}%`);
    stops.push(`${color} ${end.toFixed(2)}%`);
  }
  return `linear-gradient(to right, ${stops.join(", ")})`;
}

function hueLensFilterCenterForSliderValue(
  sliderValue: number,
  segments: readonly HueLensTrackSegment[]
): number {
  if (segments.length === 0) return sliderValue;
  const clamped = Math.max(0, Math.min(359, sliderValue));
  const compactSegmentWidth = 360 / segments.length;
  const compactIndex = Math.min(
    segments.length - 1,
    Math.floor(clamped / compactSegmentWidth)
  );
  const compactStart = compactIndex * compactSegmentWidth;
  const progress = (clamped - compactStart) / compactSegmentWidth;
  const prismSegmentWidth = 360 / PRISM_WORDMARK_PALETTE.length;
  const prismStart = segments[compactIndex].prismIndex * prismSegmentWidth;
  return Math.max(0, Math.min(359, prismStart + progress * prismSegmentWidth));
}

function hueLensSliderValueForFilterCenter(
  hueCenter: number,
  segments: readonly HueLensTrackSegment[]
): number {
  if (segments.length === 0) return hueCenter;
  const prismSegmentWidth = 360 / PRISM_WORDMARK_PALETTE.length;
  const compactSegmentWidth = 360 / segments.length;
  const prismIndex = Math.min(
    PRISM_WORDMARK_PALETTE.length - 1,
    Math.floor(Math.max(0, Math.min(359, hueCenter)) / prismSegmentWidth)
  );
  let compactIndex = segments.findIndex((segment) => segment.prismIndex === prismIndex);
  if (compactIndex < 0) {
    compactIndex = 0;
    let bestDistance = Infinity;
    for (let i = 0; i < segments.length; i += 1) {
      const center = segments[i].prismIndex * prismSegmentWidth + prismSegmentWidth / 2;
      const distance = Math.abs(center - hueCenter);
      if (distance < bestDistance) {
        bestDistance = distance;
        compactIndex = i;
      }
    }
    return compactIndex * compactSegmentWidth + compactSegmentWidth / 2;
  }
  const prismStart = prismIndex * prismSegmentWidth;
  const progress = (hueCenter - prismStart) / prismSegmentWidth;
  return Math.max(
    0,
    Math.min(359, compactIndex * compactSegmentWidth + progress * compactSegmentWidth)
  );
}

function compareBotsByHueRibbonPosition(a: Bot, b: Bot): number {
  const aColor = a.color?.trim();
  const bColor = b.color?.trim();
  const aPosition = aColor ? hueLensPositionForHue(hexToHsl(aColor).h) : 0;
  const bPosition = bColor ? hueLensPositionForHue(hexToHsl(bColor).h) : 0;
  return (
    aPosition - bPosition ||
    a.name.localeCompare(b.name) ||
    a.id.localeCompare(b.id)
  );
}

function hueRibbonWindowSize(
  totalBots: number,
  viewportWidth: number,
  viewportHeight: number,
  preferredRows?: number,
  preferredCols?: number
): number {
  if (totalBots <= 0) return 0;
  if (preferredRows && preferredCols) {
    return Math.min(totalBots, preferredRows * preferredCols);
  }
  const { flatTileCountMin } = pickerDensityBreakpoints(
    viewportWidth,
    viewportHeight
  );
  const showAllMax = Math.max(
    HUE_RIBBON_MIN_VISIBLE_BOTS,
    flatTileCountMin - 1
  );
  const targetCount =
    totalBots <= showAllMax
      ? totalBots
      : Math.min(
          totalBots,
          Math.max(HUE_RIBBON_MIN_VISIBLE_BOTS, flatTileCountMin)
        );

  for (let offset = 0; offset < totalBots; offset += 1) {
    const larger = targetCount + offset;
    if (
      larger <= totalBots &&
      hueRibbonWindowFillsGrid(larger, viewportWidth, viewportHeight, preferredRows)
    ) {
      return larger;
    }

    const smaller = targetCount - offset;
    if (
      smaller >= HUE_RIBBON_MIN_VISIBLE_BOTS &&
      hueRibbonWindowFillsGrid(smaller, viewportWidth, viewportHeight, preferredRows)
    ) {
      return smaller;
    }
  }

  return targetCount;
}

function hueRibbonWindowFillsGrid(
  count: number,
  viewportWidth: number,
  viewportHeight: number,
  preferredRows?: number
): boolean {
  const geom = pickerGeometry(count, viewportWidth, viewportHeight, {
    balanceOddRows: false,
    preferredRows,
  });
  return geom.fillerCells === 0;
}

function hueRibbonWindowBots(
  bots: Bot[],
  hueCenter: number | null,
  trackSegments: readonly HueLensTrackSegment[],
  viewportWidth: number,
  viewportHeight: number,
  preferredRows?: number,
  preferredCols?: number
): Bot[] {
  if (hueCenter === null) return bots;

  const ribbon = bots
    .filter(botHasFilterableColor)
    .sort(compareBotsByHueRibbonPosition);
  const windowSize = hueRibbonWindowSize(
    ribbon.length,
    viewportWidth,
    viewportHeight,
    preferredRows,
    preferredCols
  );
  if (windowSize <= 0) return [];
  if (windowSize >= ribbon.length) return ribbon;

  const sliderValue = hueLensSliderValueForFilterCenter(
    hueCenter,
    trackSegments
  );
  const sliderProgress = Math.max(
    0,
    Math.min(1, sliderValue / HUE_LENS_SLIDER_RANGE)
  );
  const centerIndex = Math.floor(sliderProgress * ribbon.length) % ribbon.length;
  const startIndex =
    centerIndex - Math.floor(windowSize / 2) + ribbon.length;

  return Array.from({ length: windowSize }, (_, offset) => (
    ribbon[(startIndex + offset) % ribbon.length]
  ));
}

// Slider's native [0..359] range maps linearly to a 0..100 percentage that
// approximates the thumb's center as a fraction of the track. The native
// thumb has a small inset relative to the track ends, so this isn't pixel-
// perfect at the extremes — but the orb it drives in `.messagesFrame::after`
// is a wide, soft radial gradient masked at the rails, so visually 1px of
// thumb-vs-orb offset reads as zero. `null` filter parks the orb at 50%,
// which lines up with the slider's 180-resting position.
const HUE_LENS_SLIDER_RANGE = 359;
function hueLensSliderPercent(
  hueCenter: number | null,
  segments: readonly HueLensTrackSegment[]
): number {
  if (hueCenter === null) return 50;
  const sliderValue = hueLensSliderValueForFilterCenter(hueCenter, segments);
  return Math.max(0, Math.min(100, (sliderValue / HUE_LENS_SLIDER_RANGE) * 100));
}

// Match the page accent to the compacted PRISM track segment currently
// under the slider thumb. This keeps the hero triangle and ambient glow
// visually anchored to the user's actual thumb position instead of drifting
// around a separate full-spectrum hue wheel.
function hueLensSliderTintHex(
  hueCenter: number | null,
  segments: readonly HueLensTrackSegment[]
): string | null {
  if (hueCenter === null) return null;
  const sliderValue = hueLensSliderValueForFilterCenter(hueCenter, segments);
  if (segments.length === 0) return null;
  const compactSegmentWidth = 360 / segments.length;
  const compactIndex = Math.min(
    segments.length - 1,
    Math.floor(Math.max(0, Math.min(359, sliderValue)) / compactSegmentWidth)
  );
  return segments[compactIndex]?.color ?? null;
}

function panelBotDisplayAccent(
  rawHex: string,
  theme: "light" | "dark",
  harmonyActive: boolean
): string {
  const normalized = normalizeAccentForTheme(rawHex, theme);
  if (!harmonyActive) return normalized;

  const { h, s, l } = hexToHsl(normalized);
  const targetLightness = theme === "dark"
    ? BOT_PANEL_COLOR_HARMONY_LIGHTNESS_TARGET_DARK
    : BOT_PANEL_COLOR_HARMONY_LIGHTNESS_TARGET_LIGHT;
  return normalizeAccentForTheme(
    hslToHex(
      h,
      blendToward(s, BOT_PANEL_COLOR_HARMONY_SATURATION_TARGET, BOT_PANEL_COLOR_HARMONY_STRENGTH),
      blendToward(l, targetLightness, BOT_PANEL_COLOR_HARMONY_STRENGTH)
    ),
    theme
  );
}

function botColorSortKey(
  bot: Bot,
  theme: "light" | "dark",
  harmonyActive: boolean
): {
  hueGroup: number;
  hue: number;
  luminance: number;
  saturation: number;
  name: string;
} {
  const rawColor = bot.color?.trim();
  if (!rawColor || !hexChannels(rawColor)) {
    return {
      hueGroup: BOT_COLOR_SORT_COLORLESS_GROUP,
      hue: 0,
      luminance: 0,
      saturation: 0,
      name: bot.name,
    };
  }

  const displayColor = panelBotDisplayAccent(rawColor, theme, harmonyActive);
  const { h, s } = hexToHsl(displayColor);
  const isGrayscale = s <= BOT_COLOR_SORT_GRAYSCALE_SATURATION_MAX;
  return {
    hueGroup: isGrayscale
      ? BOT_COLOR_SORT_GRAYSCALE_GROUP
      : botColorFamilyGroup(h),
    hue: botHueSortValue(h),
    luminance: relativeLuminance(displayColor),
    saturation: s,
    name: bot.name,
  };
}

function compareBotsByColor(
  a: Bot,
  b: Bot,
  theme: "light" | "dark",
  harmonyActive: boolean
): number {
  const aKey = botColorSortKey(a, theme, harmonyActive);
  const bKey = botColorSortKey(b, theme, harmonyActive);
  if (aKey.hueGroup !== bKey.hueGroup) return aKey.hueGroup - bKey.hueGroup;
  if (aKey.luminance !== bKey.luminance) return bKey.luminance - aKey.luminance;
  if (aKey.hue !== bKey.hue) return aKey.hue - bKey.hue;
  if (aKey.saturation !== bKey.saturation) return bKey.saturation - aKey.saturation;
  return aKey.name.localeCompare(bKey.name, undefined, { sensitivity: "base" });
}

// At high bot counts the right drawer stops being a list and becomes a
// Prism-colored dashboard. The five wordmark letters give us five
// semantic buckets for the user's bots: P/R/I/S/M. randomHex() now
// always seeds saturated colors inside the accent band, so every
// newly generated bot lands in one of these five buckets — there is
// no separate neutral group.
type PrismGroupId = "p" | "r" | "i" | "s" | "m";
type BotLibraryFilterId = "all" | PrismGroupId;
type BotPanelView =
  | "home"
  | "create"
  | "library"
  | "marketplace"
  | "botHub"
  | "customize"
  | "defaultCustomize"
  | "settings";

function botMarketplaceThemeStateLabel(
  state: BotMarketplaceThemeInstallState,
  installedCount: number,
  totalCount: number
): string {
  if (state === "installed") return "Installed";
  if (state === "partial") return `${installedCount}/${totalCount} installed`;
  return `${totalCount} bots`;
}

function botMarketplaceThemeActionLabel(
  state: BotMarketplaceThemeInstallState,
  installing: boolean
): string {
  if (installing) return "Installing";
  if (state === "installed") return "Installed";
  if (state === "partial") return "Install missing";
  return "Install pack";
}

function marketplaceLensPreviewLine(lens: MarketplaceLensEntry): string {
  if (lens.lensKind === "sacred_wisdom") {
    return "Creates fictional bots inspired by this tradition. Does not impersonate sacred figures or religious authorities.";
  }
  if (lens.lensKind === "civic_perspective" || lens.lensKind === "research_persona") {
    return "Creates fictional perspectives for brainstorming and audience modeling. Not real polling data.";
  }
  return lens.description;
}

async function fetchBotMarketplaceManifest(): Promise<BotMarketplaceManifest> {
  const response = await fetch(BOT_MARKETPLACE_MANIFEST_PATH, {
    cache: "no-store",
  });
  if (!response.ok) {
    throw new Error(`Marketplace catalog unavailable (${response.status}).`);
  }
  return normalizeBotMarketplaceManifest(await response.json());
}

const BOT_LIBRARY_FILTER_ALL = "all" as const;
const BOT_LIBRARY_GROUP_FILTER_ALL = "all" as const;
const BOT_LIBRARY_GROUP_FILTER_UNGROUPED = "ungrouped" as const;
const BOT_LIBRARY_GROUP_CREATE_NEW = "create-new" as const;
