function MessageMoodFace(props: {
  moodKey: NonNullable<Message["moodKey"]>;
  variant?: "classic" | "prism";
  placement?: "leading" | "trailing";
  color?: string | null;
  voicePreset?: BotVoicePreset;
  faceStyle?: BotFaceStyle | null;
  isTalking?: boolean;
  mouthOpen?: boolean;
  mouthShape?: ZenLiveBotMouthShape | null;
  questionMarkActive?: boolean;
}): React.JSX.Element {
  const variant = props.variant ?? "classic";
  const placement = props.placement ?? "trailing";
  const moodKey = props.moodKey;
  const seatEmojiTier = coffeeSeatEmojiMoodFromPrism(moodKey);
  const seatMouthShape =
    props.mouthShape ?? (props.mouthOpen === true ? "open-wide" : "closed");
  const seatPlateGlyph = coffeeSeatPlateGlyph(seatEmojiTier, seatMouthShape);
  const questionMarkActive = props.questionMarkActive === true;
  const color = props.color?.trim();
  const style = color
    ? ({ ["--coffee-bot-color" as string]: color } as React.CSSProperties)
    : undefined;
  const showRasterFrame = variant === "prism";
  return (
    <span
      className={styles.messageMoodBadge}
      data-mood={moodKey}
      data-placement={placement}
      data-face="coffee"
      data-variant={variant}
      style={style}
      aria-hidden="true"
    >
      <CoffeeSeatPlateEmoji
        enabled={variant === "prism"}
        isTalking={props.isTalking === true}
        scheduleKey={`message-mood-${variant}-${moodKey}`}
        showQuestionMark={questionMarkActive}
        baseText={seatPlateGlyph.text}
        rotateDeg={seatPlateGlyph.rotateDeg}
        voicePreset={props.voicePreset ?? "neutral"}
        faceEyesFont={props.faceStyle?.eyesFont}
        faceEyeCharacter={props.faceStyle?.eyeCharacter}
        faceMouthFont={props.faceStyle?.mouthFont}
        faceFontWeight={props.faceStyle?.weight}
        faceEyeScale={props.faceStyle?.eyeScale}
        faceEyeOffsetY={props.faceStyle?.eyeOffsetY}
        className={styles.messageMoodCoffeeFace}
      />
      {showRasterFrame ? <BotFaceFrame /> : null}
    </span>
  );
}

// PRISM fallback for non-private Default/no-bot surfaces that still need a
// single accent token. Private/incognito remains the only monochrome path.
const PRISM_DEFAULT_ACCENT = PRISM_COLORS.s;

function neutralRowColor(resolvedTheme: "light" | "dark"): string {
  return resolvedTheme === "dark" ? "#ffffff" : "#000000";
}

// Resolve a sidebar conversation row's custom-bot tint color from the server-side
// denormalized `lastBotColor`. Default/no-bot chats are handled separately so
// they can keep the same row-gradient structure with a neutral black/white tint.
//
// Order matters:
//   1. Incognito wins — private rows never pick up a hue (grayscale
//      styling comes from the private-row CSS, not from this resolver).
//   2. `lastBotColor` is the server's denormalized color at the time it
//      responded, so it stays correct even if the bot was later deleted
//      or recolored.
//   3. `hasAssistantReply && !lastBotColor` means the last reply came
//      from the Default bot (no bot_id) — no custom hue.
//   4. `botId` → live bots[] lookup. Catches the pre-reply window where
//      a conversation has a locked bot but no assistant message yet.
//   5. No locked bot and no reply either — no custom hue.
function resolveRowColor(
  c: ConversationSummary,
  bots: Bot[]
): string | null {
  if (c.incognito) return null;
  if (c.lastBotColor) return c.lastBotColor;
  if (c.hasAssistantReply) return null;
  if (c.botId) {
    const live = bots.find((b) => b.id === c.botId)?.color;
    if (live) return live;
  }
  return null;
}

type ConversationGroupKeyInput = Pick<
  ConversationSummary,
  "id" | "mode" | "botId" | "lastBotId" | "hasAssistantReply" | "hubRole" | "hubBotId" | "parentHubId"
>;

const PRISM_CONVERSATION_GROUP_KEY = "default";
const BOT_CONVERSATION_GROUP_PREFIX = "bot:";
const LEGACY_BOT_CONVERSATION_GROUP_PREFIX = "legacy-bot:";

function conversationGroupKey(c: ConversationGroupKeyInput): string {
  const effectiveBotId = conversationEffectiveBotId(c);
  return effectiveBotId
    ? `${BOT_CONVERSATION_GROUP_PREFIX}${effectiveBotId}`
    : PRISM_CONVERSATION_GROUP_KEY;
}

function conversationEffectiveBotId(c: ConversationGroupKeyInput): string | null {
  if (c.hubRole === "side") {
    return c.hubBotId ?? null;
  }
  if (c.hubBotId) return c.hubBotId;
  if (c.mode === "zen" && c.hasAssistantReply) return c.lastBotId ?? null;
  if (c.mode === "chat" && c.botId) return c.botId;
  return null;
}

/** Mirror of `conversationGroupKey` for cases where only the bot id is in
 *  hand — e.g. picking a panel to auto-open after a new chat is committed. */
function conversationGroupKeyForBotId(botId: string): string {
  return `${BOT_CONVERSATION_GROUP_PREFIX}${botId}`;
}

function conversationGroupBotId(key: string): string | null {
  if (key.startsWith(BOT_CONVERSATION_GROUP_PREFIX)) {
    return key.slice(BOT_CONVERSATION_GROUP_PREFIX.length);
  }
  if (key.startsWith(LEGACY_BOT_CONVERSATION_GROUP_PREFIX)) {
    return key.slice(LEGACY_BOT_CONVERSATION_GROUP_PREFIX.length);
  }
  return null;
}

function conversationGroupDeleteKey(key: string): string {
  return `group:${key}`;
}

/** Namespaces a single chat row delete in `pendingDeleteKey` (sidebar ×). */
function conversationRowDeleteKey(conversationId: string): string {
  return `chatdel:${conversationId}`;
}

/** HTML `id` slug — `group.key` may contain `:` (e.g. `bot:uuid`). */
function conversationGroupDomSafeSlug(key: string): string {
  return key.replace(/[^a-zA-Z0-9_-]/g, "_");
}

function conversationGroupNestedListId(key: string): string {
  return `conversation-group-chats-${conversationGroupDomSafeSlug(key)}`;
}

function conversationGroupHeaderButtonId(key: string): string {
  return `conversation-group-toggle-${conversationGroupDomSafeSlug(key)}`;
}

function conversationGroupOrderStorageKey(userId: string): string {
  return `${CONVERSATION_GROUP_ORDER_STORAGE_KEY}:${userId}`;
}

function botLibraryGroupsStorageKey(userId: string): string {
  return `${BOT_LIBRARY_GROUPS_STORAGE_KEY}:${userId}`;
}

function botMarketplaceLensesStorageKey(userId: string): string {
  return `${BOT_MARKETPLACE_LENSES_STORAGE_KEY}:${userId}`;
}

function commandCenterStateStorageKey(userId: string): string {
  return `${COMMAND_CENTER_STATE_STORAGE_KEY}:${userId}`;
}

function loadConversationGroupOrder(userId: string): string[] {
  if (typeof window === "undefined") return [];
  try {
    const raw = window.localStorage.getItem(conversationGroupOrderStorageKey(userId));
    const parsed: unknown = raw ? JSON.parse(raw) : [];
    return Array.isArray(parsed)
      ? parsed.filter((key): key is string => typeof key === "string")
      : [];
  } catch {
    return [];
  }
}

function loadInstalledMarketplaceLensIds(userId: string): Set<string> {
  if (typeof window === "undefined") return new Set();
  try {
    const raw = window.localStorage.getItem(botMarketplaceLensesStorageKey(userId));
    const parsed: unknown = raw ? JSON.parse(raw) : [];
    if (!Array.isArray(parsed)) return new Set();
    return new Set(
      parsed
        .map((id) => (typeof id === "string" ? id.trim().toLowerCase() : ""))
        .filter((id) => id.length > 0)
    );
  } catch {
    return new Set();
  }
}

function saveInstalledMarketplaceLensIds(userId: string, lensIds: ReadonlySet<string>): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      botMarketplaceLensesStorageKey(userId),
      JSON.stringify(Array.from(lensIds).sort())
    );
  } catch {
    // Non-fatal: keep the in-memory install state for this page session.
  }
}

function persistConversationGroupOrder(userId: string, order: string[]): void {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(
      conversationGroupOrderStorageKey(userId),
      JSON.stringify(order)
    );
  } catch {
    // Non-fatal: drag ordering still works for the current page session.
  }
}

function reorderConversationGroupKeys(
  currentOrder: string[],
  draggedKey: string,
  targetKey: string,
  position: ConversationGroupDropPosition
): string[] {
  if (draggedKey === targetKey) return currentOrder;
  const withoutDragged = currentOrder.filter((key) => key !== draggedKey);
  const targetIndex = withoutDragged.indexOf(targetKey);
  if (targetIndex === -1) return currentOrder;
  const insertIndex = position === "after" ? targetIndex + 1 : targetIndex;
  return [
    ...withoutDragged.slice(0, insertIndex),
    draggedKey,
    ...withoutDragged.slice(insertIndex),
  ];
}

function buildConversationGroupSummary(
  key: string,
  conversations: ConversationSummary[],
  bots: Bot[],
  unreadConversationIds: Set<string>
): ConversationGroupSummary {
  const sortedConversations = conversations.slice().sort((a, b) => {
    return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
  });
  const primaryConversation = sortedConversations[0];
  const botId = conversationGroupBotId(key);
  const bot = botId ? bots.find((candidate) => candidate.id === botId) : null;
  const fallbackColor =
    sortedConversations.find((conversation) => conversation.lastBotColor)?.lastBotColor ?? null;
  const latestUpdatedAt =
    conversations
      .map((conversation) => conversation.updatedAt)
      .sort((a, b) => new Date(b).getTime() - new Date(a).getTime())[0] ?? "";
  return {
    key,
    sessionRootId: primaryConversation?.id ?? key,
    botId,
    name: botId ? bot?.name?.trim() || "Deleted bot" : DEFAULT_ASSISTANT_NAME,
    glyph: bot
      ? isBotGlyphName(bot.glyph)
        ? bot.glyph
        : DEFAULT_BOT_GLYPH
      : "triangle",
    color: botId ? bot?.color ?? fallbackColor : null,
    count: sortedConversations.length,
    conversations: sortedConversations,
    latestUpdatedAt,
    unread: sortedConversations.some((conversation) => unreadConversationIds.has(conversation.id)),
  };
}

function buildConversationGroups(
  conversations: ConversationSummary[],
  bots: Bot[],
  unreadConversationIds: Set<string>
): ConversationGroupSummary[] {
  const grouped = new Map<string, ConversationSummary[]>();
  for (const conversation of conversations) {
    const key = conversationGroupKey(conversation);
    const existing = grouped.get(key);
    if (existing) {
      if (!existing.some((c) => c.id === conversation.id)) {
        existing.push(conversation);
      }
    } else {
      grouped.set(key, [conversation]);
    }
  }
  return [...grouped.entries()]
    .filter(([, rows]) => rows.length > 0)
    .map(([key, rows]) =>
      buildConversationGroupSummary(key, rows, bots, unreadConversationIds)
    );
}

function ThemeGlyph({ mode }: { mode: Theme }): React.ReactElement {
  // Stroke-only 16x16 glyphs that take their color from currentColor, so the
  // same button can shift between muted/hover/locked hues purely via CSS.
  // Matches the lock glyph's visual weight (14px glyph inside a 30px button).
  return (
    <svg
      className={styles.themeToggleGlyph}
      viewBox="0 0 16 16"
      aria-hidden="true"
    >
      {mode === "light" && (
        <>
          {/* Sun: central disc + 8 radial rays. */}
          <circle cx="8" cy="8" r="3" suppressHydrationWarning />
          <path
            d="M8 1v2M8 13v2M1 8h2M13 8h2M3 3l1.5 1.5M11.5 11.5l1.5 1.5M3 13l1.5-1.5M11.5 4.5l1.5-1.5"
            suppressHydrationWarning
          />
        </>
      )}
      {mode === "dark" && (
        /* Crescent moon: one arc carved out of a larger one. */
        <path
          d="M13 9A5.5 5.5 0 1 1 7 3a4.5 4.5 0 0 0 6 6Z"
          suppressHydrationWarning
        />
      )}
      {mode === "system" && (
        <>
          {/* Half-filled circle: outline the full disc, then fill the right
             hemisphere so it reads as "sun on one side, moon on the other". */}
          <circle cx="8" cy="8" r="5.5" suppressHydrationWarning />
          <path
            d="M8 2.5A5.5 5.5 0 0 1 8 13.5Z"
            fill="currentColor"
            stroke="none"
            suppressHydrationWarning
          />
        </>
      )}
    </svg>
  );
}

