  const moveConversationGroup = useCallback((
    draggedKey: string,
    targetKey: string,
    position: ConversationGroupDropPosition
  ) => {
    if (!user || draggedKey === targetKey) return;
    setConversationGroupOrder((previous) => {
      const knownKeys = new Set(availableConversationGroupKeys);
      const normalizedOrder = [
        ...previous.filter((key) => knownKeys.has(key)),
        ...availableConversationGroupKeys.filter((key) => !previous.includes(key)),
      ];
      const next = reorderConversationGroupKeys(
        normalizedOrder,
        draggedKey,
        targetKey,
        position
      );
      if (
        next.length === previous.length &&
        next.every((key, index) => key === previous[index])
      ) {
        return previous;
      }
      persistConversationGroupOrder(user.id, next);
      return next;
    });
  }, [availableConversationGroupKeys, user]);

  const conversationRowGlowStyle = useCallback((index: number): React.CSSProperties => {
    const estimatedRowStridePx = 42;
    const rowHeightPx = 36;
    const glowFalloffPx = 1200;
    const rowTopInViewport = Math.max(0, index * estimatedRowStridePx - conversationListScrollTop);
    // Linear intensity (no easing) so adjacent rows differ by a constant
    // delta and the gradient feels continuous across tiles. The raw
    // viewport-derived value is remapped from [0, 1] to [0, 0.45] so
    // the bottom of the list resolves to fully transparent fill and
    // the top peaks at a calm 45% color band.
    const baseIntensity = Math.max(0, Math.min(1, 1 - rowTopInViewport / glowFalloffPx));
    const privateDepthCurve = Math.pow(baseIntensity, 2.45);
    const privateGlareFactor = Math.max(0, (baseIntensity - 0.28) / 0.72);
    const privateGlareCurve = Math.pow(privateGlareFactor, 2.2);
    // Light mode should keep the top rows calmer (less dark/tinted) so
    // the first visible groups don't overpower the sidebar. Dark mode
    // keeps the original stronger depth envelope.
    const intensity = baseIntensity * (resolvedTheme === "light" ? 0.32 : 0.45);
    const baseFill = intensity * 60;
    const innerGlow = intensity * 90;
    const outerGlow = intensity * 40;
    const fillGlow = intensity * 22;
    // Bottom-of-list shade: pulls each row toward black as its row
    // color band fades out, so the very bottom rows feel slightly
    // darker than the sidebar surface instead of disappearing.
    const bottomShade = (1 - baseIntensity) * 14;
    // Anchor the diagonal "bright" and "counter" spots to absolute
    // viewport positions in the conversation list so each row only
    // exposes its own slice of a single continuous gradient.
    const sunYInRow = 4 - rowTopInViewport;
    const sunYPct = (sunYInRow / rowHeightPx) * 100;
    const counterYInRow = 320 - rowTopInViewport;
    const counterYPct = (counterYInRow / rowHeightPx) * 100;
    // Theme-aware text ramp matched to the fill intensity curve:
    // - Light mode: top/new rows are darker fills, so text should start
    //   light and taper darker as fill intensity drops.
    // - Dark mode: keep the existing near-black -> white ramp.
    const textChannel = resolvedTheme === "light"
      ? Math.round(42 + baseIntensity * 206)
      : Math.round(255 - baseIntensity * 244);
    const textChannelHex = textChannel.toString(16).padStart(2, "0");
    const rowText = `#${textChannelHex}${textChannelHex}${textChannelHex}`;
    const privateRowGlare = privateGlareCurve * 48;
    const privateRowTint = 2 + privateDepthCurve * 26;
    const privateRowTintSoft = privateRowTint * 0.45;
    const privateRowGlareHover = privateRowGlare > 0 ? Math.min(100, privateRowGlare + 10) : 0;
    const privateRowTintHover = Math.min(100, privateRowTint + 6);
    const privateRowTintSoftHover = privateRowTint * 0.62;
    const privateRowSurfaceOpacity = 68 + (1 - baseIntensity) * 30;
    const privateRowBgOpacity = 66 + (1 - baseIntensity) * 32;
    return {
      "--row-depth-base": `${baseFill.toFixed(1)}%`,
      "--row-depth-glow": `${innerGlow.toFixed(1)}%`,
      "--row-depth-glow-outer": `${outerGlow.toFixed(1)}%`,
      "--row-depth-fill": `${fillGlow.toFixed(1)}%`,
      "--row-depth-shade": `${bottomShade.toFixed(1)}%`,
      "--row-glow-y": `${sunYPct.toFixed(1)}%`,
      "--row-counter-y": `${counterYPct.toFixed(1)}%`,
      "--row-text-color": rowText,
      "--private-row-glare": `${privateRowGlare.toFixed(1)}%`,
      "--private-row-tint": `${privateRowTint.toFixed(1)}%`,
      "--private-row-tint-soft": `${privateRowTintSoft.toFixed(1)}%`,
      "--private-row-glare-hover": `${privateRowGlareHover.toFixed(1)}%`,
      "--private-row-tint-hover": `${privateRowTintHover.toFixed(1)}%`,
      "--private-row-tint-soft-hover": `${privateRowTintSoftHover.toFixed(1)}%`,
      "--private-row-surface-opacity": `${privateRowSurfaceOpacity.toFixed(1)}%`,
      "--private-row-bg-opacity": `${privateRowBgOpacity.toFixed(1)}%`,
    } as React.CSSProperties;
  }, [conversationListScrollTop, resolvedTheme]);

