  function restoreFactoryDefaults() {
    setPanelError(null);
    setPanelNotice(null);
    setDeleteAccountArmed(false);
    if (!factoryResetArmed) {
      setFactoryResetArmed(true);
      return;
    }
    void restoreFactoryDefaultsConfirmed();
  }

  async function restoreFactoryDefaultsConfirmed() {
    if (!user?.id) {
      setPanelError("Sign in before restoring factory defaults.");
      return;
    }
    setBusy(true);
    setPanelError(null);
    try {
      await api("/api/account/factory-reset", { method: "POST", body: "{}" });
      setFactoryResetArmed(false);
      resetBrowserFactoryDefaultsForUser(user.id);
      navigateToView("chat");
      const starterPackResult = await installPrismStarterPackFromMarketplace();
      await bootstrap();
      await refreshAll();
      setPanelNotice(
        `Factory defaults restored with ${starterPackResult.starterBotCount} PRISM starter bots. Tutorials will run again when you enter each mode.`
      );
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Factory reset failed.");
    } finally {
      setBotTransferOverlay(null);
      setBusy(false);
    }
  }

  function deleteAccount() {
    setPanelError(null);
    setFactoryResetArmed(false);
    if (!deleteAccountArmed) {
      setDeleteAccountArmed(true);
      return;
    }
    void deleteAccountConfirmed();
  }

  function openProfileNameModal() {
    setPanelError(null);
    setPanelNotice(null);
    setFactoryResetArmed(false);
    setDeleteAccountArmed(false);
    setProfileNameDraft(settings?.displayName?.trim() || user?.displayName?.trim() || "");
    setProfileNameModalOpen(true);
  }

  async function submitProfileNameChange() {
    const nextDisplayName = profileNameDraft.trim();
    setPanelError(null);
    setPanelNotice(null);
    if (nextDisplayName.length === 0) {
      setPanelError("Profile name cannot be empty.");
      return;
    }
    setBusy(true);
    try {
      const response = await api<{
        ok: true;
        settings?: Partial<UserSettings>;
      }>("/api/settings", {
        method: "PATCH",
        body: JSON.stringify({ displayName: nextDisplayName }),
      });
      const savedDisplayName =
        typeof response.settings?.displayName === "string" &&
        response.settings.displayName.trim().length > 0
          ? response.settings.displayName
          : nextDisplayName.slice(0, 80);
      setSettings((previous) =>
        previous ? { ...previous, displayName: savedDisplayName } : previous
      );
      setUser((previous) =>
        previous ? { ...previous, displayName: savedDisplayName } : previous
      );
      setProfileNameModalOpen(false);
      setProfileNameDraft("");
      setPanelNotice("Profile name updated.");
      await refreshSettings();
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Profile name change failed.");
    } finally {
      setBusy(false);
    }
  }

  async function deleteAccountConfirmed() {
    setBusy(true);
    setPanelError(null);
    try {
      await api("/api/account", { method: "DELETE" });
      setDeleteAccountArmed(false);
      setUser(null);
      setPreAuthChecklistComplete(false);
      setConversations([]);
      setDetail(null);
      setSessionOpinion(null);
      setBotOpinion(null);
      setMemories([]);
      setSettings(null);
      setModelCatalog(null);
      setBots([]);
      setImages([]);
      window.location.href = "/?mode=register";
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Account deletion failed.");
    } finally {
      setBusy(false);
    }
  }

