  async function generateAtmosphereFromSlashCommand(): Promise<void> {
    if (view !== "chat") {
      setError("/atmosphere is only available in Zen.");
      return;
    }
    const conversationId =
      detail?.id && detail.id !== "pending" ? detail.id : selectedId;
    if (!conversationId || conversationId === "pending" || detail?.mode !== "zen") {
      setError("Open a saved Zen conversation before using /atmosphere.");
      return;
    }
    if (detail.messages.length === 0) {
      setError("Send a Zen message before generating Atmosphere.");
      return;
    }
    if (
      zenWallpaperBusyConversationId === conversationId ||
      zenWallpaperGenerationInFlightRef.current.has(conversationId)
    ) {
      setError("Atmosphere is already generating.");
      return;
    }
    const promptOverride = customAtmospherePromptEnabled
      ? customAtmospherePromptDraft.trim()
      : undefined;
    if (customAtmospherePromptEnabled && !promptOverride) {
      setError("Type a custom Atmosphere prompt, or turn off Custom before using /atmosphere.");
      return;
    }

    setError(null);
    setConversationStarterPrompts(null);
    clearComposerDraftNow();
    if (editingMessageId !== null) {
      setEditingMessageId(null);
      setEditingOriginalText("");
    }
    await requestZenWallpaperUpdate(conversationId, {
      enabled: true,
      force: true,
      promptOverride,
    });
  }

  function showLocalCommandToast(title: string, detail: string): void {
    const now = Date.now();
    setLocalCommandToast({
      id: `local-command:${now}`,
      title,
      detail,
      expiresAt: now + LOCAL_COMMAND_TOAST_DISMISS_MS,
    });
  }

  function refreshPrismFromNavbar(): void {
    if (typeof window === "undefined") return;
    window.location.reload();
  }

  function consumeDeprecatedRefreshCommand(trimmedLine: string, source: "chat" | "coffee"): boolean {
    const tokens = normalizeComposerSlashCommandLine(trimmedLine)
      .split(/\s+/)
      .map((token) => token.trim())
      .filter((token) => token.length > 0);
    const normalizedCommand = tokens[0]?.toLowerCase() ?? "";
    if (normalizedCommand !== "/refresh") return false;
    if (tokens.length > 1) {
      const message = "/refresh does not take extra text. Use it by itself.";
      if (source === "coffee") {
        setCoffeeError(message);
      } else {
        setError(message);
      }
      return true;
    }
    if (source === "coffee") {
      setCoffeeError(null);
      setCoffeeDraft("");
      coffeeDraftRef.current = "";
      coffeeComposerRichRef.current?.setValue("");
    } else {
      setError(null);
      setConversationStarterPrompts(null);
      clearComposerDraftNow();
    }
    showLocalCommandToast("Refresh moved", "Use the recycle icon in the navbar.");
    return true;
  }

  function clearReplyWorkForLocalTopicReset(): void {
    const starterRequest = zenInitialStarterRequestRef.current;
    if (starterRequest) {
      starterRequest.cancelled = true;
      starterRequest.replayWhenReady = false;
    }
    queuedPromptDrainGenerationRef.current += 1;
    setQueuedChatPrompts([]);
    setDispatchingQueuedPrompt(null);
    clearZenFollowupCooldownTimer();
    zenFollowupBufferRef.current = null;
    setZenFollowupBuffer(null);
    zenInitialThinkingCancelControllerRef.current = null;
    priorityCommandCancelControllerRef.current = pendingReplyAbortControllerRef.current;
    stopPendingReply();
    freezeActiveAssistantRevealForLocalTopicReset();
    setPendingMessageCleanupMessageIds(new Set<string>());
    setCleanupRevealMessageKeys(new Set<string>());
  }

  async function resetTopicFromNvmSlashCommand(source: "chat" | "coffee"): Promise<void> {
    if (pendingReply || chatAssistantRevealInProgress || zenFollowupBufferRef.current) {
      clearReplyWorkForLocalTopicReset();
    } else {
      clearZenFollowupCooldownTimer();
      zenFollowupBufferRef.current = null;
      setZenFollowupBuffer(null);
    }
    setError(null);
    if (source === "chat") {
      pendingNvmTopicResetRef.current = true;
      setConversationStarterPrompts(null);
      setStarterComposerRevealed(false);
      setAskQuestionComposerRevealed(false);
      clearComposerDraftNow();
      if (editingMessageId !== null) {
        setEditingMessageId(null);
        setEditingOriginalText("");
      }
      showLocalCommandToast("Topic reset", "Next message starts fresh.");
      return;
    }
    if (source === "coffee") {
      setCoffeeError(null);
      setCoffeeDraft("");
      showLocalCommandToast("Topic reset", "Next message starts fresh.");
    }
  }

  function firstComposerCommandToken(trimmedLine: string): string {
    return normalizeComposerSlashCommandLine(trimmedLine).split(/\s+/)[0]?.trim().toLowerCase() ?? "";
  }

  function isBuiltInOperationalSlashCommand(trimmedLine: string): boolean {
    const normalizedCommand = firstComposerCommandToken(trimmedLine);
    return (
      normalizedCommand === "/compact" ||
      normalizedCommand === "/summarize" ||
      normalizedCommand === "/clear" ||
      normalizedCommand === "/cls" ||
      BUILT_IN_ATMOSPHERE_SLASH_COMMANDS.has(normalizedCommand) ||
      normalizedCommand === "/refresh" ||
      normalizedCommand === "/restart" ||
      normalizedCommand === "/new-session" ||
      normalizedCommand === "/forgive-me" ||
      normalizedCommand === "/undo" ||
      normalizedCommand === "/undo-turn" ||
      normalizedCommand === NVM_SLASH_COMMAND ||
      BUILT_IN_HELP_SLASH_COMMANDS.has(normalizedCommand)
    );
  }

  function isPrismDevComposerCommand(trimmedLine: string): boolean {
    return (
      PRISM_WEB_DEV_CHAT_COMMANDS_ENABLED &&
      parsePrismDevChatCommand(trimmedLine) !== null
    );
  }

  function isDevOnlySlashCommand(trimmedLine: string): boolean {
    if (DEV_TOOLS_ENABLED) {
      const normalizedCommand = firstComposerCommandToken(trimmedLine);
      if (normalizedCommand === "/forget" || normalizedCommand === "/forget-all") {
        return true;
      }
    }
    return isPrismDevComposerCommand(trimmedLine);
  }

  function isLocalOnlyComposerCommand(trimmedLine: string): boolean {
    if (parseGlobalClearCommand(trimmedLine).kind !== "none") return true;
    return (
      isBuiltInOperationalSlashCommand(trimmedLine) ||
      isDevOnlySlashCommand(trimmedLine)
    );
  }

  function ignoreLocalOnlyComposerCommandWhileReplying(trimmedLine: string): boolean {
    if (parseUndoSlashCommand(trimmedLine).kind !== "none") return false;
    if (parseNvmSlashCommand(trimmedLine).kind !== "none") return false;
    if (isPrismDevComposerCommand(trimmedLine)) return false;
    const replyBusy =
      (pendingReply && !canSendTextWhileReplyPending()) ||
      chatAssistantRevealInProgress;
    if (!replyBusy) return false;
    if (!isLocalOnlyComposerCommand(trimmedLine)) return false;
    clearComposerDraftNow();
    setError(null);
    return true;
  }

  /** Built-in operational slash commands that run locally instead of becoming model input. */
  async function consumeBuiltInOperationalSlashCommand(trimmedLine: string): Promise<boolean> {
    const tokens = trimmedLine
      .split(/\s+/)
      .map((token) => token.trim())
      .filter((token) => token.length > 0);
    if (tokens.length === 0) return false;
    const normalizedCommand = tokens[0].toLowerCase();
    if (!isBuiltInOperationalSlashCommand(trimmedLine)) {
      return false;
    }
    const nvmCommand = parseNvmSlashCommand(trimmedLine);
    if (BUILT_IN_HELP_SLASH_COMMANDS.has(normalizedCommand)) {
      clearComposerDraftNow();
      setConversationStarterPrompts(null);
      openCommandCenterHelpModal();
      return true;
    }
    const undoCommand = parseUndoSlashCommand(trimmedLine);
    if (undoCommand.kind === "error") {
      setError(undoCommand.error);
      return true;
    }
    if (undoCommand.kind === "ok") {
      await undoLatestMessageFromSlashCommand(undoCommand.count);
      return true;
    }
    if (nvmCommand.kind === "error") {
      setError(nvmCommand.error);
      return true;
    }
    if (nvmCommand.kind === "ok") {
      await resetTopicFromNvmSlashCommand("chat");
      return true;
    }
    if (tokens.length > 1) {
      setError(`${normalizedCommand} does not take extra text. Use it by itself.`);
      return true;
    }
    if (normalizedCommand === "/clear" || normalizedCommand === "/cls") {
      await clearConversationFromSlashCommand();
      return true;
    }
    if (BUILT_IN_ATMOSPHERE_SLASH_COMMANDS.has(normalizedCommand)) {
      await generateAtmosphereFromSlashCommand();
      return true;
    }
    if (normalizedCommand === "/refresh") {
      consumeDeprecatedRefreshCommand(trimmedLine, "chat");
      return true;
    }
    if (normalizedCommand === "/restart") {
      await restartServerFromSlashCommand();
      return true;
    }
    if (normalizedCommand === "/new-session") {
      await startNewZenSessionFromSlashCommand();
      return true;
    }
    if (normalizedCommand === "/forgive-me") {
      await resetPrismMoodFromSlashCommand();
      return true;
    }
    await compactCurrentChatFromSlashCommand(
      normalizedCommand === "/summarize" ? "summarize" : "compact"
    );
    return true;
  }

  /** Local slash dev commands hidden from normal slash discovery. */
  async function consumeDevSlashCommand(trimmedLine: string): Promise<boolean> {
    if (!DEV_TOOLS_ENABLED) return false;
    const tokens = trimmedLine
      .split(/\s+/)
      .map((token) => token.trim())
      .filter((token) => token.length > 0);
    if (tokens.length === 0) return false;
    const normalizedCommand = tokens[0].toLowerCase();
    if (normalizedCommand !== "/forget" && normalizedCommand !== "/forget-all") {
      return false;
    }
    setError(null);
    setConversationStarterPrompts(null);
    clearComposerDraftNow();
    if (tokens.length > 1) {
      setError(`${normalizedCommand} does not take extra text. Use /forget or /forget-all by itself.`);
      return true;
    }
    if (normalizedCommand === "/forget") {
      await forgetCurrentBotMemoryFromSlashCommand();
      if (editingMessageId !== null) {
        setEditingMessageId(null);
        setEditingOriginalText("");
      }
      setForceNewConversationOnNextSend(true);
      startFreshConversation(false);
      setComposerPrimed(false);
      return true;
    }
    if (normalizedCommand === "/forget-all") {
      // `/forget-all` is the hard reset for chat testing, so summary context
      // and every per-user memory artifact are always cleared.
      await clearSummariesFromSlashCommand();
      // Order matters: nuke the conversation first so its messages stop
      // referencing memories/summaries, then drop every per-user memory
      // artifact so the next chat starts with no recall surface at all.
      await clearConversationFromSlashCommand();
      await clearAllSessionMemoryFromSlashCommand();
      // Keep Chat mode from auto-reopening the latest saved thread until the
      // user explicitly starts or opens a conversation again.
      setChatAutoRestoreSuppressed(true);
      // Next real send must open a brand-new chat conversation server-side.
      setForceNewConversationOnNextSend(true);
      if (editingMessageId !== null) {
        setEditingMessageId(null);
        setEditingOriginalText("");
      }
      startFreshConversation(false);
      setComposerPrimed(false);
      return true;
    }
    return false;
  }

  function resolveCommandCenterPromptShortcuts(rawDraft: string): {
    kind: "none";
  } | {
    kind: "error";
    error: string;
  } | {
    kind: "resolved";
    promptShortcut: PromptShortcutMetadata | null;
    prompt: string;
    modelChoice: string;
  } {
    const promptNames = commandCenterPromptPicks.flatMap((command) =>
      commandInvocationNames(command)
    );
    const ranges = resolvePromptShortcutTextRanges(rawDraft, { promptNames });
    if (ranges.length === 0) return { kind: "none" };

    const commandByInvocation = new Map<string, CommandCenterCommand>();
    for (const command of commandCenterPromptPicks) {
      for (const name of commandInvocationNames(command)) {
        commandByInvocation.set(name.toLowerCase(), command);
      }
    }

    let prompt = "";
    let cursor = 0;
    let firstCommand: CommandCenterCommand | null = null;
    let firstInvocation = "";
    const promptRandomizationReplacements: NonNullable<
      PromptShortcutMetadata["wildcardReplacements"]
    > = [];
    const promptRuns: PromptShortcutRunMetadata[] = [];
    for (let index = 0; index < ranges.length; index += 1) {
      const range = ranges[index]!;
      const command = commandByInvocation.get(range.name.toLowerCase());
      if (!command) continue;
      const randomizationResolution = resolvePromptRandomizationGroups(command.command.trim(), {
        decks: commandCenterWildcardDecks,
      });
      const basePromptResolution = resolveBuiltInPromptWildcardInvocations(
        randomizationResolution.prompt,
        randomizationResolution.replacements
      );
      const basePrompt = basePromptResolution.prompt;
      if (!basePrompt) {
        return { kind: "error", error: `/${command.name} has no prompt text configured yet.` };
      }
      prompt += rawDraft.slice(cursor, range.start);
      const casedBasePrompt = formatPromptShortcutInsertion(
        basePrompt,
        prompt,
        rawDraft.slice(range.end)
      );
      const replacementOffset = prompt.length;
      const casedBasePromptReplacements = promptShortcutWildcardReplacementsForPromptText(
        casedBasePrompt,
        basePromptResolution.replacements
      );
      const fullPromptReplacements = casedBasePromptReplacements.map((replacement) => ({
        ...replacement,
        start:
          typeof replacement.start === "number"
            ? replacementOffset + replacement.start
            : replacement.start,
        end:
          typeof replacement.end === "number"
            ? replacementOffset + replacement.end
            : replacement.end,
      }));
      promptRuns.push({
        commandId: command.id,
        name: command.name,
        invocation: rawDraft.slice(range.start, range.end),
        sourceStart: range.start,
        sourceEnd: range.end,
        resolvedPrompt: casedBasePrompt,
        ...(casedBasePromptReplacements.length > 0
          ? { wildcardReplacements: casedBasePromptReplacements }
          : {}),
      });
      if (!firstCommand) {
        firstCommand = command;
        firstInvocation = rawDraft.slice(range.start, range.end);
      }
      promptRandomizationReplacements.push(...fullPromptReplacements);
      prompt += casedBasePrompt;
      cursor = range.end;
    }
    prompt += rawDraft.slice(cursor);

    if (!firstCommand) return { kind: "none" };
    const resolvedPrompt = prompt.trim();
    const trimStartOffset = prompt.length - prompt.trimStart().length;
    const promptReplacements = promptShortcutWildcardReplacementsForPromptText(
      prompt,
      promptRandomizationReplacements
    );
    const wildcardReplacements = promptShortcutWildcardReplacementsForPromptText(
      resolvedPrompt,
      promptReplacements.map((replacement) => ({
        ...replacement,
        start:
          typeof replacement.start === "number"
            ? replacement.start - trimStartOffset
            : replacement.start,
        end:
          typeof replacement.end === "number"
            ? replacement.end - trimStartOffset
            : replacement.end,
      }))
    );
    const promptShortcut: PromptShortcutMetadata = {
      v: 1,
      commandId: firstCommand.id,
      name: firstCommand.name,
      invocation: firstInvocation,
      template: rawDraft,
      flags: [],
      resolvedPrompt,
      ...(wildcardReplacements.length > 0
        ? { wildcardReplacements }
        : {}),
      ...(promptRuns.length > 0 ? { promptRuns } : {}),
    };
    return {
      kind: "resolved",
      promptShortcut,
      prompt,
      modelChoice: commandCenterPreferredModel,
    };
  }

  function draftContainsTrueWildcardSlots(value: string): boolean {
    return promptContainsModelFilledWildcardSlots(value);
  }

  function resolveComposerWildcardDraft(rawDraft: string): {
    prompt: string;
    promptWildcards: PromptWildcardRunMetadata | null;
  } {
    const deckResolution = resolvePromptRandomizationGroups(rawDraft, {
      decks: commandCenterWildcardDecks,
    });
    const resolution = resolveBuiltInPromptWildcardInvocations(
      deckResolution.prompt,
      deckResolution.replacements
    );
    const hasWildcardRun =
      resolution.replacements.length > 0 ||
      draftContainsTrueWildcardSlots(rawDraft) ||
      deckResolution.prompt !== resolution.prompt ||
      draftContainsTrueWildcardSlots(resolution.prompt);
    return {
      prompt: resolution.prompt,
      promptWildcards: hasWildcardRun
        ? {
            v: 1,
            template: rawDraft,
            resolvedPrompt: resolution.prompt.trim(),
            ...(resolution.replacements.length > 0
              ? { wildcardReplacements: resolution.replacements }
              : {}),
          }
        : null,
    };
  }

  function clearPendingImageJobPoll(jobId: string) {
    const handle = pendingImageJobPollTimersRef.current.get(jobId);
    if (handle !== undefined) {
      window.clearInterval(handle);
      pendingImageJobPollTimersRef.current.delete(jobId);
    }
  }

  function startPendingImageJobPoll(
    jobId: string,
    conversationId: string,
    options?: { markPrivateGenerated?: boolean }
  ) {
    clearPendingImageJobPoll(jobId);
    const tick = async () => {
      try {
        const poll = await api<{
          ok: true;
          status: "running" | "succeeded" | "failed";
          messages?: Message[];
          error?: string;
        }>(`/api/image-jobs/${encodeURIComponent(jobId)}`);
        if (poll.status === "running") return;
        clearPendingImageJobPoll(jobId);
        setComposerImageJobOrb((current) => (current?.jobId === jobId ? null : current));
        if (poll.status === "failed") {
          setError(poll.error ?? "Image generation did not finish.");
          appendDevChatDebugLines([
            {
              kind: "tool",
              text:
                `[poll] tool sendGeneratedImage: failed — jobId=${jobId}` +
                (poll.error ? ` — ${poll.error}` : ""),
            },
          ]);
          return;
        }
        const incoming = poll.messages ?? [];
        appendDevChatDebugLines([
          {
            kind: "tool",
            text:
              `[poll] tool sendGeneratedImage: succeeded — jobId=${jobId} — ` +
              `${incoming.length} new message(s) attached`,
          },
        ]);
        if (incoming.length === 0) return;
        if (options?.markPrivateGenerated) {
          const generatedIds = collectGeneratedImageIds(incoming);
          if (generatedIds.length > 0) {
            setImagePrivateGeneratedIds((current) => {
              const next = new Set(current);
              for (const id of generatedIds) next.add(id);
              return next.size === current.length ? current : [...next];
            });
          }
        }
        setDetail((current) => {
          if (!current || current.id !== conversationId) return current;
          const seen = new Set(current.messages.map((m) => m.id));
          const toAdd = incoming.filter((m) => !seen.has(m.id));
          if (toAdd.length === 0) return current;
          return {
            ...current,
            messages: [...current.messages, ...toAdd],
            hasAssistantReply: true,
          };
        });
      } catch {
        clearPendingImageJobPoll(jobId);
        setComposerImageJobOrb((current) => (current?.jobId === jobId ? null : current));
      }
    };
    const handle = window.setInterval(() => void tick(), 850);
    pendingImageJobPollTimersRef.current.set(jobId, handle);
    void tick();
  }

  function wirePendingImageJobFromEnvelope(
    envelope: ChatPostEnvelope,
    opts: { stillViewing: boolean; activeConversationId: string | null }
  ) {
    if (!opts.stillViewing || !envelope.pendingImageJob) return;
    const convId =
      envelope.pendingImageJob.conversationId ?? envelope.conversation.id;
    if (
      opts.activeConversationId !== null &&
      convId !== opts.activeConversationId
    ) {
      return;
    }
    setComposerImageJobOrb({
      jobId: envelope.pendingImageJob.jobId,
      conversationId: convId,
    });
    // If the user queued follow-up text while this turn was waiting, push the
    // next queued message immediately once the image job is confirmed so chat
    // can keep moving independently from image generation.
    if (!dispatchingQueuedPrompt && queuedChatPrompts.length > 0) {
      scheduleNextQueuedPrompt(convId);
    }
    startPendingImageJobPoll(envelope.pendingImageJob.jobId, convId, {
      markPrivateGenerated: envelope.conversation.incognito === true,
    });
  }

  async function setZenInitialStarterReplaySuppression(
    conversationId: string,
    action: "suppress" | "promote"
  ): Promise<void> {
    await api<{ ok: true }>(
      `/api/conversations/${encodeURIComponent(conversationId)}/zen-starter-replay`,
      {
        method: "POST",
        body: JSON.stringify({ action }),
      }
    );
  }

  function cacheZenInitialStarterReply(envelope: ChatPostEnvelope): void {
    if (!user?.id) return;
    const conversationId = envelope.conversation.id;
    const suppressPromise = setZenInitialStarterReplaySuppression(
      conversationId,
      "suppress"
    ).catch((err) => {
      if (zenInitialStarterCachedReplyRef.current?.envelope.conversation.id === conversationId) {
        setError(
          err instanceof Error
            ? err.message
            : "Prism saved the canceled opener, but could not hide it."
        );
      }
    });
    zenInitialStarterCachedReplyRef.current = {
      savedAt: Date.now(),
      envelope,
      suppressPromise,
    };
    clearLegacyZenInitialStarterCachedReply(user.id);
  }

  function clearZenInitialStarterReplyCache(): void {
    zenInitialStarterCachedReplyRef.current = null;
    if (user?.id) {
      clearLegacyZenInitialStarterCachedReply(user.id);
    }
  }

  function commitZenInitialStarterEnvelope(
    envelope: ChatPostEnvelope,
    options: { consumeCache: boolean }
  ): void {
    const patchedConversation = attachLivePsychicScratchpadToConversation(
      applyCommandDisplayAliases(applyExplicitAskQuestionFallback(envelope.conversation)),
      envelope.psychicDebug,
      psychicTextEnabledForConversation(envelope.conversation, {
        productChatSurface: view === "chat",
      })
    );
    if (options.consumeCache) {
      clearZenInitialStarterReplyCache();
    }
    zenInitialStarterLiveEnvelopeRef.current = {
      ...envelope,
      conversation: patchedConversation,
    };
    setChatAutoRestoreSuppressed(false);
    clearPendingReplyState();
    setPendingReplyStartMessageCount(0);
    markLatestAssistantRevealEligible(patchedConversation);
    hardResetChatArchiveStateForConversation(patchedConversation.id);
    captureFallbackMessageIdFromEnvelope(envelope);
    setDetail(patchedConversation);
    setSelectedId(patchedConversation.id);
    setSessionOpinion(envelope.opinion ?? null);
    setBotOpinion(envelope.botOpinion ?? null);
    clearComposerDraftNow();
    setComposerPrimed(false);
    setStarterComposerRevealed(false);
    setAskQuestionComposerRevealed(false);
    setChatStartupSummary(null);
    chatSummaryRefreshMarkerRef.current = null;
    if (
      Array.isArray(envelope.conversationStarters) &&
      envelope.conversationStarters.length >= 4
    ) {
      setConversationStarterPrompts({
        conversationId: patchedConversation.id,
        prompts: envelope.conversationStarters.slice(0, 4),
        assistantMessageId: getLatestAssistantMessageId(patchedConversation.messages),
      });
    } else {
      setConversationStarterPrompts(null);
    }
    wirePendingImageJobFromEnvelope(envelope, {
      stillViewing: true,
      activeConversationId: patchedConversation.id,
    });
    setChatEphemeralNowMs(Date.now());
    void refreshConversations();
    void refreshOpenMemoryViews();
  }

  function replayCachedZenInitialStarterReply(): boolean {
    if (!user?.id) return false;
    const cached = zenInitialStarterCachedReplyRef.current;
    if (!cached) return false;
    const conversationId = cached.envelope.conversation.id;
    setZenInitialStarterOverlayActive(true);
    setChatAutoRestoreSuppressed(false);
    setPendingReply(true);
    setPendingReplyStartedAtMs(Date.now());
    setPendingReplyDenialRisk(false);
    setPendingReplyStartMessageCount(0);
    setPendingReplyConversationId(conversationId);
    setPendingReplyIsNewConversation(false);
    setDetail({
      ...cached.envelope.conversation,
      hasAssistantReply: false,
      messages: [],
    });
    setSelectedId(conversationId);
    setStarterComposerRevealed(false);
    setConversationStarterPrompts(null);
    setError(null);
    void (async () => {
      try {
        await cached.suppressPromise;
        await setZenInitialStarterReplaySuppression(conversationId, "promote");
        if (zenInitialStarterCachedReplyRef.current !== cached) return;
        commitZenInitialStarterEnvelope(cached.envelope, { consumeCache: true });
      } catch (err) {
        if (zenInitialStarterCachedReplyRef.current !== cached) return;
        clearPendingReplyState();
        setChatAutoRestoreSuppressed(true);
        setError(
          err instanceof Error
            ? err.message
            : "Prism could not replay the canceled opener."
        );
      }
    })();
    return true;
  }

  function armCanceledZenInitialStarterReplay(): boolean {
    const starterRequest = zenInitialStarterRequestRef.current;
    if (!starterRequest?.cancelled) return false;
    starterRequest.replayWhenReady = true;
    setZenInitialStarterOverlayActive(true);
    setChatAutoRestoreSuppressed(false);
    setPendingReply(true);
    setPendingReplyStartedAtMs(Date.now());
    setPendingReplyDenialRisk(false);
    setPendingReplyStartMessageCount(0);
    setPendingReplyConversationId(starterRequest.conversationId);
    setPendingReplyIsNewConversation(starterRequest.startedNewConversation);
    setDetail(
      starterRequest.pendingDetail ?? {
        id: "pending",
        title: "New chat",
        botId: null,
        incognito: false,
        lastBotId: null,
        lastBotColor: null,
        hasAssistantReply: false,
        messages: [],
      }
    );
    setSelectedId(starterRequest.conversationId);
    setError(null);
    return true;
  }

  function clearAllDisplayedConversationState(): void {
    pendingNvmTopicResetRef.current = false;
    setDetail((current) =>
      current
        ? {
            ...current,
            hasAssistantReply: false,
            lastBotId: null,
            lastBotColor: null,
            zenWallpaper: resetZenWallpaperForFreshConversation(current.zenWallpaper),
            messages: [],
          }
        : current
    );
    setSessionOpinion(null);
    setBotOpinion(null);
    setChatStartupSummary(null);
    setPendingZenSessionBreak(null);
    setPendingZenSessionResumeContext(null);
    chatSummaryRefreshMarkerRef.current = null;
    setSummaryDebug(null);
    setZenSessionBreak(null);
    persistZenSessionBreak(null);
    setManualCompactionStatus(null);
    setConversationStarterPrompts(null);
    setAskQuestionComposerRevealed(false);
    revealZenHeaderForFreshSurface();
    if (editingMessageId !== null) {
      setEditingMessageId(null);
      setEditingOriginalText("");
    }
    clearComposerDraftNow();
    setComposerPrimed(false);
    clearCoffeeLoopTimer();
    abortCoffeeRequests();
    resetCoffeeRhythm();
    setCoffeeDraft("");
    setCoffeeError(null);
    coffeeLastSubmittedDraftRef.current = null;
    setCoffeeConversation((current) =>
      current
        ? {
            ...current,
            hasAssistantReply: false,
            lastBotId: null,
            lastBotColor: null,
            messages: [],
          }
        : current
    );
    if (view === "chat") {
      rotateZenFallbackWallpaperSeed();
    }
  }

  function consumeGlobalClearCommand(trimmedLine: string, source: "chat" | "coffee"): boolean {
    const parsed = parseGlobalClearCommand(trimmedLine);
    if (parsed.kind === "none") return false;
    if (parsed.kind === "error") {
      if (source === "coffee") {
        setCoffeeError(parsed.error);
      } else {
        setError(parsed.error);
      }
      return true;
    }
    clearAllDisplayedConversationState();
    setError(null);
    return true;
  }

  function appendOptimisticZenFollowupMessage(input: {
    content: string;
    pendingMessageCleanup?: boolean;
    promptWildcards?: PromptWildcardRunMetadata | null;
  }): string {
    const optimisticZenPersonaBot =
      zenPersonaBotIdRef.current
        ? bots.find((bot) => bot.id === zenPersonaBotIdRef.current) ?? null
        : null;
    const optimisticMessageId = `pending-zen-followup-${Date.now().toString(36)}-${Math.random()
      .toString(36)
      .slice(2, 8)}`;
    const optimisticMessage: Message = {
      id: optimisticMessageId,
      role: "user",
      content: input.content,
      createdAt: new Date().toISOString(),
      ...(zenPersonaBotIdRef.current ? { botId: zenPersonaBotIdRef.current } : {}),
      ...(optimisticZenPersonaBot?.color ? { botColor: optimisticZenPersonaBot.color } : {}),
      ...(input.promptWildcards ? { promptWildcards: input.promptWildcards } : {}),
    };
    if (input.pendingMessageCleanup === true) {
      setPendingMessageCleanupMessageIds((current) => {
        const next = new Set(current);
        next.add(optimisticMessageId);
        return next;
      });
    }
    setDetail((current) =>
      current ? { ...current, messages: [...current.messages, optimisticMessage] } : current
    );
    return optimisticMessageId;
  }

  function scheduleZenFollowupMergedSend(): void {
    clearZenFollowupCooldownTimer();
    zenFollowupCooldownTimerRef.current = setTimeout(() => {
      zenFollowupCooldownTimerRef.current = null;
      if (zenFollowupDispatchingRef.current) return;
      const snapshot = zenFollowupBufferRef.current;
      const messages = snapshot?.messages.slice(-ZEN_SUCCESSIVE_MESSAGE_CONTEXT_LIMIT) ?? [];
      const pendingMessageCleanupIds =
        snapshot?.pendingMessageCleanupMessageIds ?? [];
      const latest = messages[messages.length - 1]?.replace(/\s+/g, " ").trim() ?? "";
      if (!snapshot || !latest) {
        clearPendingMessageCleanupIds(pendingMessageCleanupIds);
        setZenFollowupBuffer(null);
        return;
      }
      const promptInputOverride = zenFollowupModelPrompt(messages);
      zenFollowupDispatchingRef.current = true;
      zenFollowupBufferRef.current = null;
      setZenFollowupBuffer(null);
      const dispatch = async (): Promise<void> => {
        const conversationId = snapshot.conversationId;
        if (conversationId && conversationId !== "pending") {
          for (const buffered of messages.slice(0, -1)) {
            const content = buffered.replace(/\s+/g, " ").trim();
            if (!content) continue;
            await api(`/api/conversations/${encodeURIComponent(conversationId)}/messages/user`, {
              method: "POST",
              body: JSON.stringify({ content }),
            });
          }
        }
        await sendMessage(
          { preventDefault() {} } as React.FormEvent,
          {
            draftOverride: latest,
            promptInputOverride,
            queuedConversationId: conversationId,
            skipComposerHistory: true,
            zenFollowupDispatch: true,
            zenFollowupCleanupMessageIds: pendingMessageCleanupIds,
          }
        );
      };
      void dispatch()
        .catch((err) => {
          setError(err instanceof Error ? err.message : "Could not send buffered Zen follow-up.");
          setComposerDraftNow(latest);
          setComposerSendTintActive(true);
        })
        .finally(() => {
          zenFollowupDispatchingRef.current = false;
        });
    }, COFFEE_SEND_COOLDOWN_MS);
  }

  function disabledTextModelSendMessage(): string | null {
    if (!settings) return null;
    const responseMode = responseModeForProvider(effectivePreferredProvider);
    const resolvedChoice = resolveModelChoiceForResponseMode({
      responseMode,
      providerPreference: effectivePreferredProvider,
      choices: visibleModelChoicesByProvider(
        modelCatalog,
        settings,
        chatModelChoiceByProvider
      ),
      onlineOptions: onlineChatModelOptions,
    });
    const settingsDefaultDisabled =
      responseMode === "local"
        ? modelChoiceIsDisabled(settings.preferredLocalModel)
        : modelChoiceIsDisabled(settings.preferredOnlineModel);
    if (
      resolvedChoice.modelChoice === AUTO_MODEL_CHOICE &&
      settingsDefaultDisabled
    ) {
      return `${responseModeShortLabel(responseMode)} replies are disabled in Settings. Choose a model in Settings, or pick a model here before sending.`;
    }
    if (resolvedChoice.modelChoice !== DISABLED_MODEL_CHOICE) return null;
    return `${responseModeShortLabel(responseMode)} replies are disabled. Choose Auto or a model before sending.`;
  }

  async function sendMessage(
    e: React.FormEvent | React.KeyboardEvent<HTMLTextAreaElement | HTMLFormElement>,
    options: {
      starterPrompt?: boolean;
      starterPromptWarrantsIntro?: boolean;
      draftOverride?: string;
      promptInputOverride?: string;
      manualToolOverride?: ChatManualToolRequest;
      queuedConversationId?: string | null;
      skipComposerHistory?: boolean;
      personaTransition?: ZenPersonaTransitionInput;
      zenAutonomy?: ZenAutonomyInput;
      zenAskQuestionPatience?: ZenAskQuestionPatienceInput;
      zenLiveActionInterrupt?: ZenLiveActionInterruptInput;
      preserveComposerDraft?: boolean;
      zenFollowupDispatch?: boolean;
      zenFollowupCleanupMessageIds?: string[];
      onZenAutonomyResult?: (decision: ZenAutonomyDecision | null) => void;
      conversationDetailOverride?: ConversationDetail;
    } = {}
  ) {
    e.preventDefault();
    const isPersonaTransition = options.personaTransition !== undefined;
    const isZenAutonomy = options.zenAutonomy !== undefined;
    const isAskQuestionPatienceTurn = options.zenAskQuestionPatience !== undefined;
    const isZenLiveActionInterrupt = options.zenLiveActionInterrupt !== undefined;
    const isAssistantOnlyTurn =
      isPersonaTransition ||
      isZenAutonomy ||
      isAskQuestionPatienceTurn ||
      isZenLiveActionInterrupt;
    const preserveComposerDraft = options.preserveComposerDraft === true;
    const rawDraft = options.draftOverride ?? draft;
    const rawTrimmed = rawDraft.trim();
    const commandTrimmed = normalizeComposerSlashCommandLine(rawTrimmed);
    if (
      commandTrimmed.length > 0 &&
      !options.starterPrompt &&
      !isAssistantOnlyTurn &&
      ignoreLocalOnlyComposerCommandWhileReplying(commandTrimmed)
    ) {
      return;
    }
    if (
      commandTrimmed.length > 0 &&
      !options.starterPrompt &&
      !isAssistantOnlyTurn &&
      await consumeBuiltInOperationalSlashCommand(commandTrimmed)
    ) {
      if (!options.skipComposerHistory) {
        appendComposerHistoryEntry(rawDraft);
      }
      return;
    }
    if (
      commandTrimmed.length > 0 &&
      !options.starterPrompt &&
      !isAssistantOnlyTurn &&
      consumeGlobalClearCommand(commandTrimmed, "chat")
    ) {
      if (!options.skipComposerHistory) {
        appendComposerHistoryEntry(rawDraft);
      }
      return;
    }
    if (
      commandTrimmed.length > 0 &&
      !options.starterPrompt &&
      !isAssistantOnlyTurn &&
      await consumeDevSlashCommand(commandTrimmed)
    ) {
      if (!options.skipComposerHistory) {
        appendComposerHistoryEntry(rawDraft);
      }
      return;
    }
    if (
      commandTrimmed.length > 0 &&
      !options.starterPrompt &&
      !isAssistantOnlyTurn &&
      consumePrismDevComposerCommand(commandTrimmed)
    ) {
      if (!options.skipComposerHistory) {
        appendComposerHistoryEntry(rawDraft);
      }
      clearComposerDraftNow();
      return;
    }
    const commandCenterResolution =
      rawTrimmed.length > 0 && !options.starterPrompt && !isAssistantOnlyTurn
        ? resolveCommandCenterPromptShortcuts(rawDraft)
        : { kind: "none" as const };
    if (commandCenterResolution.kind === "error") {
      setError(commandCenterResolution.error);
      return;
    }
    const commandCenterModelChoice =
      commandCenterResolution.kind === "resolved"
        ? resolveCommandCenterModelChoiceForSend(
            commandCenterResolution.modelChoice,
            settings,
            modelCatalog
          )
        : AUTO_MODEL_CHOICE;
    if (commandCenterModelChoice === DISABLED_MODEL_CHOICE) {
      setError(
        "Prompt runs are disabled. Choose Auto or a local model in Command Center before using that command."
      );
      return;
    }
    if (!isAssistantOnlyTurn) {
      const disabledMessage = disabledTextModelSendMessage();
      if (disabledMessage) {
        setError(disabledMessage);
        return;
      }
    }
    const commandCenterPromptShortcut =
      commandCenterResolution.kind === "resolved"
        ? commandCenterResolution.promptShortcut
        : null;
    const commandCenterPromptActive = commandCenterResolution.kind === "resolved";
    const naturalContextResetRequested =
      rawTrimmed.length > 0 &&
      view === "chat" &&
      !options.starterPrompt &&
      !isAssistantOnlyTurn &&
      !editingMessageId &&
      !commandCenterPromptActive &&
      shouldResetPreviousSessionContext(rawTrimmed);
    let naturalContextResetApplied = false;
    const commandCenterSubmitActive =
      commandCenterPromptActive && commandCenterResolution.promptShortcut !== null;
    const composerWildcardResolution =
      commandCenterResolution.kind === "resolved"
        ? resolveComposerWildcardDraft(commandCenterResolution.prompt)
        : isPersonaTransition
          ? { prompt: "", promptWildcards: null }
          : isZenAutonomy
            ? { prompt: "", promptWildcards: null }
          : isAskQuestionPatienceTurn
            ? { prompt: "", promptWildcards: null }
          : isZenLiveActionInterrupt
            ? { prompt: "", promptWildcards: null }
          : resolveComposerWildcardDraft(rawDraft);
    const composerPromptWildcards = composerWildcardResolution.promptWildcards;
    const parsedManualToolResolution =
      !commandCenterPromptActive && !isAssistantOnlyTurn && !options.starterPrompt
        ? resolveComposerManualToolRequest(composerWildcardResolution.prompt)
        : null;
    const manualToolResolution = options.manualToolOverride
      ? {
          message: composerManualToolMessage(
            options.manualToolOverride,
            composerWildcardResolution.prompt
          ),
          manualTool: options.manualToolOverride,
        }
      : parsedManualToolResolution;
    const manualToolForSend = manualToolResolution?.manualTool;
    const trimmed = (manualToolResolution?.message ?? composerWildcardResolution.prompt).trim();
    if (manualToolForSend && trimmed.length === 0) {
      setError(
        manualToolForSend.name === "askQuestion"
          ? "Add a question after the tool chip."
          : "Add a search query or image prompt after the tool chip."
      );
      return;
    }
    if (manualToolForSend?.name === "askQuestion" && !options.manualToolOverride) {
      const question = (manualToolForSend.question ?? trimmed).trim();
      if (!question) {
        setError("Add a question after the tool chip.");
        return;
      }
      setManualAskQuestionModal({
        question,
        options: ensureManualAskQuestionOptionRows(
          Array.isArray(manualToolForSend.options) ? manualToolForSend.options : []
        ),
      });
      return;
    }
    const displayTrimmed = commandCenterPromptActive ? rawTrimmed : trimmed;
    const restoreDraftAfterSendStops = commandCenterPromptActive ? rawDraft : trimmed;
    const isStarterPrompt =
      options.starterPrompt === true &&
      (!detail || detail.messages.length === 0);
    const commandCenterPromptHasTrueWildcardSlots =
      commandCenterPromptActive && draftContainsTrueWildcardSlots(trimmed);
    const composerPromptHasTrueWildcardSlots =
      composerPromptWildcards !== null && draftContainsTrueWildcardSlots(trimmed);
    const standaloneComposerWildcardRun =
      !commandCenterPromptActive &&
      composerPromptWildcards !== null &&
      isStandaloneWildcardComposerDraft(rawTrimmed);
    const composerPromptWildcardsForSend =
      standaloneComposerWildcardRun && !composerPromptHasTrueWildcardSlots
        ? null
        : composerPromptWildcards;
    const commandCenterPromptHasWildcardReplacements =
      (commandCenterPromptShortcut?.wildcardReplacements?.length ?? 0) > 0;
    const composerPromptHasWildcardRun = composerPromptWildcardsForSend !== null;
    const promptHasWildcardFinalization =
      commandCenterPromptHasTrueWildcardSlots ||
      composerPromptHasTrueWildcardSlots ||
      commandCenterPromptHasWildcardReplacements ||
      composerPromptHasWildcardRun;
    const messageCleanupAwaitsServer =
      settings?.composerWritingAssist !== false &&
      !standaloneComposerWildcardRun &&
      !isStarterPrompt &&
      !isAssistantOnlyTurn &&
      !isPersonaTransition &&
      !isZenAutonomy &&
      !isAskQuestionPatienceTurn &&
      !isZenLiveActionInterrupt &&
      promptHasWildcardFinalization &&
      trimmed.length > 0;
    const messageFinalizationAwaitsServer =
      messageCleanupAwaitsServer ||
      commandCenterPromptHasTrueWildcardSlots ||
      composerPromptHasTrueWildcardSlots;
    let interruptedAssistantPersistPromise: Promise<unknown> | null = null;
    const activeSideChatSend =
      view === "chat" && detail?.hubRole === "side" && detail.mode === "chat";
    const zenFollowupBufferingSend =
      view === "chat" &&
      !activeSideChatSend &&
      !options.zenFollowupDispatch &&
      !isStarterPrompt &&
      !isAssistantOnlyTurn &&
      editingMessageId === null &&
      !commandCenterPromptActive &&
      zenFollowupBufferRef.current !== null &&
      displayTrimmed.length > 0;
    if (zenFollowupBufferingSend) {
      const activeConversationId =
        detail?.id && detail.id !== "pending" ? detail.id : selectedId;
      const interruption = prepareActiveAssistantRevealInterruption();
      if (interruption) {
        const sentenceComplete = visibleChatRevealHasCompletedFirstSentence(
          interruption.interruptedText,
          interruption.visibleTokenCount
        );
        const persistPromise = sentenceComplete
          ? applyActiveAssistantRevealInterruption(interruption)
          : discardActiveAssistantRevealForGrace(interruption);
        if (persistPromise) {
          if (sentenceComplete) {
            interruptedAssistantPersistPromise = persistPromise;
          } else {
            try {
              await persistPromise;
            } catch (err) {
              setError(
                err instanceof Error
                  ? err.message
                  : "Prism was interrupted, but the saved thread could not be updated."
              );
              setComposerDraftNow(rawDraft);
              setComposerSendTintActive(rawDraft.trim().length > 0);
              return;
            }
          }
        }
      }
      beginOrRefreshZenFollowupBuffer(activeConversationId);
      const followupMessageFinalizationAwaitsServer =
        messageFinalizationAwaitsServer || composerPromptWildcards !== null;
      const optimisticFollowupContent = pendingCleanupOptimisticMessageContent({
        rawDraft: rawTrimmed,
        resolvedDisplayContent: displayTrimmed,
        pendingCleanup: followupMessageFinalizationAwaitsServer,
      });
      const optimisticFollowupMessageId = appendOptimisticZenFollowupMessage({
        content: optimisticFollowupContent,
        pendingMessageCleanup: followupMessageFinalizationAwaitsServer,
        promptWildcards: followupMessageFinalizationAwaitsServer
          ? composerPromptWildcardsForSend
          : null,
      });
      setZenFollowupBuffer((current) => {
        const now = Date.now();
        const messages = [
          ...(current?.messages ?? []),
          displayTrimmed,
        ].slice(-ZEN_SUCCESSIVE_MESSAGE_CONTEXT_LIMIT);
        const pendingMessageCleanupIds = [
          ...(current?.pendingMessageCleanupMessageIds ?? []),
          ...(followupMessageFinalizationAwaitsServer ? [optimisticFollowupMessageId] : []),
        ];
        const next = {
          conversationId: current?.conversationId ?? activeConversationId,
          messages,
          pendingMessageCleanupMessageIds: pendingMessageCleanupIds,
          startedAtMs: current?.startedAtMs ?? now,
          lastActivityAtMs: now,
          generation: (current?.generation ?? 0) + 1,
        };
        zenFollowupBufferRef.current = next;
        return next;
      });
      if (!options.skipComposerHistory) {
        appendComposerHistoryEntry(rawDraft);
      }
      clearComposerDraftNow();
      setError(null);
      if (interruptedAssistantPersistPromise) {
        try {
          await interruptedAssistantPersistPromise;
        } catch (err) {
          setError(
            err instanceof Error
              ? err.message
              : "Prism was interrupted, but the saved thread could not be updated."
          );
          setComposerDraftNow(rawDraft);
          setComposerSendTintActive(rawDraft.trim().length > 0);
          return;
        }
      }
      scheduleZenFollowupMergedSend();
      return;
    }
    let detailForSend = options.conversationDetailOverride ?? detail;
    let baselineMessageCount = detailForSend?.messages.length ?? 0;
    const isInitialZenOpeningTurn =
      view === "chat" &&
      !isAssistantOnlyTurn &&
      !editingMessageId &&
      (isStarterPrompt || trimmed.length > 0) &&
      baselineMessageCount === 0 &&
      detailForSend?.hasAssistantReply !== true;
    const isInitialZenStarterPrompt = isInitialZenOpeningTurn && isStarterPrompt;
    if (isInitialZenStarterPrompt) {
      if (replayCachedZenInitialStarterReply()) return;
      if (armCanceledZenInitialStarterReplay()) return;
      setZenInitialStarterOverlayActive(true);
    } else if (isInitialZenOpeningTurn) {
      setZenInitialStarterOverlayActive(true);
      clearZenInitialStarterReplyCache();
      zenInitialStarterLiveEnvelopeRef.current = null;
    } else if (!isStarterPrompt && view === "chat") {
      setZenInitialStarterOverlayActive(false);
      clearZenInitialStarterReplyCache();
      zenInitialStarterLiveEnvelopeRef.current = null;
    }
    const forceNewConversation =
      !isStarterPrompt &&
      !isZenAutonomy &&
      !isAskQuestionPatienceTurn &&
      !isZenLiveActionInterrupt &&
      forceNewConversationOnNextSend;
    if (!trimmed && !isStarterPrompt && !isAssistantOnlyTurn) return;
    if ((isChatSurfaceView(view) || activeSideChatSend) && !isAssistantOnlyTurn) {
      const chatBotIdForSend =
        detailForSend?.botId ?? detailForSend?.hubBotId ?? selectedBotId ?? null;
      if (!chatBotIdForSend) {
        setError("Choose a bot before chatting.");
        return;
      }
    }
    let prismInterruptionForSend: PrismMoodInterruptionInput | undefined;
    if (
      commandCenterSubmitActive &&
      pendingReply &&
      !canSendTextWhileReplyPending()
    ) {
      priorityCommandCancelControllerRef.current = pendingReplyAbortControllerRef.current;
      stopPendingReply();
    }
    if (!isStarterPrompt && trimmed.length > 0 && view === "chat") {
      const interruption = prepareActiveAssistantRevealInterruption();
      if (interruption) {
        const persistPromise = applyActiveAssistantRevealInterruption(interruption);
        detailForSend = interruption.patchedDetail;
        baselineMessageCount = detailForSend.messages.length;
        if (persistPromise) {
          interruptedAssistantPersistPromise = persistPromise;
        } else {
          prismInterruptionForSend = {
            kind: "assistant_reveal",
            assistantMessageId: interruption.assistantMessageId,
            visibleTokenCount: interruption.visibleTokenCount,
            totalTokenCount: interruption.totalTokenCount,
            interruptedContent: interruption.interruptionContent,
          };
        }
      }
    }
    const zenImmediateInterruptPendingReply =
      !isStarterPrompt &&
      trimmed.length > 0 &&
      view === "chat" &&
      pendingReply &&
      !canSendTextWhileReplyPending() &&
      !commandCenterSubmitActive;
    if (zenImmediateInterruptPendingReply) {
      priorityCommandCancelControllerRef.current = pendingReplyAbortControllerRef.current;
      stopPendingReply();
    }
    if (
      pendingReply &&
      !commandCenterSubmitActive &&
      !zenImmediateInterruptPendingReply &&
      !canSendTextWhileReplyPending()
    ) {
      if (!isStarterPrompt && trimmed.length > 0) {
        hideZenHeaderForConversationAction();
        setQueuedChatPrompts((previous) => [
          ...previous,
          {
            id: `q-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
            text: rawDraft,
            targetConversationId: pendingReplyConversationId,
          },
        ]);
        if (!editingMessageId) {
          if (!options.skipComposerHistory) {
            appendComposerHistoryEntry(rawDraft);
          }
        }
        clearComposerDraftNow();
        setError(null);
      }
      return;
    }
    if (naturalContextResetRequested) {
      const contextResetConversationId =
        detailForSend?.id && detailForSend.id !== "pending"
          ? detailForSend.id
          : selectedId;
      const cleared = await clearConversationFromSlashCommand({
        conversationIdOverride: contextResetConversationId,
        preserveComposer: true,
        allowPendingReply: true,
      });
      if (!cleared) {
        setComposerDraftNow(rawDraft);
        setComposerSendTintActive(rawDraft.trim().length > 0);
        return;
      }
      naturalContextResetApplied = true;
      setPendingZenSessionBreak(null);
      setPendingZenSessionResumeContext(null);
      setZenSessionBreak(null);
      persistZenSessionBreak(null);
      chatSummaryRefreshMarkerRef.current = null;
      prismInterruptionForSend = undefined;
      detailForSend = detailForSend
        ? {
            ...detailForSend,
            title: "New chat",
            hasAssistantReply: false,
            lastBotId: null,
            lastBotColor: null,
            zenWallpaper: resetZenWallpaperForFreshConversation(detailForSend.zenWallpaper),
            messages: [],
          }
        : null;
      baselineMessageCount = 0;
    }
    if (chatAutoRestoreSuppressed) {
      setChatAutoRestoreSuppressed(false);
    }
    if (forceNewConversationOnNextSend) {
      setForceNewConversationOnNextSend(false);
    }
    if (editingMessageId && !isStarterPrompt) {
      const editMessageId = editingMessageId;
      hideZenHeaderForConversationAction();
      clearComposerDraftNow();
      setEditingMessageId(null);
      setEditingOriginalText("");
      draftComposerRef.current?.blur();
      requestMessageEdit(editMessageId, displayTrimmed, {
        ...(commandCenterModelChoice !== AUTO_MODEL_CHOICE
          ? { commandCenterModelChoice }
          : {}),
        ...(commandCenterPromptActive
          ? {
              commandCenterPrompt: true,
              resolvedCommandCenterPrompt: trimmed,
            }
          : {}),
        ...(commandCenterPromptShortcut
          ? { promptShortcut: commandCenterPromptShortcut }
          : {}),
        ...(composerPromptWildcardsForSend
          ? { promptWildcards: composerPromptWildcardsForSend }
          : {}),
      });
      return;
    }
    if (!isZenAutonomy && !isZenLiveActionInterrupt) {
      hideZenHeaderForConversationAction();
      // Any typed/chosen follow-up supersedes the starter quick-replies row.
      if (!isStarterPrompt) {
        setConversationStarterPrompts(null);
      }
      if (view === "chat") {
        setChatStartupSummary(null);
        chatSummaryRefreshMarkerRef.current = null;
      }
    }
    const requestConversationId = options.queuedConversationId ?? (
      detailForSend?.id && detailForSend.id !== "pending"
        ? detailForSend.id
        : selectedId
    );
    const requestStartedNewConversation = requestConversationId === null || forceNewConversation;
    if (!isZenAutonomy && !isZenLiveActionInterrupt) {
      resumeChatModeAutoscrollForOutgoingTurn(
        requestConversationId ??
          detailForSend?.id ??
          selectedId ??
          (requestStartedNewConversation ? "pending" : null)
      );
    }
    const archiveConversationId =
      requestConversationId ??
      (detailForSend?.id && detailForSend.id !== "pending" ? detailForSend.id : null);
    if (!isZenAutonomy && !isZenLiveActionInterrupt && view === "chat" && archiveConversationId) {
      // Every new send starts from the compact active-turn view again.
      hardResetChatArchiveStateForConversation(archiveConversationId);
    }
    const chatRequestController = new AbortController();
    if (!isZenAutonomy) {
      pendingReplyAbortControllerRef.current = chatRequestController;
    }
    const clearPendingReplyVisuals = () => {
      if (isZenAutonomy) {
        if (pendingReplyAbortControllerRef.current === chatRequestController) {
          pendingReplyAbortControllerRef.current = null;
        }
        return;
      }
      setPendingReply(false);
      setPendingReplyStartedAtMs(null);
      setPendingReplyDenialRisk(false);
      setPendingReplyConversationId(null);
      setPendingReplyIsNewConversation(false);
      if (pendingReplyAbortControllerRef.current === chatRequestController) {
        pendingReplyAbortControllerRef.current = null;
      }
    };
    if (!isZenAutonomy) {
      setPendingReply(true);
      setPendingReplyStartedAtMs(Date.now());
      setPendingReplyDenialRisk(
        promptLooksDenialProne(isStarterPrompt ? "" : trimmed)
      );
      setPendingReplyStartMessageCount(baselineMessageCount);
      setPendingReplyConversationId(requestConversationId);
      setPendingReplyIsNewConversation(requestStartedNewConversation);
    }
    setError(null);

    const mentionedZenPersonaBotId =
      view === "chat" && !activeSideChatSend && !isStarterPrompt && !isAssistantOnlyTurn
        ? findFirstBotMentionId(displayTrimmed, composeMentionBotPicks)
        : null;
    const zenPersonaBotIdForSend =
      view === "chat"
        ? activeSideChatSend
          ? detailForSend?.botId ?? detailForSend?.hubBotId ?? null
          : isPersonaTransition
          ? options.personaTransition!.toBotId
          : isZenAutonomy
            ? options.zenAutonomy!.activeBotId
          : isAskQuestionPatienceTurn
            ? options.zenAskQuestionPatience!.activeBotId
          : mentionedZenPersonaBotId ?? zenPersonaBotId
        : undefined;
    const optimisticZenPersonaBot =
      view === "chat" && zenPersonaBotIdForSend
        ? bots.find((bot) => bot.id === zenPersonaBotIdForSend) ?? null
        : null;
    if (mentionedZenPersonaBotId) {
      setZenPersonaBotId(mentionedZenPersonaBotId);
    }

    const previousDetail = detailForSend;
    const previousPendingIncognito = pendingIncognito;
    const previousZenPersonaBotId = zenPersonaBotIdRef.current;
    let optimisticPromptCleanupMessageId: string | null = null;
    const optimisticIncognito = detailForSend?.incognito === true || pendingIncognito;
    const optimisticHubBotId =
      view === "chat"
        ? zenPersonaBotIdForSend ?? detailForSend?.hubBotId ?? null
        : undefined;
    const optimisticBotId =
      detailForSend?.botId ??
      (view === "chat"
        ? null
        : isChatSurfaceView(view)
          ? selectedBotId ?? null
        : optimisticIncognito
          ? selectedBotId ?? null
          : null);
    const optimisticLastBotId =
      detailForSend?.lastBotId ??
      (view === "chat"
        ? optimisticHubBotId ?? null
        : view === "sandbox" && !optimisticIncognito
          ? selectedBotId ?? null
          : optimisticBotId);
    const optimisticLastBotColor =
      detailForSend?.lastBotColor
      ?? (optimisticLastBotId
            ? bots.find(b => b.id === optimisticLastBotId)?.color ?? null
            : null);
    let initialZenStarterPendingDetail: ConversationDetail | null =
      isInitialZenStarterPrompt && detailForSend ? detailForSend : null;
    if (isStarterPrompt && requestStartedNewConversation) {
      const pendingStarterDetail: ConversationDetail = {
        id: "pending",
        title: "New chat",
        botId: optimisticBotId,
        ...(view === "chat"
          ? {
              hubRole: "hub" as const,
              hubBotId: optimisticHubBotId ?? null,
              parentHubId: null,
            }
          : {}),
        incognito: optimisticIncognito,
        lastBotId: optimisticLastBotId,
        lastBotColor: optimisticLastBotColor,
        hasAssistantReply: false,
        ...(detailForSend?.prismMood ? { prismMood: detailForSend.prismMood } : {}),
        messages: [],
      };
      initialZenStarterPendingDetail = isInitialZenStarterPrompt
        ? pendingStarterDetail
        : initialZenStarterPendingDetail;
      setDetail(pendingStarterDetail);
    } else if (!isStarterPrompt && !isAssistantOnlyTurn && !options.zenFollowupDispatch) {
      const optimisticMessageId = `pending-${Date.now().toString(36)}-${Math.random()
        .toString(36)
        .slice(2, 8)}`;
      const optimisticUserContent = pendingCleanupOptimisticMessageContent({
        rawDraft: rawTrimmed,
        resolvedDisplayContent: displayTrimmed,
        pendingCleanup: messageFinalizationAwaitsServer,
      });
      if (messageFinalizationAwaitsServer) {
        optimisticPromptCleanupMessageId = optimisticMessageId;
        setPendingMessageCleanupMessageIds((current) => {
          const next = new Set(current);
          next.add(optimisticMessageId);
          return next;
        });
      }
      const optimisticMessage: Message = {
        id: optimisticMessageId,
        role: "user",
        content: optimisticUserContent,
        createdAt: new Date().toISOString(),
        ...(view === "chat" ? { botId: zenPersonaBotIdForSend ?? null } : {}),
        ...(isChatSurfaceView(view) ? { botId: selectedBotId ?? detailForSend?.botId ?? null } : {}),
        ...(view === "chat" && optimisticZenPersonaBot?.color
          ? { botColor: optimisticZenPersonaBot.color }
          : {}),
        ...(commandCenterPromptShortcut
          ? { promptShortcut: commandCenterPromptShortcut }
          : {}),
        ...(composerPromptWildcardsForSend
          ? { promptWildcards: composerPromptWildcardsForSend }
          : {}),
      };
      const optimisticTitle =
        detailForSend?.title ??
        (optimisticUserContent.length > 42
          ? `${optimisticUserContent.slice(0, 39)}...`
          : optimisticUserContent);
      // Forward the chat-mode conversation-level settings (bot + privacy)
      // into the optimistic detail so the shell accent + privacy affordances
      // don't flicker between send and server reply. Once the server answers
      // with the persisted row, this optimistic detail is replaced.
      // For lastBot*, keep whatever the current detail had. Our optimistic
      // update adds a USER message, not an assistant one, so "last bot to
      // speak" hasn't changed — the real update lands when the server's
      // assistant reply comes back. In Sandbox where the user can switch
      // bots per-send, we preview the new pick via the "about to speak"
      // selectedBotId so the sidebar row hints at the next color before
      // the reply lands; the server value overrides on response.
      setDetail({
        id: detailForSend?.id ?? "pending",
        title: optimisticTitle,
        botId: optimisticBotId,
        ...(view === "chat"
          ? {
              hubRole: detailForSend?.hubRole ?? ("hub" as const),
              hubBotId: optimisticHubBotId ?? null,
              parentHubId: detailForSend?.parentHubId ?? null,
            }
          : {}),
        incognito: optimisticIncognito,
        lastBotId: optimisticLastBotId,
        lastBotColor: optimisticLastBotColor,
        ...(detailForSend?.zenWallpaper ? { zenWallpaper: detailForSend.zenWallpaper } : {}),
        ...(detailForSend?.prismMood ? { prismMood: detailForSend.prismMood } : {}),
        // hasAssistantReply reflects the PRE-SEND state (whatever detail
        // already had) — the optimistic update only inserts a USER
        // message, not an assistant one. The server's real response
        // flips this to true once the assistant reply is in the db.
        hasAssistantReply: detailForSend?.hasAssistantReply ?? false,
        messages: [...(detailForSend?.messages ?? []), optimisticMessage],
      });
    }
    const zenInitialStarterRequestId = isInitialZenStarterPrompt
      ? `zen-starter-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`
      : null;
    if (zenInitialStarterRequestId) {
      zenInitialStarterRequestRef.current = {
        id: zenInitialStarterRequestId,
        controller: chatRequestController,
        conversationId: requestConversationId,
        pendingDetail: initialZenStarterPendingDetail,
        startedNewConversation: requestStartedNewConversation,
        cancelled: false,
        replayWhenReady: false,
      };
      zenInitialStarterLiveEnvelopeRef.current = null;
    }
    if (
      !isStarterPrompt &&
      !isZenAutonomy &&
      !isAskQuestionPatienceTurn &&
      !isZenLiveActionInterrupt &&
      !editingMessageId &&
      !options.skipComposerHistory
    ) {
      appendComposerHistoryEntry(rawDraft);
    }
    if (!preserveComposerDraft) {
      clearComposerDraftNow();
      if (view === "chat" && !isAssistantOnlyTurn) {
        setZenLiveUserActionPreview(null);
        setZenLiveBotAction(null);
      }
    }
    let successfulConversationId: string | null = null;
    const activeZenSessionBreakGapMs = activeZenSessionBreak
      ? effectiveZenSessionBreakGapMs(activeZenSessionBreak)
      : 0;
    const activeZenSessionBreakFreshStart =
      activeZenSessionBreak !== null &&
      zenSessionBreakUsesFreshStart(
        activeZenSessionBreakGapMs,
        zenFreshStartGapMs
      );
    const pendingZenSessionResumeContextForSend =
      !naturalContextResetApplied &&
      !isStarterPrompt &&
      view === "chat" &&
      forceNewConversation &&
      pendingZenSessionResumeContext
        ? pendingZenSessionResumeContext
        : null;
    const pendingZenSessionBreakForSend =
      !naturalContextResetApplied &&
      !isStarterPrompt &&
      view === "chat" &&
      forceNewConversation &&
      pendingZenSessionBreak
        ? pendingZenSessionBreak
        : null;
    const activeZenSessionBreakResumeContext =
      !naturalContextResetApplied &&
      !isStarterPrompt &&
      view === "chat" &&
      activeZenSessionBreak &&
      !activeZenSessionBreak.resumeHintConsumed &&
      requestConversationId === activeZenSessionBreak.conversationId
        ? {
            summary:
              !activeZenSessionBreakFreshStart
                ? activeZenSessionBreak.displaySummary ??
                  currentZenDisplaySummary ??
                  undefined
                : undefined,
            resumedAt: new Date().toISOString(),
            previousActiveAt: activeZenSessionBreak.previousActiveAt ?? undefined,
            gapMs: activeZenSessionBreakGapMs,
            source: activeZenSessionBreak.source,
          } satisfies SessionResumeContext
        : undefined;
    const sessionResumeContextForSend: SessionResumeContext | undefined =
      pendingZenSessionResumeContextForSend ??
      activeZenSessionBreakResumeContext;
    const topicResetForSend =
      view === "chat" &&
      !isStarterPrompt &&
      !isAssistantOnlyTurn &&
      pendingNvmTopicResetRef.current;
    const liveActionContextForSend: ZenLiveActionContextInput | undefined =
      view === "chat" &&
      !isStarterPrompt &&
      !isAssistantOnlyTurn &&
      zenLiveUserActionPreviewRef.current
        ? {
            source: "live_action",
            activeBotId: zenPersonaBotIdForSend ?? null,
            userAction: zenLiveUserActionPreviewRef.current.action,
            ...(zenLiveBotActionRef.current?.action
              ? { botAction: zenLiveBotActionRef.current.action }
              : {}),
            ...(zenLiveBotActionRef.current?.moodHint
              ? { moodHint: zenLiveBotActionRef.current.moodHint }
              : {}),
            ...(zenLiveBotActionRef.current?.clientSequenceId
              ? { clientSequenceId: zenLiveBotActionRef.current.clientSequenceId }
              : {}),
          }
        : undefined;

    try {
      if (interruptedAssistantPersistPromise) {
        try {
          await interruptedAssistantPersistPromise;
        } catch (err) {
          throw new Error(
            err instanceof Error
              ? err.message
              : "Prism was interrupted, but the saved thread could not be updated."
          );
        }
      }
      const chatBody = buildChatRequestBody(
        isStarterPrompt ||
          isZenAutonomy ||
          isAskQuestionPatienceTurn ||
          isZenLiveActionInterrupt
          ? ""
          : displayTrimmed,
        {
          starterPrompt: isStarterPrompt,
          ...(options.starterPromptWarrantsIntro
            ? { starterPromptWarrantsIntro: true }
            : {}),
          ...(forceNewConversation ? { forceNewConversation: true } : {}),
          ...(commandCenterModelChoice !== AUTO_MODEL_CHOICE
            ? { commandCenterModelChoice }
            : {}),
          ...(commandCenterPromptActive ? { commandCenterPrompt: true } : {}),
          ...(commandCenterPromptActive
            ? { resolvedCommandCenterPrompt: trimmed }
            : {}),
          ...(commandCenterPromptShortcut
            ? { promptShortcut: commandCenterPromptShortcut }
            : {}),
          ...(composerPromptWildcardsForSend
            ? { promptWildcards: composerPromptWildcardsForSend }
            : {}),
          ...(manualToolForSend ? { manualTool: manualToolForSend } : {}),
          ...(sessionResumeContextForSend
            ? { sessionResumeContext: sessionResumeContextForSend }
            : {}),
          ...(view === "chat" && detailForSend?.incognito === true
            ? { ephemeralMessages: detailForSend.messages }
            : {}),
          ...(topicResetForSend ? { topicReset: true } : {}),
          ...(prismInterruptionForSend
            ? { prismInterruption: prismInterruptionForSend }
            : {}),
          ...(view === "chat"
            ? { zenPersonaBotId: zenPersonaBotIdForSend ?? null }
            : {}),
          ...(options.personaTransition
            ? { personaTransition: options.personaTransition }
            : {}),
          ...(options.zenAutonomy
            ? { zenAutonomy: options.zenAutonomy }
            : {}),
          ...(options.zenAskQuestionPatience
            ? { zenAskQuestionPatience: options.zenAskQuestionPatience }
            : {}),
          ...(liveActionContextForSend
            ? { zenLiveActionContext: liveActionContextForSend }
            : {}),
          ...(options.zenLiveActionInterrupt
            ? { zenLiveActionInterrupt: options.zenLiveActionInterrupt }
            : {}),
          ...(options.promptInputOverride
            ? { promptInputOverride: options.promptInputOverride }
            : {}),
          ...(options.queuedConversationId !== undefined
            ? { conversationIdOverride: options.queuedConversationId }
            : {}),
        }
      );
      appendDevChatRouteStart("send", chatBody);
      const d = await api<ChatPostEnvelope>("/api/chat", {
        method: "POST",
        body: JSON.stringify(chatBody),
        signal: chatRequestController.signal,
      });
      if (manualCompactionCancelControllerRef.current === chatRequestController) {
        return;
      }
      if (priorityCommandCancelControllerRef.current === chatRequestController) {
        return;
      }
      if (topicResetForSend) {
        pendingNvmTopicResetRef.current = false;
      }
      const activeInitialStarterRequest = zenInitialStarterRequestId
        ? zenInitialStarterRequestRef.current
        : null;
      if (
        activeInitialStarterRequest?.id === zenInitialStarterRequestId &&
        activeInitialStarterRequest.cancelled
      ) {
        if (activeInitialStarterRequest.replayWhenReady) {
          commitZenInitialStarterEnvelope(d, { consumeCache: true });
        } else {
          cacheZenInitialStarterReply(d);
          setChatAutoRestoreSuppressed(true);
        }
        return;
      }
      captureFallbackMessageIdFromEnvelope(d);
      pushMemoryToasts(d.memoryLearned);
      appendDevChatDebugLines(collectDebugLinesFromEnvelope(d, "send"));
      options.onZenAutonomyResult?.(d.zenAutonomyDecision ?? null);
      successfulConversationId = d.conversation.id;
      if (
        view === "chat" &&
        requestStartedNewConversation &&
        !d.conversation.incognito
      ) {
        zenFallbackWallpaperSeedByConversationIdRef.current.set(
          d.conversation.id,
          zenFallbackWallpaperNewConversationSeedRef.current
        );
      }
      if (sessionResumeContextForSend) {
        if (pendingZenSessionResumeContextForSend) {
          const nextSessionBreak = pendingZenSessionBreakForSend
            ? {
                ...pendingZenSessionBreakForSend,
                conversationId: d.conversation.id,
                anchorMessageId: null,
                anchorMessageCount: 0,
                resumeHintConsumed: true,
              }
            : null;
          setPendingZenSessionBreak(null);
          setPendingZenSessionResumeContext(null);
          setZenSessionBreak(nextSessionBreak);
          persistZenSessionBreak(nextSessionBreak);
        } else {
          setZenSessionBreak((current) => {
            if (!current || current.conversationId !== d.conversation.id) return current;
            const next = { ...current, resumeHintConsumed: true };
            persistZenSessionBreak(next);
            return next;
          });
        }
      }
      if (
        (d.summaryCompaction?.mode === "sandbox" || d.summaryCompaction?.mode === "chat") &&
        d.summaryCompaction.triggered
      ) {
        const summaryRefreshMode: ChatLikeSummaryMode =
          d.summaryCompaction.mode === "chat" ? "chat" : "sandbox";
        setSandboxSummaryBusy(true);
        window.setTimeout(() => {
          setSandboxSummaryBusy(false);
          void refreshSummaryDebug(summaryRefreshMode);
        }, 1300);
      }
      const stillViewingRequest = requestConversationId
        ? selectedIdRef.current === requestConversationId ||
          detailIdRef.current === requestConversationId
        : selectedIdRef.current === null && detailIdRef.current === "pending";
      const zenAutonomySpoke =
        isZenAutonomy && d.zenAutonomyDecision?.action === "speak";
      if (stillViewingRequest) {
        const patchedConversation = attachLivePsychicScratchpadToConversation(
          applyCommandDisplayAliases(applyExplicitAskQuestionFallback(d.conversation)),
          d.psychicDebug,
          psychicTextEnabledForConversation(d.conversation, {
            productChatSurface: view === "chat",
          })
        );
        if (isInitialZenStarterPrompt) {
          zenInitialStarterLiveEnvelopeRef.current = {
            ...d,
            conversation: patchedConversation,
          };
        }
        let latestRevealKey: string | null = null;
        if (!isZenAutonomy || zenAutonomySpoke) {
          const transitionRevealStartAt =
            resolveZenPersonaTransitionRevealStartAt(options.personaTransition);
          latestRevealKey = markLatestAssistantRevealEligible(
            patchedConversation,
            transitionRevealStartAt === undefined
              ? {}
              : { firstSeenAtMs: transitionRevealStartAt }
          );
        }
        if (options.personaTransition?.style === "previous-introduces") {
          if (latestRevealKey) {
            registerZenPersonaPresenceIntroReveal(
              options.personaTransition,
              latestRevealKey
            );
          } else {
            const activeTransition = zenPersonaPresenceRef.current.transition;
            if (
              activeTransition &&
              activeTransition.style === "previous-introduces" &&
              activeTransition.fromBotId === options.personaTransition.fromBotId &&
              activeTransition.toBotId === options.personaTransition.toBotId
            ) {
              startZenPersonaPresenceDeparture(activeTransition);
            }
          }
        }
        const pendingCleanupIdsForReveal = [
          ...(optimisticPromptCleanupMessageId ? [optimisticPromptCleanupMessageId] : []),
          ...(options.zenFollowupCleanupMessageIds ?? []),
        ];
        const cleanupRevealKeys =
          pendingCleanupIdsForReveal.length > 0
            ? mapPendingCleanupMessagesToFinalRevealKeys({
                conversationId: patchedConversation.id,
                pendingMessageIds: pendingCleanupIdsForReveal,
                previousMessages: previousDetail?.messages ?? [],
                finalMessages: patchedConversation.messages,
              })
            : [];
        startCleanupMessageReveal(cleanupRevealKeys);
        if (view === "chat") {
          if (!isZenAutonomy || zenAutonomySpoke) {
            hardResetChatArchiveStateForConversation(d.conversation.id);
          }
          setZenPersonaBotId(
            options.personaTransition
              ? options.personaTransition.toBotId
              : isZenAutonomy && d.zenAutonomyDecision?.action !== "speak"
                ? zenPersonaBotIdRef.current
              : patchedConversation.hubBotId ?? patchedConversation.lastBotId ?? null
          );
        }
        setDetail(patchedConversation);
        wirePendingImageJobFromEnvelope(d, {
          stillViewing: stillViewingRequest,
          activeConversationId: d.conversation.id,
        });
        setSessionOpinion(d.opinion ?? null);
        setBotOpinion(d.botOpinion ?? null);
        setSelectedId(d.conversation.id);
        if (d.conversation.incognito) {
          const generatedIds = collectGeneratedImageIds(d.conversation.messages);
          if (generatedIds.length > 0) {
            setImagePrivateGeneratedIds((current) => {
              const next = new Set(current);
              for (const id of generatedIds) next.add(id);
              return next.size === current.length ? current : [...next];
            });
          }
        }
        setUnreadConversationIds(previous => {
          if (!previous.has(d.conversation.id)) return previous;
          const next = new Set(previous);
          next.delete(d.conversation.id);
          return next;
        });
        setUnreadConversationOrder(previous =>
          previous.includes(d.conversation.id)
            ? previous.filter(id => id !== d.conversation.id)
            : previous
        );
        clearPendingReplyVisuals();
      } else if (!d.conversation.incognito) {
        setUnreadConversationIds(previous => {
          const next = new Set(previous);
          next.add(d.conversation.id);
          return next;
        });
        setUnreadConversationOrder(previous =>
          previous.includes(d.conversation.id)
            ? previous
            : [...previous, d.conversation.id]
        );
      }
      if (stillViewingRequest && isStarterPrompt) {
        if (
          Array.isArray(d.conversationStarters) &&
          d.conversationStarters.length >= 4
        ) {
          setStarterComposerRevealed(false);
          setConversationStarterPrompts({
            conversationId: d.conversation.id,
            prompts: d.conversationStarters.slice(0, 4),
            assistantMessageId: getLatestAssistantMessageId(d.conversation.messages),
          });
        } else {
          setStarterComposerRevealed(false);
          setConversationStarterPrompts(null);
        }
      }
      // Pending private intent has now become the open detail returned by
      // the server. For private chats that detail is ephemeral, not a saved
      // conversation row, but detail.incognito keeps the UI isolated.
      if (pendingIncognito && stillViewingRequest) setPendingIncognito(false);
      // Server truth now reflects the user's pick, so the mid-thread
      // override is redundant — drop it so the dropdown goes back to
      // mirroring detail.botId cleanly. Only fires when an override was
      // actually set (keeps the state update a no-op in the common case).
      if (chatBotOverride !== undefined && stillViewingRequest) setChatBotOverride(undefined);
      const refreshedConversations = await refreshConversations();
      // Auto-drill into the new chat's bot panel after a brand-new chat
      // commits. Two halves of the same rule:
      //   • new chat with bot X and X has 2+ saved chats now (group exists)
      //     → open `bot:X` panel so the user lands inside it.
      //   • new chat with no bot, or a bot that doesn't form a group yet
      //     → close any open group panel so the new chat stays visible at
      //     the top level instead of being hidden behind a stale drill-in.
      // Gated on `stillViewingRequest` so a backgrounded send that lands
      // after the user navigated elsewhere never yanks the sidebar. The
      // functional setter makes the "already viewing this bot's panel"
      // case a free no-op.
      if (
        stillViewingRequest &&
        requestStartedNewConversation &&
        !d.conversation.incognito
      ) {
        const newBotId = d.conversation.botId;
        let nextOpenKey: string | null = null;
        if (newBotId) {
          const sameBotCount = refreshedConversations.filter(
            (c) => c.botId === newBotId && !c.incognito,
          ).length;
          if (sameBotCount >= 2) {
            nextOpenKey = conversationGroupKeyForBotId(newBotId);
          }
        }
        setExpandedConversationGroupKey((prev) =>
          prev === nextOpenKey ? prev : nextOpenKey,
        );
      }
      if (
        !d.conversation.incognito &&
        d.conversation.messages.filter((message) => message.role === "assistant").length === 1
      ) {
        for (const delayMs of AUTO_TITLE_REFRESH_DELAYS_MS) {
          window.setTimeout(() => {
            void refreshConversations();
          }, delayMs);
        }
      }
      await refreshOpenMemoryViews();
      if (stillViewingRequest) {
        const nextBotId =
          options.personaTransition?.toBotId ??
          d.conversation.hubBotId ??
          d.conversation.lastBotId ??
          d.conversation.botId;
        if (memoryPanelScope === "default") {
          await refreshPrismMemoryPanel();
        } else if (memoryPanelScope === "session") {
          await refreshZenSessionMemory();
        } else if (nextBotId) {
          await refreshBotMemories(nextBotId);
        } else {
          setBotMemories([]);
          setBotMemoryDossier(null);
        }
      }
    } catch (err) {
      const stillViewingRequest = requestConversationId
        ? selectedIdRef.current === requestConversationId ||
          detailIdRef.current === requestConversationId
        : selectedIdRef.current === null && detailIdRef.current === "pending";
      const requestWasAborted =
        chatRequestController.signal.aborted ||
        (err instanceof DOMException && err.name === "AbortError") ||
        (err instanceof Error && /abort/i.test(err.message));
      const requestWasZenInitialThinkingCancelled =
        zenInitialThinkingCancelControllerRef.current === chatRequestController;
      const requestWasManualCompactionCancelled =
        manualCompactionCancelControllerRef.current === chatRequestController;
      const requestWasPriorityCommandCancelled =
        priorityCommandCancelControllerRef.current === chatRequestController;
      if (requestWasAborted) {
        if (requestWasManualCompactionCancelled || requestWasPriorityCommandCancelled) {
          clearComposerDraftNow();
        } else if (stillViewingRequest || requestWasZenInitialThinkingCancelled) {
          setDetail(requestWasZenInitialThinkingCancelled ? null : previousDetail);
          setPendingIncognito(previousPendingIncognito);
          setZenPersonaBotId(previousZenPersonaBotId);
          settleZenPersonaPresence(previousZenPersonaBotId);
          if (!preserveComposerDraft) {
            setComposerDraftNow(
              isStarterPrompt || requestWasZenInitialThinkingCancelled
                ? ""
                : restoreDraftAfterSendStops
            );
            setComposerSendTintActive(
              !isStarterPrompt &&
                !requestWasZenInitialThinkingCancelled &&
                restoreDraftAfterSendStops.trim().length > 0
            );
          }
          if (requestWasZenInitialThinkingCancelled) {
            setSelectedId(null);
            setConversationStarterPrompts(null);
            setChatStartupSummary(null);
            chatSummaryRefreshMarkerRef.current = null;
            setComposerPrimed(false);
          }
        }
        setError(null);
        return;
      }
      if (forceNewConversation) {
        setForceNewConversationOnNextSend(true);
      }
      if (pendingZenSessionResumeContextForSend) {
        setChatAutoRestoreSuppressed(true);
        setChatStartupSummary(
          pendingZenSessionResumeContextForSend.summary ?? DEFAULT_CHAT_STARTUP_SUMMARY
        );
        chatSummaryRefreshMarkerRef.current = null;
      }
      if (stillViewingRequest) {
        setDetail(previousDetail);
        setPendingIncognito(previousPendingIncognito);
        setZenPersonaBotId(previousZenPersonaBotId);
        settleZenPersonaPresence(previousZenPersonaBotId);
        if (!preserveComposerDraft) {
          setComposerDraftNow(isStarterPrompt ? "" : restoreDraftAfterSendStops);
          setComposerSendTintActive(
            !isStarterPrompt && restoreDraftAfterSendStops.trim().length > 0
          );
        }
      }
      setError(
        err instanceof Error
          ? err.message
          : "Send failed. Verify the provider is reachable and try again."
      );
    } finally {
      if (manualCompactionCancelControllerRef.current === chatRequestController) {
        manualCompactionCancelControllerRef.current = null;
      }
      if (priorityCommandCancelControllerRef.current === chatRequestController) {
        priorityCommandCancelControllerRef.current = null;
      }
      if (zenInitialThinkingCancelControllerRef.current === chatRequestController) {
        zenInitialThinkingCancelControllerRef.current = null;
      }
      if (zenInitialStarterRequestRef.current?.controller === chatRequestController) {
        zenInitialStarterRequestRef.current = null;
      }
      clearPendingReplyVisuals();
      if (optimisticPromptCleanupMessageId) {
        const cleanupMessageId = optimisticPromptCleanupMessageId;
        setPendingMessageCleanupMessageIds((current) => {
          if (!current.has(cleanupMessageId)) return current;
          const next = new Set(current);
          next.delete(cleanupMessageId);
          return next;
        });
      }
      if (successfulConversationId) {
        clearPendingMessageCleanupIds(options.zenFollowupCleanupMessageIds ?? []);
        scheduleNextQueuedPrompt(successfulConversationId);
      }
    }
  }

  function updateManualAskQuestionOption(index: number, value: string): void {
    setManualAskQuestionModal((current) => {
      if (!current) return current;
      const nextOptions = [...current.options];
      const splitOptions = splitManualAskQuestionOptionText(value);
      if (splitOptions.length > 1) {
        nextOptions.splice(index, 1, ...splitOptions);
        return {
          ...current,
          options: ensureManualAskQuestionOptionRows(
            nextOptions.slice(0, MANUAL_ASK_QUESTION_OPTION_COUNT_MAX)
          ),
        };
      }
      nextOptions[index] = value;
      return {
        ...current,
        options: nextOptions.slice(0, MANUAL_ASK_QUESTION_OPTION_COUNT_MAX),
      };
    });
  }

  function addManualAskQuestionOption(): void {
    setManualAskQuestionModal((current) => {
      if (!current || current.options.length >= MANUAL_ASK_QUESTION_OPTION_COUNT_MAX) {
        return current;
      }
      return { ...current, options: [...current.options, ""] };
    });
  }

  function removeManualAskQuestionOption(index: number): void {
    setManualAskQuestionModal((current) => {
      if (!current || current.options.length <= MANUAL_ASK_QUESTION_OPTION_COUNT_MIN) {
        return current;
      }
      return {
        ...current,
        options: current.options.filter((_, optionIndex) => optionIndex !== index),
      };
    });
  }

  function manualAskQuestionPayload(): ReturnType<typeof buildManualAskQuestionPayload> {
    if (!manualAskQuestionModal) return null;
    return buildManualAskQuestionPayload(
      manualAskQuestionModal.question,
      manualAskQuestionModal.options
    );
  }

  async function submitManualAskQuestionModal(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const payload = manualAskQuestionPayload();
    if (!payload) {
      setError("Add a question before asking.");
      return;
    }
    const manualTool: ChatManualToolRequest = {
      name: "askQuestion",
      question: payload.question,
      ...(payload.options ? { options: payload.options } : {}),
    };
    setManualAskQuestionModal(null);
    setError(null);
    await sendMessage(event, {
      draftOverride: payload.question,
      manualToolOverride: manualTool,
    });
  }

  type ComposerChip = {
    id: string;
    label: string;
    /** Secondary line for chips that need compact supporting context. */
    sublabel?: string;
    action: "send" | "other";
    otherSource?: "askquestion" | "starter" | "story";
    sendValue?: string;
    promptInputOverride?: string;
  };

  type AskQuestionInteraction = {
    askQuestion: NonNullable<Message["askQuestion"]>;
    assistantMessageId: string;
    source: "askquestion" | "starter";
  };

  type StoryActionInteraction = {
    tellFictionalStory: NonNullable<Message["tellFictionalStory"]>;
    assistantMessageId: string;
  };

  type ComposerChipRail = {
    conversationId: string;
    chips: ComposerChip[];
    heading: string | null;
    source: "askquestion" | "starter" | "story";
    collapsed: boolean;
  };

  function storyChipLabel(label: string | null | undefined, fallback: string): string {
    const cleaned = label?.replace(/\s+/g, " ").trim() ?? "";
    return cleaned.length > 0 ? cleaned : fallback;
  }

  function buildTellFictionalStoryChips(
    story: NonNullable<Message["tellFictionalStory"]>
  ): ComposerChip[] {
    const continueLabel = storyChipLabel(story.continueLabel, "Keep Going");
    const bookmarkLabel = storyChipLabel(story.bookmarkLabel, "Bookmark");
    const finishLabel = storyChipLabel(story.finishLabel, "End Story");
    return [
      {
        id: "continue-story",
        label: continueLabel,
        action: "send",
        sendValue: continueLabel,
        promptInputOverride: `${continueLabel}\n\nContinue the fictional story from the previous story passage. Start from where it left off; do not recap unless the story naturally needs a brief bridge.`,
      },
      {
        id: "bookmark-story",
        label: bookmarkLabel,
        sublabel: "Save my place",
        action: "send",
        sendValue: bookmarkLabel,
        promptInputOverride: `${bookmarkLabel}\n\nBookmark the current place in the fictional story from the previous passage. Briefly note the current scene, key characters, unresolved threads, and where to resume.`,
      },
      {
        id: "finish-story",
        label: finishLabel,
        action: "send",
        sendValue: finishLabel,
        promptInputOverride: `${finishLabel}\n\nWrap up the fictional story from the previous passage. Resolve the active scene naturally, then provide the full prose of the story so far in one Markdown code block for easy copy-paste.`,
      },
    ];
  }

  function getStoryActionInteractionForMessage(msg: Message): StoryActionInteraction | null {
    if (!detail || msg.role !== "assistant" || !msg.tellFictionalStory) return null;
    const messageIndex = detail.messages.findIndex((message) => message.id === msg.id);
    if (messageIndex < 0) return null;
    const answerMessage =
      detail.messages
        .slice(messageIndex + 1)
        .find((message) => message.role === "user") ?? null;
    if (answerMessage) return null;
    return {
      tellFictionalStory: msg.tellFictionalStory,
      assistantMessageId: msg.id,
    };
  }

  function buildAskQuestionChips(
    askQuestion: NonNullable<Message["askQuestion"]>,
    _source: "askquestion" | "starter" = "askquestion"
  ): ComposerChip[] {
    return askQuestion.options.map((option, index) => {
      const cleaned = stripEmojiFromAskQuestionLabel(option.label);
      const fallback = `Option ${index + 1}`;
      const label = suggestedReplyLooksInternalChoiceNarration(cleaned)
        ? fallback
        : cleaned || fallback;
      const sendValue = label.trim();
      return {
        id: option.id,
        label,
        action: "send" as const,
        // Preserve the authored option text unless a model leaked internal
        // selection narration such as "the user chose...".
        sendValue: sendValue || fallback,
      };
    });
  }

  function buildStarterAskQuestion(msg: Message): NonNullable<Message["askQuestion"]> | null {
    if (
      !detail ||
      !conversationStarterPrompts ||
      conversationStarterPrompts.conversationId !== detail.id
    ) {
      return null;
    }
    const anchorAssistant = findConversationStarterAnchorMessage(
      detail.messages,
      conversationStarterPrompts.assistantMessageId
    );
    if (!anchorAssistant || anchorAssistant.id !== msg.id) return null;
    if (hasUserReplyAfterMessage(detail.messages, anchorAssistant.id)) return null;
    const options = conversationStarterPrompts.prompts
      .slice(0, 4)
      .map((prompt, index) => ({
        id: String.fromCharCode(97 + index),
        label: prompt.trim(),
      }))
      .filter((option) => option.label.length > 0);
    if (options.length !== 4) return null;
    return {
      v: 1,
      name: "AskQuestion",
      prompt: "Choose a reply:",
      options,
    };
  }

  function renderComposerChipContent(
    chip: ComposerChip,
    options: { splitAskQuestionLabels: boolean } = { splitAskQuestionLabels: false }
  ): React.ReactNode {
    if (chip.sublabel) {
      return (
        <span className={styles.conversationStarterChipStack}>
          <span className={styles.conversationStarterChipPrimary}>{chip.label}</span>
          <span className={styles.conversationStarterChipSub}>{chip.sublabel}</span>
        </span>
      );
    }
    if (options.splitAskQuestionLabels && chip.action !== "other") {
      const { title, detail } = splitAskQuestionOptionHeading(chip.label);
      if (detail) {
        return (
          <span className={styles.conversationStarterChipStack}>
            <span className={styles.conversationStarterChipPrimary}>{title}</span>
            <span className={styles.conversationStarterChipSub}>{detail}</span>
          </span>
        );
      }
    }
    return chip.label;
  }

  function getAskQuestionInteractionForMessage(msg: Message): AskQuestionInteraction | null {
    if (!detail || msg.role !== "assistant") return null;
    const askQuestion = resolveAssistantAskQuestion(msg);
    if (
      askQuestion &&
      askQuestion.name === "AskQuestion" &&
      askQuestion.options.length >= 2 &&
      askQuestion.options.length <= 4
    ) {
      const messageIndex = detail.messages.findIndex((message) => message.id === msg.id);
      if (messageIndex < 0) return null;
      const answerMessage =
        detail.messages
          .slice(messageIndex + 1)
          .find((message) => message.role === "user") ?? null;
      if (answerMessage) {
        return null;
      }
      if (pendingAskQuestionState?.assistantMessageId !== msg.id) return null;
      if (pendingAskQuestionWaitingForReveal) return null;
      return {
        askQuestion,
        assistantMessageId: msg.id,
        source: "askquestion",
      };
    }

    if (starterPromptsWaitingForReveal) return null;
    const starterAskQuestion = buildStarterAskQuestion(msg);
    if (!starterAskQuestion) return null;
    return {
      askQuestion: starterAskQuestion,
      assistantMessageId: msg.id,
      source: "starter",
    };
  }

  function handleComposerChipPointerDown(
    event: React.PointerEvent<HTMLButtonElement>,
    chip: ComposerChip
  ): void {
    if (chip.action !== "other") return;
    if (pendingReply) return;
    event.preventDefault();
    event.stopPropagation();
    revealChoiceComposerForOther(chip.otherSource, { flushRender: true });
  }

  function handleComposerChipPick(chip: ComposerChip): void {
    if (chip.action === "other") {
      revealChoiceComposerForOther(chip.otherSource);
      return;
    }
    hideZenHeaderForConversationAction();
    resumeChatModeAutoscrollForOutgoingTurn(detail?.id ?? selectedId);
    setConversationStarterPrompts(null);
    setStarterComposerRevealed(false);
    const syntheticSubmit = {
      preventDefault: () => {
        /* no-op — used so sendMessage can share the submit pathway */
      },
    } as React.FormEvent<HTMLFormElement>;
    void sendMessage(syntheticSubmit, {
      draftOverride: chip.sendValue ?? chip.label,
      ...(chip.promptInputOverride
        ? { promptInputOverride: chip.promptInputOverride }
        : {}),
    });
  }

  async function resendUserMessage(msg: Message): Promise<void> {
    if (msg.role !== "user") return;
    const commandAlias = commandDisplayByMessageIdRef.current.get(msg.id);
    const resendText = resendDraftTextForMessage({
      content: msg.content,
      commandAliasOriginalText: commandAlias?.originalText,
      promptShortcutTemplate: msg.promptShortcut?.template,
      promptWildcardTemplate: msg.promptWildcards?.template,
    });
    if (resendText.length === 0) return;
    closeMessageContextOverlay();
    // Force normal send mode if an edit draft was active.
    setEditingMessageId(null);
    setEditingOriginalText("");
    if (
      view === "chat" &&
      detail &&
      !detail.incognito &&
      !String(msg.id).startsWith("pending-")
    ) {
      try {
        const forkedConversation = await forkConversationFromMessage(msg.id, {
          includeMessage: false,
          mode: "zen",
        });
        const syntheticSubmit = {
          preventDefault: () => {
            /* no-op — used so sendMessage can share the submit pathway */
          },
        } as React.FormEvent<HTMLFormElement>;
        void sendMessage(syntheticSubmit, {
          draftOverride: resendText,
          queuedConversationId: forkedConversation.id,
          conversationDetailOverride: forkedConversation,
        });
      } catch (err) {
        setError(err instanceof Error ? err.message : "Message resend failed.");
      }
      return;
    }
    // Sandbox: rewind from this user message so the visible thread AND the
    // server-side conversation both drop everything after it before the
    // resend lands as a fresh turn. This piggybacks on the Edit pipeline
    // (rewind → /api/chat) with the same text, so message rows and
    // thread-scoped memory summaries are truncated in lockstep with the UI.
    // Chat mode keeps its append-duplicate behavior here because chat
    // history is the user's persistent record — only Sandbox treats Resend
    // as a "rewind to this point" gesture.
    if (view === "sandbox") {
      if (String(msg.id).startsWith("pending-")) {
        const syntheticSubmit = {
          preventDefault: () => {
            /* no-op — same as chat resend: plain send without /rewind */
          },
        } as React.FormEvent<HTMLFormElement>;
        void sendMessage(syntheticSubmit, { draftOverride: resendText });
        return;
      }
      void performMessageEdit(msg.id, resendText);
      return;
    }
    const syntheticSubmit = {
      preventDefault: () => {
        /* no-op — used so sendMessage can share the submit pathway */
      },
    } as React.FormEvent<HTMLFormElement>;
    void sendMessage(syntheticSubmit, { draftOverride: resendText });
  }

  function randomChatNudgeFromContext(): string {
    const activeBotId =
      chatBotOverride !== undefined
        ? chatBotOverride
        : detail?.id !== undefined && detail.id !== "pending"
          ? detail.botId
          : (detail?.botId ?? selectedBotId ?? null);
    const activeBotName =
      activeBotId !== null
        ? bots.find((candidate) => candidate.id === activeBotId)?.name ?? "this bot"
        : "you";
    const latestAssistant = [...(detail?.messages ?? [])]
      .reverse()
      .find((message) => message.role === "assistant");
    if (!detail || detail.messages.length === 0) {
      return randomArrayItem([
        "What is one small thing worth being curious about today?",
        "Tell me something oddly specific that might make me think.",
        "Help me choose a tiny direction for the next ten minutes.",
        "What is a question I probably have not thought to ask yet?",
        "Give me a strange-but-useful idea to play with.",
        "Start with something simple and unexpectedly interesting.",
      ]);
    }
    const candidateTopicWords =
      latestAssistant?.content
        .toLowerCase()
        .replace(/[^a-z0-9\s]/g, " ")
        .split(/\s+/)
        .filter((word) => word.length >= 5)
        .filter((word) => !RANDOM_NUDGE_STOP_WORDS.has(word)) ?? [];
    const topicSeed = candidateTopicWords[0] ?? "that";
    const templates = [
      `That makes me wonder: what is the most useful angle on ${topicSeed}?`,
      `Can you say more about ${topicSeed}, but keep it practical?`,
      `I want to push on ${topicSeed} a little. What am I missing?`,
      `Could you give me a concrete example of ${topicSeed}?`,
      `Let's take that somewhere more specific with ${activeBotName}.`,
      "I like that direction. Give me one small next step.",
    ];
    return randomArrayItem(templates);
  }

  function buildComposerRandomPromptRecentMessages(): Array<{
    role: "user" | "assistant";
    content: string;
    botName?: string;
  }> {
    return (detail?.messages ?? [])
      .slice(-8)
      .map((message) => {
        const content = resolveMessageDisplayContent(message).trim();
        if (!content) return null;
        return {
          role: message.role,
          content,
          ...(message.botName ? { botName: message.botName } : {}),
        };
      })
      .filter(
        (message): message is { role: "user" | "assistant"; content: string; botName?: string } =>
          message !== null
      );
  }

  async function synthesizeRandomConversationNudge(fallbackPrompt: string): Promise<string> {
    try {
      const activePromptBotId =
        composeBotAccentId ??
        (view === "sandbox" ? selectedBotId : null);
      const requestBody = {
        ...buildChatRequestBody("", {}),
        ...(activePromptBotId !== null ? { botId: activePromptBotId } : {}),
        recentMessages: buildComposerRandomPromptRecentMessages(),
      };
      const response = await api<{
        prompt?: string;
        provider?: Provider;
        model?: string;
      }>("/api/composer/random-prompt", {
        method: "POST",
        body: JSON.stringify(requestBody),
      });
      const prompt = response.prompt?.trim();
      return prompt && prompt.length > 0 ? prompt : fallbackPrompt;
    } catch {
      return fallbackPrompt;
    }
  }

  /** Quick chips: Prism AskQuestion (if pending) beats server “Talk to me” prompts. Single UI path. */
  function getComposerChipRail(): ComposerChipRail | null {
    const id = detail?.id;
    if (!detail || id === undefined || id === "pending") return null;
    const qa = pendingAskQuestion;
    if (qa && pendingAskQuestionWaitingForReveal) return null;
    if (qa) {
      return {
        conversationId: id,
        chips: buildAskQuestionChips(qa, "askquestion"),
        heading: normalizeAskQuestionText(qa.prompt) || null,
        source: "askquestion",
        collapsed: false,
      };
    }
    const latestAssistantForStory = [...detail.messages]
      .reverse()
      .find((message) => message.role === "assistant");
    const storyInteraction = latestAssistantForStory
      ? getStoryActionInteractionForMessage(latestAssistantForStory)
      : null;
    if (storyInteraction) {
      return {
        conversationId: id,
        chips: buildTellFictionalStoryChips(storyInteraction.tellFictionalStory),
        heading: "Story actions",
        source: "story",
        collapsed: false,
      };
    }
    if (
      conversationStarterPrompts &&
      conversationStarterPrompts.conversationId === id &&
      conversationStarterPrompts.prompts.length > 0
    ) {
      if (starterPromptsWaitingForReveal) return null;
      const latestAssistant = [...detail.messages]
        .reverse()
        .find((message) => message.role === "assistant");
      const starterAskQuestion = latestAssistant
        ? buildStarterAskQuestion(latestAssistant)
        : null;
      if (!starterAskQuestion) return null;
      return {
        conversationId: id,
        chips: buildAskQuestionChips(starterAskQuestion, "starter"),
        heading: null,
        source: "starter",
        collapsed: false,
      };
    }
    return null;
  }

  function renderComposerChipRail(): React.ReactNode {
    const rail = getComposerChipRail();
    if (!rail) return null;
    if (viewportWidth > PICKER_MOBILE_BREAKPOINT) {
      return null;
    }

    if (rail.collapsed) {
      const rawHex = activeBot?.color?.trim();
      const accentHex = rawHex
        ? normalizeAccentForTheme(rawHex, resolvedTheme)
        : resolvedTheme === "light"
          ? "#64748b"
          : "#94a3b8";
      const shadeTarget = resolvedTheme === "light" ? "#ffffff" : "#000000";
      const shade = mixHex(accentHex, shadeTarget, 0.38);
      const bubbleStyle = {
        "--memory-bubble-size": "52px",
        "--memory-bubble-color": shade,
        "--memory-bubble-source-color": accentHex,
        "--memory-bubble-ink": pickReadableText(shade),
        "--memory-bubble-glow": accentHex,
        "--memory-bubble-tilt": "0deg",
        "--memory-bubble-z": "6",
        "--memory-bubble-font-size": "1.35rem",
        "--memory-bubble-line-count": 1,
      } as React.CSSProperties;

      return (
        <div className={styles.askQuestionRecallBubbleDock} data-dev-panel-safe-area="bottom">
          <button
            type="button"
            className={`${styles.memoryBubble} ${styles.askQuestionRecallBubble}`}
            data-clickable="true"
            style={bubbleStyle}
            aria-label="Show suggested replies"
            title="Show suggested replies"
            disabled={pendingReply && view !== "chat"}
            onClick={() => {
              if (rail.source === "starter") {
                setStarterComposerRevealed(false);
              } else {
                askQuestionComposerHiddenForReadingKeyRef.current = null;
                setAskQuestionComposerRevealed(false);
              }
            }}
          >
            ?
          </button>
        </div>
      );
    }

    if (choiceChipRailComposerRevealed) {
      const prompt =
        rail.heading ??
        (rail.source === "starter" ? "Choose a reply:" : "Choose a reply");
      return (
        <div
          ref={askQuestionRailRef}
          className={styles.askQuestionCollapsedPromptDock}
          data-dev-panel-safe-area="bottom"
          data-ask-question-collapsed-prompt="true"
          role="status"
          aria-live="polite"
        >
          <p className={styles.askQuestionCollapsedPromptText}>{prompt}</p>
          {askQuestionPatienceAssistantMessageId
            ? renderAskQuestionPatienceMeter(askQuestionPatienceAssistantMessageId, "dock")
            : null}
        </div>
      );
    }

    const railClassName = `${styles.conversationStarterRail} ${styles.askQuestionRail}`;
    return (
      <div
        ref={askQuestionRailRef}
        role="group"
        aria-label="Suggested replies"
        className={railClassName}
        data-dev-panel-safe-area="bottom"
      >
        {rail.source === "askquestion" || rail.source === "story" ? (
          <div className={styles.conversationStarterHeadingRow}>
            {rail.heading ? (
              <p className={styles.conversationStarterChipHeading}>{rail.heading}</p>
            ) : (
              <span aria-hidden="true" />
            )}
            <button
              type="button"
              className={styles.askQuestionDismissButton}
              aria-label="Hide suggested replies"
              title="Hide suggested replies"
              disabled={pendingReply}
              onClick={() => setAskQuestionComposerRevealed(true)}
            >
              <X size={15} strokeWidth={2.4} aria-hidden="true" />
            </button>
          </div>
        ) : rail.heading ? (
          <p className={styles.conversationStarterChipHeading}>{rail.heading}</p>
        ) : null}
        {askQuestionPatienceAssistantMessageId
          ? renderAskQuestionPatienceMeter(askQuestionPatienceAssistantMessageId, "rail")
          : null}
        {rail.chips.map((chip, chipIndex) => (
          <button
            key={`${chip.id}-${chip.label.slice(0, 48)}-${chipIndex}`}
            type="button"
            disabled={pendingReply && view !== "chat"}
            className={styles.conversationStarterChip}
            data-chip-kind={chip.action}
            aria-label={`Suggested reply: ${chip.sendValue ?? chip.label}`}
            onPointerDown={(event) => handleComposerChipPointerDown(event, chip)}
            onClick={() => handleComposerChipPick(chip)}
          >
            {renderComposerChipContent(chip, {
              splitAskQuestionLabels: true,
            })}
          </button>
        ))}
      </div>
    );
  }

  function renderPsychicThoughtLine(msg: Message): React.ReactNode {
    if (isZenSurfaceView(view)) {
      return null;
    }
    if (!psychicTextEnabledForConversation(detail, { productChatSurface: view === "chat" })) {
      return null;
    }
    const pendingThinking = msg.id === psychicThinkingTargetMessageId;
    const psychicLine = psychicThoughtDisplayLineForMessage(msg, {
      pendingThinking,
      pendingDelayElapsed: pendingThinking,
      showScratchpad: devToolsRuntimeActive,
    });
    if (!psychicLine) return null;
    return (
      <div
        className={styles.psychicThoughtBlock}
        data-psychic-state={psychicLine.state}
        data-psychic-animated={psychicLine.animated ? "true" : "false"}
        role={psychicLine.state === "thinking" ? "status" : undefined}
        aria-live={psychicLine.state === "thinking" ? "polite" : undefined}
        aria-label={psychicLine.ariaLabel}
      >
        <span className={styles.psychicThoughtLabel}>{psychicLine.label}</span>
        <p>
          <span className={styles.psychicThoughtText}>{psychicLine.summary}</span>
          {psychicLine.state === "thinking" ? (
            <span className={styles.psychicThoughtShimmer} aria-hidden="true">
              <span />
              <span />
              <span />
            </span>
          ) : null}
        </p>
        {psychicLine.scratchpad ? (
          <div className={styles.psychicScratchpadBlock}>
            <div className={styles.psychicScratchpadHeader}>
              <span className={styles.psychicScratchpadLabel}>Scratchpad</span>
              {psychicLine.scratchpadMeta ? (
                <span className={styles.psychicScratchpadMeta}>
                  {psychicLine.scratchpadMeta}
                </span>
              ) : null}
            </div>
            <pre className={styles.psychicScratchpadText}>
              {psychicLine.scratchpad}
            </pre>
          </div>
        ) : null}
      </div>
    );
  }

  function renderAskQuestionInlineCard(msg: Message): React.ReactNode {
    if (viewportWidth <= PICKER_MOBILE_BREAKPOINT) return null;
    const interaction = getAskQuestionInteractionForMessage(msg);
    if (!interaction) return null;

    const chips = buildAskQuestionChips(interaction.askQuestion, interaction.source);
    const prompt =
      interaction.source === "starter"
        ? ""
        : askQuestionPromptForInlinePanel(interaction.askQuestion.prompt);
    const choicesDisabled = pendingReply;
    return (
      <div
        className={styles.askQuestionInlineCard}
        data-ask-question-panel="true"
        data-ask-question-assistant-id={interaction.assistantMessageId}
        data-ask-question-state="unanswered"
        role="group"
        aria-label="Suggested replies"
        onClick={(event) => event.stopPropagation()}
      >
        <div className={styles.askQuestionInlineHeader}>
          <span className={styles.askQuestionInlineEyebrow}>
            Choose a reply
          </span>
        </div>
        {prompt ? (
          <p className={styles.askQuestionInlinePrompt}>{prompt}</p>
        ) : null}
        {renderAskQuestionPatienceMeter(interaction.assistantMessageId, "inline")}
        <div
          className={styles.askQuestionInlineChoices}
          data-choices-disabled={choicesDisabled ? "true" : undefined}
        >
          {chips.map((chip, chipIndex) => (
            <button
              key={`${interaction.assistantMessageId}-${chip.id}-${chip.label.slice(0, 48)}-${chipIndex}`}
              type="button"
              disabled={choicesDisabled}
              className={styles.conversationStarterChip}
              data-chip-kind={chip.action}
              aria-label={`Suggested reply: ${chip.sendValue ?? chip.label}`}
              onPointerDown={(event) => handleComposerChipPointerDown(event, chip)}
              onClick={() => handleComposerChipPick(chip)}
            >
              {renderComposerChipContent(chip, { splitAskQuestionLabels: true })}
            </button>
          ))}
        </div>
      </div>
    );
  }

  function renderManualAskQuestionResultCard(msg: Message): React.ReactNode {
    if (msg.role !== "user" || !msg.manualAskQuestion) return null;
    const manualAskQuestion = msg.manualAskQuestion;
    if (
      manualAskQuestion.name !== "AskQuestion" ||
      manualAskQuestion.options.length < 2 ||
      manualAskQuestion.options.length > 4
    ) {
      return null;
    }
    const selectedIndex =
      typeof manualAskQuestion.selectedOptionIndex === "number"
        ? manualAskQuestion.selectedOptionIndex
        : manualAskQuestion.options.findIndex(
            (option) => option.id === manualAskQuestion.selectedOptionId
          );
    const selectedOption =
      selectedIndex >= 0 ? manualAskQuestion.options[selectedIndex] : undefined;
    return (
      <div
        className={styles.askQuestionInlineCard}
        data-ask-question-panel="true"
        data-manual-ask-question-panel="true"
        data-ask-question-state={selectedOption ? "other-selected" : "unanswered"}
        role="group"
        aria-label="AskQuestion result"
        onClick={(event) => event.stopPropagation()}
      >
        <div className={styles.askQuestionInlineHeader}>
          <span className={styles.askQuestionInlineEyebrow}>Asked the bot</span>
        </div>
        <p className={styles.askQuestionInlinePrompt}>
          {manualAskQuestion.question}
        </p>
        {selectedOption ? (
          <div className={styles.askQuestionInlineAnswer}>
            <span>Bot picked</span>
            <p>{selectedOption.label}</p>
          </div>
        ) : null}
        <div
          className={styles.askQuestionInlineChoices}
          data-choices-disabled="true"
        >
          {manualAskQuestion.options.map((option, optionIndex) => {
            const selected = selectedIndex === optionIndex;
            return (
              <div
                key={`${msg.id}-${option.id}-${option.label.slice(0, 48)}-${optionIndex}`}
                className={`${styles.conversationStarterChip} ${styles.manualAskQuestionChoice}`}
                data-manual-ask-question-selected={selected ? "true" : undefined}
                aria-current={selected ? "true" : undefined}
              >
                {renderComposerChipContent(
                  {
                    id: option.id,
                    label: option.label,
                    action: "send",
                    sendValue: option.label,
                  },
                  { splitAskQuestionLabels: true }
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  function renderStoryActionInlineCard(msg: Message): React.ReactNode {
    if (viewportWidth <= PICKER_MOBILE_BREAKPOINT) return null;
    const interaction = getStoryActionInteractionForMessage(msg);
    if (!interaction) return null;
    const chips = buildTellFictionalStoryChips(interaction.tellFictionalStory);
    const choicesDisabled = pendingReply;
    return (
      <div
        className={styles.askQuestionInlineCard}
        data-story-action-panel="true"
        data-story-action-assistant-id={interaction.assistantMessageId}
        role="group"
        aria-label="Story actions"
        onClick={(event) => event.stopPropagation()}
      >
        <div className={styles.askQuestionInlineHeader}>
          <span className={styles.askQuestionInlineEyebrow}>Story actions</span>
        </div>
        <div
          className={styles.askQuestionInlineChoices}
          data-choices-disabled={choicesDisabled ? "true" : undefined}
        >
          {chips.map((chip, chipIndex) => (
            <button
              key={`${interaction.assistantMessageId}-${chip.id}-${chip.label.slice(0, 48)}-${chipIndex}`}
              type="button"
              disabled={choicesDisabled}
              className={styles.conversationStarterChip}
              data-chip-kind="story"
              aria-label={`Story action: ${chip.label}`}
              onClick={() => handleComposerChipPick(chip)}
            >
              {renderComposerChipContent(chip, { splitAskQuestionLabels: false })}
            </button>
          ))}
        </div>
      </div>
    );
  }

  function renderImageJobOrbDock(): React.ReactNode {
    const rail = getComposerChipRail();
    if (rail?.collapsed) return null;
    if (!composerImageJobOrb || !detail || detail.id !== composerImageJobOrb.conversationId) {
      return null;
    }
    const rawHex = activeBot?.color?.trim();
    const accentHex = rawHex
      ? normalizeAccentForTheme(rawHex, resolvedTheme)
      : resolvedTheme === "light"
        ? "#64748b"
        : "#94a3b8";
    const shadeTarget = resolvedTheme === "light" ? "#ffffff" : "#000000";
    const shade = mixHex(accentHex, shadeTarget, 0.38);
    const bubbleStyle = {
      "--memory-bubble-size": "52px",
      "--memory-bubble-color": shade,
      "--memory-bubble-source-color": accentHex,
      "--memory-bubble-ink": pickReadableText(shade),
      "--memory-bubble-glow": accentHex,
      "--memory-bubble-tilt": "0deg",
      "--memory-bubble-z": "6",
      "--memory-bubble-font-size": "1.25rem",
      "--memory-bubble-line-count": 1,
    } as React.CSSProperties;
    return (
      <div
        className={`${styles.askQuestionRecallBubbleDock} ${styles.imageJobOrbDock}`}
        data-dev-panel-safe-area="bottom"
      >
        <div
          className={`${styles.memoryBubble} ${styles.askQuestionRecallBubble}`}
          style={bubbleStyle}
          aria-label="Image generating"
          title="Image is generating…"
          role="status"
        >
          <span className={styles.imageJobOrbGlyphWrap} aria-hidden="true">
            <ImageGlyph className={styles.imageJobOrbGlyph} strokeWidth={2} size={22} />
          </span>
        </div>
      </div>
    );
  }

  function removeQueuedPrompt(queueId: string): void {
    setQueuedChatPrompts((previous) => previous.filter((item) => item.id !== queueId));
  }

  function scheduleNextQueuedPrompt(fallbackConversationId: string): void {
    let nextQueuedPrompt:
      | { id: string; text: string; targetConversationId: string | null }
      | undefined;
    setQueuedChatPrompts((previous) => {
      nextQueuedPrompt = previous[0];
      return previous.length > 0 ? previous.slice(1) : previous;
    });
    if (!nextQueuedPrompt || nextQueuedPrompt.text.trim().length === 0) return;
    const queuedConversationId =
      nextQueuedPrompt.targetConversationId ?? fallbackConversationId;
    setDispatchingQueuedPrompt({
      id: nextQueuedPrompt.id,
      text: nextQueuedPrompt.text,
    });
    const queuedPromptDrainGeneration = queuedPromptDrainGenerationRef.current;
    const syntheticSubmit = {
      preventDefault: () => {
        /* no-op — queue drain uses the regular send pipeline */
      },
    } as React.FormEvent<HTMLFormElement>;
    window.setTimeout(() => {
      if (queuedPromptDrainGenerationRef.current !== queuedPromptDrainGeneration) return;
      void sendMessage(syntheticSubmit, {
        draftOverride: nextQueuedPrompt?.text,
        queuedConversationId,
      });
    }, 210);
    window.setTimeout(() => {
      if (queuedPromptDrainGenerationRef.current !== queuedPromptDrainGeneration) return;
      setDispatchingQueuedPrompt((current) =>
        current?.id === nextQueuedPrompt?.id ? null : current
      );
    }, 560);
  }

  useEffect(() => {
    if (!composerImageJobOrb) return;
    if (queuedChatPrompts.length === 0) return;
    if (dispatchingQueuedPrompt) return;
    const activeConversationId =
      detail?.id && detail.id !== "pending"
        ? detail.id
        : selectedId;
    if (!activeConversationId || activeConversationId !== composerImageJobOrb.conversationId) {
      return;
    }
    scheduleNextQueuedPrompt(composerImageJobOrb.conversationId);
  }, [
    composerImageJobOrb,
    queuedChatPrompts,
    dispatchingQueuedPrompt,
    detail?.id,
    selectedId,
  ]);

  function renderQueuedPromptRail(): React.ReactNode {
    if (queuedChatPrompts.length === 0 && !dispatchingQueuedPrompt) return null;
    return (
      <div className={styles.queuedPromptRailDock}>
        <div className={styles.queuedPromptRail} role="list" aria-label="Queued messages">
        {dispatchingQueuedPrompt ? (
          <span
            key={`dispatching-${dispatchingQueuedPrompt.id}`}
            className={`${styles.queuedPromptChip} ${styles.queuedPromptChipDispatching}`}
            role="listitem"
            aria-live="polite"
          >
            <span className={styles.queuedPromptChipLabel}>{dispatchingQueuedPrompt.text}</span>
            <span className={styles.queuedPromptChipMeta}>Sending…</span>
          </span>
        ) : null}
        {queuedChatPrompts.map((item, index) => (
          <button
            key={item.id}
            type="button"
            className={styles.queuedPromptChip}
            role="listitem"
            title="Click to remove from queue"
            onClick={() => removeQueuedPrompt(item.id)}
          >
            <span className={styles.queuedPromptChipLabel}>{item.text}</span>
            <span className={styles.queuedPromptChipMeta}>Queued #{index + 1} · Click to remove</span>
          </button>
        ))}
        </div>
      </div>
    );
  }

  async function sendRandomConversationNudge(): Promise<void> {
    if (pendingReply && !canSendTextWhileReplyPending() && view !== "chat") return;
    if (composerRandomPromptBusy) return;
    const rail =
      detail?.id && detail.id !== "pending"
        ? getComposerChipRail()
        : null;
    const starterPromptChoices =
      rail && detail?.id === rail.conversationId
        ? rail.chips
            .filter((chip) => chip.action === "send")
            .map((chip) => chip.sendValue ?? chip.label)
        : [];
    const chosenPrompt =
      starterPromptChoices.length > 0
        ? randomArrayItem(starterPromptChoices)
        : randomChatNudgeFromContext();
    setComposerRandomPromptBusy(true);
    const synthesizedPrompt = await synthesizeRandomConversationNudge(chosenPrompt);
    setComposerRandomPromptBusy(false);
    const syntheticSubmit = {
      preventDefault: () => {
        /* no-op — used so sendMessage can share the submit pathway */
      },
    } as React.FormEvent<HTMLFormElement>;
    void sendMessage(syntheticSubmit, {
      draftOverride: synthesizedPrompt,
      skipComposerHistory: true,
    });
  }

  useEffect(() => {
    if (view !== "chat") return;
    const pendingCoffeeSubmit = pendingCoffeeGlobalComposerSubmitRef.current;
    if (!pendingCoffeeSubmit) return;
    pendingCoffeeGlobalComposerSubmitRef.current = null;
    if (pendingCoffeeSubmit.randomNudge) {
      void sendRandomConversationNudge();
      return;
    }
    const syntheticSubmit = {
      preventDefault: () => {
        /* no-op - Coffee global composer hands off to the Zen send pipeline */
      },
    } as React.FormEvent<HTMLFormElement>;
    void sendMessage(syntheticSubmit, {
      starterPrompt: pendingCoffeeSubmit.starterPrompt,
      draftOverride: pendingCoffeeSubmit.draft,
    });
  }, [view]);

  function isStarterPromptAvailable(value: string): boolean {
    return value.trim().length === 0 && (!detail || detail.messages.length === 0);
  }

  function isStarterPromptReady(value: string): boolean {
    return composerPrimed && isStarterPromptAvailable(value);
  }

  function assistantRevealStillTyping(message: Message | undefined): boolean {
    if (!chatAssistantTypingMechanicsActive || !detail?.id || !message) return false;
    const revealKey = `${detail.id}:${message.id}`;
    if (!chatAssistantRevealEligibleKeysRef.current.has(revealKey)) return false;
    if (chatCompletedRevealKeysRef.current.has(revealKey)) return false;
    if (chatCancelledRevealTokenCountByKeyRef.current.has(revealKey)) return true;
    const displayContent = resolveVisibleMessageContent(message);
    const tokenTotal = Math.max(1, tokenizeMessageReveal(displayContent).length);
    const visibleTokenCount = resolveAssistantRevealVisibleTokenCount({
      revealKey,
      displayContent,
      nowMs: chatEphemeralNowMs,
      completed: false,
      moodKey: DEFAULT_MESSAGE_MOOD,
      delayMultiplier: resolveZenAssistantRevealDelayMultiplier(revealKey),
      startDelayMs: resolveMessageActionTextLagMs(message),
    });
    return visibleTokenCount < tokenTotal;
  }

  const pendingAskQuestionState = detail
    ? getConversationPendingAskQuestionState(
        detail.messages,
        askQuestionPatienceClosedAssistantMessageIds
      )
    : undefined;
  const pendingAskQuestion = pendingAskQuestionState?.askQuestion;
  const pendingAskQuestionAssistantMessage =
    pendingAskQuestionState
      ? detail?.messages.find(
          (message) => message.id === pendingAskQuestionState.assistantMessageId
        )
      : undefined;
  const pendingAskQuestionWaitingForReveal =
    Boolean(
      chatAssistantTypingMechanicsActive &&
      detail?.id &&
      pendingAskQuestionState &&
      pendingAskQuestionAssistantMessage &&
      (() => {
        if (!pendingAskQuestionAssistantMessage) return false;
        const revealKey = `${detail.id}:${pendingAskQuestionState.assistantMessageId}`;
        if (!chatAssistantRevealEligibleKeysRef.current.has(revealKey)) return false;
        if (chatCompletedRevealKeysRef.current.has(revealKey)) return false;
        if (chatCancelledRevealTokenCountByKeyRef.current.has(revealKey)) return false;
        const displayContent = resolveVisibleMessageContent(pendingAskQuestionAssistantMessage);
        const revealTokens = tokenizeMessageReveal(displayContent);
        const tokenTotal = Math.max(1, revealTokens.length);
        const visibleTokenCount = resolveAssistantRevealVisibleTokenCount({
          revealKey,
          displayContent,
          nowMs: chatEphemeralNowMs,
          completed: false,
          moodKey: DEFAULT_MESSAGE_MOOD,
          delayMultiplier: resolveZenAssistantRevealDelayMultiplier(revealKey),
          startDelayMs: resolveMessageActionTextLagMs(pendingAskQuestionAssistantMessage),
        });
        return visibleTokenCount < tokenTotal;
      })()
    );
  const askQuestionInteractive = pendingAskQuestion !== undefined && !pendingAskQuestionWaitingForReveal;
  const pendingAskQuestionKey =
    pendingAskQuestion && pendingAskQuestionState && detail?.id
      ? buildAskQuestionInteractionKey({
          conversationId: detail.id,
          assistantMessageId: pendingAskQuestionState.assistantMessageId,
          prompt: pendingAskQuestion.prompt,
          options: pendingAskQuestion.options,
        })
      : null;
  const pendingAskQuestionInteractiveKey = askQuestionInteractive ? pendingAskQuestionKey : null;
  const starterPromptsAvailable =
    conversationStarterPrompts !== null &&
    conversationStarterPrompts.conversationId === detail?.id &&
    conversationStarterPrompts.prompts.length > 0;
  const starterPromptsAnchorMessage =
    starterPromptsAvailable && detail
      ? findConversationStarterAnchorMessage(
          detail.messages,
          conversationStarterPrompts.assistantMessageId
        )
      : undefined;
  const starterPromptsAnswered =
    starterPromptsAvailable && detail
      ? hasUserReplyAfterMessage(
          detail.messages,
          starterPromptsAnchorMessage?.id ?? null
        )
      : false;
  const starterPromptsWaitingForReveal =
    starterPromptsAvailable &&
    !starterPromptsAnswered &&
    assistantRevealStillTyping(starterPromptsAnchorMessage);
  const starterPromptsInteractive =
    starterPromptsAvailable &&
    Boolean(starterPromptsAnchorMessage) &&
    !starterPromptsAnswered &&
    !starterPromptsWaitingForReveal;
  const starterPromptCenteredMessageId =
    starterPromptsInteractive && !starterComposerRevealed
      ? starterPromptsAnchorMessage?.id ?? null
      : null;
  const starterPromptsInteractiveKey = starterPromptsInteractive && conversationStarterPrompts
    ? [
        conversationStarterPrompts.conversationId,
        conversationStarterPrompts.assistantMessageId ?? "starter",
        conversationStarterPrompts.prompts.join("|"),
      ].join(":")
    : null;
  const choiceChipRailInteractiveKey =
    pendingAskQuestionInteractiveKey ?? starterPromptsInteractiveKey;
  const choiceChipRailAnchorMessageId =
    pendingAskQuestionInteractiveKey !== null
      ? pendingAskQuestionState?.assistantMessageId ?? null
      : starterPromptsInteractive
        ? starterPromptsAnchorMessage?.id ?? null
        : null;
  const choiceChipRailControlsViewport = shouldChoiceChipRailControlViewport({
    chatSurface: view === "chat",
    anchorMessageId: choiceChipRailAnchorMessageId,
    latestAssistantMessageId,
  });
  const choiceChipRailComposerRevealed =
    pendingAskQuestionInteractiveKey !== null
      ? askQuestionComposerRevealed
      : starterComposerRevealed;
  const activeChoiceComposerSource: "askquestion" | "starter" | null =
    pendingAskQuestionInteractiveKey !== null
      ? "askquestion"
      : starterPromptsInteractive
        ? "starter"
        : null;
  const composerHiddenByChoiceChips = false;
  useEffect(() => {
    if (!chatLikeSurface || composerHiddenByChoiceChips) {
      setZenLiveUserActionPreview(null);
      return;
    }
    const debugDraftActive =
      devToolsRuntimeActive &&
      view === "chat" &&
      !devDebugComposerMinimized &&
      debugComposerDraft.trim().length > 0;
    const previewSource = debugDraftActive ? "debug" : "composer";
    const previewDraft = debugDraftActive ? debugComposerDraft : draft;
    const trimmedDraft = previewDraft.trim();
    const sourceChanged =
      zenLiveUserActionPreviewSourceRef.current !== previewSource;
    zenLiveUserActionPreviewSourceRef.current = previewSource;
    setZenLiveUserActionPreview((previous) =>
      resolvePersistentZenActionPreview(sourceChanged ? null : previous, previewDraft, {
        reset: /^[!/]/u.test(trimmedDraft),
      })
    );
  }, [
    chatLikeSurface,
    composerHiddenByChoiceChips,
    debugComposerDraft,
    devDebugComposerMinimized,
    devToolsRuntimeActive,
    draft,
    view,
  ]);
  const zenComposerActionPreview =
    chatLikeSurface && !composerHiddenByChoiceChips ? zenLiveUserActionPreview : null;
  const zenLiveVisibleBotAction = useMemo<ZenLiveBotActionState | null>(() => {
    if (!zenLiveBotAction) return null;
    return (zenLiveBotAction.botId ?? null) === zenPersonaPresence.visibleBotId
      ? zenLiveBotAction
      : null;
  }, [zenLiveBotAction, zenPersonaPresence.visibleBotId]);
  const zenDefaultPrismPresenceVisible =
    chatLikeSurface &&
    zenPersonaBotId === null &&
    zenPersonaPresence.visibleBotId === null &&
    (!zenEmptyHeroVisible || !sidebarOpen);
  const zenDefaultPrismPresenceForming =
    zenDefaultPrismPresenceVisible &&
    view === "chat" &&
    pendingReplyVisible &&
    pendingReplyStartMessageCount === 0 &&
    detail?.hasAssistantReply !== true;
  const zenLiveAskQuestionMarkerVisible = pendingAskQuestionInteractiveKey !== null;
  const zenLivePresenceRailVisible =
    zenDefaultPrismPresenceVisible ||
    Boolean(
      zenLiveVisibleBotAction ||
        zenComposerActionPreview ||
        zenLivePresenceBot ||
        zenLiveBotTalking ||
        zenLiveAskQuestionMarkerVisible
    ) || zenPersonaPresence.phase !== "stable";
  useEffect(() => {
    setZenLiveUserActionPreview(null);
    setZenLiveBotAction(null);
    zenLiveActionAbortRef.current?.abort();
    if (zenLiveActionIdleTimerRef.current !== null) {
      clearTimeout(zenLiveActionIdleTimerRef.current);
      zenLiveActionIdleTimerRef.current = null;
    }
  }, [selectedId, view, zenPersonaBotId]);
  const requestZenLiveActionReaction = useCallback(
    async (source: "draft_action" | "idle"): Promise<void> => {
      if (
        view !== "chat" ||
        composerHiddenByChoiceChips ||
        pendingReplyVisible ||
        chatAssistantRevealInProgress
      ) {
        return;
      }
      const userCue = zenLiveUserActionPreviewRef.current;
      if (!userCue && source === "draft_action") return;
      const currentActionDraftText =
        source === "draft_action" &&
        zenLiveUserActionPreviewSourceRef.current === "debug"
          ? debugComposerDraftRef.current
          : draftLiveRef.current;
      const activeBotId = zenPersonaBotIdRef.current ?? null;
      const sequenceId = `zen-live-${++zenLiveActionRequestSeqRef.current}`;
      const activeConversationId =
        detailIdRef.current && detailIdRef.current !== "pending"
          ? detailIdRef.current
          : selectedIdRef.current ?? undefined;
      const previousBotAction = zenLiveBotActionRef.current?.action;
      zenLiveActionAbortRef.current?.abort();
      const controller = new AbortController();
      zenLiveActionAbortRef.current = controller;
      try {
        const response = await api<{
          ok: true;
          reaction: ZenLiveActionReactionResponse;
        }>("/api/zen/live-action-reaction", {
          method: "POST",
          body: JSON.stringify({
            source,
            activeBotId,
            personaName: zenPersonaBot?.name ?? "Prism",
            ...(userCue ? { userAction: userCue.action } : {}),
            ...(previousBotAction ? { previousBotAction } : {}),
            ...(activeConversationId ? { conversationId: activeConversationId } : {}),
            idleMs: source === "idle"
              ? Math.max(0, Date.now() - (chatComposerLastTypedAtMsRef.current ?? Date.now()))
              : 0,
            clientSequenceId: sequenceId,
          }),
          signal: controller.signal,
        });
        if (zenLiveActionAbortRef.current !== controller) return;
        if (
          responseIsStaleZenLiveAction(
            response.reaction,
            sequenceId,
            activeBotId
          )
        ) {
          return;
        }
        const nextAction = normalizeZenLiveBotActionState(
          response.reaction,
          source,
          Date.now()
        );
        if (!nextAction) return;
        setZenLiveBotAction(nextAction);
        if (
          nextAction.responseKind !== "interrupt_candidate" ||
          pendingReplyVisible ||
          chatAssistantRevealInProgress ||
          source === "idle" ||
          !userCue ||
          currentActionDraftText.trim().length === 0
        ) {
          return;
        }
        const interruptKey = `${activeBotId ?? "prism"}:${userCue.key}:${nextAction.action}`;
        const nowMs = Date.now();
        if (
          zenLiveActionLastInterruptKeyRef.current === interruptKey ||
          nowMs - zenLiveActionLastInterruptAtMsRef.current <
            ZEN_LIVE_ACTION_INTERRUPT_COOLDOWN_MS
        ) {
          return;
        }
        zenLiveActionLastInterruptKeyRef.current = interruptKey;
        zenLiveActionLastInterruptAtMsRef.current = nowMs;
        await sendMessage(
          { preventDefault() {} } as React.FormEvent,
          {
            draftOverride: "",
            skipComposerHistory: true,
            preserveComposerDraft: true,
            zenLiveActionInterrupt: {
              source: "live_action_interrupt",
              activeBotId,
              userAction: userCue.action,
              botAction: nextAction.action,
              moodHint: nextAction.moodHint,
              ...(nextAction.interruptReason
                ? { reason: nextAction.interruptReason }
                : {}),
              clientTurnId: `zen-live-interrupt-${nowMs.toString(36)}`,
            },
          }
        );
      } catch (err) {
        if (
          err instanceof DOMException && err.name === "AbortError"
        ) {
          return;
        }
        if (controller.signal.aborted) return;
      } finally {
        if (zenLiveActionAbortRef.current === controller) {
          zenLiveActionAbortRef.current = null;
        }
      }
    },
    [
      chatAssistantRevealInProgress,
      composerHiddenByChoiceChips,
      pendingReplyVisible,
      view,
      zenPersonaBot?.name,
    ]
  );
  useEffect(() => {
    if (
      !zenComposerActionPreview ||
      !chatLikeSurface ||
      composerHiddenByChoiceChips ||
      pendingReplyVisible ||
      chatAssistantRevealInProgress
    ) {
      return;
    }
    const timer = setTimeout(() => {
      void requestZenLiveActionReaction("draft_action");
    }, ZEN_LIVE_ACTION_REACTION_DEBOUNCE_MS);
    return () => clearTimeout(timer);
  }, [
    chatAssistantRevealInProgress,
    chatLikeSurface,
    composerHiddenByChoiceChips,
    pendingReplyVisible,
    requestZenLiveActionReaction,
    zenComposerActionPreview?.key,
  ]);
  useEffect(() => {
    if (zenLiveActionIdleTimerRef.current !== null) {
      clearTimeout(zenLiveActionIdleTimerRef.current);
      zenLiveActionIdleTimerRef.current = null;
    }
    if (
      !zenComposerActionPreview ||
      !chatLikeSurface ||
      composerHiddenByChoiceChips ||
      pendingReplyVisible ||
      chatAssistantRevealInProgress
    ) {
      return;
    }
    const delay =
      zenLiveBotAction?.source === "idle"
        ? ZEN_LIVE_ACTION_IDLE_REPEAT_MS
        : ZEN_LIVE_ACTION_IDLE_FIRST_MS;
    zenLiveActionIdleTimerRef.current = setTimeout(() => {
      zenLiveActionIdleTimerRef.current = null;
      void requestZenLiveActionReaction("idle");
    }, delay);
    return () => {
      if (zenLiveActionIdleTimerRef.current !== null) {
        clearTimeout(zenLiveActionIdleTimerRef.current);
        zenLiveActionIdleTimerRef.current = null;
      }
    };
  }, [
    chatAssistantRevealInProgress,
    chatLikeSurface,
    composerHiddenByChoiceChips,
    pendingReplyVisible,
    requestZenLiveActionReaction,
    zenComposerActionPreview?.key,
    zenLiveBotAction?.createdAtMs,
    zenLiveBotAction?.source,
  ]);
  const askQuestionPatienceAssistantMessageId =
    pendingAskQuestionInteractiveKey !== null
      ? pendingAskQuestionState?.assistantMessageId ?? null
      : null;
  const askQuestionPatienceConversationId =
    detail?.id && detail.id !== "pending" ? detail.id : null;
  const askQuestionPatienceKey =
    view === "chat" &&
    zenAskQuestionPatienceEnabled &&
    pendingAskQuestionInteractiveKey !== null &&
    askQuestionPatienceConversationId !== null &&
    askQuestionPatienceAssistantMessageId !== null
      ? `${askQuestionPatienceConversationId}:${askQuestionPatienceAssistantMessageId}`
      : null;
  const askQuestionPatienceDurationMs =
    normalizeZenAskQuestionPatienceMsSetting(zenAskQuestionPatienceMs);
  askQuestionPatienceCurrentKeyRef.current = askQuestionPatienceKey;
  const askQuestionPatienceElapsedForProgress = askQuestionPatienceKey
    ? askQuestionPatienceActiveKeyRef.current === askQuestionPatienceKey
      ? askQuestionPatienceElapsedMs
      : askQuestionPatienceElapsedByKeyRef.current.get(askQuestionPatienceKey) ?? 0
    : 0;
  const askQuestionPatienceProgress = askQuestionPatienceKey
    ? Math.max(
        0,
        Math.min(
          1,
          1 -
            askQuestionPatienceElapsedForProgress /
              Math.max(1, askQuestionPatienceDurationMs)
        )
      )
    : 1;

  async function reportAskQuestionPatienceTimeout(args: {
    key: string;
    conversationId: string;
    assistantMessageId: string;
    askQuestion?: NonNullable<Message["askQuestion"]>;
    activeBotId: string | null;
    timeoutMs: number;
    activeElapsedMs: number;
  }): Promise<void> {
    try {
      const result = await api<{
        ok: true;
        applied?: boolean;
        duplicate?: boolean;
        reason?: string;
        penaltyLevel?: ZenAskQuestionPatienceInput["penaltyLevel"];
        prismMood?: PrismMoodSnapshot;
      }>(
        `/api/conversations/${encodeURIComponent(args.conversationId)}/prism-mood/ask-question-timeout`,
        {
          method: "POST",
          body: JSON.stringify({
            assistantMessageId: args.assistantMessageId,
            timeoutMs: args.timeoutMs,
            activeElapsedMs: args.activeElapsedMs,
          }),
        }
      );
      if (result.prismMood) {
        setDetail((current) =>
          current?.id === args.conversationId
            ? { ...current, prismMood: result.prismMood }
            : current
        );
      }
      const stillViewingConversation =
        selectedIdRef.current === args.conversationId ||
        detailIdRef.current === args.conversationId;
      const stillActiveOrLocallyClosed =
        askQuestionPatienceCurrentKeyRef.current === args.key ||
        askQuestionPatienceClosedAssistantMessageIdsRef.current.has(
          args.assistantMessageId
        );
      if (
        !stillViewingConversation ||
        !stillActiveOrLocallyClosed ||
        (result.applied !== true &&
          !(result.reason === "missing_message" && args.assistantMessageId.startsWith("dev-tool-lab-")))
      ) {
        return;
      }
      const syntheticSubmit = {
        preventDefault: () => {
          /* no-op - used so sendMessage can share the assistant-only pathway */
        },
      } as React.FormEvent<HTMLFormElement>;
      void sendMessage(syntheticSubmit, {
        skipComposerHistory: true,
        zenAskQuestionPatience: {
          source: "ask_question_patience",
          activeBotId: args.activeBotId,
          assistantMessageId: args.assistantMessageId,
          ...(args.askQuestion?.prompt
            ? { prompt: args.askQuestion.prompt }
            : {}),
          ...(args.askQuestion?.options?.length
            ? { options: args.askQuestion.options.map((option) => ({
                id: option.id,
                label: option.label,
              })) }
            : {}),
          timeoutMs: args.timeoutMs,
          activeElapsedMs: args.activeElapsedMs,
          ...(result.penaltyLevel ? { penaltyLevel: result.penaltyLevel } : {}),
          clientTurnId: `askq-patience-${Date.now().toString(36)}-${Math.random()
            .toString(36)
            .slice(2, 8)}`,
        },
      });
    } catch {
      // Keep this quiet: a timer miss should not interrupt the conversation UI.
    }
  }

  function renderAskQuestionPatienceMeter(
    assistantMessageId: string,
    placement: "inline" | "rail" | "dock"
  ): React.ReactNode {
    if (
      !askQuestionPatienceKey ||
      assistantMessageId !== askQuestionPatienceAssistantMessageId
    ) {
      return null;
    }
    const meterStyle = {
      "--ask-question-patience-progress": askQuestionPatienceProgress.toFixed(4),
      "--ask-question-patience-progress-width": `${(
        askQuestionPatienceProgress * 100
      ).toFixed(2)}%`,
    } as React.CSSProperties;
    return (
      <div
        className={styles.askQuestionPatienceMeter}
        data-placement={placement}
        data-expired={askQuestionPatienceProgress <= 0 ? "true" : undefined}
        style={meterStyle}
        aria-hidden="true"
      >
        <span />
      </div>
    );
  }

  useEffect(() => {
    askQuestionPatienceLastTickMsRef.current = null;
    askQuestionPatienceLastTypingAtMsRef.current = null;

    if (!askQuestionPatienceKey) {
      return;
    }

    if (askQuestionPatienceActiveKeyRef.current !== askQuestionPatienceKey) {
      askQuestionPatienceActiveKeyRef.current = askQuestionPatienceKey;
      const restoredElapsedMs = Math.max(
        0,
        Math.min(
          askQuestionPatienceDurationMs,
          askQuestionPatienceElapsedByKeyRef.current.get(askQuestionPatienceKey) ??
            0
        )
      );
      askQuestionPatienceElapsedMsRef.current = restoredElapsedMs;
      setAskQuestionPatienceElapsedMs(restoredElapsedMs);
      return;
    }

    const clampedElapsedMs = Math.max(
      0,
      Math.min(askQuestionPatienceDurationMs, askQuestionPatienceElapsedMsRef.current)
    );
    if (clampedElapsedMs !== askQuestionPatienceElapsedMsRef.current) {
      askQuestionPatienceElapsedMsRef.current = clampedElapsedMs;
      askQuestionPatienceElapsedByKeyRef.current.set(
        askQuestionPatienceKey,
        clampedElapsedMs
      );
      setAskQuestionPatienceElapsedMs(clampedElapsedMs);
    }
  }, [askQuestionPatienceKey, askQuestionPatienceDurationMs]);

  useEffect(() => {
    if (
      !askQuestionPatienceKey ||
      !askQuestionPatienceConversationId ||
      !askQuestionPatienceAssistantMessageId
    ) {
      askQuestionPatienceLastTickMsRef.current = null;
      return;
    }
    let frameId = 0;
    let cancelled = false;
    const tick = (nowMs: number): void => {
      if (cancelled) return;
      const fromMs = askQuestionPatienceLastTickMsRef.current ?? nowMs;
      const paused = shouldPauseAskQuestionPatience({
        active: true,
        pendingReply: Boolean(pendingReply),
        documentHidden: typeof document !== "undefined" ? document.hidden : false,
        composerRevealed: choiceChipRailComposerRevealed,
        nowMs,
        lastTypingAtMs: askQuestionPatienceLastTypingAtMsRef.current,
      });
      const result = advanceAskQuestionPatience({
        durationMs: askQuestionPatienceDurationMs,
        elapsedMs: askQuestionPatienceElapsedMsRef.current,
        fromMs,
        toMs: nowMs,
        paused,
      });
      askQuestionPatienceLastTickMsRef.current = nowMs;
      if (result.elapsedMs !== askQuestionPatienceElapsedMsRef.current) {
        askQuestionPatienceElapsedMsRef.current = result.elapsedMs;
        askQuestionPatienceElapsedByKeyRef.current.set(
          askQuestionPatienceKey,
          result.elapsedMs
        );
        setAskQuestionPatienceElapsedMs(result.elapsedMs);
      }
      const alreadyReported =
        askQuestionPatienceReportedKeysRef.current.has(askQuestionPatienceKey);
      if (
        shouldReportAskQuestionPatienceExpiry({
          expired: result.expired,
          alreadyReported,
        })
      ) {
        askQuestionPatienceReportedKeysRef.current.add(askQuestionPatienceKey);
        setAskQuestionPatienceClosedAssistantMessageIds((current) => {
          if (current.has(askQuestionPatienceAssistantMessageId)) {
            askQuestionPatienceClosedAssistantMessageIdsRef.current = current;
            return current;
          }
          const next = new Set(current);
          next.add(askQuestionPatienceAssistantMessageId);
          askQuestionPatienceClosedAssistantMessageIdsRef.current = next;
          return next;
        });
        void reportAskQuestionPatienceTimeout({
          key: askQuestionPatienceKey,
          conversationId: askQuestionPatienceConversationId,
          assistantMessageId: askQuestionPatienceAssistantMessageId,
          ...(pendingAskQuestion ? { askQuestion: pendingAskQuestion } : {}),
          activeBotId: zenPersonaBotIdRef.current ?? null,
          timeoutMs: askQuestionPatienceDurationMs,
          activeElapsedMs: result.elapsedMs,
        });
      }
      if (!result.expired) {
        frameId = window.requestAnimationFrame(tick);
      }
    };
    frameId = window.requestAnimationFrame(tick);
    return () => {
      cancelled = true;
      window.cancelAnimationFrame(frameId);
    };
  }, [
    askQuestionPatienceAssistantMessageId,
    askQuestionPatienceConversationId,
    askQuestionPatienceDurationMs,
    askQuestionPatienceKey,
    choiceChipRailComposerRevealed,
    pendingReply,
  ]);

  useLayoutEffect(() => {
    if (!choiceComposerFocusAfterRevealRef.current || composerHiddenByChoiceChips) {
      return;
    }
    choiceComposerFocusAfterRevealRef.current = false;
    draftComposerRef.current?.focus({ preventScroll: true });
    const frame = window.requestAnimationFrame(() => {
      draftComposerRef.current?.focus({ preventScroll: true });
    });
    return () => window.cancelAnimationFrame(frame);
  }, [composerHiddenByChoiceChips]);

  function focusRevealedChoiceComposer(): void {
    draftComposerRef.current?.focus({ preventScroll: true });
  }

  function queueChoiceComposerFocusAfterReveal(
    options: { immediate?: boolean } = {}
  ): void {
    choiceComposerFocusAfterRevealRef.current = true;
    if (options.immediate) {
      focusRevealedChoiceComposer();
    }
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        if (!choiceComposerFocusAfterRevealRef.current) return;
        choiceComposerFocusAfterRevealRef.current = false;
        focusRevealedChoiceComposer();
      });
    });
  }

  function revealChoiceComposerForOther(
    source: ComposerChip["otherSource"],
    options: { flushRender?: boolean } = {}
  ): void {
    hideZenHeaderForConversationAction();
    resumeChatModeAutoscrollForOutgoingTurn(detail?.id ?? selectedId);
    askQuestionComposerHiddenForReadingKeyRef.current = null;
    const reveal = (): void => {
      const sourceToReveal = activeChoiceComposerSource ?? source ?? "askquestion";
      if (sourceToReveal === "starter") {
        setStarterComposerRevealed(true);
      } else {
        setAskQuestionComposerRevealed(true);
      }
      resetComposerHistoryCursor();
      setComposerFocused(true);
      setComposerSendTintActive(true);
      setComposerPrimed(false);
    };
    if (options.flushRender) {
      flushSync(reveal);
    } else {
      reveal();
    }
    queueChoiceComposerFocusAfterReveal({ immediate: options.flushRender === true });
  }

  function eventTargetIsTextEditable(target: EventTarget | null): boolean {
    if (!(target instanceof HTMLElement)) return false;
    return Boolean(
      target.closest(
        "input, textarea, select, [contenteditable='true'], [role='textbox'], [data-markdown-cm-host='true']"
      )
    );
  }

  function revealHiddenZenComposerWithText(text: string): void {
    if (view !== "chat" || !composerHiddenByChoiceChips || text.length === 0) return;
    if (pendingAskQuestionInteractiveKey !== null) {
      askQuestionComposerHiddenForReadingKeyRef.current = null;
      setAskQuestionComposerRevealed(true);
    } else if (starterPromptsInteractive) {
      setStarterComposerRevealed(true);
    } else {
      return;
    }
    resetComposerHistoryCursor();
    setComposerFocused(true);
    setComposerSendTintActive(true);
    setComposerPrimed(false);
    markComposerTypingActivity();
    setDraft((current) => `${current}${text}`);
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        draftComposerRef.current?.focus({ preventScroll: true });
      });
    });
  }

  useEffect(() => {
    if (view !== "chat" || !composerHiddenByChoiceChips) return;

    const handleHiddenComposerKeyDown = (event: KeyboardEvent): void => {
      if (event.defaultPrevented || event.isComposing) return;
      if (event.metaKey || event.ctrlKey || event.altKey) return;
      if (eventTargetIsTextEditable(event.target)) return;
      const target = event.target instanceof HTMLElement ? event.target : null;
      if (
        (event.key === " " || event.key === "Enter") &&
        target?.closest("button, [role='button'], a[href]") !== null
      ) {
        return;
      }
      if (event.key.length !== 1) return;
      event.preventDefault();
      revealHiddenZenComposerWithText(event.key);
    };

    const handleHiddenComposerPaste = (event: ClipboardEvent): void => {
      if (event.defaultPrevented) return;
      if (eventTargetIsTextEditable(event.target)) return;
      const text = event.clipboardData?.getData("text/plain") ?? "";
      if (text.length === 0) return;
      event.preventDefault();
      revealHiddenZenComposerWithText(text);
    };

    window.addEventListener("keydown", handleHiddenComposerKeyDown, true);
    window.addEventListener("paste", handleHiddenComposerPaste, true);
    return () => {
      window.removeEventListener("keydown", handleHiddenComposerKeyDown, true);
      window.removeEventListener("paste", handleHiddenComposerPaste, true);
    };
  }, [
    composerHiddenByChoiceChips,
    pendingAskQuestionInteractiveKey,
    starterPromptsInteractive,
    view,
  ]);

  useEffect(() => {
    askQuestionComposerHiddenForReadingKeyRef.current = null;
    if (pendingAskQuestionKey) {
      setAskQuestionComposerRevealed(false);
      return;
    }
    setAskQuestionComposerRevealed(false);
  }, [pendingAskQuestionKey]);

  useEffect(() => {
    setStarterComposerRevealed(false);
  }, [starterPromptsInteractiveKey]);

  useEffect(() => {
    const previousCenteredId = starterPromptCenteredMessageIdRef.current;
    if (previousCenteredId === starterPromptCenteredMessageId) return;
    starterPromptCenteredMessageIdRef.current = starterPromptCenteredMessageId;
    if (starterPromptSettlingTimerRef.current !== null) {
      window.clearTimeout(starterPromptSettlingTimerRef.current);
      starterPromptSettlingTimerRef.current = null;
    }
    if (starterPromptCenteredMessageId !== null) {
      setStarterPromptSettlingMessageId(null);
      return;
    }
    if (previousCenteredId === null) return;
    setStarterPromptSettlingMessageId(previousCenteredId);
    starterPromptSettlingTimerRef.current = window.setTimeout(() => {
      starterPromptSettlingTimerRef.current = null;
      setStarterPromptSettlingMessageId((current) =>
        current === previousCenteredId ? null : current
      );
    }, 560);
  }, [starterPromptCenteredMessageId]);

  useEffect(() => {
    return () => {
      if (starterPromptSettlingTimerRef.current !== null) {
        window.clearTimeout(starterPromptSettlingTimerRef.current);
        starterPromptSettlingTimerRef.current = null;
      }
    };
  }, []);

  function centerActiveChoicePanelInMessages(): void {
    if (!choiceChipRailInteractiveKey || !choiceChipRailAnchorMessageId) return;
    if (!choiceChipRailControlsViewport) return;
    if (choiceChipRailComposerRevealed) return;
    if (
      askQuestionComposerHiddenForReadingKeyRef.current ===
      choiceChipRailInteractiveKey
    ) {
      return;
    }
    const el = messagesScrollRef.current;
    if (!el) return;
    const row = findMessageRowById(el, choiceChipRailAnchorMessageId);
    if (!row) return;
    const panel =
      row.querySelector<HTMLElement>('[data-ask-question-panel="true"]') ??
      findChatModeMessageScrollAnchor(row);
    const rootRect = el.getBoundingClientRect();
    const target = view === "chat" ? row : panel;
    const targetRect = target.getBoundingClientRect();
    const targetCenterY =
      targetRect.top - rootRect.top + el.scrollTop + targetRect.height / 2;
    const railRect = askQuestionRailRef.current?.getBoundingClientRect() ?? null;
    const railBottomInset = railRect
      ? Math.max(0, rootRect.bottom - Math.max(rootRect.top, railRect.top))
      : 0;
    const topInset = view === "chat"
      ? Math.min(128, Math.max(64, el.clientHeight * 0.1))
      : 0;
    const bottomInset = view === "chat"
      ? railBottomInset > 0
        ? Math.max(
            Math.min(168, Math.max(96, el.clientHeight * 0.15)),
            railBottomInset + 24
          )
        : Math.min(116, Math.max(64, el.clientHeight * 0.1))
      : railBottomInset;
    const readableHeight = Math.max(
      180,
      el.clientHeight - topInset - bottomInset
    );
    const maxScrollTop = Math.max(0, el.scrollHeight - el.clientHeight);
    const targetTop = Math.max(
      0,
      Math.min(maxScrollTop, targetCenterY - topInset - readableHeight / 2)
    );
    chatProgrammaticScrollUntilMsRef.current = Date.now() + 180;
    el.scrollTo({ top: targetTop, behavior: "auto" });
    if (detail?.id) {
      chatLastScrollTopByConversationRef.current.set(detail.id, targetTop);
      chatLastScrollHeightByConversationRef.current.set(detail.id, el.scrollHeight);
    }
  }

  useEffect(() => {
    if (
      !choiceChipRailInteractiveKey ||
      !choiceChipRailControlsViewport ||
      choiceChipRailComposerRevealed
    ) {
      return;
    }
    let settleTimerA: number | null = null;
    let settleTimerB: number | null = null;
    requestAnimationFrame(() => {
      requestAnimationFrame(centerActiveChoicePanelInMessages);
    });
    settleTimerA = window.setTimeout(centerActiveChoicePanelInMessages, 140);
    settleTimerB = window.setTimeout(centerActiveChoicePanelInMessages, 320);
    return () => {
      if (settleTimerA !== null) window.clearTimeout(settleTimerA);
      if (settleTimerB !== null) window.clearTimeout(settleTimerB);
    };
  }, [
    choiceChipRailAnchorMessageId,
    choiceChipRailComposerRevealed,
    choiceChipRailControlsViewport,
    choiceChipRailInteractiveKey,
    detail?.id,
  ]);
  const askQuestionPromptDockSpaceActive =
    choiceChipRailInteractiveKey !== null &&
    choiceChipRailControlsViewport &&
    choiceChipRailComposerRevealed &&
    viewportWidth <= PICKER_MOBILE_BREAKPOINT;
  const askQuestionTailSpaceActive =
    choiceChipRailInteractiveKey !== null &&
    choiceChipRailControlsViewport &&
    !askQuestionPromptDockSpaceActive;
  const askQuestionCollapsedBubbleActive = false;

  function snapAskQuestionComposerToChatBottom(force = false): void {
    const rail = getComposerChipRail();
    if (!rail?.collapsed) return;
    if (
      !choiceChipRailInteractiveKey ||
      !choiceChipRailControlsViewport ||
      (!force && !choiceChipRailComposerRevealed)
    ) {
      return;
    }
    const el = messagesScrollRef.current;
    if (!el) return;
    chatProgrammaticScrollUntilMsRef.current = Date.now() + 160;
    el.scrollTop = Math.max(0, el.scrollHeight - el.clientHeight);
    if (detail?.id) {
      chatLastScrollTopByConversationRef.current.set(detail.id, el.scrollTop);
      chatLastScrollHeightByConversationRef.current.set(detail.id, el.scrollHeight);
    }
  }

  function hideAskQuestionComposerForReading(): void {
    if (!choiceChipRailInteractiveKey || !choiceChipRailComposerRevealed) return;
    askQuestionComposerHiddenForReadingKeyRef.current = choiceChipRailInteractiveKey;
    if (pendingAskQuestionInteractiveKey !== null) {
      setAskQuestionComposerRevealed(false);
    } else {
      setStarterComposerRevealed(false);
    }
    draftComposerRef.current?.blur();
  }

  function zenAtmosphereOpacitiesFromStates(
    states: Record<string, ZenAtmosphereLayerState>
  ): Record<string, number> {
    return Object.fromEntries(
      Object.entries(states).map(([imageId, state]) => [
        imageId,
        state.opacity,
      ])
    );
  }

  function applyZenAtmosphereLayerStates(
    next: Record<string, ZenAtmosphereLayerState>,
    options?: { preserveParallax?: boolean }
  ): void {
    setZenAtmosphereLayerStates((previous) => {
      const resolvedNext = options?.preserveParallax
        ? Object.fromEntries(
            Object.entries(next).map(([imageId, state]) => [
              imageId,
              {
                ...state,
                parallaxY: previous[imageId]?.parallaxY ?? 0,
              },
            ])
          )
        : next;
      const previousKeys = Object.keys(previous);
      const nextKeys = Object.keys(resolvedNext);
      if (previousKeys.length === nextKeys.length) {
        const unchanged = nextKeys.every(
          (key) =>
            Math.abs((previous[key]?.opacity ?? 0) - resolvedNext[key]!.opacity) <
              0.005 &&
            Math.abs(
              (previous[key]?.parallaxY ?? 0) - resolvedNext[key]!.parallaxY
            ) < 0.5
        );
        if (unchanged) return previous;
      }
      return resolvedNext;
    });
  }

  function clearZenAtmosphereParallaxSettleTimer(): void {
    if (zenAtmosphereParallaxSettleTimerRef.current === null) return;
    window.clearTimeout(zenAtmosphereParallaxSettleTimerRef.current);
    zenAtmosphereParallaxSettleTimerRef.current = null;
  }

  function scheduleZenAtmosphereParallaxSettleRefresh(): void {
    const waitMs = Math.max(
      16,
      zenAtmosphereParallaxSuspendedUntilMsRef.current - window.performance.now() + 24
    );
    if (zenAtmosphereParallaxSettleTimerRef.current !== null) {
      window.clearTimeout(zenAtmosphereParallaxSettleTimerRef.current);
    }
    zenAtmosphereParallaxSettleTimerRef.current = window.setTimeout(() => {
      zenAtmosphereParallaxSettleTimerRef.current = null;
      updateZenAtmosphereScrollBlend(messagesScrollRef.current);
    }, waitMs);
  }

  function zenAtmosphereParallaxSuspendedByFling(
    scrollRoot: HTMLDivElement
  ): boolean {
    const nowMs = window.performance.now();
    const previousSample = zenAtmosphereParallaxScrollSampleRef.current;
    zenAtmosphereParallaxScrollSampleRef.current = {
      scrollTop: scrollRoot.scrollTop,
      sampledAtMs: nowMs,
    };
    if (previousSample) {
      const elapsedMs = Math.max(1, nowMs - previousSample.sampledAtMs);
      const scrollDeltaPx = Math.abs(scrollRoot.scrollTop - previousSample.scrollTop);
      const velocityPxPerMs = scrollDeltaPx / elapsedMs;
      if (
        velocityPxPerMs >= ZEN_ATMOSPHERE_PARALLAX_FLING_VELOCITY_PX_PER_MS ||
        scrollDeltaPx >= ZEN_ATMOSPHERE_PARALLAX_FLING_DELTA_PX
      ) {
        zenAtmosphereParallaxSuspendedUntilMsRef.current =
          nowMs + ZEN_ATMOSPHERE_PARALLAX_FLING_SETTLE_MS;
      }
    }
    const suspended = nowMs < zenAtmosphereParallaxSuspendedUntilMsRef.current;
    if (suspended) {
      scheduleZenAtmosphereParallaxSettleRefresh();
    }
    return suspended;
  }

  function updateZenAtmosphereGlobalParallax(
    scrollRoot: HTMLDivElement,
    options?: { preserveParallax?: boolean }
  ): void {
    if (options?.preserveParallax) return;
    const maxParallaxPx = Math.min(
      ZEN_ATMOSPHERE_PARALLAX_MAX_PX,
      Math.max(20, scrollRoot.clientHeight * ZEN_ATMOSPHERE_PARALLAX_MAX_RATIO)
    );
    const nextParallaxY = Math.max(
      -maxParallaxPx,
      Math.min(0, -scrollRoot.scrollTop * ZEN_ATMOSPHERE_PARALLAX_SCROLL_RATE)
    );
    setZenAtmosphereGlobalParallaxY((current) =>
      Math.abs(current - nextParallaxY) < 0.5 ? current : nextParallaxY
    );
  }

  function calculateZenAtmosphereLayerStates(
    scrollRoot: HTMLDivElement
  ): Record<string, ZenAtmosphereLayerState> {
    if (view !== "chat" || zenAtmosphereTimeline.length === 0) return {};
    const messages = detail?.messages ?? [];
    const rootRect = scrollRoot.getBoundingClientRect();
    const messageCountToY = (messageCount: number): number => {
      const count = Math.max(0, Math.floor(messageCount));
      if (count === 0) return 0;
      if (messages.length === 0) {
        return count * Math.max(140, scrollRoot.clientHeight * 0.22);
      }
      if (count > 0 && count <= messages.length) {
        const anchorMessage = messages[count - 1];
        const row = anchorMessage ? findMessageRowById(scrollRoot, anchorMessage.id) : null;
        if (row) {
          const rowRect = row.getBoundingClientRect();
          return rowRect.top - rootRect.top + scrollRoot.scrollTop;
        }
      }
      if (count <= messages.length) {
        return (count / Math.max(1, messages.length)) * scrollRoot.scrollHeight;
      }
      const averageMessageHeight = Math.max(
        140,
        scrollRoot.scrollHeight / Math.max(1, messages.length)
      );
      return scrollRoot.scrollHeight + (count - messages.length) * averageMessageHeight;
    };
    const readerY = scrollRoot.scrollTop + scrollRoot.clientHeight * 0.5;
    const revealScrollDistancePx = Math.min(
      ZEN_ATMOSPHERE_REVEAL_SCROLL_DISTANCE_MAX_PX,
      Math.max(
        ZEN_ATMOSPHERE_REVEAL_SCROLL_DISTANCE_MIN_PX,
        scrollRoot.clientHeight * ZEN_ATMOSPHERE_REVEAL_SCROLL_DISTANCE_VIEWPORT_RATIO
      )
    );
    const parallaxMaxPx = Math.min(
      ZEN_ATMOSPHERE_PARALLAX_MAX_PX,
      Math.max(20, scrollRoot.clientHeight * ZEN_ATMOSPHERE_PARALLAX_MAX_RATIO)
    );
    return calculateZenAtmosphereLayerStatesForReader({
      timeline: zenAtmosphereTimeline,
      readerY,
      revealScrollDistancePx,
      messageCountToY,
      parallaxRate: ZEN_ATMOSPHERE_PARALLAX_SCROLL_RATE,
      parallaxMaxPx,
    });
  }

  function updateZenAtmosphereScrollBlend(scrollRoot: HTMLDivElement | null): void {
    if (!scrollRoot) {
      if (zenAtmosphereTimeline.length === 0) {
        applyZenAtmosphereLayerStates({});
        setZenAtmosphereGlobalParallaxY(0);
        setZenAtmosphereScrollBlendReadyKey(null);
        zenAtmosphereParallaxScrollSampleRef.current = null;
        zenAtmosphereParallaxSuspendedUntilMsRef.current = 0;
        clearZenAtmosphereParallaxSettleTimer();
      }
      return;
    }
    const parallaxSuspended = zenAtmosphereParallaxSuspendedByFling(scrollRoot);
    updateZenAtmosphereGlobalParallax(scrollRoot, {
      preserveParallax: parallaxSuspended,
    });
    const measuredLayerStates = calculateZenAtmosphereLayerStates(scrollRoot);
    const measuredLayerOpacities = zenAtmosphereOpacitiesFromStates(
      measuredLayerStates
    );
    const initialLayerOpacity = maxZenAtmosphereLayerOpacity(
      zenAtmosphereOpacitiesFromStates(zenAtmosphereInitialLayerStates)
    );
    if (
      zenAtmosphereScrollBlendReadyKey !== zenAtmosphereTimelineKey &&
      initialLayerOpacity > 0.01 &&
      maxZenAtmosphereLayerOpacity(measuredLayerOpacities) <= 0.01
    ) {
      applyZenAtmosphereLayerStates(zenAtmosphereInitialLayerStates, {
        preserveParallax: parallaxSuspended,
      });
      return;
    }
    applyZenAtmosphereLayerStates(measuredLayerStates, {
      preserveParallax: parallaxSuspended,
    });
    setZenAtmosphereScrollBlendReadyKey((current) =>
      current === zenAtmosphereTimelineKey ? current : zenAtmosphereTimelineKey
    );
  }

  function scheduleZenAtmosphereScrollBlend(scrollRoot: HTMLDivElement | null): void {
    if (zenAtmosphereScrollFrameRef.current !== null) return;
    zenAtmosphereScrollFrameRef.current = window.requestAnimationFrame(() => {
      zenAtmosphereScrollFrameRef.current = null;
      updateZenAtmosphereScrollBlend(scrollRoot ?? messagesScrollRef.current);
    });
  }

  useLayoutEffect(() => {
    if (view !== "chat" || zenAtmosphereTimeline.length === 0) {
      applyZenAtmosphereLayerStates({});
      setZenAtmosphereScrollBlendReadyKey(null);
      zenAtmosphereParallaxScrollSampleRef.current = null;
      zenAtmosphereParallaxSuspendedUntilMsRef.current = 0;
      clearZenAtmosphereParallaxSettleTimer();
      return;
    }
    const scrollRoot = messagesScrollRef.current;
    if (!scrollRoot) return;
    updateZenAtmosphereScrollBlend(scrollRoot);
    const frame = window.requestAnimationFrame(() => {
      updateZenAtmosphereScrollBlend(scrollRoot);
    });
    return () => window.cancelAnimationFrame(frame);
  }, [view, detail?.id, detail?.messages.length, zenAtmosphereTimelineKey]);

  useEffect(() => {
    return () => {
      if (zenAtmosphereScrollFrameRef.current !== null) {
        window.cancelAnimationFrame(zenAtmosphereScrollFrameRef.current);
        zenAtmosphereScrollFrameRef.current = null;
      }
      clearZenAtmosphereParallaxSettleTimer();
      if (chatScrollElasticResetTimerRef.current !== null) {
        window.clearTimeout(chatScrollElasticResetTimerRef.current);
        chatScrollElasticResetTimerRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    resetChatModeScrollElastic();
  }, [chatEphemeralMode, detail?.id, view]);

  useEffect(() => {
    if (!askQuestionTailSpaceActive) return;
    if (askQuestionComposerHiddenForReadingKeyRef.current !== null) {
      return;
    }
    centerActiveChoicePanelInMessages();
    const t1 = window.setTimeout(centerActiveChoicePanelInMessages, 120);
    const t2 = window.setTimeout(centerActiveChoicePanelInMessages, 300);
    return () => {
      window.clearTimeout(t1);
      window.clearTimeout(t2);
    };
  }, [askQuestionTailSpaceActive, choiceChipRailAnchorMessageId]);

  function clearChatModeScrollElasticResetTimer(): void {
    if (chatScrollElasticResetTimerRef.current === null) return;
    window.clearTimeout(chatScrollElasticResetTimerRef.current);
    chatScrollElasticResetTimerRef.current = null;
  }

  function setChatModeScrollElasticOffset(
    scrollRoot: HTMLDivElement | null,
    offsetPx: number,
    pulling: boolean
  ): void {
    const nextOffset =
      Math.abs(offsetPx) < 0.5
        ? 0
        : Math.max(
            -CHAT_MODE_SCROLL_ELASTIC_MAX_OFFSET_PX,
            Math.min(CHAT_MODE_SCROLL_ELASTIC_MAX_OFFSET_PX, offsetPx)
          );
    chatScrollElasticOffsetRef.current = nextOffset;
    if (!scrollRoot) return;
    scrollRoot.style.setProperty("--chat-elastic-offset-y", `${nextOffset.toFixed(2)}px`);
    if (pulling && nextOffset !== 0) {
      scrollRoot.dataset.chatElasticPulling = "true";
    } else {
      delete scrollRoot.dataset.chatElasticPulling;
    }
  }

  function resetChatModeScrollElastic(scrollRoot = messagesScrollRef.current): void {
    clearChatModeScrollElasticResetTimer();
    setChatModeScrollElasticOffset(scrollRoot, 0, false);
  }

  useEffect(() => {
    if (!zenEmptyHeroVisible) return;
    const scrollRoot = messagesScrollRef.current;
    if (!scrollRoot) return;
    scrollRoot.scrollTop = 0;
    resetChatModeScrollElastic(scrollRoot);
  }, [zenEmptyHeroVisible]);

  useEffect(() => {
    if (view !== "chat" || !chatEphemeralMode || zenEmptyHeroVisible) {
      clearZenReadableBottomMomentumHold();
      return;
    }
    const scrollRoot = messagesScrollRef.current;
    if (!scrollRoot) return;
    const handleNativeWheel = (event: WheelEvent): void => {
      if (event.deltaY < -1) {
        clearZenReadableBottomMomentumHold();
        return;
      }
      const readableMaxScrollTop = resolveZenReadableMaxScrollTop(scrollRoot);
      const shouldHold =
        event.deltaY > 1 &&
        (zenReadableBottomMomentumHoldActive() ||
          shouldHoldZenReadableBottom(scrollRoot, readableMaxScrollTop, event.deltaY));
      if (!shouldHold) return;
      if (event.cancelable) {
        event.preventDefault();
      }
      holdZenReadableBottom(scrollRoot, detail?.id, readableMaxScrollTop);
    };
    scrollRoot.addEventListener("wheel", handleNativeWheel, {
      capture: true,
      passive: false,
    });
    return () => {
      scrollRoot.removeEventListener("wheel", handleNativeWheel, {
        capture: true,
      });
    };
  }, [
    view,
    chatEphemeralMode,
    detail?.id,
    detail?.messages.length,
    latestAssistantMessageId,
    latestUserMessageId,
    zenEmptyHeroVisible,
  ]);

  function queueChatModeScrollElasticReset(scrollRoot: HTMLDivElement): void {
    clearChatModeScrollElasticResetTimer();
    chatScrollElasticResetTimerRef.current = window.setTimeout(() => {
      chatScrollElasticResetTimerRef.current = null;
      setChatModeScrollElasticOffset(scrollRoot, 0, false);
    }, CHAT_MODE_SCROLL_ELASTIC_RESET_DELAY_MS);
  }

  function applyChatModeScrollElasticPull(
    scrollRoot: HTMLDivElement,
    direction: 1 | -1,
    gestureDistancePx: number,
    resistance: number
  ): void {
    const currentOffset = chatScrollElasticOffsetRef.current;
    const currentMagnitude =
      Math.sign(currentOffset) === direction ? Math.abs(currentOffset) : 0;
    const remaining = Math.max(
      0,
      CHAT_MODE_SCROLL_ELASTIC_MAX_OFFSET_PX - currentMagnitude
    );
    const nextMagnitude =
      currentMagnitude + Math.min(remaining, gestureDistancePx * resistance);
    setChatModeScrollElasticOffset(scrollRoot, direction * nextMagnitude, true);
    queueChatModeScrollElasticReset(scrollRoot);
  }

  function handleMessagesPaneScroll(event: React.UIEvent<HTMLDivElement>): void {
    if (zenEmptyHeroVisible) {
      const el = event.currentTarget;
      if (el.scrollTop !== 0) {
        el.scrollTop = 0;
      }
      resetChatModeScrollElastic(el);
      return;
    }
    scheduleZenAtmosphereScrollBlend(event.currentTarget);
    if (!chatEphemeralMode || !detail?.id) return;
    const el = event.currentTarget;
    const readableMaxScrollTop = resolveZenReadableMaxScrollTop(el);
    if (
      el.scrollTop > readableMaxScrollTop + 0.5 ||
      (zenReadableBottomMomentumHoldActive() &&
        el.scrollTop >= readableMaxScrollTop - ZEN_READABLE_BOTTOM_SCROLL_DEADZONE_PX)
    ) {
      chatProgrammaticScrollUntilMsRef.current = Date.now() + 80;
      armZenReadableBottomMomentumHold();
      el.scrollTop = readableMaxScrollTop;
    }
    const previousScrollTop = chatLastScrollTopByConversationRef.current.get(detail.id);
    const previousScrollHeight = chatLastScrollHeightByConversationRef.current.get(detail.id);
    // Anything below this threshold is treated as scroll noise (reflow,
    // browser sub-pixel rounding, font-curve transitions). Real user
    // upward scrolls from a touchpad or wheel are an order of magnitude
    // larger than this.
    const MANUAL_SCROLL_UP_THRESHOLD_PX = 12;
    const scrollDrop =
      previousScrollTop !== undefined ? previousScrollTop - el.scrollTop : 0;
    const heightDrop =
      previousScrollHeight !== undefined ? previousScrollHeight - el.scrollHeight : 0;
    // If the scroll area shrunk between events (e.g. the streaming-reply
    // font shrank a notch and pulled the bottom up), the matching scroll
    // drop is reflow, not a user gesture. Allow a small +2px slack for
    // sub-pixel rounding.
    const probableReflow = heightDrop > 0 && scrollDrop <= heightDrop + 2;
    const programmaticScrollActive = Date.now() < chatProgrammaticScrollUntilMsRef.current;
    const scrolledUp =
      previousScrollTop !== undefined &&
      scrollDrop > MANUAL_SCROLL_UP_THRESHOLD_PX &&
      !probableReflow &&
      !programmaticScrollActive;
    if (scrolledUp) {
      cancelChatModeSmoothScroll();
      chatAutoscrollUserDisarmedByConversationRef.current.set(detail.id, true);
      chatAutoscrollArmedByConversationRef.current.set(detail.id, false);
      hideAskQuestionComposerForReading();
    }
    chatLastScrollTopByConversationRef.current.set(detail.id, el.scrollTop);
    chatLastScrollHeightByConversationRef.current.set(detail.id, el.scrollHeight);
    if (!scrolledUp) return;
  }
  function disarmChatModeAutoscrollFromUserGesture(): void {
    if (zenEmptyHeroVisible) return;
    if (!chatEphemeralMode || !detail?.id) return;
    cancelChatModeSmoothScroll();
    chatAutoscrollUserDisarmedByConversationRef.current.set(detail.id, true);
    chatAutoscrollArmedByConversationRef.current.set(detail.id, false);
    hideAskQuestionComposerForReading();
  }
  function handleChatModeThreadWheel(event: React.WheelEvent<HTMLDivElement>): void {
    const el = event.currentTarget;
    if (zenEmptyHeroVisible) {
      event.preventDefault();
      resetChatModeScrollElastic(el);
      return;
    }
    if (!chatEphemeralMode || !detail?.id) return;
    const maxScrollTop = resolveZenReadableMaxScrollTop(el);
    const atTop = el.scrollTop <= 0.5;
    const atBottom = el.scrollTop >= maxScrollTop - 0.5;
    if (event.deltaY < -1) {
      clearZenReadableBottomMomentumHold();
    }
    if (
      event.deltaY > 1 &&
      (zenReadableBottomMomentumHoldActive() ||
        shouldHoldZenReadableBottom(el, maxScrollTop, event.deltaY))
    ) {
      event.preventDefault();
      holdZenReadableBottom(el, detail.id, maxScrollTop);
      return;
    }
    if (!atTop && event.deltaY < -1) {
      disarmChatModeAutoscrollFromUserGesture();
    }
    if (atTop && event.deltaY < -1) {
      event.preventDefault();
      applyChatModeScrollElasticPull(
        el,
        1,
        Math.abs(event.deltaY),
        CHAT_MODE_SCROLL_ELASTIC_WHEEL_RESISTANCE
      );
      return;
    }
    if (atBottom && event.deltaY > 1) {
      event.preventDefault();
      holdZenReadableBottom(el, detail.id, maxScrollTop);
      return;
    }
    if (chatScrollElasticOffsetRef.current !== 0) {
      queueChatModeScrollElasticReset(el);
    }
  }
  function handleChatModeThreadTouchStart(event: React.TouchEvent<HTMLDivElement>): void {
    if (zenEmptyHeroVisible) {
      chatTouchScrollLastYRef.current = null;
      resetChatModeScrollElastic(event.currentTarget);
      return;
    }
    clearChatModeScrollElasticResetTimer();
    clearZenReadableBottomMomentumHold();
    chatTouchScrollLastYRef.current = event.touches[0]?.clientY ?? null;
  }
  function handleChatModeThreadTouchMove(event: React.TouchEvent<HTMLDivElement>): void {
    const el = event.currentTarget;
    if (zenEmptyHeroVisible) {
      event.preventDefault();
      resetChatModeScrollElastic(el);
      return;
    }
    if (!chatEphemeralMode || !detail?.id) return;
    const nextY = event.touches[0]?.clientY ?? null;
    const previousY = chatTouchScrollLastYRef.current;
    chatTouchScrollLastYRef.current = nextY;
    if (nextY === null || previousY === null) return;
    const touchDeltaY = nextY - previousY;
    const maxScrollTop = resolveZenReadableMaxScrollTop(el);
    const atTop = el.scrollTop <= 0.5;
    const atBottom = el.scrollTop >= maxScrollTop - 0.5;
    if (
      touchDeltaY < -1 &&
      (zenReadableBottomMomentumHoldActive() ||
        shouldHoldZenReadableBottom(el, maxScrollTop, Math.abs(touchDeltaY)))
    ) {
      event.preventDefault();
      holdZenReadableBottom(el, detail.id, maxScrollTop);
      return;
    }
    // Swiping down moves the thread upward. That is the user's "pause follow"
    // gesture while PRISM is typing, so let the scroll surface take over.
    // At the top edge, though, this is just elastic overscroll; do not mark
    // a fresh Zen reply as user-disarmed before the assistant row scrolls in.
    if (!atTop && touchDeltaY > 4) {
      clearZenReadableBottomMomentumHold();
      disarmChatModeAutoscrollFromUserGesture();
    }
    if (atTop && touchDeltaY > 1) {
      applyChatModeScrollElasticPull(
        el,
        1,
        touchDeltaY,
        CHAT_MODE_SCROLL_ELASTIC_TOUCH_RESISTANCE
      );
      return;
    }
    if (atBottom && touchDeltaY < -1) {
      event.preventDefault();
      holdZenReadableBottom(el, detail.id, maxScrollTop);
      return;
    }
    if (chatScrollElasticOffsetRef.current !== 0) {
      queueChatModeScrollElasticReset(el);
    }
  }
  function handleChatModeThreadTouchEnd(): void {
    chatTouchScrollLastYRef.current = null;
    resetChatModeScrollElastic();
  }

  const handleZenCanvasSpeedNudgePointerDown = useCallback(
    (event: React.PointerEvent<HTMLDivElement>): void => {
      if (!activeAssistantRevealKey) return;
      if (event.defaultPrevented) return;
      if (event.pointerType === "touch") return;
      if (event.button !== 0) return;
      if (canvasBotMarqueeRect !== null) return;
      const target = event.target;
      if (!(target instanceof Element)) return;
      if (!event.currentTarget.contains(target)) return;
      if (target.closest(ZEN_CANVAS_SPEED_NUDGE_EXCLUDED_TARGET_SELECTOR)) return;

      event.preventDefault();
      event.stopPropagation();
      zenCanvasSpeedNudgePointerRef.current = {
        pointerId: event.pointerId,
        revealKey: activeAssistantRevealKey,
      };
      try {
        event.currentTarget.setPointerCapture(event.pointerId);
      } catch {
        // Pointer capture is optional in tests and older embedded webviews.
      }
      const now = Date.now();
      setZenCanvasSpeedNudgeState((current) =>
        beginZenCanvasSpeedNudgeHold(current, {
          revealKey: activeAssistantRevealKey,
          nowMs: now,
        }).state
      );
      setChatEphemeralNowMs(now);
    },
    [activeAssistantRevealKey, canvasBotMarqueeRect]
  );

  const handleZenCanvasSpeedNudgePointerEnd = useCallback(
    (event: React.PointerEvent<HTMLDivElement>): void => {
      const activePointer = zenCanvasSpeedNudgePointerRef.current;
      if (!activePointer || activePointer.pointerId !== event.pointerId) return;
      zenCanvasSpeedNudgePointerRef.current = null;
      event.preventDefault();
      event.stopPropagation();
      try {
        if (event.currentTarget.hasPointerCapture(event.pointerId)) {
          event.currentTarget.releasePointerCapture(event.pointerId);
        }
      } catch {
        // Capture may already be released by the browser.
      }
      const now = Date.now();
      setZenCanvasSpeedNudgeState((current) =>
        endZenCanvasSpeedNudgeHold(current, {
          revealKey: activePointer.revealKey,
          nowMs: now,
        })
      );
      setChatEphemeralNowMs(now);
    },
    []
  );

  function resetComposerHistoryCursor(): void {
    composerHistoryIndexRef.current = null;
    composerHistoryDraftBeforeRecallRef.current = null;
  }

  function appendComposerHistoryEntry(entry: string): void {
    if (entry.trim().length === 0) return;
    setComposerHistory((previous) => {
      const next = [...previous, entry];
      return next.length <= COMPOSER_HISTORY_LIMIT
        ? next
        : next.slice(next.length - COMPOSER_HISTORY_LIMIT);
    });
    resetComposerHistoryCursor();
  }

  function recallPreviousComposerHistory(currentDraft: string): string | null {
    if (composerHistory.length === 0) return null;
    if (composerHistoryIndexRef.current === null) {
      composerHistoryDraftBeforeRecallRef.current = currentDraft;
      composerHistoryIndexRef.current = composerHistory.length - 1;
      return composerHistory[composerHistoryIndexRef.current] ?? null;
    }
    const nextIndex = Math.max(0, composerHistoryIndexRef.current - 1);
    composerHistoryIndexRef.current = nextIndex;
    return composerHistory[nextIndex] ?? null;
  }

  function recallNextComposerHistory(): string | null {
    if (composerHistory.length === 0 || composerHistoryIndexRef.current === null) {
      return null;
    }
    const nextIndex = composerHistoryIndexRef.current + 1;
    if (nextIndex >= composerHistory.length) {
      const draftBeforeRecall = composerHistoryDraftBeforeRecallRef.current ?? "";
      resetComposerHistoryCursor();
      return draftBeforeRecall;
    }
    composerHistoryIndexRef.current = nextIndex;
    return composerHistory[nextIndex] ?? null;
  }

  /**
   * Keep text sends unblocked while an in-thread image job is running.
   * Image generation and chat replies are independent backends.
   */
  function canSendTextWhileReplyPending(): boolean {
    if (!pendingReply) return false;
    const activeConversationId =
      detail?.id && detail.id !== "pending"
        ? detail.id
        : selectedId;
    if (!activeConversationId) return false;
    return composerImageJobOrb?.conversationId === activeConversationId;
  }

  const composerReplyInterruptActive = chatLikeSurface && chatAssistantRevealInProgress;

  function composerSubmitUsesRandomNudge(value: string): boolean {
    return (
      !composerReplyInterruptActive &&
      editingMessageId === null &&
      value.trim().length === 0
    );
  }

  function composerSubmitLabel(value: string): React.ReactNode {
    if (composerReplyInterruptActive) return "Shh!";
    if (composerSubmitUsesRandomNudge(value)) {
      return <BotGlyph name="dice" size={30} strokeWidth={1.45} />;
    }
    if (editingMessageId) return "Save edit";
    if (pendingReply && !canSendTextWhileReplyPending() && value.trim().length > 0) {
      if (view === "chat") return "Send";
      const queuedCountAfterClick = queuedChatPrompts.length + 1;
      return queuedCountAfterClick > 1 ? `Queue (${queuedCountAfterClick})` : "Queue";
    }
    return value.trim().length > 0 ? "Send" : "";
  }

  function composerSubmitAriaLabel(value: string): string {
    if (composerReplyInterruptActive) return "Shh! Interrupt current reply";
    if (composerSubmitUsesRandomNudge(value)) {
      return composerRandomPromptBusy
        ? "Generating suggested prompt"
        : "Send random suggested prompt";
    }
    if (editingMessageId) return "Save edited message";
    if (pendingReply && !canSendTextWhileReplyPending() && value.trim().length > 0) {
      if (view === "chat") return "Send and interrupt current reply";
      const queuedCountAfterClick = queuedChatPrompts.length + 1;
      return queuedCountAfterClick > 1
        ? `Queue message in position ${queuedCountAfterClick}`
        : "Queue message";
    }
    return "Send message";
  }

  function composerSubmitDisabled(value: string): boolean {
    if (composerReplyInterruptActive) return false;
    if (composerSubmitUsesRandomNudge(value)) {
      return (
        composerRandomPromptBusy ||
        (pendingReply && !canSendTextWhileReplyPending() && view !== "chat")
      );
    }
    return (
      value.trim().length === 0 ||
      (editingMessageId !== null && value.trim() === editingOriginalText.trim())
    );
  }

  function handleComposerSubmit(e: React.FormEvent<HTMLFormElement>) {
    const liveDraft = draftComposerRef.current?.getValue() ?? draft;
    if (composerReplyInterruptActive) {
      e.preventDefault();
      handleTypingIndicatorPress();
      return;
    }
    if (composerSubmitUsesRandomNudge(liveDraft)) {
      e.preventDefault();
      void sendRandomConversationNudge();
      return;
    }
    void sendMessage(e, {
      starterPrompt: isStarterPromptReady(liveDraft),
      draftOverride: liveDraft,
    });
  }

  function queueCoffeeGlobalComposerSubmit(liveDraft: string): void {
    pendingCoffeeGlobalComposerSubmitRef.current = {
      draft: liveDraft,
      randomNudge: composerSubmitUsesRandomNudge(liveDraft),
      starterPrompt: isStarterPromptReady(liveDraft),
    };
    navigateToView("chat");
  }

  function handleCoffeeGlobalComposerSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    queueCoffeeGlobalComposerSubmit(draftComposerRef.current?.getValue() ?? draft);
  }

  function handleCoffeeGlobalComposerKeyDown(e: React.KeyboardEvent<HTMLFormElement>) {
    const target = e.target;
    if (!(target instanceof HTMLElement)) return;
    const fromMarkdownEditor = target.closest("[data-markdown-cm-host='true']") !== null;
    const fromPlainTextarea = target instanceof HTMLTextAreaElement;
    if (
      e.key === "Enter" &&
      !e.shiftKey &&
      !fromMarkdownEditor &&
      fromPlainTextarea &&
      !e.defaultPrevented
    ) {
      e.preventDefault();
      queueCoffeeGlobalComposerSubmit(draftComposerRef.current?.getValue() ?? draft);
      return;
    }
    handleComposerKeyDown(e);
  }

  function updateCoffeeDraftFromComposer(next: string): void {
    const previous = coffeeDraftRef.current;
    const countsAsTyping = coffeeDraftChangeCountsAsTyping(previous, next);
    coffeeDraftRef.current = next;
    const activeCoffeeConversationId =
      coffeeConversationRef.current?.id ?? coffeeConversation?.id ?? null;
    if (activeCoffeeConversationId && countsAsTyping) {
      coffeeTableTalkLastTypedAtRef.current = Date.now();
      coffeeTableTalkLastTypedConversationIdRef.current = activeCoffeeConversationId;
    }
    setCoffeeDraft(next);
    const nextTrimmed = next.trim();
    const nextStageDirections =
      nextTrimmed.length > 0 ? extractStageDirections(nextTrimmed) : null;
    const nextIsActionOnly =
      nextStageDirections !== null &&
      nextStageDirections.mainText.trim().length === 0 &&
      nextStageDirections.actions.length > 0;
    if (nextTrimmed.length > 0 && !nextIsActionOnly) {
      clearCoffeeLoopTimer();
    }
  }

  type ShellComposerVariant = "chat" | "coffee-global" | "coffee-table";
  type ShellComposerRenderOptions = {
    variant: ShellComposerVariant;
    formRef?: React.Ref<HTMLFormElement>;
    className?: string;
    value: string;
    editorRef: React.Ref<ComposerInputHandle>;
    placeholder: string;
    submitDisabled: boolean;
    submitLabel: React.ReactNode;
    submitAriaLabel: string;
    submitIconOnly?: boolean;
    hideSubmitButton?: boolean;
    onSubmit: React.FormEventHandler<HTMLFormElement>;
    onKeyDown: React.KeyboardEventHandler<HTMLFormElement>;
    onChange: React.ChangeEventHandler<HTMLTextAreaElement>;
    onValueChange: (value: string) => void;
    onInputActivity?: () => void;
    onFocus?: () => void;
    mentionBots: readonly BotMentionPick[];
    mentionCommitMode?: ComposerMentionCommitMode;
    onMentionPersonaSelect?: (botId: string) => void;
    mentionPopoverFooter?: React.ReactNode;
    commandPicks?: readonly CommandCenterCommand[];
    toolPicks?: readonly CommandCenterCommand[];
    promptPicks?: readonly CommandCenterCommand[];
    wildcardPicks?: readonly CommandCenterCommand[];
    status?: React.ReactNode;
    topContent?: React.ReactNode;
    errorContent?: React.ReactNode;
    showEditNotice?: boolean;
    showQueuedPromptRail?: boolean;
    stacked?: boolean;
    showDebugComposer?: boolean;
    showZenLivePresence?: boolean;
    zenPresenceAtmosphereActive?: boolean;
    composeBotSelected?: boolean;
    composeReady?: boolean;
    composeSendTint?: boolean;
    formStyle?: React.CSSProperties;
  };

  const renderShellComposer = ({
    variant,
    formRef,
    className,
    value,
    editorRef,
    placeholder,
    submitDisabled,
    submitLabel,
    submitAriaLabel,
    submitIconOnly,
    hideSubmitButton,
    onSubmit,
    onKeyDown,
    onChange,
    onValueChange,
    onInputActivity,
    onFocus = handleComposerFocus,
    mentionBots,
    mentionCommitMode,
    onMentionPersonaSelect,
    mentionPopoverFooter,
    commandPicks,
    toolPicks,
    promptPicks,
    wildcardPicks,
    status,
    topContent,
    errorContent,
    showEditNotice = false,
    showQueuedPromptRail = true,
    stacked = false,
    showDebugComposer = false,
    showZenLivePresence = false,
    zenPresenceAtmosphereActive = false,
    composeBotSelected = Boolean(selectedComposeBotAccent),
    composeReady = !submitDisabled,
    composeSendTint = composerSendTintActive,
    formStyle = composeStyle,
  }: ShellComposerRenderOptions): React.JSX.Element => {
    const formClassName = [styles.compose, className].filter(Boolean).join(" ");
    const input = (
      <ComposerInput
        ref={editorRef}
        enabled={composerMarkdownEditorEnabled}
        value={value}
        placeholder={placeholder}
        writingAssistEnabled={settings?.composerWritingAssist !== false}
        generatingRandomPrompt={variant === "coffee-table" ? false : composerRandomPromptBusy}
        submitDisabled={submitDisabled}
        submitLabel={submitLabel}
        submitAriaLabel={submitAriaLabel}
        submitIconOnly={submitIconOnly}
        hideSubmitButton={hideSubmitButton}
        onChange={onChange}
        onValueChange={onValueChange}
        onInputActivity={onInputActivity}
        onFocus={onFocus}
        resolvedTheme={resolvedTheme}
        mentionBots={mentionBots}
        mentionCommitMode={mentionCommitMode}
        onMentionPersonaSelect={onMentionPersonaSelect}
        mentionPopoverFooter={mentionPopoverFooter}
        commandPicks={commandPicks}
        toolPicks={toolPicks}
        promptPicks={promptPicks}
        wildcardPicks={wildcardPicks}
        dismissPopoversSignal={composerPopoverDismissSignal}
      />
    );

    return (
      <form
        ref={formRef}
        className={formClassName}
        data-dev-panel-safe-area="bottom"
        data-starter-compose-surface="true"
        data-compose-bot-selected={composeBotSelected ? "true" : undefined}
        data-compose-ready={composeReady ? "true" : undefined}
        data-compose-send-tint={composeSendTint ? "true" : undefined}
        data-choice-composer-hidden={composerHiddenByChoiceChips ? "true" : undefined}
        data-keyboard-lifted={mobileKeyboardInset > 0 ? "true" : undefined}
        data-coffee-global-compose={variant === "coffee-global" ? "true" : undefined}
        data-coffee-table-compose={variant === "coffee-table" ? "true" : undefined}
        style={formStyle}
        onSubmit={onSubmit}
        onPointerDownCapture={handleComposerPointerDown}
        onBlur={handleComposerBlur}
        onFocusCapture={revealChatComposerChrome}
        onPointerEnter={revealChatComposerChrome}
        onKeyDown={onKeyDown}
      >
        {errorContent}
        {topContent}
        {status}
        {showEditNotice && !composerHiddenByChoiceChips && editingMessageId ? (
          <div className={styles.composeEditNotice} role="status">
            <span>Editing message. Save sends the revised text.</span>
            <button type="button" onClick={cancelEditMessage}>Cancel</button>
          </div>
        ) : null}
        {showQueuedPromptRail ? renderQueuedPromptRail() : null}
        {!composerHiddenByChoiceChips ? (
          stacked ? (
            <div className={styles.chatComposerStack}>
              {showDebugComposer ? renderDebugComposer() : null}
              {showZenLivePresence && zenLivePresenceRailVisible ? (
                <div className={styles.zenLiveActionStatusRail}>
                  <ZenLiveBotPresencePlate
                    bot={zenLivePresenceBot}
                    actionState={zenLiveVisibleBotAction}
                    replyActionText={zenLiveReplyActionText}
                    userActionVisible={Boolean(zenComposerActionPreview)}
                    defaultPrismGlyph={zenDefaultPrismGlyph}
                    defaultPrismFaceStyle={zenDefaultPrismFaceStyle}
                    defaultPrismPresenceVisible={zenDefaultPrismPresenceVisible}
                    defaultPrismPresenceForming={zenDefaultPrismPresenceForming}
                    askQuestionActive={zenLiveAskQuestionMarkerVisible}
                    showThinkingSpinner={zenPendingReplyPlaceholderVisible}
                    isTalking={zenLiveBotTalking}
                    mouthOpen={zenLiveBotMouthOpen}
                    mouthShape={zenLiveBotRevealMouthShape}
                    presencePhase={zenPersonaPresence.phase}
                    resolvedTheme={resolvedTheme}
                    atmosphereActive={zenPresenceAtmosphereActive}
                    privateModeActive={privateChatActive}
                  />
                  {zenComposerActionPreview ? (
                    <ZenActionComposerPreview cue={zenComposerActionPreview} />
                  ) : null}
                </div>
              ) : null}
              <div
                className={styles.chatComposerRow}
                data-zen-live-bot-composer-boundary="true"
              >
                {input}
              </div>
            </div>
          ) : (
            input
          )
        ) : null}
      </form>
    );
  };

  function updateDebugComposerDraft(nextDraft: string): void {
    setDebugComposerDraft(nextDraft);
    publishComposerTypingActivity(Date.now());
  }

  function submitDebugComposerEcho(): void {
    const trimmed = debugComposerDraft.trim();
    if (!trimmed || pendingReply || view !== "chat") return;
    if (chatAutoRestoreSuppressed) {
      setChatAutoRestoreSuppressed(false);
    }
    if (forceNewConversationOnNextSend) {
      setForceNewConversationOnNextSend(false);
    }
    if (editingMessageId !== null) {
      setEditingMessageId(null);
      setEditingOriginalText("");
    }
    setConversationStarterPrompts(null);
    setChatStartupSummary(null);
    chatSummaryRefreshMarkerRef.current = null;
    setError(null);
    setDebugComposerDraft("");
    debugComposerDraftRef.current = "";
    if (zenLiveUserActionPreviewSourceRef.current === "debug") {
      setZenLiveUserActionPreview(null);
      setZenLiveBotAction(null);
    }
    const fallbackBotId = zenPersonaBotId;
    const fallbackBot = fallbackBotId
      ? bots.find((bot) => bot.id === fallbackBotId) ?? null
      : null;
    const debugBot = zenPersonaBot ?? fallbackBot;
    const nowIso = new Date().toISOString();
    const debugAssistantMessage: Message = {
      id: `debug-echo-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
      role: "assistant",
      content: trimmed,
      createdAt: nowIso,
      provider: "local",
      model: "dev/debug-echo",
      botId: fallbackBotId,
      botName: debugBot?.name ?? DEFAULT_ASSISTANT_NAME,
      botColor: debugBot?.color ?? undefined,
      botGlyph: debugBot?.glyph ?? undefined,
      moodKey: "neutral",
      moodConfidence: 1,
    };
    setDetail((current) => {
      const nextBotId = fallbackBotId;
      const nextBotColor = debugBot?.color ?? null;
      const baseMessages = current?.messages ?? [];
      const nextConversation = {
        id: current?.id ?? "pending",
        title: current?.title ?? "New chat",
        botId: current?.botId ?? null,
        incognito: current?.incognito ?? pendingIncognito,
        lastBotId: nextBotId,
        lastBotColor: nextBotColor,
        hasAssistantReply: true,
        messages: [...baseMessages, debugAssistantMessage],
      };
      markLatestAssistantRevealEligible(nextConversation);
      return nextConversation;
    });
    setChatEphemeralNowMs(Date.now());
  }

  const primeStarterComposer = useCallback((value: string) => {
    if (value.trim().length === 0 && (!detail || detail.messages.length === 0)) {
      setComposerPrimed(true);
    }
  }, [detail]);

  function publishComposerTypingActivity(timestampMs: number): void {
    chatComposerPublishedTypedAtMsRef.current = timestampMs;
    setChatComposerLastTypedAtMs((current) =>
      current === timestampMs ? current : timestampMs
    );
  }

  function cancelDeferredComposerDraftState(): void {
    if (pendingDraftSyncTimerRef.current !== null) {
      window.clearTimeout(pendingDraftSyncTimerRef.current);
      pendingDraftSyncTimerRef.current = null;
    }
    pendingDraftSyncValueRef.current = null;
  }

  function setComposerDraftNow(nextDraft: string): void {
    cancelDeferredComposerDraftState();
    draftLiveRef.current = nextDraft;
    setDraft(nextDraft);
  }

  function clearComposerDraftNow(): void {
    setComposerDraftNow("");
    setComposerSendTintActive(false);
  }

  function markComposerTypingActivity(): void {
    const now = Date.now();
    askQuestionPatienceLastTypingAtMsRef.current = performance.now();
    chatComposerLastTypedAtMsRef.current = now;
    const lastPublished = chatComposerPublishedTypedAtMsRef.current;
    if (
      lastPublished === null ||
      now - lastPublished >= CHAT_MODE_COMPOSER_TYPING_PUBLISH_MS
    ) {
      if (chatComposerTypingPublishTimerRef.current !== null) {
        window.clearTimeout(chatComposerTypingPublishTimerRef.current);
        chatComposerTypingPublishTimerRef.current = null;
      }
      publishComposerTypingActivity(now);
      return;
    }
    if (chatComposerTypingPublishTimerRef.current !== null) return;
    chatComposerTypingPublishTimerRef.current = window.setTimeout(() => {
      chatComposerTypingPublishTimerRef.current = null;
      const latest = chatComposerLastTypedAtMsRef.current;
      if (typeof latest !== "number") return;
      publishComposerTypingActivity(latest);
    }, Math.max(0, CHAT_MODE_COMPOSER_TYPING_PUBLISH_MS - (now - lastPublished)));
  }

  function flushDeferredComposerDraftState(): void {
    if (pendingDraftSyncTimerRef.current !== null) {
      window.clearTimeout(pendingDraftSyncTimerRef.current);
      pendingDraftSyncTimerRef.current = null;
    }
    const nextDraft = pendingDraftSyncValueRef.current;
    pendingDraftSyncValueRef.current = null;
    if (typeof nextDraft !== "string") return;
    if (draftLiveRef.current !== nextDraft) return;
    setDraft((current) => (current === nextDraft ? current : nextDraft));
  }

  function scheduleDeferredComposerDraftState(nextDraft: string): void {
    pendingDraftSyncValueRef.current = nextDraft;
    if (pendingDraftSyncTimerRef.current !== null) {
      window.clearTimeout(pendingDraftSyncTimerRef.current);
    }
    pendingDraftSyncTimerRef.current = window.setTimeout(() => {
      flushDeferredComposerDraftState();
    }, CHAT_MODE_COMPOSER_PARENT_DRAFT_SYNC_MS);
  }

  function updateComposerDraft(nextDraft: string) {
    const normalizedNextDraft = clampTextAfterLeadingCommandChip(
      nextDraft,
      composerCommandPicks
    );
    const previousDraft = draftLiveRef.current;
    draftLiveRef.current = normalizedNextDraft;
    resetComposerHistoryCursor();
    if (normalizedNextDraft !== previousDraft) {
      setComposerSendTintActive(true);
      markComposerTypingActivity();
      if (
        view === "chat" &&
        normalizedNextDraft.trim().length > 0 &&
        (pendingReplyVisible || chatAssistantRevealInProgress)
      ) {
        const activeConversationId =
          detail?.id && detail.id !== "pending" ? detail.id : selectedId;
        beginOrRefreshZenFollowupBuffer(activeConversationId);
        if (chatAssistantRevealInProgress && activeConversationId) {
          cancelChatModeSmoothScroll();
          chatAutoscrollUserDisarmedByConversationRef.current.set(
            activeConversationId,
            true
          );
          chatAutoscrollArmedByConversationRef.current.set(activeConversationId, false);
        }
        if (pendingReplyVisible) {
          priorityCommandCancelControllerRef.current = pendingReplyAbortControllerRef.current;
          stopPendingReply();
        }
      }
    }
    const shouldDeferParentDraftSync =
      composerMarkdownEditorEnabled &&
      view === "chat" &&
      chatAssistantRevealInProgress &&
      normalizedNextDraft.trim().length > 0 &&
      previousDraft.trim().length > 0;
    if (shouldDeferParentDraftSync) {
      scheduleDeferredComposerDraftState(normalizedNextDraft);
    } else {
      cancelDeferredComposerDraftState();
      setDraft(normalizedNextDraft);
    }
    if (normalizedNextDraft !== previousDraft) {
      snapAskQuestionComposerToChatBottom();
    }
  }

  function handleComposerChange(e: React.ChangeEvent<HTMLTextAreaElement>) {
    updateComposerDraft(e.currentTarget.value);
  }

  function handleComposerFocus() {
    revealChatComposerChrome();
    setComposerFocused(true);
    setComposerSendTintActive(true);
    snapAskQuestionComposerToChatBottom();
  }

  function handleComposerPointerDown(event: React.PointerEvent<HTMLFormElement>) {
    if (eventTargetIsTextEditable(event.target)) return;
    setComposerSendTintActive(true);
    snapAskQuestionComposerToChatBottom();
  }

  function handleComposerBlur(e: React.FocusEvent<HTMLFormElement>) {
    const nextFocus = e.relatedTarget;
    if (nextFocus instanceof Node && e.currentTarget.contains(nextFocus)) return;
    setComposerFocused(false);
    setComposerPrimed(false);
  }

  function handleComposerKeyDown(e: React.KeyboardEvent<HTMLFormElement>) {
    const target = e.target;
    if (!(target instanceof HTMLElement)) return;
    if (target.closest("[data-debug-composer='true']")) return;
    if (e.defaultPrevented) return;
    setComposerSendTintActive(true);
    const fromMarkdownEditor = target.closest("[data-markdown-cm-host='true']") !== null;
    const fromPlainTextarea = target instanceof HTMLTextAreaElement;
    if (!fromMarkdownEditor && !fromPlainTextarea) return;
    revealChatComposerChrome();

    if (
      e.key === "ArrowUp" &&
      !e.shiftKey &&
      !e.altKey &&
      !e.metaKey &&
      !e.ctrlKey
    ) {
      const liveDraft = draftComposerRef.current?.getValue() ?? draft;
      const recalled = recallPreviousComposerHistory(liveDraft);
      if (recalled !== null) {
        e.preventDefault();
        setComposerPrimed(false);
        setDraft(recalled);
        setComposerSendTintActive(recalled.trim().length > 0);
      }
      return;
    }

    if (
      e.key === "ArrowDown" &&
      !e.shiftKey &&
      !e.altKey &&
      !e.metaKey &&
      !e.ctrlKey
    ) {
      const recalled = recallNextComposerHistory();
      if (recalled !== null) {
        e.preventDefault();
        setComposerPrimed(false);
        setDraft(recalled);
        setComposerSendTintActive(recalled.trim().length > 0);
      }
      return;
    }

    if (e.key !== "Enter" || e.shiftKey) return;
    if (fromMarkdownEditor) return;
    e.preventDefault();
    const liveDraft = draftComposerRef.current?.getValue() ?? draft;
    void sendMessage(e, {
      starterPrompt: isStarterPromptReady(liveDraft),
      draftOverride: liveDraft,
    });
  }

  /** Always render submit control; empty state swaps it to random prompt dice. */
  const hideMobileEmptySend = false;

  function startFreshConversation(privateMode: boolean) {
    setZenPrivateReturnCheckpoint(null);
    setImagePrivateMode(privateMode);
    if (view === "chat") {
      const switchingPrivacyMode = pendingIncognito !== privateMode;
      if (switchingPrivacyMode && !pendingReplyVisible) {
        pulseConversationSurfaceLoading();
      }
      revealZenHeaderForFreshSurface();
      setConversationStarterPrompts(null);
      setChatStartupSummary(null);
      setPendingZenSessionBreak(null);
      setPendingZenSessionResumeContext(null);
      chatSummaryRefreshMarkerRef.current = null;
      setChatAutoRestoreSuppressed(true);
      setForceNewConversationOnNextSend(false);
      setSelectedId(null);
      setDetail(null);
      setSelectedBotId(null);
      setSandboxGridSelectedBotId(null);
      setChatBotOverride(undefined);
      setZenPersonaBotId(null);
      setBotLibraryGroupFilterId(BOT_LIBRARY_GROUP_FILTER_ALL);
      setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
      closeEmptyStateBotSearch();
      if (hueFilterCenter !== null) {
        startBotPickerReturnToAll();
      } else {
        setHueFilterCenter(null);
      }
      setPendingIncognito(privateMode);
      rotateZenFallbackWallpaperSeed();
      return;
    }
    const normalStarterBotId = detail
      ? chatBotOverride !== undefined
        ? chatBotOverride
        : detail.botId
      : selectedBotId;
    const privateStarterBotId = privateMode
      ? chatBotOverride !== undefined
        ? chatBotOverride
        : selectedBotId !== null
          ? selectedBotId
        : detail?.id !== undefined && detail.id !== "pending"
          ? detail.botId
          : (detail?.botId ?? selectedBotId ?? null)
      : null;
    const starterBotId = privateMode ? privateStarterBotId : normalStarterBotId;
    setConversationStarterPrompts(null);
    setSelectedId(null);
    // Sandbox "New chat" should return to bot selection without pre-creating
    // a pending thread. The next send/starter action creates the chat.
    setDetail(null);
    setSelectedBotId(starterBotId);
    setChatBotOverride(undefined);
    closeEmptyStateBotSearch();
    if (hueFilterCenter !== null) {
      startBotPickerReturnToAll();
    } else {
      setHueFilterCenter(null);
    }
    setPendingIncognito(privateMode);
  }

  function setAppWidePrivateMode(privateMode: boolean): void {
    setImagePrivateMode(privateMode);
    if (privateMode) {
      if (privatePoofTimerRef.current !== null) {
        window.clearTimeout(privatePoofTimerRef.current);
        privatePoofTimerRef.current = null;
      }
      setPrivatePoofActive(false);
      if (view === "chat" && !appWidePrivateMode && !zenPrivateReturnCheckpoint) {
        setZenPrivateReturnCheckpoint({
          selectedId,
          detail,
          selectedBotId,
          zenPersonaBotId,
          chatBotOverride,
          sessionOpinion,
          botOpinion,
        });
      }
      setPendingIncognito(true);
      return;
    }
    setPendingIncognito(false);
    if (view === "chat" && zenPrivateReturnCheckpoint) {
      setSelectedId(zenPrivateReturnCheckpoint.selectedId);
      setDetail(zenPrivateReturnCheckpoint.detail);
      setSelectedBotId(zenPrivateReturnCheckpoint.selectedBotId);
      setZenPersonaBotId(zenPrivateReturnCheckpoint.zenPersonaBotId);
      setChatBotOverride(zenPrivateReturnCheckpoint.chatBotOverride);
      setSessionOpinion(zenPrivateReturnCheckpoint.sessionOpinion);
      setBotOpinion(zenPrivateReturnCheckpoint.botOpinion);
      setZenPrivateReturnCheckpoint(null);
      setError(null);
      return;
    }
    setZenPrivateReturnCheckpoint(null);
    const restoreConversationId =
      selectedId ?? (detail?.id && detail.id !== "pending" ? detail.id : null);
    if (detail?.incognito && restoreConversationId) {
      void refreshConversation(restoreConversationId).catch(() => {});
    }
  }

  function toggleAppWidePrivateMode(): void {
    if (!appWidePrivateMode) {
      setAppWidePrivateMode(true);
      return;
    }
    if (privatePoofTimerRef.current !== null) {
      window.clearTimeout(privatePoofTimerRef.current);
    }
    setPrivatePoofActive(true);
    privatePoofTimerRef.current = window.setTimeout(() => {
      privatePoofTimerRef.current = null;
      setAppWidePrivateMode(false);
      setPrivatePoofActive(false);
    }, 360);
  }

  /** Click-to-start: dispatches a starter prompt request as if the user typed
   *  nothing and submitted. The bot (or default Prism) opens the conversation
   *  with its own first message. */
  function handleHeroStartConversation(
    event: React.MouseEvent<HTMLButtonElement>
  ): void {
    event.stopPropagation();
    if (replayCachedZenInitialStarterReply()) return;
    if (armCanceledZenInitialStarterReplay()) return;
    if (pendingReply) return;
    if (!isStarterPromptAvailable(draft)) return;
    setChatAutoRestoreSuppressed(false);
    void sendMessage(
      { preventDefault: () => {} } as React.FormEvent<HTMLFormElement>,
      { starterPrompt: true, starterPromptWarrantsIntro: true }
    );
  }

  function resetChatHeaderToSpotlight() {
    startFreshConversation(false);
    setComposerPrimed(false);
    showEmptyStateSearchAfterReturn();
  }

  function readSettingsDraftText(
    form: HTMLFormElement,
    fieldName: string,
    draftValue: string
  ): string {
    if (draftValue.trim().length > 0) return draftValue;
    const value = new FormData(form).get(fieldName);
    if (typeof value === "string" && value.trim().length > 0) return value;
    if (typeof document !== "undefined") {
      const matchingInputs = document.querySelectorAll<HTMLInputElement>(
        `input[name="${fieldName}"]`
      );
      for (const input of matchingInputs) {
        if (input.value.trim().length > 0) return input.value;
      }
    }
    return typeof value === "string" ? value : draftValue;
  }

  function readSettingsFormDataText(
    formData: FormData,
    fieldName: string,
    fallbackValue: string
  ): string {
    const value = formData.get(fieldName);
    return typeof value === "string" ? value : fallbackValue;
  }

  function normalizeSettingsPickerSubmit(
    rawValue: string,
    currentValue: string | null | undefined,
    visibleLegacyValue: string,
    options: { normalizeOnlineImage?: boolean } = {}
  ): string {
    const raw = rawValue.trim();
    const current = currentValue?.trim() ?? "";
    if (!current && raw === visibleLegacyValue) return "";
    if (modelChoiceIsDisabled(raw)) return DISABLED_MODEL_CHOICE;
    if (!raw || raw === AUTO_MODEL_CHOICE) return "";
    return options.normalizeOnlineImage ? normalizeOnlineImageModelPreference(raw) : raw;
  }

  function buildZenModeSettingsPayload(
    source: UserSettings,
    options: { resetModels?: boolean } = {}
  ): Record<string, unknown> {
    const zenFields = normalizeZenModeSettingsFields(source);
    return {
      ...zenFields,
      preferredZenWallpaperLocalImageModel: options.resetModels
        ? ""
        : normalizeSettingsPickerSubmit(
            source.preferredZenWallpaperLocalImageModel,
            settings?.preferredZenWallpaperLocalImageModel,
            settingsLocalImageModelChoice(settings?.preferredZenWallpaperLocalImageModel)
          ),
      preferredZenWallpaperOpenAiImageModel: options.resetModels
        ? ""
        : normalizeSettingsPickerSubmit(
            source.preferredZenWallpaperOpenAiImageModel,
            settings?.preferredZenWallpaperOpenAiImageModel,
            settingsOnlineImageModelChoice(settings?.preferredZenWallpaperOpenAiImageModel),
            { normalizeOnlineImage: true }
          ),
    };
  }

  async function saveZenModeSettings(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    if (!settings) return;
    const payload = buildZenModeSettingsPayload(settings);
    setBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      await api("/api/settings", {
        method: "PATCH",
        body: JSON.stringify(payload),
      });
      setSettings((previous) =>
        previous ? ({ ...previous, ...payload } as UserSettings) : previous
      );
      await refreshSettings();
      setPanelNotice("Zen Mode settings saved.");
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Zen Mode settings failed to save.");
      await refreshSettings();
    } finally {
      setBusy(false);
    }
  }

  async function restoreZenModeDefaults() {
    if (!settings) return;
    const payload = {
      ...defaultZenModeSettings(),
      preferredZenWallpaperLocalImageModel: "",
      preferredZenWallpaperOpenAiImageModel: "",
    };
    setBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      await api("/api/settings", {
        method: "PATCH",
        body: JSON.stringify(payload),
      });
      setSettings((previous) =>
        previous ? ({ ...previous, ...payload } as UserSettings) : previous
      );
      await refreshSettings();
      setPanelNotice("Zen Mode defaults restored.");
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Could not restore Zen defaults.");
      await refreshSettings();
    } finally {
      setBusy(false);
    }
  }

  async function saveCoffeeModeSettings(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    if (!settings) return;
    const payload = {
      coffeeExperimentalTableAngleEnabled:
        settings.coffeeExperimentalTableAngleEnabled === true,
    };
    setBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      await api("/api/settings", {
        method: "PATCH",
        body: JSON.stringify(payload),
      });
      setSettings((previous) =>
        previous ? ({ ...previous, ...payload } as UserSettings) : previous
      );
      await refreshSettings();
      setPanelNotice("Coffee Mode settings saved.");
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Coffee Mode settings failed to save.");
      await refreshSettings();
    } finally {
      setBusy(false);
    }
  }

  async function saveSettings(
    e: React.FormEvent<HTMLFormElement>,
    options: { closeHostsModalOnSuccess?: boolean } = {}
  ) {
    e.preventDefault();
    if (!settings) return;
    setBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      // Only include the key field when the user typed something; otherwise
      // the backend would have no way to tell "no change" apart from "clear".
      // Server re-sanitizes via `sanitizeOpenAiKeyInput`, so a paste of
      // `OPENAI_API_KEY=sk-...` (or a quoted variant) is stripped before
      // it ever gets encrypted into the user row.
      const formData = new FormData(e.currentTarget);
      const prismDefaultLlmModel = readSettingsFormDataText(
        formData,
        SETTINGS_PRISM_DEFAULT_LLM_MODEL_FIELD,
        settings.prismDefaultLlmModel
      ).trim();
      const prismImageToolLlmModel = readSettingsFormDataText(
        formData,
        SETTINGS_PRISM_IMAGE_TOOL_LLM_MODEL_FIELD,
        settings.prismImageToolLlmModel
      ).trim();
      const preferredLocalModelRaw = readSettingsFormDataText(
        formData,
        SETTINGS_PREFERRED_LOCAL_MODEL_FIELD,
        settings.preferredLocalModel
      ).trim();
      const preferredOnlineModelRaw = readSettingsFormDataText(
        formData,
        SETTINGS_PREFERRED_ONLINE_MODEL_FIELD,
        settings.preferredOnlineModel
      ).trim();
      const preferredLocalImageModel = readSettingsFormDataText(
        formData,
        SETTINGS_PREFERRED_LOCAL_IMAGE_MODEL_FIELD,
        settings.preferredLocalImageModel
      ).trim();
      const preferredOpenAiImageModelRaw = readSettingsFormDataText(
        formData,
        SETTINGS_PREFERRED_OPENAI_IMAGE_MODEL_FIELD,
        settings.preferredOpenAiImageModel
      ).trim();
      const preferredZenWallpaperLocalImageModel = readSettingsFormDataText(
        formData,
        SETTINGS_PREFERRED_ZEN_WALLPAPER_LOCAL_IMAGE_MODEL_FIELD,
        settings.preferredZenWallpaperLocalImageModel
      ).trim();
      const preferredZenWallpaperOpenAiImageModelRaw = readSettingsFormDataText(
        formData,
        SETTINGS_PREFERRED_ZEN_WALLPAPER_OPENAI_IMAGE_MODEL_FIELD,
        settings.preferredZenWallpaperOpenAiImageModel
      ).trim();
      const lenientLocalFallbackModel = readSettingsFormDataText(
        formData,
        SETTINGS_LENIENT_LOCAL_FALLBACK_MODEL_FIELD,
        settings.lenientLocalFallbackModel
      ).trim();
      const lenientLocalImageFallbackModel = readSettingsFormDataText(
        formData,
        SETTINGS_LENIENT_LOCAL_IMAGE_FALLBACK_MODEL_FIELD,
        settings.lenientLocalImageFallbackModel
      ).trim();
      const visiblePrismDefaultLlmModel = settingsLocalLlmModelChoice(
        settings.prismDefaultLlmModel,
        commandCenterAuxiliaryModelId(settings)
      );
      const visiblePrismImageToolLlmModel = settingsLocalLlmModelChoice(
        settings.prismImageToolLlmModel,
        defaultModelChoiceForProvider(modelCatalog, settings, "local")
      );
      const visiblePreferredLocalModel = visibleConcreteModelChoiceForProvider(
        modelCatalog,
        settings,
        "local",
        settings.preferredLocalModel
      );
      const visiblePreferredOnlineModel = visibleConcreteOnlineModelChoice(
        modelCatalog,
        settings,
        settings.preferredOnlineModel
      );
      const visiblePreferredLocalImageModel = settingsLocalImageModelChoice(
        settings.preferredLocalImageModel
      );
      const visiblePreferredOpenAiImageModel = settingsOnlineImageModelChoice(
        settings.preferredOpenAiImageModel
      );
      const visiblePreferredZenWallpaperLocalImageModel = settingsLocalImageModelChoice(
        settings.preferredZenWallpaperLocalImageModel
      );
      const visiblePreferredZenWallpaperOpenAiImageModel = settingsOnlineImageModelChoice(
        settings.preferredZenWallpaperOpenAiImageModel
      );
      const body: Record<string, unknown> = {
        ...settings,
        prismDefaultLlmModel: normalizeSettingsPickerSubmit(
          prismDefaultLlmModel,
          settings.prismDefaultLlmModel,
          visiblePrismDefaultLlmModel
        ),
        prismImageToolLlmModel: normalizeSettingsPickerSubmit(
          prismImageToolLlmModel,
          settings.prismImageToolLlmModel,
          visiblePrismImageToolLlmModel
        ),
        preferredLocalModel: normalizeSettingsPickerSubmit(
          preferredLocalModelRaw,
          settings.preferredLocalModel,
          visiblePreferredLocalModel
        ),
        preferredOnlineModel: normalizeSettingsPickerSubmit(
          preferredOnlineModelRaw,
          settings.preferredOnlineModel,
          visiblePreferredOnlineModel
        ),
        preferredLocalImageModel: normalizeSettingsPickerSubmit(
          preferredLocalImageModel,
          settings.preferredLocalImageModel,
          visiblePreferredLocalImageModel
        ),
        preferredOpenAiImageModel: normalizeSettingsPickerSubmit(
          preferredOpenAiImageModelRaw,
          settings.preferredOpenAiImageModel,
          visiblePreferredOpenAiImageModel,
          { normalizeOnlineImage: true }
        ),
        preferredZenWallpaperLocalImageModel: normalizeSettingsPickerSubmit(
          preferredZenWallpaperLocalImageModel,
          settings.preferredZenWallpaperLocalImageModel,
          visiblePreferredZenWallpaperLocalImageModel
        ),
        preferredZenWallpaperOpenAiImageModel: normalizeSettingsPickerSubmit(
          preferredZenWallpaperOpenAiImageModelRaw,
          settings.preferredZenWallpaperOpenAiImageModel,
          visiblePreferredZenWallpaperOpenAiImageModel,
          { normalizeOnlineImage: true }
        ),
        lenientLocalFallbackModel,
        lenientLocalImageFallbackModel,
      };
      const submittedOpenAiKey = readSettingsDraftText(
        e.currentTarget,
        SETTINGS_OPENAI_KEY_FIELD,
        openAiKey
      );
      const submittedAnthropicKey = readSettingsDraftText(
        e.currentTarget,
        SETTINGS_ANTHROPIC_KEY_FIELD,
        anthropicKey
      );
      const submittedElevenLabsKey = readSettingsDraftText(
        e.currentTarget,
        SETTINGS_ELEVENLABS_KEY_FIELD,
        elevenLabsKey
      );
      const trimmedKey = submittedOpenAiKey.trim();
      if (trimmedKey.length > 0) {
        body.openAiApiKey = trimmedKey;
      }
      const trimmedAnthropicKey = submittedAnthropicKey.trim();
      if (trimmedAnthropicKey.length > 0) {
        body.anthropicApiKey = trimmedAnthropicKey;
      }
      const trimmedElevenLabsKey = submittedElevenLabsKey.trim();
      if (trimmedElevenLabsKey.length > 0) {
        body.elevenLabsApiKey = trimmedElevenLabsKey;
      }
      const saved = await api<{
        settings?: Partial<SavedApiKeySettingsState>;
      }>("/api/settings", { method: "PATCH", body: JSON.stringify(body) });
      let confirmedKeySettings: SavedApiKeySettingsState | null = null;
      if (saved.settings) {
        const keySettings = normalizeSavedApiKeySettingsState(saved.settings);
        confirmedKeySettings = keySettings;
        setSettings((previous) =>
          previous
            ? {
                ...previous,
                ...keySettings,
              }
            : previous
        );
      }
      const { comfyUiHost: savedComfyHost, keySettings } = await refreshSettings();
      confirmedKeySettings = keySettings;
      const missingSavedKeys = [
        trimmedKey.length > 0 && !confirmedKeySettings.hasOpenAiApiKey
          ? "OpenAI"
          : null,
        trimmedAnthropicKey.length > 0 &&
        !confirmedKeySettings.hasAnthropicApiKey
          ? "Anthropic"
          : null,
        trimmedElevenLabsKey.length > 0 &&
        !confirmedKeySettings.hasElevenLabsApiKey
          ? "ElevenLabs"
          : null,
      ].filter((label): label is string => Boolean(label));
      if (missingSavedKeys.length > 0) {
        throw new Error(
          `Could not confirm saved ${missingSavedKeys.join(", ")} API key${
            missingSavedKeys.length === 1 ? "" : "s"
          }.`
        );
      }
      clearSettingsApiKeyDrafts();
      await refreshModels(savedComfyHost);
      await refreshProviderKeyStatus();
      await refreshSecondaryOllamaStatus();
      await refreshComfyUiStatus();
      setPanelNotice("Settings saved.");
      if (options.closeHostsModalOnSuccess) {
        setSettingsHostsModalOpen(false);
      }
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Save failed.");
      return false;
    } finally {
      setBusy(false);
    }
  }

  function setBotCustomizerModelVisible(modelId: string, visible: boolean) {
    if (modelId === REQUIRED_PRIMARY_LOCAL_MODEL_ID) {
      return;
    }
    if (!visible) {
      setNewBotLocalModel((current) =>
        current === modelId ? AUTO_MODEL_CHOICE : current
      );
      setNewBotOnlineModel((current) =>
        current === modelId ? AUTO_MODEL_CHOICE : current
      );
      setNewBotLocalImageModel((current) =>
        current === modelId ? AUTO_MODEL_CHOICE : current
      );
      setNewBotOpenAiImageModel((current) =>
        current === modelId ? AUTO_MODEL_CHOICE : current
      );
      const clearModelChoiceByProvider = (
        previous: Record<Provider, string>
      ): Record<Provider, string> => ({
        ...previous,
        local: previous.local === modelId ? AUTO_MODEL_CHOICE : previous.local,
        openai: previous.openai === modelId ? AUTO_MODEL_CHOICE : previous.openai,
        anthropic:
          previous.anthropic === modelId ? AUTO_MODEL_CHOICE : previous.anthropic,
      });
      setChatModelChoiceByProvider(clearModelChoiceByProvider);
      setCoffeeModelChoiceByProvider(clearModelChoiceByProvider);
      setStoryModelChoiceByProvider(clearModelChoiceByProvider);
      setImageGenModelChoiceByProvider((previous) => ({
        ...previous,
        local: previous.local === modelId ? AUTO_MODEL_CHOICE : previous.local,
        openai: previous.openai === modelId ? AUTO_MODEL_CHOICE : previous.openai,
      }));
      setCommandCenterPreferredModel((current) => {
        const parsed = parseCommandCenterModelChoice(current);
        return parsed?.modelId === modelId ? AUTO_MODEL_CHOICE : current;
      });
    }
    setSettings((previous) => {
      if (!previous) return previous;
      const current = new Set(previous.hiddenBotModelIds ?? []);
      if (visible) {
        current.delete(modelId);
      } else {
        current.add(modelId);
      }
      const clearIfHidden = (value: string | null | undefined): string => {
        const trimmed = value?.trim() ?? "";
        return !visible && trimmed === modelId ? "" : trimmed;
      };
      return {
        ...previous,
        hiddenBotModelIds: Array.from(current),
        preferredLocalModel: clearIfHidden(previous.preferredLocalModel),
        preferredOnlineModel: clearIfHidden(previous.preferredOnlineModel),
        preferredLocalImageModel: clearIfHidden(previous.preferredLocalImageModel),
        preferredOpenAiImageModel: clearIfHidden(previous.preferredOpenAiImageModel),
        preferredZenWallpaperLocalImageModel: clearIfHidden(
          previous.preferredZenWallpaperLocalImageModel
        ),
        preferredZenWallpaperOpenAiImageModel: clearIfHidden(
          previous.preferredZenWallpaperOpenAiImageModel
        ),
        lenientLocalFallbackModel: clearIfHidden(previous.lenientLocalFallbackModel),
        lenientLocalImageFallbackModel: clearIfHidden(
          previous.lenientLocalImageFallbackModel
        ),
      };
    });
  }

  function setComfyUiWorkflowVisible(modelId: string, visible: boolean) {
    if (!visible) {
      setImageGenModelChoiceByProvider((previous) =>
        previous.local === modelId
          ? { ...previous, local: AUTO_MODEL_CHOICE }
          : previous
      );
      setNewBotLocalImageModel((current) =>
        current === modelId ? AUTO_MODEL_CHOICE : current
      );
    }
    setSettings((previous) => {
      if (!previous) return previous;
      const hidden = new Set(previous.hiddenComfyUiWorkflowIds ?? []);
      if (visible) {
        hidden.delete(modelId);
      } else {
        hidden.add(modelId);
      }
      const clearIfHidden = (value: string | null | undefined): string => {
        const trimmed = value?.trim() ?? "";
        return !visible && trimmed === modelId ? "" : trimmed;
      };
      return {
        ...previous,
        hiddenComfyUiWorkflowIds: Array.from(hidden),
        preferredLocalImageModel: clearIfHidden(previous.preferredLocalImageModel),
        preferredZenWallpaperLocalImageModel: clearIfHidden(
          previous.preferredZenWallpaperLocalImageModel
        ),
        lenientLocalImageFallbackModel: clearIfHidden(
          previous.lenientLocalImageFallbackModel
        ),
      };
    });
  }

  async function switchProvider(provider: Provider) {
    if (!settings || settings.preferredProvider === provider) return;
    const previous = settings;
    // Optimistically flip the UI; a failed PATCH rolls back.
    setSettings({ ...settings, preferredProvider: provider });
    setError(null);
    setPanelError(null);
    try {
      await api("/api/settings", {
        method: "PATCH",
        body: JSON.stringify({ preferredProvider: provider }),
      });
      await refreshSettings();
    } catch (err) {
      setSettings(previous);
      setError(err instanceof Error ? err.message : "Provider switch failed.");
    }
  }

  async function cycleThemeMode() {
    const nextTheme = nextThemeMode(effectiveThemeMode);

    if (settings) {
      // Logged in: persist the choice server-side, optimistically update the UI.
      const previous = settings;
      setSettings({ ...settings, theme: nextTheme });
      setError(null);
      try {
        await api("/api/settings", {
          method: "PATCH",
          body: JSON.stringify({ theme: nextTheme }),
        });
        await refreshSettings();
      } catch (err) {
        setSettings(previous);
        setError(err instanceof Error ? err.message : "Theme switch failed.");
      }
      return;
    }

    // Pre-auth: stash in localStorage so the choice survives reloads and
    // seeds the new user's theme if they register next.
    setPreAuthTheme(nextTheme);
    try {
      window.localStorage.setItem("prism_theme", nextTheme);
    } catch {
      // Non-fatal: if storage is blocked the toggle still works in-memory.
    }
  }

  async function clearSavedKey(provider: "openai" | "anthropic" | "elevenlabs") {
    const providerName =
      provider === "openai"
        ? "OpenAI"
        : provider === "anthropic"
          ? "Anthropic"
          : "ElevenLabs";
    const confirmed = window.confirm(
      `Remove the saved ${providerName} API key from this account? Chat will fall back to the server default if one is configured.`
    );
    if (!confirmed) return;
    setBusy(true);
    setPanelError(null);
    try {
      const saved = await api<{
        settings?: Partial<SavedApiKeySettingsState>;
      }>("/api/settings", {
        method: "PATCH",
        body: JSON.stringify(
          provider === "openai"
            ? { openAiApiKey: null }
            : provider === "anthropic"
              ? { anthropicApiKey: null }
              : { elevenLabsApiKey: null }
        ),
      });
      if (saved.settings) {
        const keySettings = normalizeSavedApiKeySettingsState(saved.settings);
        setSettings((previous) =>
          previous
            ? {
                ...previous,
                ...keySettings,
              }
            : previous
        );
      }
      if (provider === "openai") {
        clearSettingsApiKeyDrafts(["openai"]);
      } else if (provider === "anthropic") {
        clearSettingsApiKeyDrafts(["anthropic"]);
      } else {
        clearSettingsApiKeyDrafts(["elevenlabs"]);
      }
      const { comfyUiHost } = await refreshSettings();
      await refreshModels(comfyUiHost);
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Clear failed.");
    } finally {
      setBusy(false);
    }
  }

  function memoryToastScopeLabel(memory: MemoryEventPayload): string {
    if (!memory.botId) return "Global";
    return bots.find((bot) => bot.id === memory.botId)?.name ?? "Bot";
  }

  function pushMemoryToasts(memoryLearned: ChatPostEnvelope["memoryLearned"]): void {
    const created = memoryLearned?.created ?? [];
    const retracted = memoryLearned?.retracted ?? [];
    const rejected = memoryLearned?.rejected ?? [];
    if (created.length === 0 && retracted.length === 0 && rejected.length === 0) return;

    const now = Date.now();
    const nextToasts: MemoryToast[] = [
      ...created.map((memory) => ({
        id: `created:${memory.id}:${now}`,
        kind: "created" as const,
        memory,
        expiresAt: now + MEMORY_TOAST_DISMISS_MS,
      })),
      ...retracted.map((memory) => ({
        id: `retracted:${memory.id}:${now}`,
        kind: "retracted" as const,
        memory,
        expiresAt: now + MEMORY_TOAST_DISMISS_MS,
      })),
      ...rejected.map((memory, index) => ({
        id: `rejected:${index}:${now}`,
        kind: "rejected" as const,
        rejected: memory,
        expiresAt: now + MEMORY_TOAST_DISMISS_MS,
      })),
    ];
    setMemoryToasts((current) => [...nextToasts, ...current].slice(0, 8));
  }

  async function undoMemoryToast(toast: MemoryToast) {
    setMemoryToasts((current) => current.filter((item) => item.id !== toast.id));
    if (toast.kind === "rejected") return;
    if (toast.kind === "created") {
      const params = new URLSearchParams();
      params.set("allowLongTerm", "true");
      if (toast.memory.source === "about_you") {
        params.set("allowAboutYou", "true");
      }
      await api(`/api/memories/${encodeURIComponent(toast.memory.id)}?${params.toString()}`, {
        method: "DELETE",
      });
    } else {
      await api("/api/memories/restore", {
        method: "POST",
        body: JSON.stringify({
          text: toast.memory.text,
          botId: toast.memory.botId,
          conversationId: toast.memory.conversationId,
          confidence: toast.memory.confidence,
          category: toast.memory.category,
          tier: toast.memory.tier,
          source: toast.memory.source,
          certainty: toast.memory.certainty,
          durability: toast.memory.durability,
          sourceMessageIds: toast.memory.sourceMessageIds ?? [],
        }),
      });
    }
    await refreshOpenMemoryViews();
  }

  function memoryToastTitle(toast: MemoryToast): string {
    if (toast.kind === "rejected") return "Memory skipped";
    const memory = toast.memory;
    if (toast.kind === "created" && memory.validationStatus === "auto_fixed") {
      return "Memory cleaned up";
    }
    return toast.kind === "created" ? "Memory saved" : "Memory forgotten";
  }

  function memoryToastDetail(toast: MemoryToast): string {
    if (toast.kind === "rejected") {
      return `Not saved · ${toast.rejected.originalText}`;
    }
    const memory = toast.memory;
    const prefix =
      toast.kind === "created" && memory.validationStatus === "auto_fixed"
        ? "edited for clarity"
        : "tap to undo";
    return `${memoryToastScopeLabel(memory)} · ${prefix} · ${memory.text}`;
  }

  function memoryDeleteApiOptions(memory: UserMemory): {
    allowLongTerm?: boolean;
    allowAboutYou?: boolean;
  } {
    const longTerm = memoryTier(memory) === "long_term";
    const aboutYou = memory.source === "about_you";
    const out: { allowLongTerm?: boolean; allowAboutYou?: boolean } = {};
    if (longTerm) out.allowLongTerm = true;
    if (aboutYou) out.allowAboutYou = true;
    return out;
  }

  async function deleteMemory(
    id: string,
    options?: { allowLongTerm?: boolean; allowAboutYou?: boolean }
  ) {
    const params = new URLSearchParams();
    if (options?.allowLongTerm) params.set("allowLongTerm", "true");
    if (options?.allowAboutYou) params.set("allowAboutYou", "true");
    const qs = params.toString();
    const result = await api<{ deleted?: boolean }>(
      `/api/memories/${encodeURIComponent(id)}${qs ? `?${qs}` : ""}`,
      { method: "DELETE" }
    );
    if (result.deleted === false) {
      setError("Could not remove that memory. Try again.");
      return;
    }
    setFocusedMemoryId((current) => (current === id ? null : current));
    await refreshOpenMemoryViews();
  }

  async function deleteZenSessionMemory(id: string) {
    const result = await api<{ deleted?: boolean }>(
      `/api/zen/session-memory/${encodeURIComponent(id)}`,
      { method: "DELETE" }
    );
    if (result.deleted === false) {
      setError("Could not remove that session memory. Try again.");
      return;
    }
    disarmDelete();
    setZenSessionMemories((current) => current.filter((memory) => memory.id !== id));
    await refreshZenSessionMemory();
  }

  async function demoteLongTermMemory(id: string) {
    const result = await api<{ demoted?: boolean }>(
      `/api/memories/${encodeURIComponent(id)}/demote`,
      {
        method: "POST",
        body: JSON.stringify({ confidence: 0.34 }),
      }
    );
    if (result.demoted === false) {
      setError("Could not move that memory back to short-term.");
      return;
    }
    setFocusedMemoryId((current) => (current === id ? null : current));
    await refreshOpenMemoryViews();
  }

  // Fork is always anchored to an assistant bubble now (per-message
  // "Fork here" is the only entry point), so `messageId` is mandatory.
  // The backend endpoint remains tolerant of a missing id for
  // compatibility with older clients; the client-side tightening just
  // removes the whole-conversation clone code path we're no longer
  // exposing.
  async function forkConversationFromMessage(
    messageId: string,
    options: {
      includeMessage?: boolean;
      independent?: boolean;
      mode?: "zen";
    } = {}
  ): Promise<ConversationDetail> {
    const sourceConversationId =
      selectedId ??
      (detail?.id && detail.id !== "pending" ? detail.id : null);
    if (!sourceConversationId) {
      throw new Error("Choose a conversation before forking.");
    }
    const fork = await api<{ conversationId: string }>(
      `/api/conversations/${sourceConversationId}/fork`,
      {
        method: "POST",
        body: JSON.stringify({
          messageId,
          ...(options.includeMessage === false ? { includeMessage: false } : {}),
          ...(options.independent ? { independent: true } : {}),
          ...(options.mode ? { mode: options.mode } : {}),
        }),
      }
    );
    const d = await api<{
      conversation: ConversationDetail;
      opinion?: SessionOpinion;
      botOpinion?: BotOpinion;
    }>(`/api/conversations/${fork.conversationId}`);
    const forkedConversation = applyCommandDisplayAliases(
      applyExplicitAskQuestionFallback(d.conversation)
    );
    setSelectedId(fork.conversationId);
    selectedIdRef.current = fork.conversationId;
    setDetail(forkedConversation);
    detailIdRef.current = forkedConversation.id;
    setSessionOpinion(d.opinion ?? null);
    setBotOpinion(d.botOpinion ?? null);
    return forkedConversation;
  }

  async function forkChat(messageId: string) {
    if (!selectedId) return;
    const d = await api<{ conversationId: string }>(`/api/conversations/${selectedId}/fork`, { method: "POST", body: JSON.stringify({ messageId }) });
    await refreshConversations(); await refreshConversation(d.conversationId);
  }

  async function copyMessageToClipboard(msg: Message): Promise<void> {
    try {
      const commandAlias = commandDisplayByMessageIdRef.current.get(msg.id);
      await writeClipboardText(commandAlias?.originalText ?? msg.content);
      setCopiedMessageId(msg.id);
      if (copiedMessageTimerRef.current) {
        clearTimeout(copiedMessageTimerRef.current);
      }
      copiedMessageTimerRef.current = setTimeout(() => {
        setCopiedMessageId(current => current === msg.id ? null : current);
        copiedMessageTimerRef.current = null;
      }, MESSAGE_COPY_FEEDBACK_MS);
    } catch {
      setError("Copy failed. Select the message and copy it manually.");
    }
  }

  function removeMessageFromConversationDetail(
    conversation: ConversationDetail,
    messageId: string
  ): ConversationDetail {
    const nextMessages = conversation.messages.filter((message) => message.id !== messageId);
    if (nextMessages.length === conversation.messages.length) return conversation;
    const lastAssistant = [...nextMessages]
      .reverse()
      .find((message): message is Message => message.role === "assistant");
    if (!lastAssistant) {
      return {
        ...conversation,
        messages: nextMessages,
        hasAssistantReply: false,
        lastBotId: null,
        lastBotColor: null,
      };
    }
    const normalizedBotName = lastAssistant.botName?.trim() ?? "";
    const matchingBots =
      normalizedBotName.length > 0
        ? bots.filter((candidate) => candidate.name.trim() === normalizedBotName)
        : [];
    const inferredLastBotId =
      normalizedBotName.length === 0 ||
      normalizedBotName.toLowerCase() === DEFAULT_ASSISTANT_NAME.toLowerCase()
        ? null
        : matchingBots.length === 1
          ? matchingBots[0]?.id ?? null
          : null;
    return {
      ...conversation,
      messages: nextMessages,
      hasAssistantReply: true,
      lastBotId: inferredLastBotId,
      lastBotColor: lastAssistant.botColor ?? null,
    };
  }

  function latestMessageInConversation(
    conversation: ConversationDetail
  ): Message | null {
    return conversation.messages.reduce<Message | null>((latest, message) => {
      if (!latest) return message;
      return message.createdAt > latest.createdAt ? message : latest;
    }, null);
  }

  function messageIsLatestInConversation(
    conversation: ConversationDetail,
    messageId: string
  ): boolean {
    return latestMessageInConversation(conversation)?.id === messageId;
  }

  function shouldBranchZenDelete(msg: Message): boolean {
    if (view !== "chat") return false;
    if (!detail || detail.incognito || !selectedId) return false;
    if (String(msg.id).startsWith("pending-")) return false;
    return !messageIsLatestInConversation(detail, msg.id);
  }

  async function deleteMessageFromHistory(msg: Message): Promise<void> {
    closeMessageContextOverlay();
    if (!detail) return;
    const removeFromVisibleThread = () => {
      setDetail((current) => {
        if (!current) return current;
        return removeMessageFromConversationDetail(current, msg.id);
      });
    };
    const isLocalOnly = detail.incognito || String(msg.id).startsWith("pending-") || !selectedId;
    if (isLocalOnly) {
      removeFromVisibleThread();
      return;
    }
    if (shouldBranchZenDelete(msg)) {
      const previousDetail = detail;
      const previousSelectedId = selectedId;
      try {
        const forkedConversation = await forkConversationFromMessage(msg.id, {
          mode: "zen",
        });
        const clonedLastMessage = latestMessageInConversation(forkedConversation);
        if (!clonedLastMessage) {
          throw new Error("Could not find the forked message to remove.");
        }
        setDetail(removeMessageFromConversationDetail(forkedConversation, clonedLastMessage.id));
        await api<{ ok: true; deleted: boolean; conversationId?: string }>(
          `/api/messages/${encodeURIComponent(clonedLastMessage.id)}`,
          { method: "DELETE" }
        );
        await refreshConversation(forkedConversation.id);
        void refreshConversations();
        await refreshOpenMemoryViews();
      } catch (err) {
        setSelectedId(previousSelectedId);
        selectedIdRef.current = previousSelectedId;
        setDetail(previousDetail);
        detailIdRef.current = previousDetail.id;
        setError(err instanceof Error ? err.message : "Message delete failed.");
      }
      return;
    }
    const previousDetail = detail;
    const conversationId = selectedId;
    removeFromVisibleThread();
    try {
      await api<{ ok: true; deleted: boolean; conversationId?: string }>(
        `/api/messages/${encodeURIComponent(msg.id)}`,
        { method: "DELETE" }
      );
      await refreshConversation(conversationId);
      void refreshConversations();
      await refreshOpenMemoryViews();
    } catch (err) {
      setDetail(previousDetail);
      setError(err instanceof Error ? err.message : "Message delete failed.");
    }
  }

  const closeMessageContextOverlay = useCallback(() => {
    setMessageContextMenu(null);
    setContextFocusedMessageId(null);
    setMobileFocusedMessageId(null);
    setModelRevealMessageId(null);
  }, []);

  function clampContextMenuPosition(
    x: number,
    y: number,
    estimatedWidth: number,
    estimatedHeight: number,
    bottomBoundaryY = window.innerHeight
  ): { x: number; y: number } {
    const minX = CONTEXT_MENU_VIEWPORT_MARGIN_PX;
    const minY = CONTEXT_MENU_VIEWPORT_MARGIN_PX;
    const maxX = Math.max(
      minX,
      window.innerWidth - estimatedWidth - CONTEXT_MENU_VIEWPORT_MARGIN_PX
    );
    const maxY = Math.max(
      minY,
      bottomBoundaryY - estimatedHeight - CONTEXT_MENU_VIEWPORT_MARGIN_PX
    );
    return {
      x: Math.min(Math.max(x, minX), maxX),
      y: Math.min(Math.max(y, minY), maxY),
    };
  }

  function contextMenuComposerBoundaryY(): number {
    if (typeof document === "undefined") return window.innerHeight;
    let boundaryY = window.innerHeight;
    document
      .querySelectorAll<HTMLElement>(CONTEXT_MENU_COMPOSER_BOUNDARY_SELECTOR)
      .forEach((node) => {
        if (!isElementVisibleForZenLiveBotBoundary(node)) return;
        const rect = node.getBoundingClientRect();
        if (rect.bottom <= 0 || rect.top >= window.innerHeight) return;
        boundaryY = Math.min(boundaryY, Math.max(0, rect.top));
      });
    return boundaryY;
  }

  function contextMenuMaxHeightForBoundary(bottomBoundaryY: number): number {
    return Math.max(
      0,
      Math.floor(bottomBoundaryY - CONTEXT_MENU_VIEWPORT_MARGIN_PX * 2)
    );
  }

  const openBotContextMenu = useCallback((
    bot: Bot,
    x: number,
    y: number,
    selectedBotIds?: string[]
  ) => {
    const bottomBoundaryY = contextMenuComposerBoundaryY();
    const clamped = clampContextMenuPosition(
      x,
      y,
      BOT_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
      BOT_CONTEXT_MENU_ESTIMATED_HEIGHT_PX,
      bottomBoundaryY
    );
    setBotContextMenu({
      botId: bot.id,
      selectedBotIds:
        Array.isArray(selectedBotIds) && selectedBotIds.length > 1
          ? Array.from(new Set(selectedBotIds))
          : [],
      x: clamped.x,
      y: clamped.y,
      maxHeight: contextMenuMaxHeightForBoundary(bottomBoundaryY),
    });
    closeMessageContextOverlay();
    setConversationGroupContextMenu(null);
    setCanvasToolsContextMenu(null);
    setChatOverflowMenuOpen(false);
  }, [closeMessageContextOverlay]);

