  async function importBotFromArchiveBytes(
    archiveBytes: Uint8Array,
    options?: ImportBotOptions
  ): Promise<ImportBotResult> {
    if (!options?.suppressPanelReset) {
      setPanelError(null);
      setPanelNotice(null);
    }
    const parsed = parsePrismBotArchive(archiveBytes);
    const importedBotHash = normalizeImportedBotHash(parsed.botJson.botHash);
    if (
      importedBotHash &&
      !options?.allowDuplicateHash &&
      bots.some((candidate) => normalizeImportedBotHash(candidate.export_hash) === importedBotHash)
    ) {
      throw new Error("This bot is already in your library!");
    }
    const parsedBot = parsed.botJson.bot;
    if (!parsedBot) {
      throw new Error("Invalid bot export file.");
    }
    const importedName = parsedBot.name.trim();
    if (!importedName) {
      throw new Error("Bot export is missing a valid name.");
    }

    const fallbackProfile = blankBotProfile();
    const hasStructuredProfile =
      parsed.botJson.profile !== null
      && typeof parsed.botJson.profile === "object"
      && !Array.isArray(parsed.botJson.profile);
    const profile = hasStructuredProfile
      ? parseStoredBotPrompt(
        serializeStoredBotPrompt(parsed.botJson.profile as BotProfileFields, importedName)
      ).fields
      : fallbackProfile;
    const importedVisiblePrompt =
      typeof parsed.botJson.systemPrompt === "string" ? parsed.botJson.systemPrompt.trim() : "";
    const systemPrompt = hasStructuredProfile
      ? serializeStoredBotPrompt(profile, importedName)
      : importedVisiblePrompt || serializeStoredBotPrompt(profile, importedName);

    const created = await api<{ bot?: { id?: string } }>("/api/bots", {
      method: "POST",
      body: JSON.stringify({
        name: importedName,
        systemPrompt,
        localModel: parsedBot.localModel ?? "",
        onlineModel: parsedBot.onlineModel ?? "",
        localImageModel:
          typeof parsedBot.localImageModel === "string"
            ? parsedBot.localImageModel
            : "",
        openaiImageModel:
          typeof parsedBot.openaiImageModel === "string"
            ? parsedBot.openaiImageModel
            : "",
        onlineEnabled: parsedBot.onlineEnabled !== false,
        flirtEnabled: parsedBot.flirtEnabled === true,
        chatEnabled: parsedBot.chatEnabled !== false,
        temperature:
          typeof parsedBot.temperature === "number"
            ? normalizeBotTemperature(parsedBot.temperature)
            : BOT_TEMPERATURE_DEFAULT,
        maxTokens:
          typeof parsedBot.maxTokens === "number"
            ? normalizeBotMaxTokens(parsedBot.maxTokens)
            : BOT_REPLY_LENGTH_DEFAULT_TOKENS,
        topP:
          typeof parsedBot.topP === "number"
            ? normalizeBotTopP(parsedBot.topP)
            : BOT_TOP_P_DEFAULT,
        topK:
          typeof parsedBot.topK === "number"
            ? normalizeBotTopK(parsedBot.topK)
            : BOT_TOP_K_DEFAULT,
        repetitionPenalty:
          typeof parsedBot.repetitionPenalty === "number"
            ? normalizeBotRepetitionPenalty(parsedBot.repetitionPenalty)
            : BOT_REPETITION_PENALTY_DEFAULT,
        color: typeof parsedBot.color === "string" && parsedBot.color.trim().length > 0
          ? parsedBot.color.trim()
          : null,
        glyph: typeof parsedBot.glyph === "string" && parsedBot.glyph.trim().length > 0
          ? parsedBot.glyph.trim()
          : null,
        faceEyesFont: normalizeBotFaceFontId(parsedBot.faceEyesFont),
        faceEyeCharacter: normalizeBotFaceEyeCharacter(parsedBot.faceEyeCharacter),
        faceMouthFont: normalizeBotFaceFontId(parsedBot.faceMouthFont),
        faceFontWeight: normalizeBotFaceFontWeight(parsedBot.faceFontWeight),
        faceEyeScale: normalizeBotFaceEyeScale(parsedBot.faceEyeScale),
        faceEyeOffsetY: normalizeBotFaceEyeOffsetY(parsedBot.faceEyeOffsetY),
        exportHash: importedBotHash,
      }),
    });
    const createdBotId = created.bot?.id;
    if (!createdBotId) {
      throw new Error("Imported bot was created without an id.");
    }

    const memories = parsed.memories;
    options?.onProgress?.({
      kind: "bot-created",
      importedName,
      restoredMemories: 0,
      totalMemories: memories.length,
    });
    let restored = 0;
    for (const memory of memories) {
      const text = memory.trim();
      if (!text) continue;
      await api("/api/memories/restore", {
        method: "POST",
        body: JSON.stringify({
          text,
          botId: createdBotId,
          source: "compiled",
          category: "general",
          sourceMessageIds: [],
        }),
      });
      restored += 1;
      options?.onProgress?.({
        kind: "memory-restored",
        importedName,
        restoredMemories: restored,
        totalMemories: memories.length,
      });
    }

    let refreshedBots: Bot[] | null = null;
    if (!options?.deferRefresh) {
      refreshedBots = await refreshBots();
      await refreshMemories();
      await refreshBotMemories(createdBotId);
    }
    if (options?.selectInChat !== false) {
      selectImportedBotInChatMode(createdBotId);
    }
    if (options?.openImportedBotInEditor) {
      const importedBot = refreshedBots?.find((bot) => bot.id === createdBotId) ?? null;
      if (importedBot) {
        setSelectedBotPanelBotId(importedBot.id);
        setBotPanelView("customize");
        startEditBot(importedBot);
      }
    }
    if (!options?.suppressNotice) {
      setPanelNotice(
        restored > 0
          ? `${importedName} imported with ${restored} memories.`
          : `${importedName} imported.`
      );
    }
    if (panelRef.current === "bots" && !options?.keepBotsPanelOpen) {
      closePanel();
    }
    return {
      botId: createdBotId,
      importedName,
      importedBotHash,
      restoredMemories: restored,
    };
  }

  function parseBotGroupManifest(raw: string): BotGroupManifestV1 | null {
    try {
      const parsedUnknown = JSON.parse(raw) as unknown;
      if (!parsedUnknown || typeof parsedUnknown !== "object" || Array.isArray(parsedUnknown)) {
        return null;
      }
      const manifest = parsedUnknown as Partial<BotGroupManifestV1>;
      if (manifest.schema !== "prism-bot-group-manifest-v1") return null;
      return manifest as BotGroupManifestV1;
    } catch {
      return null;
    }
  }

  async function importBotCollectionBundle(file: File): Promise<void> {
    setPanelError(null);
    setPanelNotice(null);
    updateBotTransferOverlay((current) => ({
      ...current,
      title: "Importing bot collection",
      subject: file.name,
      detail: "Reading collection file.",
      currentStepLabel: "Opening .bots file",
      totalSteps: null,
    }));
    const archiveBytes = new Uint8Array(await file.arrayBuffer());
    let entries: Record<string, Uint8Array>;
    try {
      updateBotTransferOverlay((current) => ({
        ...current,
        detail: "Unpacking bot collection.",
        currentStepLabel: "Reading bundled bots",
      }));
      await waitForBotTransferPaint();
      entries = unzipSync(archiveBytes);
    } catch {
      throw new Error("Could not read bot collection file.");
    }
    const allEntries = Object.entries(entries);
    const botEntries = allEntries.filter(([name]) => name.trim().toLowerCase().endsWith(".bot"));
    if (botEntries.length === 0) {
      throw new Error("Bot collection contains no .bot files.");
    }
    const manifestEntry = allEntries.find(
      ([name]) => name.trim().toLowerCase().endsWith("manifest.json")
    );
    const manifest = manifestEntry
      ? parseBotGroupManifest(strFromU8(manifestEntry[1]))
      : null;
    const preparedEntries: PreparedBotCollectionImportEntry[] = [];
    let failedCount = 0;
    let totalMemoryEntries = 0;
    for (const [entryName, bytes] of botEntries) {
      try {
        const parsed = parsePrismBotArchive(bytes);
        const importedName = parsed.botJson.bot.name.trim() || entryName;
        const memoryCount = parsed.memories.length;
        totalMemoryEntries += memoryCount;
        preparedEntries.push({
          entryName,
          archiveBytes: bytes,
          parsed,
          importedName,
          memoryCount,
        });
      } catch {
        failedCount += 1;
      }
    }
    if (preparedEntries.length === 0 && failedCount > 0) {
      throw new Error("Bot collection import failed. None of the .bot files could be imported.");
    }
    const totalWorkSteps =
      preparedEntries.reduce((sum, entry) => sum + 1 + entry.memoryCount, 0) +
      failedCount +
      1;
    let completedWorkSteps = failedCount;
    let completedMemorySteps = 0;
    updateBotTransferOverlay((current) => ({
      ...current,
      detail:
        totalMemoryEntries > 0
          ? `Found ${preparedEntries.length} bots and ${totalMemoryEntries} memories.`
          : `Found ${preparedEntries.length} bots.`,
      currentStepLabel: "Preparing import",
      completedSteps: completedWorkSteps,
      totalSteps: Math.max(1, totalWorkSteps),
      stats: {
        ...current.stats,
        totalBots: botEntries.length,
        completedBots: failedCount,
        totalMemories: totalMemoryEntries,
        completedMemories: 0,
        failed: failedCount,
      },
    }));
    await waitForBotTransferPaint();
    const botIdByHash = new Map<string, string>();
    for (const bot of bots) {
      const hash = normalizeImportedBotHash(bot.export_hash);
      if (hash) botIdByHash.set(hash, bot.id);
    }
    const importedBotIds: string[] = [];
    const importedBotIdByEntryName = new Map<string, string>();
    let importedCount = 0;
    let overwrittenCount = 0;
    let skippedCount = 0;
    let restoredTotal = 0;

    for (const entry of preparedEntries) {
      const entryTotalSteps = 1 + entry.memoryCount;
      let entryCompletedSteps = 0;
      let entryRestoredMemories = 0;
      const completeRemainingEntrySteps = () => {
        const remaining = Math.max(0, entryTotalSteps - entryCompletedSteps);
        if (remaining === 0) return;
        completedWorkSteps += remaining;
        entryCompletedSteps += remaining;
      };
      try {
        updateBotTransferOverlay((current) => ({
          ...current,
          subject: entry.importedName,
          detail: entry.memoryCount > 0
            ? `Restoring ${entry.memoryCount} memories for ${entry.importedName}.`
            : `Importing ${entry.importedName}.`,
          currentStepLabel: `Importing ${entry.importedName}`,
          stats: {
            ...current.stats,
            imported: importedCount,
            overwritten: overwrittenCount,
            skipped: skippedCount,
            failed: failedCount,
          },
        }));
        const importedHash = normalizeImportedBotHash(entry.parsed.botJson.botHash);
        let allowDuplicateHash = false;
        if (importedHash && botIdByHash.has(importedHash)) {
          const shouldOverwrite = window.confirm(
            `${entry.importedName} already exists. Click OK to overwrite, or Cancel to skip it.`
          );
          if (!shouldOverwrite) {
            skippedCount += 1;
            completeRemainingEntrySteps();
            updateBotTransferOverlay((current) => ({
              ...current,
              detail: `${entry.importedName} skipped.`,
              currentStepLabel: `${skippedCount} skipped`,
              completedSteps: Math.min(completedWorkSteps, current.totalSteps ?? completedWorkSteps),
              stats: {
                ...current.stats,
                completedBots: importedCount + skippedCount + failedCount,
                imported: importedCount,
                overwritten: overwrittenCount,
                skipped: skippedCount,
                failed: failedCount,
                completedMemories: completedMemorySteps,
              },
            }));
            continue;
          }
          const existingId = botIdByHash.get(importedHash);
          if (existingId) {
            updateBotTransferOverlay((current) => ({
              ...current,
              detail: `Replacing existing ${entry.importedName}.`,
              currentStepLabel: "Overwriting duplicate",
            }));
            await api(`/api/bots/${encodeURIComponent(existingId)}`, { method: "DELETE" });
          }
          botIdByHash.delete(importedHash);
          allowDuplicateHash = true;
          overwrittenCount += 1;
        }
        const result = await importBotFromArchiveBytes(entry.archiveBytes, {
          allowDuplicateHash,
          suppressNotice: true,
          suppressPanelReset: true,
          selectInChat: false,
          deferRefresh: true,
          onProgress: (event) => {
            if (event.kind === "bot-created" && entryCompletedSteps === 0) {
              entryCompletedSteps += 1;
              completedWorkSteps += 1;
            }
            if (event.kind === "memory-restored") {
              const memoryDelta = Math.max(0, event.restoredMemories - entryRestoredMemories);
              entryRestoredMemories = event.restoredMemories;
              entryCompletedSteps += memoryDelta;
              completedWorkSteps += memoryDelta;
              completedMemorySteps += memoryDelta;
            }
            updateBotTransferOverlay((current) => ({
              ...current,
              subject: event.importedName,
              detail:
                event.totalMemories > 0
                  ? `${event.restoredMemories} of ${event.totalMemories} memories restored.`
                  : "Profile restored.",
              currentStepLabel:
                event.kind === "memory-restored"
                  ? `Restoring memories for ${event.importedName}`
                  : `Created ${event.importedName}`,
              completedSteps: Math.min(completedWorkSteps, current.totalSteps ?? completedWorkSteps),
              stats: {
                ...current.stats,
                completedMemories: completedMemorySteps,
                imported: importedCount,
                overwritten: overwrittenCount,
                skipped: skippedCount,
                failed: failedCount,
              },
            }));
          },
        });
        completeRemainingEntrySteps();
        importedCount += 1;
        restoredTotal += result.restoredMemories;
        importedBotIds.push(result.botId);
        importedBotIdByEntryName.set(entry.entryName.trim().toLowerCase(), result.botId);
        if (result.importedBotHash) {
          botIdByHash.set(result.importedBotHash, result.botId);
        }
        updateBotTransferOverlay((current) => ({
          ...current,
          subject: result.importedName,
          detail:
            result.restoredMemories > 0
              ? `${result.importedName} imported with ${result.restoredMemories} memories.`
              : `${result.importedName} imported.`,
          currentStepLabel: `${importedCount} of ${preparedEntries.length} bots imported`,
          completedSteps: Math.min(completedWorkSteps, current.totalSteps ?? completedWorkSteps),
          stats: {
            ...current.stats,
            completedBots: importedCount + skippedCount + failedCount,
            completedMemories: completedMemorySteps,
            imported: importedCount,
            overwritten: overwrittenCount,
            skipped: skippedCount,
            failed: failedCount,
          },
        }));
      } catch {
        failedCount += 1;
        completeRemainingEntrySteps();
        updateBotTransferOverlay((current) => ({
          ...current,
          detail: `${entry.importedName} could not be imported.`,
          currentStepLabel: `${failedCount} failed`,
          completedSteps: Math.min(completedWorkSteps, current.totalSteps ?? completedWorkSteps),
          stats: {
            ...current.stats,
            completedBots: importedCount + skippedCount + failedCount,
            completedMemories: completedMemorySteps,
            imported: importedCount,
            overwritten: overwrittenCount,
            skipped: skippedCount,
            failed: failedCount,
          },
        }));
      }
    }

    if (manifest?.group?.name && importedBotIds.length > 0) {
      const manifestName = manifest.group.name.trim();
      const manifestDescription =
        typeof manifest.group.description === "string" ? manifest.group.description.trim() : "";
      const manifestBotIds =
        Array.isArray(manifest.group.botFileNames) && manifest.group.botFileNames.length > 0
          ? manifest.group.botFileNames
              .map((name) => importedBotIdByEntryName.get(String(name).trim().toLowerCase()) ?? null)
              .filter((id): id is string => Boolean(id))
          : [];
      const targetBotIds = manifestBotIds.length > 0 ? manifestBotIds : importedBotIds;
      setBotLibraryGroups((current) => {
        const normalized = normalizeBotLibraryGroups(current);
        const existingIndex = normalized.findIndex(
          (group) => group.name.trim().toLowerCase() === manifestName.toLowerCase()
        );
        if (existingIndex >= 0) {
          const existing = normalized[existingIndex];
          const next = [...normalized];
          next[existingIndex] = {
            ...existing,
            description: manifestDescription || existing.description,
            botIds: Array.from(new Set([...existing.botIds, ...targetBotIds])),
            updatedAt: new Date().toISOString(),
          };
          return normalizeBotLibraryGroups(next);
        }
        return normalizeBotLibraryGroups([
          ...normalized,
          {
            id:
              typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
                ? `group:${crypto.randomUUID()}`
                : `group:${Date.now().toString(36)}`,
            name: manifestName,
            description: manifestDescription,
            botIds: Array.from(new Set(targetBotIds)),
            deleteProtected: false,
            builtIn: false,
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
          },
        ]);
      });
    }

    if (importedCount === 0 && failedCount > 0) {
      throw new Error("Bot collection import failed. None of the .bot files could be imported.");
    }
    if (importedBotIds.length > 0) {
      updateBotTransferOverlay((current) => ({
        ...current,
        subject: `${importedBotIds.length} imported`,
        detail: "Refreshing bot library and memories.",
        currentStepLabel: "Refreshing Prism",
        completedSteps: Math.min(completedWorkSteps, Math.max(0, (current.totalSteps ?? 1) - 1)),
      }));
      await refreshBots();
      await refreshMemories();
      if (importedBotIds.length === 1) {
        await refreshBotMemories(importedBotIds[0]!);
      }
    }
    completedWorkSteps = Math.max(completedWorkSteps, totalWorkSteps);
    updateBotTransferOverlay((current) => ({
      ...current,
      detail: "Import complete.",
      currentStepLabel: "Complete",
      completedSteps: current.totalSteps ?? completedWorkSteps,
      stats: {
        ...current.stats,
        completedBots: importedCount + skippedCount + failedCount,
        completedMemories: completedMemorySteps,
        imported: importedCount,
        overwritten: overwrittenCount,
        skipped: skippedCount,
        failed: failedCount,
      },
    }));
    const summaryParts = [
      `${importedCount} imported`,
      `${overwrittenCount} overwritten`,
      `${skippedCount} skipped`,
      `${failedCount} failed`,
    ];
    if (restoredTotal > 0) {
      summaryParts.push(`${restoredTotal} memories restored`);
    }
    setPanelNotice(`Bot collection import complete: ${summaryParts.join(" · ")}.`);
    if (importedBotIds.length === 1) {
      selectImportedBotInChatMode(importedBotIds[0]!);
    }
  }

  async function fetchMarketplaceBotBundle(entry: BotMarketplaceEntry): Promise<Uint8Array> {
    const response = await fetch(entry.bundlePath, { cache: "no-store" });
    if (!response.ok) {
      throw new Error(`Marketplace bundle unavailable for ${entry.name} (${response.status}).`);
    }
    return new Uint8Array(await response.arrayBuffer());
  }

  function validateMarketplacePreparedBundle(prepared: BotMarketplacePreparedBundle): void {
    const parsed = parsePrismBotArchive(prepared.bytes);
    const parsedHash = normalizeImportedBotHash(parsed.botJson.botHash);
    if (parsedHash !== prepared.entry.botHash) {
      throw new Error(`${prepared.entry.name} marketplace bundle has the wrong bot hash.`);
    }
    const parsedName = parsed.botJson.bot.name.trim();
    if (!parsedName) {
      throw new Error(`${prepared.entry.name} marketplace bundle is missing a bot name.`);
    }
    if (!normalizeBotFaceFontId(parsed.botJson.bot.faceEyesFont)) {
      throw new Error(`${prepared.entry.name} marketplace bundle is missing a valid eye face font.`);
    }
    if (!normalizeBotFaceFontId(parsed.botJson.bot.faceMouthFont)) {
      throw new Error(`${prepared.entry.name} marketplace bundle is missing a valid mouth face font.`);
    }
    if (normalizeBotFaceFontWeight(parsed.botJson.bot.faceFontWeight) === null) {
      throw new Error(`${prepared.entry.name} marketplace bundle is missing a valid face weight.`);
    }
    if (
      parsed.botJson.bot.faceEyeScale !== undefined &&
      parsed.botJson.bot.faceEyeScale !== null &&
      normalizeBotFaceEyeScale(parsed.botJson.bot.faceEyeScale) === null
    ) {
      throw new Error(`${prepared.entry.name} marketplace bundle has an invalid eye scale.`);
    }
    if (
      parsed.botJson.bot.faceEyeOffsetY !== undefined &&
      parsed.botJson.bot.faceEyeOffsetY !== null &&
      normalizeBotFaceEyeOffsetY(parsed.botJson.bot.faceEyeOffsetY) === null
    ) {
      throw new Error(`${prepared.entry.name} marketplace bundle has an invalid eye height.`);
    }
  }

  async function prepareMarketplaceBundles(
    entries: readonly BotMarketplaceEntry[]
  ): Promise<BotMarketplacePreparedBundle[]> {
    const bundleBytesByPath = new Map<string, Uint8Array>();
    await Promise.all(
      entries.map(async (entry) => {
        bundleBytesByPath.set(entry.bundlePath, await fetchMarketplaceBotBundle(entry));
      })
    );
    const prepared = validateMarketplaceSelectionBundles(entries, bundleBytesByPath);
    for (const bundle of prepared) {
      validateMarketplacePreparedBundle(bundle);
    }
    return prepared;
  }

  function startMarketplaceInstallOverlay(options: {
    title: string;
    subject: string;
    detail: string;
    currentStepLabel: string;
    totalBots?: number;
    accentColor?: string | null;
    glyph?: BotGlyphName;
  }): void {
    startBotTransferOverlay({
      mode: "import",
      title: options.title,
      subject: options.subject,
      detail: options.detail,
      currentStepLabel: options.currentStepLabel,
      completedSteps: 0,
      totalSteps: null,
      accentColor: options.accentColor ?? null,
      glyph: options.glyph ?? DEFAULT_BOT_GLYPH,
      stats: {
        totalBots: options.totalBots,
        completedBots: typeof options.totalBots === "number" ? 0 : undefined,
      },
    });
  }

  async function importMarketplacePreparedBundlesWithOverlay(
    prepared: readonly BotMarketplacePreparedBundle[],
    options: {
      title: string;
      subject: string;
    }
  ): Promise<MarketplaceBundleImportResult> {
    if (prepared.length === 0) {
      updateBotTransferOverlay((current) => ({
        ...current,
        title: options.title,
        subject: options.subject,
        detail: "Everything in this marketplace selection is already installed.",
        currentStepLabel: "Already installed",
        completedSteps: 1,
        totalSteps: 1,
        stats: { ...current.stats, completedBots: 0, totalBots: 0 },
      }));
      await waitForBotTransferPaint();
      return { importedBotIds: [], importedBotReferences: [], restoredTotal: 0 };
    }

    const bundleHints = prepared.map((bundle) => ({
      bundle,
      hint: parseImportBotLoadingHint(bundle.bytes),
    }));
    const totalMemories = bundleHints.reduce((sum, { hint }) => sum + hint.memoryCount, 0);
    const totalSteps = Math.max(
      2,
      1 + bundleHints.reduce((sum, { hint }) => sum + 1 + hint.memoryCount, 0)
    );
    let completedSteps = 1;
    let completedMemorySteps = 0;
    let importedCount = 0;
    let restoredTotal = 0;
    const importedBotIds: string[] = [];
    const importedBotReferences: MarketplaceInstalledBotReference[] = [];

    updateBotTransferOverlay((current) => ({
      ...current,
      title: options.title,
      subject: options.subject,
      detail:
        totalMemories > 0
          ? `Installing ${prepared.length} bot${prepared.length === 1 ? "" : "s"} and restoring ${totalMemories} memories.`
          : `Installing ${prepared.length} bot${prepared.length === 1 ? "" : "s"}.`,
      currentStepLabel: "Preparing marketplace install",
      completedSteps,
      totalSteps,
      stats: {
        ...current.stats,
        totalBots: prepared.length,
        completedBots: 0,
        totalMemories,
        completedMemories: 0,
      },
    }));
    await waitForBotTransferPaint();

    for (const { bundle, hint } of bundleHints) {
      let botCreated = false;
      let entryRestoredMemories = 0;
      const subject = hint.name ?? bundle.entry.name;
      updateBotTransferOverlay((current) => ({
        ...current,
        subject,
        detail:
          hint.memoryCount > 0
            ? `Restoring ${hint.memoryCount} memories for ${subject}.`
            : `Installing ${subject}.`,
        currentStepLabel: `Installing ${subject}`,
        accentColor: hint.color ?? bundle.entry.color ?? current.accentColor,
        glyph: hint.glyph,
      }));
      await waitForBotTransferPaint();
      const result = await importBotFromArchiveBytes(bundle.bytes, {
        suppressNotice: true,
        suppressPanelReset: true,
        selectInChat: false,
        deferRefresh: true,
        keepBotsPanelOpen: true,
        onProgress: (event) => {
          if (event.kind === "bot-created" && !botCreated) {
            botCreated = true;
            completedSteps += 1;
          }
          if (event.kind === "memory-restored") {
            const memoryDelta = Math.max(0, event.restoredMemories - entryRestoredMemories);
            entryRestoredMemories = event.restoredMemories;
            completedSteps += memoryDelta;
            completedMemorySteps += memoryDelta;
          }
          updateBotTransferOverlay((current) => ({
            ...current,
            subject: event.importedName,
            detail:
              event.totalMemories > 0
                ? `${event.restoredMemories} of ${event.totalMemories} memories restored.`
                : "Profile restored.",
            currentStepLabel:
              event.kind === "memory-restored"
                ? `Restoring memories for ${event.importedName}`
                : `Created ${event.importedName}`,
            completedSteps: Math.min(completedSteps, current.totalSteps ?? completedSteps),
            stats: {
              ...current.stats,
              completedBots: importedCount + (botCreated ? 1 : 0),
              completedMemories: completedMemorySteps,
              imported: importedCount,
            },
          }));
        },
      });
      if (!botCreated) {
        completedSteps += 1;
      }
      importedCount += 1;
      restoredTotal += result.restoredMemories;
      importedBotIds.push(result.botId);
      importedBotReferences.push({
        botHash: result.importedBotHash ?? bundle.entry.botHash,
        botId: result.botId,
      });
      updateBotTransferOverlay((current) => ({
        ...current,
        subject: result.importedName,
        detail:
          result.restoredMemories > 0
            ? `${result.importedName} installed with ${result.restoredMemories} memories.`
            : `${result.importedName} installed.`,
        currentStepLabel: `${importedCount} of ${prepared.length} bots installed`,
        completedSteps: Math.min(completedSteps, current.totalSteps ?? completedSteps),
        stats: {
          ...current.stats,
          completedBots: importedCount,
          completedMemories: completedMemorySteps,
          imported: importedCount,
        },
      }));
    }

    return { importedBotIds, importedBotReferences, restoredTotal };
  }

  async function installPrismStarterPackFromMarketplace(): Promise<{
    installedCount: number;
    starterBotCount: number;
  }> {
    const currentBots = await refreshBots();
    const installedHashes = marketplaceInstalledHashSet(
      currentBots.map((bot) => bot.export_hash)
    );
    const manifest = botMarketplaceManifest ?? (await fetchBotMarketplaceManifest());
    setBotMarketplaceManifest(manifest);
    setBotMarketplaceSelectedThemeId((current) =>
      current && manifest.themes.some((theme) => theme.id === current)
        ? current
        : manifest.themes[0]?.id ?? null
    );
    setBotMarketplaceSelectedLensCategoryId((current) =>
      current && manifest.lensCategories.some((category) => category.id === current)
        ? current
        : manifest.lensCategories[0]?.id ?? null
    );

    const entries = marketplaceEntriesForTheme(manifest, BOT_MARKETPLACE_STARTER_THEME_ID);
    if (entries.length === 0) {
      throw new Error("Prism starter pack is missing from the marketplace catalog.");
    }

    startMarketplaceInstallOverlay({
      title: "Installing starter bots",
      subject: "Prism Originals",
      detail: "Fetching marketplace bundles.",
      currentStepLabel: "Downloading starter pack",
      totalBots: entries.length,
    });
    await waitForBotTransferPaint();
    const missingEntries = marketplaceMissingEntries(entries, installedHashes);
    const prepared = await prepareMarketplaceBundles(missingEntries);
    const importResult = await importMarketplacePreparedBundlesWithOverlay(prepared, {
      title: "Installing starter bots",
      subject: "Prism Originals",
    });

    if (prepared.length > 0) {
      updateBotTransferOverlay((current) => ({
        ...current,
        subject: "Prism Originals",
        detail: "Refreshing bot library and memories.",
        currentStepLabel: "Refreshing Prism",
        completedSteps: Math.min(current.completedSteps, Math.max(0, (current.totalSteps ?? 1) - 1)),
      }));
    }
    const refreshedBots = prepared.length > 0 ? await refreshBots() : currentBots;
    if (prepared.length > 0) {
      await refreshMemories();
    }
    const refreshedIdByHash = new Map<string, string>();
    for (const bot of refreshedBots) {
      const hash = normalizeImportedBotHash(bot.export_hash);
      if (hash) refreshedIdByHash.set(hash, bot.id);
    }
    const starterBotIds = entries
      .map((entry) => refreshedIdByHash.get(entry.botHash) ?? null)
      .filter((botId): botId is string => Boolean(botId));
    const factoryGroups = createFactoryResetBotLibraryGroups(starterBotIds);
    setBotLibraryGroups(factoryGroups);
    if (user?.id && typeof window !== "undefined") {
      try {
        markStarterPackInstalled(user.id);
        window.localStorage.setItem(
          botLibraryGroupsStorageKey(user.id),
          JSON.stringify(factoryGroups)
        );
      } catch {
        // Non-fatal: the in-memory group state is already set for this page session.
      }
    }
    updateBotTransferOverlay((current) => ({
      ...current,
      subject: "Prism Originals",
      detail:
        importResult.importedBotIds.length > 0
          ? `${importResult.importedBotIds.length} starter bots installed.`
          : "Prism Originals are already installed.",
      currentStepLabel: "Complete",
      completedSteps: current.totalSteps ?? current.completedSteps,
      stats: {
        ...current.stats,
        completedBots: importResult.importedBotIds.length,
        completedMemories: importResult.restoredTotal,
        imported: importResult.importedBotIds.length,
      },
    }));
    return {
      installedCount: prepared.length,
      starterBotCount: starterBotIds.length,
    };
  }

  async function installMarketplaceBot(entry: BotMarketplaceEntry): Promise<void> {
    if (botMarketplaceInstallingKey || botTransferBusy) return;
    const installedBotId = botMarketplaceInstalledBotIdByHash.get(entry.botHash);
    const installedBot = installedBotId
      ? bots.find((bot) => bot.id === installedBotId) ?? null
      : null;
    if (installedBot) {
      openBotCustomizer(installedBot);
      return;
    }
    setBotMarketplaceInstallingKey(`bot:${entry.id}`);
    setPanelError(null);
    setPanelNotice(null);
    try {
      const entryGlyph = isBotGlyphName(entry.glyph) ? entry.glyph : DEFAULT_BOT_GLYPH;
      startMarketplaceInstallOverlay({
        title: "Installing marketplace bot",
        subject: entry.name,
        detail: "Fetching marketplace bundle.",
        currentStepLabel: "Downloading bot",
        totalBots: 1,
        accentColor: entry.color ?? null,
        glyph: entryGlyph,
      });
      await waitForBotTransferPaint();
      const [prepared] = await prepareMarketplaceBundles([entry]);
      if (!prepared) throw new Error(`${entry.name} marketplace bundle could not be prepared.`);
      const importResult = await importMarketplacePreparedBundlesWithOverlay([prepared], {
        title: "Installing marketplace bot",
        subject: entry.name,
      });
      updateBotTransferOverlay((current) => ({
        ...current,
        subject: entry.name,
        detail: "Refreshing bot library and memories.",
        currentStepLabel: "Refreshing Prism",
        completedSteps: Math.min(current.completedSteps, Math.max(0, (current.totalSteps ?? 1) - 1)),
      }));
      const refreshedBots = await refreshBots();
      await refreshMemories();
      const importedBotId = importResult.importedBotIds[0] ?? null;
      if (importedBotId) {
        await refreshBotMemories(importedBotId);
      }
      if (botMarketplaceManifest) {
        setBotLibraryGroups((current) =>
          upsertMarketplaceBotLibraryThemeGroups(
            current,
            botMarketplaceManifest,
            [entry],
            refreshedBots,
            importResult.importedBotReferences
          )
        );
      }
      setBotPanelView("marketplace");
      updateBotTransferOverlay((current) => ({
        ...current,
        subject: entry.name,
        detail:
          importResult.restoredTotal > 0
            ? `${entry.name} installed with ${importResult.restoredTotal} memories.`
            : `${entry.name} installed.`,
        currentStepLabel: "Complete",
        completedSteps: current.totalSteps ?? current.completedSteps,
        stats: {
          ...current.stats,
          completedBots: 1,
          completedMemories: importResult.restoredTotal,
          imported: 1,
        },
      }));
      setPanelNotice(
        importResult.restoredTotal > 0
          ? `${entry.name} installed with ${importResult.restoredTotal} memories.`
          : `${entry.name} installed.`
      );
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Marketplace install failed.");
    } finally {
      setBotTransferOverlay(null);
      setBotMarketplaceInstallingKey(null);
    }
  }

  async function installMarketplaceTheme(theme: BotMarketplaceTheme): Promise<void> {
    if (!botMarketplaceManifest || botMarketplaceInstallingKey || botTransferBusy) return;
    const entries = marketplaceEntriesForTheme(botMarketplaceManifest, theme.id);
    if (entries.length === 0) return;
    setBotMarketplaceInstallingKey(`theme:${theme.id}`);
    setPanelError(null);
    setPanelNotice(null);
    try {
      startMarketplaceInstallOverlay({
        title: "Installing marketplace pack",
        subject: theme.name,
        detail: "Fetching marketplace bundles.",
        currentStepLabel: "Downloading pack",
        totalBots: entries.length,
      });
      await waitForBotTransferPaint();
      const prepared = await prepareMarketplaceBundles(entries);
      const missingPrepared = prepared.filter(
        ({ entry }) => !botMarketplaceInstalledHashes.has(entry.botHash)
      );
      const importResult = await importMarketplacePreparedBundlesWithOverlay(missingPrepared, {
        title: "Installing marketplace pack",
        subject: theme.name,
      });
      updateBotTransferOverlay((current) => ({
        ...current,
        subject: theme.name,
        detail: "Refreshing bot library and memories.",
        currentStepLabel: "Refreshing Prism",
        completedSteps: Math.min(current.completedSteps, Math.max(0, (current.totalSteps ?? 1) - 1)),
      }));
      const refreshedBots = await refreshBots();
      await refreshMemories();
      setBotLibraryGroups((current) =>
        upsertMarketplaceBotLibraryThemeGroups(
          current,
          botMarketplaceManifest,
          entries,
          refreshedBots,
          importResult.importedBotReferences
        )
      );
      setBotPanelView("marketplace");
      if (missingPrepared.length === 0) {
        updateBotTransferOverlay((current) => ({
          ...current,
          subject: theme.name,
          detail: `${theme.name} is already installed.`,
          currentStepLabel: "Complete",
          completedSteps: current.totalSteps ?? current.completedSteps,
        }));
        setPanelNotice(`${theme.name} is already installed.`);
      } else {
        updateBotTransferOverlay((current) => ({
          ...current,
          subject: theme.name,
          detail:
            importResult.restoredTotal > 0
              ? `${theme.name} installed: ${importResult.importedBotIds.length} bots and ${importResult.restoredTotal} memories.`
              : `${theme.name} installed: ${importResult.importedBotIds.length} bots.`,
          currentStepLabel: "Complete",
          completedSteps: current.totalSteps ?? current.completedSteps,
          stats: {
            ...current.stats,
            completedBots: importResult.importedBotIds.length,
            completedMemories: importResult.restoredTotal,
            imported: importResult.importedBotIds.length,
          },
        }));
        setPanelNotice(
          importResult.restoredTotal > 0
            ? `${theme.name} installed: ${importResult.importedBotIds.length} bots and ${importResult.restoredTotal} memories.`
            : `${theme.name} installed: ${importResult.importedBotIds.length} bots.`
        );
      }
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Marketplace theme install failed.");
    } finally {
      setBotTransferOverlay(null);
      setBotMarketplaceInstallingKey(null);
    }
  }

  async function installStarterBotsFromEmptyState(source: "coffee" | "story"): Promise<void> {
    if (botMarketplaceInstallingKey || botTransferBusy) return;
    setBotMarketplaceInstallingKey(`theme:${BOT_MARKETPLACE_STARTER_THEME_ID}`);
    setPanelError(null);
    setPanelNotice(null);
    setCoffeeError(null);
    setStoryError(null);
    try {
      const result = await installPrismStarterPackFromMarketplace();
      const message =
        result.installedCount > 0
          ? `Installed ${result.installedCount} Prism Originals starter bots.`
          : `Prism Originals are already installed.`;
      setPanelNotice(message);
      if (source === "coffee") {
        setCoffeeSearch("");
      } else {
        setStorySearch("");
      }
    } catch (err) {
      const message =
        err instanceof Error ? err.message : "Prism Originals could not be installed.";
      if (source === "coffee") {
        setCoffeeError(message);
      } else {
        setStoryError(message);
      }
    } finally {
      setBotTransferOverlay(null);
      setBotMarketplaceInstallingKey(null);
    }
  }

  useEffect(() => {
    if (!user?.id) return;
    const freshAccountEligible =
      !hasAnyAccounts || starterPackFreshAccountEligibleUserRef.current === user.id;
    if (!freshAccountEligible) return;
    if (starterPackInstallMarked(user.id)) return;
    if (starterPackAutoInstallAttemptedUserRef.current === user.id) return;
    let cancelled = false;
    starterPackAutoInstallAttemptedUserRef.current = user.id;
    if (starterPackFreshAccountEligibleUserRef.current === user.id) {
      starterPackFreshAccountEligibleUserRef.current = null;
    }
    setBotMarketplaceInstallingKey(`theme:${BOT_MARKETPLACE_STARTER_THEME_ID}`);
    setPanelError(null);
    setPanelNotice("Installing Prism Originals starter bots...");
    void (async () => {
      try {
        const result = await installPrismStarterPackFromMarketplace();
        if (cancelled) return;
        setPanelNotice(
          result.installedCount > 0
            ? `Installed ${result.installedCount} Prism Originals starter bots.`
            : "Prism Originals are ready."
        );
      } catch (err) {
        if (!cancelled) {
          setPanelError(
            err instanceof Error
              ? `Starter bots could not be installed: ${err.message}`
              : "Starter bots could not be installed."
          );
        }
      } finally {
        if (!cancelled) {
          setBotTransferOverlay(null);
          setBotMarketplaceInstallingKey(null);
        }
      }
    })();
    return () => {
      cancelled = true;
    };
    // The installer is a local workflow function; this effect is intentionally keyed to auth/install state.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user?.id, hasAnyAccounts]);

  function commitInstalledMarketplaceLensIds(nextLensIds: ReadonlySet<string>): void {
    const normalized = new Set(
      Array.from(nextLensIds)
        .map((lensId) => lensId.trim().toLowerCase())
        .filter((lensId) => lensId.length > 0)
    );
    setInstalledMarketplaceLensIds(normalized);
    if (user?.id) {
      saveInstalledMarketplaceLensIds(user.id, normalized);
    }
  }

  function installMarketplaceLens(lens: MarketplaceLensEntry, options?: { quiet?: boolean }): void {
    if (!options?.quiet && (botMarketplaceInstallingKey || botTransferBusy)) return;
    if (!options?.quiet) {
      setBotMarketplaceInstallingKey(`lens:${lens.id}`);
      setPanelError(null);
      setPanelNotice(null);
      startMarketplaceInstallOverlay({
        title: "Installing marketplace Lens",
        subject: lens.displayName,
        detail: "Saving Lens to your library.",
        currentStepLabel: "Installing Lens",
      });
    }
    const next = new Set(installedMarketplaceLensIds);
    next.add(lens.id);
    if (options?.quiet) {
      commitInstalledMarketplaceLensIds(next);
      return;
    }
    void (async () => {
      try {
        await waitForBotTransferPaint();
        commitInstalledMarketplaceLensIds(next);
        updateBotTransferOverlay((current) => ({
          ...current,
          detail: `${lens.displayName} installed.`,
          currentStepLabel: "Complete",
          completedSteps: 1,
          totalSteps: 1,
        }));
        setPanelNotice(`${lens.displayName} installed.`);
      } finally {
        setBotTransferOverlay(null);
        setBotMarketplaceInstallingKey(null);
      }
    })();
  }

  function removeMarketplaceLens(lens: MarketplaceLensEntry): void {
    const next = new Set(installedMarketplaceLensIds);
    next.delete(lens.id);
    commitInstalledMarketplaceLensIds(next);
    if (newBotLensId === lens.id) {
      setNewBotLensId("");
      setNewBotGeneratedMemorySeeds(null);
      setBotLensDropActive(false);
    }
    setPanelError(null);
    setPanelNotice(`${lens.displayName} removed.`);
  }

  function applyMarketplaceLensToRandomizer(lens: MarketplaceLensEntry): void {
    if (marketplaceLensInstallState(lens, installedMarketplaceLensIds) !== "installed") {
      installMarketplaceLens(lens, { quiet: true });
    }
    setNewBotLensId(lens.id);
    setNewBotGeneratedMemorySeeds(null);
    setBotLensDropActive(false);
    setPanelError(null);
    setPanelNotice(null);
  }

	  function applyMarketplaceLensToGenerator(lens: MarketplaceLensEntry): void {
	    applyMarketplaceLensToRandomizer(lens);
	    setBotMarketplaceSection("lens");
	    setBotPanelView("create");
	  }

	  function browseMarketplaceLenses(): void {
	    setBotMarketplaceSection("lens");
	    openBotMarketplace();
	  }

	  function marketplaceLensById(lensId: string): MarketplaceLensEntry | null {
    const normalized = lensId.trim().toLowerCase();
    if (!normalized) return null;
    return botMarketplaceVisibleLenses.find((lens) => lens.id === normalized) ?? null;
  }

  function writeMarketplaceLensDragData(
    event: React.DragEvent<HTMLElement>,
    lens: MarketplaceLensEntry
  ): void {
    event.dataTransfer.effectAllowed = "copy";
    event.dataTransfer.setData(PRISM_LENS_DRAG_MIME, lens.id);
    event.dataTransfer.setData("text/plain", lens.id);
  }

  function readMarketplaceLensDragId(event: React.DragEvent<HTMLElement>): string {
    return (
      event.dataTransfer.getData(PRISM_LENS_DRAG_MIME) ||
      event.dataTransfer.getData("text/plain")
    ).trim().toLowerCase();
  }

  function dragEventHasMarketplaceLens(event: React.DragEvent<HTMLElement>): boolean {
    return Array.from(event.dataTransfer.types).includes(PRISM_LENS_DRAG_MIME);
  }

  function handleRandomizerLensDragOver(event: React.DragEvent<HTMLElement>): void {
    if (!dragEventHasMarketplaceLens(event)) return;
    event.preventDefault();
    event.dataTransfer.dropEffect = "copy";
    setBotLensDropActive(true);
  }

  function handleRandomizerLensDragLeave(event: React.DragEvent<HTMLElement>): void {
    const nextTarget = event.relatedTarget;
    if (nextTarget instanceof Node && event.currentTarget.contains(nextTarget)) return;
    setBotLensDropActive(false);
  }

  function handleRandomizerLensDrop(event: React.DragEvent<HTMLElement>): void {
    const lens = marketplaceLensById(readMarketplaceLensDragId(event));
    setBotLensDropActive(false);
    if (!lens) return;
    event.preventDefault();
    applyMarketplaceLensToRandomizer(lens);
  }

  function showBotLensTileTooltip(
    event: React.FocusEvent<HTMLButtonElement> | React.MouseEvent<HTMLButtonElement>,
    lens: MarketplaceLensEntry
  ): void {
    const rect = event.currentTarget.getBoundingClientRect();
    const tooltipWidth = 220;
    const gap = 10;
    const fitsRight = rect.right + gap + tooltipWidth < window.innerWidth - 12;
    setBotLensTooltip({
      label: lens.displayName,
      placement: fitsRight ? "right" : "left",
      x: fitsRight ? rect.right + gap : rect.left - gap,
      y: rect.top + rect.height / 2,
    });
  }

  function hideBotLensTileTooltip(): void {
    setBotLensTooltip(null);
  }

  async function handleBotImportFileSelection(
    event: React.ChangeEvent<HTMLInputElement>
  ): Promise<void> {
    const file = event.currentTarget.files?.[0];
    event.currentTarget.value = "";
    if (botTransferBusy) return;
    if (!file) return;
    const lower = file.name.trim().toLowerCase();
    const isBotFile = lower.endsWith(".bot");
    const isBotCollectionFile = lower.endsWith(BOT_COLLECTION_FILE_EXTENSION);
    if (!isBotFile && !isBotCollectionFile) {
      setPanelError("Only .bot or .bots files can be imported from disk.");
      return;
    }
    startBotTransferOverlay({
      mode: "import",
      title: isBotCollectionFile ? "Importing bot collection" : "Importing bot",
      subject: file.name,
      detail: isBotCollectionFile
        ? "Reading collection file."
        : "Reading bot export.",
      currentStepLabel: "Opening file",
      completedSteps: 0,
      totalSteps: null,
      accentColor: null,
      glyph: DEFAULT_BOT_GLYPH,
      stats: {},
    });
    try {
      if (isBotCollectionFile) {
        await importBotCollectionBundle(file);
      } else {
        const archiveBytes = new Uint8Array(await file.arrayBuffer());
        const hint = parseImportBotLoadingHint(archiveBytes);
        const totalSteps = Math.max(2, hint.memoryCount + 2);
        let completedSteps = 0;
        let restoredMemories = 0;
        updateBotTransferOverlay((current) => ({
          ...current,
          subject: hint.name ?? file.name,
          detail:
            hint.memoryCount > 0
              ? `Restoring profile and ${hint.memoryCount} memories.`
              : "Restoring profile.",
          currentStepLabel: "Preparing import",
          totalSteps,
          accentColor: hint.color,
          glyph: hint.glyph,
          stats: { totalBots: 1, completedBots: 0, totalMemories: hint.memoryCount },
        }));
        await waitForBotTransferPaint();
        const result = await importBotFromArchiveBytes(archiveBytes, {
          onProgress: (event) => {
            if (event.kind === "bot-created" && completedSteps === 0) {
              completedSteps = 1;
            }
            if (event.kind === "memory-restored") {
              const memoryDelta = Math.max(0, event.restoredMemories - restoredMemories);
              restoredMemories = event.restoredMemories;
              completedSteps += memoryDelta;
            }
            updateBotTransferOverlay((current) => ({
              ...current,
              subject: event.importedName,
              detail:
                event.totalMemories > 0
                  ? `${event.restoredMemories} of ${event.totalMemories} memories restored.`
                  : "Profile restored.",
              currentStepLabel:
                event.kind === "memory-restored"
                  ? `Restoring memories for ${event.importedName}`
                  : `Created ${event.importedName}`,
              completedSteps: Math.min(completedSteps, current.totalSteps ?? completedSteps),
              stats: {
                ...current.stats,
                completedBots: event.kind === "bot-created" ? 1 : current.stats.completedBots,
                completedMemories: restoredMemories,
              },
            }));
          },
        });
        updateBotTransferOverlay((current) => ({
          ...current,
          subject: result.importedName,
          detail:
            result.restoredMemories > 0
              ? `${result.importedName} imported with ${result.restoredMemories} memories.`
              : `${result.importedName} imported.`,
          currentStepLabel: "Complete",
          completedSteps: current.totalSteps ?? totalSteps,
          stats: {
            ...current.stats,
            completedBots: 1,
            completedMemories: result.restoredMemories,
            imported: 1,
          },
        }));
      }
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Bot import failed.");
    } finally {
      setBotTransferOverlay(null);
    }
  }

  function openImportBotModal(): void {
    if (botTransferBusy) return;
    setPanelError(null);
    setImportBotPasteError(null);
    setImportBotPasteText("");
    setImportBotPasteBusy(false);
    if (!devToolsRuntimeActive || !devToolsBotImportPasteEnabled) {
      setImportBotModalPhase("closed");
      queueMicrotask(() => {
        botImportInputRef.current?.click();
      });
      return;
    }
    setImportBotModalPhase("choose");
  }

  function handleImportBotChooseUpload(): void {
    closeImportBotModal();
    queueMicrotask(() => {
      botImportInputRef.current?.click();
    });
  }

  async function handleConfirmImportBotPaste(): Promise<void> {
    if (botTransferBusy) return;
    setImportBotPasteError(
      "Pasted JSON bot imports are no longer supported. Import a zipped .bot file instead."
    );
  }

  const updateCanvasBotMarqueeSelection = useCallback((
    drag: CanvasBotMarqueeDragState,
    clientX: number,
    clientY: number
  ) => {
    const frameRect = drag.frameRect;
    const clampedStartX = Math.max(frameRect.left, Math.min(frameRect.right, drag.startClientX));
    const clampedStartY = Math.max(frameRect.top, Math.min(frameRect.bottom, drag.startClientY));
    const clampedCurrentX = Math.max(frameRect.left, Math.min(frameRect.right, clientX));
    const clampedCurrentY = Math.max(frameRect.top, Math.min(frameRect.bottom, clientY));
    const left = Math.min(clampedStartX, clampedCurrentX);
    const top = Math.min(clampedStartY, clampedCurrentY);
    const right = Math.max(clampedStartX, clampedCurrentX);
    const bottom = Math.max(clampedStartY, clampedCurrentY);
    const viewportRect = { left, top, right, bottom };
    setCanvasBotMarqueeRect({
      left: left - frameRect.left,
      top: top - frameRect.top,
      width: right - left,
      height: bottom - top,
    });
    const hitBotIds: string[] = [];
    for (const { botId, rect } of drag.tileRects) {
      if (rectsIntersect(viewportRect, rect)) hitBotIds.push(botId);
    }
    const nextSelectedIds = resolveCanvasBotMarqueeSelection({
      mode: drag.mode,
      baseSelectedBotIds: drag.baseSelectedBotIds,
      hitBotIds,
    });
    setCanvasSelectedBotIds((current) =>
      stringSetsEqual(current, nextSelectedIds) ? current : nextSelectedIds
    );
  }, []);

  const handleCanvasBotMarqueePointerDown = useCallback((
    event: React.PointerEvent<HTMLDivElement>
  ): boolean => {
    if (detail || pendingReplyVisible) return false;
    if (event.pointerType === "touch") return false;
    if (event.button !== 0) return false;
    const target = event.target;
    let pressedBotId: string | null = null;
    if (target instanceof Element) {
      const botTileTarget = target.closest<HTMLElement>("[data-bot-id]");
      const startsOnBotTile = botTileTarget !== null;
      pressedBotId = botTileTarget?.dataset.botId ?? null;
      const allowBotTileShiftDrag = event.shiftKey && startsOnBotTile;
      const blockedInteractiveTarget = target.closest(BOT_CANVAS_BACKGROUND_INTERACTIVE_SELECTOR);
      if (blockedInteractiveTarget && !allowBotTileShiftDrag) {
        return false;
      }
      if (startsOnBotTile && !allowBotTileShiftDrag) {
        return false;
      }
    }
    const frame = event.currentTarget;
    const frameRect = frame.getBoundingClientRect();
    if (frameRect.width <= 0 || frameRect.height <= 0) return false;
    const tileRects = Array.from(frame.querySelectorAll<HTMLElement>("[data-bot-id]"))
      .map((node) => {
        const botId = node.dataset.botId;
        if (!botId) return null;
        return { botId, rect: node.getBoundingClientRect() };
      })
      .filter((entry): entry is { botId: string; rect: DOMRect } => Boolean(entry));
    if (tileRects.length === 0) return false;
    canvasBotMarqueeDragRef.current = {
      pointerId: event.pointerId,
      frame,
      frameRect,
      startClientX: event.clientX,
      startClientY: event.clientY,
      pressedBotId,
      active: false,
      mode: event.shiftKey ? "toggle" : "replace",
      baseSelectedBotIds: new Set(canvasSelectedBotIds),
      tileRects,
    };
    setCanvasBotMarqueeRect(null);
    try {
      frame.setPointerCapture(event.pointerId);
    } catch {
      // Some browser/test environments do not expose pointer capture.
    }
    return true;
  }, [canvasSelectedBotIds, detail, pendingReplyVisible]);

  const handleCanvasBotMarqueePointerMove = useCallback((
    event: React.PointerEvent<HTMLDivElement>
  ): boolean => {
    const drag = canvasBotMarqueeDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return false;
    const dx = event.clientX - drag.startClientX;
    const dy = event.clientY - drag.startClientY;
    if (!drag.active) {
      if (Math.hypot(dx, dy) < BOT_MARQUEE_DRAG_THRESHOLD_PX) return true;
      drag.active = true;
    }
    event.preventDefault();
    updateCanvasBotMarqueeSelection(drag, event.clientX, event.clientY);
    return true;
  }, [updateCanvasBotMarqueeSelection]);

  const handleCanvasBotMarqueePointerEnd = useCallback((
    event: React.PointerEvent<HTMLDivElement>
  ): boolean => {
    const drag = canvasBotMarqueeDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return false;
    const wasActive = drag.active;
    if (wasActive) {
      updateCanvasBotMarqueeSelection(drag, event.clientX, event.clientY);
      canvasBotMarqueeSuppressClickRef.current = true;
      window.setTimeout(() => {
        canvasBotMarqueeSuppressClickRef.current = false;
      }, 0);
      event.preventDefault();
      event.stopPropagation();
    } else {
      const nextSelectedIds = resolveInactiveCanvasBotMarqueeSelection(
        drag.mode,
        drag.baseSelectedBotIds,
        drag.pressedBotId
      );
      setCanvasSelectedBotIds((current) =>
        stringSetsEqual(current, nextSelectedIds) ? current : nextSelectedIds
      );
      if (drag.mode === "toggle" && drag.pressedBotId) {
        canvasBotMarqueeSuppressClickRef.current = true;
        window.setTimeout(() => {
          canvasBotMarqueeSuppressClickRef.current = false;
        }, 0);
        event.preventDefault();
        event.stopPropagation();
      }
    }
    setCanvasBotMarqueeRect(null);
    canvasBotMarqueeDragRef.current = null;
    try {
      if (drag.frame.hasPointerCapture(event.pointerId)) {
        drag.frame.releasePointerCapture(event.pointerId);
      }
    } catch {
      // Non-fatal: capture may already be released.
    }
    return true;
  }, [updateCanvasBotMarqueeSelection]);

  const resetEmptyStateBotSelection = useCallback(() => {
    cancelPendingEmptyStateSearchOpen();
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    setCanvasBotMarqueeRect(null);
    canvasBotMarqueeDragRef.current = null;
    setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
  }, [cancelPendingEmptyStateSearchOpen]);

  function applyBotLibraryGroupFilter(nextFilterId: string): void {
    setBotLibraryGroupFilterId(nextFilterId);
    setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
    if (
      nextFilterId !== BOT_LIBRARY_GROUP_FILTER_ALL &&
      (view === "chat" || view === "sandbox") &&
      !detail &&
      !pendingReplyVisible
    ) {
      resetEmptyStateBotSelection();
      setHueFilterCenter(null);
    }
  }

  function applyBotLibraryHeaderFilter(nextValue: string): void {
    if (nextValue === BOT_LIBRARY_GROUP_FILTER_ALL) {
      performShowAllBotsView(null);
      return;
    }
    if (nextValue === BOT_LIBRARY_GROUP_FILTER_UNGROUPED) {
      applyBotLibraryGroupFilter(BOT_LIBRARY_GROUP_FILTER_UNGROUPED);
      return;
    }
    if (nextValue.startsWith(BOT_LIBRARY_HEADER_SAVED_GROUP_PREFIX)) {
      const groupId = nextValue.slice(BOT_LIBRARY_HEADER_SAVED_GROUP_PREFIX.length);
      applyBotLibraryGroupFilter(groupId);
      return;
    }
  }

  const handleEmptyStateBackgroundClick = useCallback((event: React.MouseEvent<HTMLDivElement>) => {
    if (canvasBotMarqueeSuppressClickRef.current) {
      canvasBotMarqueeSuppressClickRef.current = false;
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    if (detail || pendingIncognito) return;
    const target = event.target;
    if (!(target instanceof Element)) return;
    const interactiveTarget = target.closest(BOT_CANVAS_BACKGROUND_INTERACTIVE_SELECTOR);
    if (interactiveTarget) return;
    if (event.shiftKey) {
      event.preventDefault();
      event.stopPropagation();
      return;
    }
    const shouldReturnToBotDirectory =
      bots.length > 0 &&
      !pendingReplyVisible &&
      (
        selectedBotId !== null ||
        composerPrimed ||
        hueFilterCenter !== null ||
        botLibraryGroupFilterId !== BOT_LIBRARY_GROUP_FILTER_ALL ||
        botPanelGroup !== BOT_LIBRARY_FILTER_ALL
      );
    if (shouldReturnToBotDirectory) {
      event.preventDefault();
      event.stopPropagation();
      setSelectedId(null);
      setDetail(null);
      setChatBotOverride(undefined);
      setBotLibraryGroupFilterId(BOT_LIBRARY_GROUP_FILTER_ALL);
      setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
      setEmptyStateSearchOpen(false);
      setEmptyStateBotNameFilter("");
      startBotPickerReturnToAll();
      setSelectedBotId(null);
      setSandboxGridSelectedBotId(null);
      setComposerPrimed(false);
      setConversationStarterPrompts(null);
      setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
      return;
    }
    setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
  }, [
    bots.length,
    botLibraryGroupFilterId,
    botPanelGroup,
    composerPrimed,
    detail,
    hueFilterCenter,
    pendingIncognito,
    pendingReplyVisible,
    selectedBotId,
    startBotPickerReturnToAll,
  ]);

  const openEmptyStateBotSearch = useCallback(() => {
    cancelPendingEmptyStateSearchOpen();
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    if (botPickerReturnEndAtRef.current > Date.now()) return;
    if (emptyStateSearchActive) {
      setEmptyStateSearchOpen(false);
      setEmptyStateBotNameFilter("");
      return;
    }
    if (hueFilterCenter !== null) {
      setEmptyStateSearchOpen(false);
      setEmptyStateBotNameFilter("");
      startBotPickerReturnToAll();
      return;
    }
    setHueFilterCenter(null);
    setEmptyStateSearchOpen(true);
  }, [
    cancelPendingEmptyStateSearchOpen,
    emptyStateSearchActive,
    hueFilterCenter,
    startBotPickerReturnToAll,
  ]);

  const closeEmptyStateBotSearch = useCallback(() => {
    cancelPendingEmptyStateSearchOpen();
    setEmptyStateSearchOpen(false);
    setEmptyStateBotNameFilter("");
    spotlightTypingArmedRef.current = false;
  }, [cancelPendingEmptyStateSearchOpen]);

  function resetEmptyStateToPrismHome(): void {
    closeEmptyStateBotSearch();
    resetEmptyStateBotSelection();
    setBotLibraryGroupFilterId(BOT_LIBRARY_GROUP_FILTER_ALL);
    setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
    setZenPersonaBotId(null);
    setPendingIncognito(false);
    if (hueFilterCenter !== null) {
      startBotPickerReturnToAll();
    } else {
      setHueFilterCenter(null);
    }
  }

  const focusDraftInput = useCallback(() => {
    window.setTimeout(() => {
      draftComposerRef.current?.focus({ preventScroll: true });
    }, 0);
  }, []);

  const closeEmptyStateBotSearchAndFocusDraft = useCallback(() => {
    closeEmptyStateBotSearch();
    focusDraftInput();
  }, [closeEmptyStateBotSearch, focusDraftInput]);

  const commitEmptyStateBotSelection = useCallback((botId: string) => {
    canvasBotMarqueeDragRef.current = null;
    setCanvasBotMarqueeRect(null);
    setCanvasSelectedBotIds((current) => (current.size === 0 ? current : new Set()));
    if (selectedBotId === botId) {
      setSandboxGridSelectedBotId(botId);
      if (view === "chat") {
        setZenPersonaBotId(botId);
      }
      focusDraftInput();
      return;
    }
    cancelPendingEmptyStateSearchOpen();
    setCanvasBotSwitchOverlayPhase("enter");
    canvasBotSwitchTransitionStartedAtRef.current = Date.now();
    pendingCanvasBotUnfoldRef.current = true;
    setCanvasBotSwitchTransitioning(true);
    // Committing a bot exits visible lens mode, but keeps the current
    // filtered/zoomed bot view intact. `emptyStateLensVisible` hides the
    // slider while `shellStyle` lets the selected bot own the interface
    // color, so the hue lens no longer competes with the bot accent.
    setSelectedBotId(botId);
    setSandboxGridSelectedBotId(botId);
    if (view === "chat") {
      setZenPersonaBotId(botId);
    }
    setEmptyStateSearchOpen(false);
    setEmptyStateBotNameFilter("");
    spotlightTypingArmedRef.current = false;
    focusDraftInput();
  }, [cancelPendingEmptyStateSearchOpen, focusDraftInput, selectedBotId, view]);

  useEffect(() => {
    if (view !== "chat") return;
    const botId = pendingImportedChatBotSelectionRef.current;
    if (!botId) return;
    pendingImportedChatBotSelectionRef.current = null;
    commitEmptyStateBotSelection(botId);
  }, [commitEmptyStateBotSelection, view]);

  function selectImportedBotInChatMode(botId: string): void {
    pendingImportedChatBotSelectionRef.current = null;
    if (view !== "chat") {
      pendingImportedChatBotSelectionRef.current = botId;
      navigateToView("chat");
      return;
    }
    setConversationStarterPrompts(null);
    setSelectedId(null);
    setDetail(null);
    setChatBotOverride(undefined);
    setSidebarOpen(false);
    commitEmptyStateBotSelection(botId);
  }

  const openEmptyStateBotSearchFromTyping = useCallback((typedCharacter: string) => {
    cancelPendingEmptyStateSearchOpen();
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    setEmptyStateBotNameFilter((current) =>
      current.length > 0 ? `${current}${typedCharacter}` : typedCharacter
    );
    if (hueFilterCenter !== null) {
      setEmptyStateSearchOpen(false);
      startBotPickerReturnToAll();
      showEmptyStateSearchAfterReturn();
      return;
    }
    setHueFilterCenter(null);
    showEmptyStateSearchAfterReturn();
  }, [
    cancelPendingEmptyStateSearchOpen,
    hueFilterCenter,
    showEmptyStateSearchAfterReturn,
    startBotPickerReturnToAll,
  ]);

  const handleComposerBotSelectionChange = useCallback(
    (next: string) => {
      const nextBotId = next || null;
      setSelectedBotId(nextBotId);
      // Empty-canvas picker controls need to keep their highlighted tile and
      // immersive Hub persona in sync when selection comes from the dropdown.
      if (view === "chat") {
        setZenPersonaBotId(nextBotId);
        setSandboxGridSelectedBotId(nextBotId);
      } else if (view === "sandbox") {
        setSandboxGridSelectedBotId(nextBotId);
      }
    },
    [view]
  );

  function zenSessionHasNotStarted(): boolean {
    return view === "chat" && (!detail || detail.messages.length === 0);
  }

  function armFreshZenPersona(nextBotId: string | null): void {
    if (zenSessionHasNotStarted() && zenPersonaBotIdRef.current !== nextBotId) {
      rotateZenFallbackWallpaperSeed();
    }
    setZenPersonaBotId(nextBotId);
    setSelectedBotId(nextBotId);
    setChatBotOverride(undefined);
    closeEmptyStateBotSearch();
    focusDraftInput();
  }

  function commitZenPersonaTransition(nextBotId: string | null): void {
    if (pendingReplyVisible) return;
    const fromBotId = zenPersonaBotIdRef.current;
    if (fromBotId === nextBotId) return;

    const style = resolveZenPersonaTransitionStyle(zenPersonaTransitionChoice, {
      fromBotId,
      toBotId: nextBotId,
    });

    if (style === "off") {
      settleZenPersonaPresence(nextBotId);
      setZenPersonaBotId(nextBotId);
      setSelectedBotId(nextBotId);
      setChatBotOverride(undefined);
      closeEmptyStateBotSearch();
      focusDraftInput();
      return;
    }

    beginZenPersonaPresenceTransition({
      fromBotId,
      toBotId: nextBotId,
      style,
    });
    setZenPersonaBotId(nextBotId);
    const syntheticSubmit = {
      preventDefault() {
        // no-op; used so Persona transitions share the normal submit path
      },
    } as React.FormEvent<HTMLFormElement>;
    void sendMessage(syntheticSubmit, {
      draftOverride: "",
      skipComposerHistory: true,
      personaTransition: {
        fromBotId,
        toBotId: nextBotId,
        source: "picker",
        style,
      },
    });
  }

  function handleZenPersonaSelectionChange(next: string): void {
    const nextBotId = next || null;
    if (zenSessionHasNotStarted()) {
      armFreshZenPersona(nextBotId);
      return;
    }
    commitZenPersonaTransition(nextBotId);
  }

  function handleZenMentionPersonaSelection(botId: string): void {
    if (zenSessionHasNotStarted()) {
      armFreshZenPersona(botId);
      return;
    }
    commitZenPersonaTransition(botId);
  }

  async function persistZenPersonaTransitionChoice(
    next: ZenPersonaTransitionChoice
  ): Promise<void> {
    const normalized = normalizeZenPersonaTransitionChoice(next);
    if (zenPersonaTransitionChoice === normalized) return;
    const previousChoice = zenPersonaTransitionChoice;
    setZenPersonaTransitionChoice(normalized);
    setSettings((previous) =>
      previous
        ? { ...previous, zenPersonaTransitionChoice: normalized }
        : previous
    );
    if (!settings) return;
    setError(null);
    setPanelError(null);
    try {
      await api("/api/settings", {
        method: "PATCH",
        body: JSON.stringify({ zenPersonaTransitionChoice: normalized }),
      });
      await refreshSettings();
    } catch (err) {
      setZenPersonaTransitionChoice(previousChoice);
      setSettings((previous) =>
        previous
          ? { ...previous, zenPersonaTransitionChoice: previousChoice }
          : previous
      );
      setError(
        err instanceof Error ? err.message : "Facet switch mode failed to save."
      );
    }
  }

  function renderZenPersonaTransitionChoiceControl(compact = false): React.ReactNode {
    return (
      <ZenPersonaTransitionChoiceControl
        value={zenPersonaTransitionChoice}
        onChange={(next) => {
          void persistZenPersonaTransitionChoice(next);
        }}
        compact={compact}
      />
    );
  }

  useEffect(() => {
    if (!emptyStateTypingSearchAvailable) return;
    function handlePageTyping(event: KeyboardEvent) {
      if (event.defaultPrevented || event.metaKey || event.ctrlKey || event.altKey) return;
      const activeElement = document.activeElement;
      if (event.key === "Tab") {
        if (!emptyStateSearchActive && !spotlightTypingArmedRef.current) return;
        if (
          activeElement instanceof Element &&
          activeElement.closest(
            "[data-starter-compose-surface='true'],[data-prism-compose-field='true']"
          )
        ) {
          return;
        }
        const spotlightInput = emptyStateSearchInputRef.current;
        const focusSpotlight = () => {
          if (hueFilterCenter !== null) {
            setEmptyStateSearchOpen(false);
            startBotPickerReturnToAll();
            focusEmptyStateSearchAfterReturn();
            return;
          }
          setHueFilterCenter(null);
          setEmptyStateSearchOpen(true);
          window.setTimeout(() => {
            spotlightInput?.focus({ preventScroll: true });
          }, 0);
        };

        event.preventDefault();
        if (!emptyStateSearchActive) {
          focusSpotlight();
          return;
        }
        if (activeElement === spotlightInput) {
          closeEmptyStateBotSearchAndFocusDraft();
          return;
        }
        spotlightInput?.focus({ preventScroll: true });
        return;
      }
      const activeElementIsEditable =
        activeElement instanceof HTMLElement &&
        (
          activeElement.isContentEditable ||
          activeElement instanceof HTMLInputElement ||
          activeElement instanceof HTMLTextAreaElement ||
          activeElement instanceof HTMLSelectElement
        );
      if (activeElementIsEditable) return;
      const pageHasFocus =
        !activeElement ||
        activeElement === document.body ||
        activeElement === document.documentElement;
      const spotlightHasFocusFallback = emptyStateSearchActive || pageHasFocus;
      if (!spotlightHasFocusFallback) return;

      if (event.key === "Backspace" && emptyStateSearchActive) {
        event.preventDefault();
        setEmptyStateBotNameFilter((current) => {
          if (current.length <= 1) {
            window.setTimeout(closeEmptyStateBotSearchAndFocusDraft, 0);
            return "";
          }
          return current.slice(0, -1);
        });
        return;
      }
      if (event.key === "Escape" && emptyStateSearchActive) {
        event.preventDefault();
        closeEmptyStateBotSearch();
        return;
      }
      if (event.key.length !== 1 || event.key.trim().length === 0) return;
      if (!emptyStateSearchActive && !spotlightTypingArmedRef.current) return;
      if (!emptyStateSearchActive && !pageHasFocus) return;
      event.preventDefault();
      openEmptyStateBotSearchFromTyping(event.key);
    }
    window.addEventListener("keydown", handlePageTyping);
    return () => window.removeEventListener("keydown", handlePageTyping);
  }, [
    closeEmptyStateBotSearchAndFocusDraft,
    closeEmptyStateBotSearch,
    emptyStateSearchActive,
    emptyStateTypingSearchAvailable,
    focusEmptyStateSearchAfterReturn,
    hueFilterCenter,
    openEmptyStateBotSearchFromTyping,
    startBotPickerReturnToAll,
  ]);

  useEffect(() => {
    if (!emptyStateSearchActive) return;
    function handleDocumentClick(event: MouseEvent) {
      const target = event.target;
      if (!(target instanceof Node)) return;
      if (emptyStateSearchRef.current?.contains(target)) return;
      closeEmptyStateBotSearch();
    }
    document.addEventListener("click", handleDocumentClick);
    return () => document.removeEventListener("click", handleDocumentClick);
  }, [closeEmptyStateBotSearch, emptyStateSearchActive]);

  const toggleCanvasBotSelection = useCallback((botId: string) => {
    setCanvasSelectedBotIds((current) => {
      const next = new Set(current);
      if (next.has(botId)) {
        next.delete(botId);
      } else {
        next.add(botId);
      }
      return stringSetsEqual(current, next) ? current : next;
    });
  }, []);

  const selectCanvasBot = useCallback((botId: string) => {
    setCanvasSelectedBotIds((current) => {
      if (current.has(botId)) return current;
      const next = new Set(current);
      next.add(botId);
      return next;
    });
  }, []);

  const relocateHueLensToBot = useCallback(
    (botId: string, geom: PickerGeometry): boolean => {
      if (emptyStateSearchActive || hueFilterCenter !== null) return false;
      if (!pickerUsesHueNavigation(geom, viewportWidth)) return false;
      const bot = pickerSourceBots.find((candidate) => candidate.id === botId);
      if (!bot || !botHasFilterableColor(bot)) return false;
      const { h } = hexToHsl(bot.color!.trim());
      setHueFilterCenter(hueLensPositionForHue(h));
      setSelectedBotId(null);
      return true;
    },
    [emptyStateSearchActive, hueFilterCenter, pickerSourceBots, viewportWidth]
  );

  // Touch keyboard-balloon handlers. Shared by both the Chat-mode and
  // Sandbox-mode empty-state picker frames. Active only when the gesture
  // is genuine touch input AND the picker is in hue-navigation territory:
  // Stage 3+ on mobile, Stage 4+ elsewhere. The first tap zooms/snaps the
  // hue lens; once narrowed, taps select individual bots again.
  const handleTouchPickerDown = useCallback(
    (event: React.PointerEvent<HTMLDivElement>, geom: PickerGeometry) => {
      if (event.pointerType !== "touch") return;
      if (!pickerUsesHueNavigation(geom, viewportWidth)) return;
      // Capture so subsequent move/up events route here even if the
      // finger drifts off this element. Without capture, the user's
      // finger crossing into a child tile would lose the gesture.
      event.currentTarget.setPointerCapture(event.pointerId);
      touchPreviewPointerIdRef.current = event.pointerId;
    },
    [viewportWidth]
  );

  const handleTouchPickerMove = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      if (event.pointerId !== touchPreviewPointerIdRef.current) return;
      cancelBotContextLongPress(event.pointerId);
    },
    [cancelBotContextLongPress]
  );

  const handleTouchPickerUp = useCallback(
    (event: React.PointerEvent<HTMLDivElement>, geom: PickerGeometry) => {
      if (event.pointerId !== touchPreviewPointerIdRef.current) return;
      cancelBotContextLongPress(event.pointerId);
      if (botContextSuppressClickRef.current) {
        event.preventDefault();
        setTouchPreview(null);
        touchPreviewPointerIdRef.current = null;
        if (event.currentTarget.hasPointerCapture(event.pointerId)) {
          event.currentTarget.releasePointerCapture(event.pointerId);
        }
        window.setTimeout(() => {
          botContextSuppressClickRef.current = false;
        }, 150);
        return;
      }
      const botId = findBotIdAtPoint(event.clientX, event.clientY);
      if (botId) {
        const relocated = relocateHueLensToBot(botId, geom);
        if (!relocated) {
          commitEmptyStateBotSelection(botId);
        }
      }
      setTouchPreview(null);
      touchPreviewPointerIdRef.current = null;
      if (event.currentTarget.hasPointerCapture(event.pointerId)) {
        event.currentTarget.releasePointerCapture(event.pointerId);
      }
    },
    [cancelBotContextLongPress, commitEmptyStateBotSelection, relocateHueLensToBot]
  );

  const handleTouchPickerCancel = useCallback(
    (event: React.PointerEvent<HTMLDivElement>) => {
      if (event.pointerId !== touchPreviewPointerIdRef.current) return;
      cancelBotContextLongPress(event.pointerId);
      setTouchPreview(null);
      touchPreviewPointerIdRef.current = null;
      if (event.currentTarget.hasPointerCapture(event.pointerId)) {
        event.currentTarget.releasePointerCapture(event.pointerId);
      }
    },
    [cancelBotContextLongPress]
  );

  const renderEmptyStateBotSearch = (): React.JSX.Element | null => {
    if (!emptyStateSearchActive || pickerSourceBots.length === 0) return null;
    const resultLabel =
      normalizedEmptyStateBotNameFilter.length === 0
        ? "Start typing to filter bots by name."
        : filteredBots.length === 1
          ? "1 bot found"
          : `${filteredBots.length} bots found`;
    return (
      <div
        ref={emptyStateSearchRef}
        className={styles.emptyStateSearch}
        role="search"
        onBlur={(event) => {
          const nextFocus = event.relatedTarget;
          if (nextFocus instanceof Node && event.currentTarget.contains(nextFocus)) return;
          closeEmptyStateBotSearch();
        }}
      >
        <div className={styles.emptyStateSearchField}>
          <span className={styles.emptyStateSearchGlyph} aria-hidden="true">
            ⌕
          </span>
          <input
            ref={emptyStateSearchInputRef}
            type="search"
            value={emptyStateBotNameFilter}
            onChange={(event) => setEmptyStateBotNameFilter(event.currentTarget.value)}
            onKeyDown={(event) => {
              if (event.key === "Escape") {
                event.preventDefault();
                closeEmptyStateBotSearch();
                return;
              }
              if (event.key === "Backspace" && emptyStateBotNameFilter.length <= 1) {
                event.preventDefault();
                closeEmptyStateBotSearchAndFocusDraft();
              }
            }}
            className={styles.emptyStateSearchInput}
            placeholder="Search bots"
            aria-label="Search bots by name"
          />
        </div>
        <div className={styles.emptyStateSearchMeta} aria-live="polite">
          {resultLabel}
        </div>
      </div>
    );
  };

  const renderCanvasBotBrowserRail = ({
    variant,
    style,
    railRef,
    searchInputRef,
    searchValue,
    onSearchChange,
    onSearchKeyDown,
    searchPlaceholder,
    searchAriaLabel,
    botPicker,
    groupPicker,
    resultLabel,
  }: {
    variant: "chat" | "coffee";
    style?: React.CSSProperties;
    railRef?: React.Ref<HTMLDivElement>;
    searchInputRef?: React.Ref<HTMLInputElement>;
    searchValue: string;
    onSearchChange: (nextValue: string) => void;
    onSearchKeyDown?: (event: React.KeyboardEvent<HTMLInputElement>) => void;
    searchPlaceholder: string;
    searchAriaLabel: string;
    botPicker?: React.ReactNode;
    groupPicker: React.ReactNode;
    resultLabel?: string;
  }): React.JSX.Element => {
    const railClassName = [
      styles.canvasBotBrowserRail,
      variant === "chat" ? styles.chatCanvasPickerControls : styles.coffeeCanvasPickerControls,
    ].join(" ");
    return (
      <div
        ref={railRef}
        className={railClassName}
        style={style}
        role="search"
        data-bot-browser-variant={variant}
        data-starter-bot-affordance={variant === "chat" ? "true" : undefined}
        onClick={(event) => event.stopPropagation()}
      >
        <label className={`${styles.coffeeSearchBar} ${styles.canvasBotBrowserSearch}`}>
          <span aria-hidden="true">⌕</span>
          <input
            ref={searchInputRef}
            type="search"
            value={searchValue}
            onChange={(event) => onSearchChange(event.currentTarget.value)}
            onKeyDown={onSearchKeyDown}
            placeholder={searchPlaceholder}
            aria-label={searchAriaLabel}
          />
        </label>
        {botPicker}
        {groupPicker}
        {resultLabel ? (
          <span className={styles.srOnly} aria-live="polite">
            {resultLabel}
          </span>
        ) : null}
      </div>
    );
  };

  const renderFocusedBotLibraryGroupDashboard = ({
    emptyStateClassName,
    heroBot,
  }: {
    emptyStateClassName: string;
    heroBot: Bot | null;
  }): React.JSX.Element | null => {
    const focusedBotLibraryGroup = activeBotLibraryGroupFilter;
    if (
      !focusedBotLibraryGroup ||
      pendingIncognito ||
      emptyStateSearchActive ||
      heroBot
    ) {
      return null;
    }

    const groupDashboardBots = baseFilteredPanelBots;
    const groupDescription = focusedBotLibraryGroup.description.trim();
    const groupProtectedBotCount = groupDashboardBots.filter((bot) =>
      isBotDeleteProtected(bot.id)
    ).length;
    const groupEyebrowLabel = botLibraryGroupDashboardEyebrowLabel(
      groupDashboardBots.length,
      focusedBotLibraryGroup.builtIn ? undefined : BOT_LIBRARY_GROUP_BOT_CAP,
      groupProtectedBotCount
    );
    const groupDeleteProtected = focusedBotLibraryGroup.deleteProtected;
    const nextGroupDeleteProtected = !groupDeleteProtected;
    const groupProtectionLabel = groupDeleteProtected ? "Allow deletion" : "Protect group";
    const groupProtectionTitle = groupDeleteProtected
      ? `Allow deletion for bots in ${focusedBotLibraryGroup.name}`
      : `Protect bots in ${focusedBotLibraryGroup.name} from deletion`;
    const groupExportTitle =
      groupDashboardBots.length > 0
        ? `Export ${focusedBotLibraryGroup.name} as a bot collection`
        : `${focusedBotLibraryGroup.name} has no bots to export`;

    return (
      <div
        className={`${emptyStateClassName} ${styles.emptyStateGroupDashboard}`}
        onClick={handleEmptyStateBackgroundClick}
      >
        <section
          className={styles.botGroupDashboard}
          style={botLibraryGroupVisualStyle(
            focusedBotLibraryGroup,
            groupDashboardBots,
            resolvedTheme
          )}
          data-starter-bot-affordance="true"
          aria-labelledby="bot-library-group-dashboard-title"
          onClick={(event) => event.stopPropagation()}
        >
          <header className={styles.botGroupDashboardHeader}>
            <div className={styles.botGroupDashboardCopy}>
              <span className={styles.botGroupDashboardEyebrow}>
                {groupEyebrowLabel}
              </span>
              <h2 id="bot-library-group-dashboard-title">
                {focusedBotLibraryGroup.name}
              </h2>
              {groupDescription ? <p>{groupDescription}</p> : null}
            </div>
            <div className={styles.botGroupDashboardActions}>
              <button
                type="button"
                className={`${styles.botGroupDashboardAction} ${styles.botGroupDashboardProtectionAction}`}
                data-active={groupDeleteProtected ? "true" : undefined}
                onClick={() =>
                  setBotLibraryGroupDeleteProtection(
                    focusedBotLibraryGroup.id,
                    nextGroupDeleteProtected
                  )
                }
                aria-label={groupProtectionTitle}
                title={groupProtectionTitle}
              >
                <BotGlyph
                  name={groupDeleteProtected ? "key" : "lock"}
                  size={14}
                  strokeWidth={2.05}
                />
                <span>{groupProtectionLabel}</span>
              </button>
              <button
                type="button"
                className={styles.botGroupDashboardAction}
                disabled={groupDashboardBots.length === 0 || botTransferBusy}
                onClick={() =>
                  void exportBotsAsCollection(groupDashboardBots, {
                    group: {
                      name: focusedBotLibraryGroup.name,
                      description: focusedBotLibraryGroup.description,
                    },
                  })
                }
                aria-label={groupExportTitle}
                title={groupExportTitle}
              >
                <Download size={14} strokeWidth={2.1} aria-hidden="true" />
                <span>Export group</span>
              </button>
              {!focusedBotLibraryGroup.builtIn ? (
                <>
                  <button
                    type="button"
                    className={styles.botGroupDashboardAction}
                    onClick={() => editBotLibraryGroup(focusedBotLibraryGroup.id)}
                  >
                    Edit
                  </button>
                  <button
                    type="button"
                    className={`${styles.botGroupDashboardAction} ${styles.botGroupDashboardDangerAction}`}
                    onClick={() => requestDeleteBotLibraryGroup(focusedBotLibraryGroup.id)}
                    aria-label={`Delete ${focusedBotLibraryGroup.name}`}
                  >
                    <Trash2 size={14} strokeWidth={2.15} aria-hidden="true" />
                    <span>Delete</span>
                  </button>
                </>
              ) : null}
            </div>
          </header>
          {groupDashboardBots.length > 0 ? (
            <div
              className={styles.botGroupDashboardBotGrid}
              role="list"
              aria-label={`Bots in ${focusedBotLibraryGroup.name}`}
            >
              {groupDashboardBots.map((b) => {
                const isMarqueeSelected = canvasSelectedBotIds.has(b.id);
                const isProtected = isBotDeleteProtected(b.id);
                const isFavorite = favoriteBotIdSet.has(b.id);
                const tileTraits = [
                  isFavorite ? "favorite" : null,
                  isProtected ? "protected" : null,
                ].filter(Boolean);
                const rawColor = b.color?.trim();
                const accent = rawColor
                  ? displayAccentForMode(rawColor, resolvedTheme, appWidePrivateMode)
                  : null;
                const tileStyle = accent
                  ? ({ "--bot-color": accent } as React.CSSProperties)
                  : undefined;
                const tileClassName = [
                  styles.chatBotTile,
                  styles.chatBotTileWithName,
                  styles.botGroupDashboardBotTile,
                  isProtected ? styles.chatBotTileProtected : null,
                  isMarqueeSelected ? styles.chatBotTileMarqueeSelected : null,
                ].filter(Boolean).join(" ");
                return (
                  <button
                    key={b.id}
                    type="button"
                    className={tileClassName}
                    style={tileStyle}
                    data-bot-id={b.id}
                    onContextMenu={(event) => {
                      event.preventDefault();
                      event.stopPropagation();
                      openBotLibraryGroupBotContextMenu(
                        focusedBotLibraryGroup.id,
                        b,
                        event.clientX,
                        event.clientY
                      );
                    }}
                    onClick={(event) => {
                      if (canvasBotMarqueeSuppressClickRef.current) {
                        canvasBotMarqueeSuppressClickRef.current = false;
                        event.preventDefault();
                        event.stopPropagation();
                        return;
                      }
                      if (event.shiftKey || event.ctrlKey || event.metaKey) {
                        event.preventDefault();
                        event.stopPropagation();
                        toggleCanvasBotSelection(b.id);
                        return;
                      }
                      commitEmptyStateBotSelection(b.id);
                    }}
                    aria-label={
                      tileTraits.length > 0
                        ? `${b.name}, ${tileTraits.join(", ")}`
                        : b.name
                    }
                    data-favorite={isFavorite ? "true" : undefined}
                    data-delete-protected={isProtected ? "true" : undefined}
                    title={b.name}
                  >
                    <span className={styles.chatBotTileBotGlyph}>
                      <BotGlyph name={b.glyph} size={34} strokeWidth={1.9} />
                    </span>
                    <span className={styles.chatBotTileFeaturedName}>{b.name}</span>
                  </button>
                );
              })}
            </div>
          ) : (
            <p className={styles.botGroupDashboardEmpty} role="status">
              {focusedBotLibraryGroup.id === BOT_LIBRARY_FAVORITES_GROUP_ID
                ? "No favorite bots yet."
                : "No bots in this group yet."}
            </p>
          )}
        </section>
      </div>
    );
  };

  const renderChatCanvasPickerControls = (
    style?: React.CSSProperties
  ): React.JSX.Element | null => {
    if ((view !== "chat" && view !== "sandbox") || pickerSourceBots.length === 0) return null;
    const resultLabel =
      normalizedEmptyStateBotNameFilter.length === 0
        ? "Type to filter bots by name."
        : filteredBots.length === 1
          ? "1 bot found"
          : `${filteredBots.length} bots found`;
    const botHasCommenced = !!detail && detail.messages.length > 0;
    const botPickerBots = botHasCommenced ? bots : filteredBots;
    const showRailBotPicker = view === "sandbox" || botHasCommenced;
    const botPicker =
      showRailBotPicker && bots.length > 0 ? (
        <ComposerBotPicker
          value={selectedBotId ?? ""}
          onChange={handleComposerBotSelectionChange}
          bots={botPickerBots}
          resolvedTheme={resolvedTheme}
          placement="down"
          title={
            !detail
              ? "Choose a starter bot for this chat. You can also pick directly from the grid below."
              : undefined
          }
          ariaLabel="Bot for the next message"
          showName={botHasCommenced}
          enableFilters
          hueFilterCenter={hueFilterCenter}
          onHueChange={setHueFilterCenter}
          hueLensAvailable={hueLensAvailable}
          hueLensTrackGradient={hueLensTrackGradient}
          hueLensTrackSegments={hueLensTrackSegments}
          dismissPopoversSignal={composerPopoverDismissSignal}
          privateTone={appWidePrivateMode}
        />
      ) : null;
    return renderCanvasBotBrowserRail({
      variant: "chat",
      style,
      railRef: emptyStateSearchRef,
      searchInputRef: emptyStateSearchInputRef,
      searchValue: emptyStateBotNameFilter,
      onSearchChange: setEmptyStateBotNameFilter,
      onSearchKeyDown: (event) => {
        if (event.key === "Escape") {
          event.preventDefault();
          closeEmptyStateBotSearchAndFocusDraft();
        }
      },
      searchPlaceholder: "Search or add bots...",
      searchAriaLabel: "Search bots for Chat",
      botPicker,
      groupPicker: (
        <BotLibraryGroupPicker
          value={botLibraryGroupPickerValue}
          options={botLibraryGroupFilterOptions}
          onChange={applyBotLibraryHeaderFilter}
          resolvedTheme={resolvedTheme}
          showCounts={false}
          dismissPopoversSignal={composerPopoverDismissSignal}
        />
      ),
      resultLabel,
    });
  };

  const renderChatBotPickerGrid = (
    pickerGeom: PickerGeometry | null = null
  ): React.JSX.Element | null => {
    if (pickerBots.length === 0) return null;
    const geom =
      pickerGeom ??
      pickerGeometry(
        pickerBots.length,
        viewportWidth,
        viewportHeight,
        activeHueLensGridOptions
      );
    const rowWidth =
      geom.gridCols * geom.tileSize +
      (geom.gridCols - 1) * geom.tileGap;
    const frameStyle: React.CSSProperties = {
      "--picker-width": `${geom.pickerWidth}px`,
      "--picker-height": `${geom.pickerHeight}px`,
      "--picker-parallax-x": "0px",
      "--picker-parallax-y": "0px",
      "--picker-return-duration": `${BOT_PICKER_RETURN_ANIMATION_MS}ms`,
    } as React.CSSProperties;
    const pickerStyle: React.CSSProperties = {
      "--tile-size": `${geom.tileSize}px`,
      "--tile-gap": `${geom.tileGap}px`,
      "--tile-hover-scale": String(geom.hoverScale),
      "--grid-cols": geom.gridCols,
      width: `${rowWidth}px`,
    } as React.CSSProperties;
    const pickerClassName = [
      styles.chatBotPicker,
      geom.singleBot ? styles.chatBotPickerSingle : null,
      geom.threeBotStack ? styles.chatBotPickerThreeStack : null,
      geom.mobileColumnStack ? styles.chatBotPickerMobileColumnStack : null,
      geom.crosshairCursor ? styles.chatBotPickerCrosshair : null,
      geom.dotCursor ? styles.chatBotPickerDotCursor : null,
      geom.solidSwatch ? styles.chatBotPickerSolidSwatch : null,
      geom.compactPixelGrid ? styles.chatBotPickerPixelGrid : null,
      geom.radialRainbowGradient ? styles.chatBotPickerRainbowGradient : null,
    ].filter(Boolean).join(" ");
    const pickerCells = pickerFormationCells(pickerBots, geom);

    return (
      <div
        className={styles.chatBotPickerFrame}
        data-starter-bot-affordance="true"
        data-bot-picker-frame="true"
        data-single-bot={geom.singleBot ? "true" : undefined}
        data-returning-all={botPickerReturnAnimating ? "true" : undefined}
        data-search-active={emptyStateSearchActive ? "true" : undefined}
        data-touch-active={touchPreview ? "true" : undefined}
        style={frameStyle}
        onPointerLeave={e => {
          if (e.pointerType === "mouse" && !geom.compactPixelGrid) {
            resetPickerParallax(e.currentTarget);
          }
        }}
        onPointerDown={e => {
          handleTouchPickerDown(e, geom);
        }}
        onPointerMove={handleTouchPickerMove}
        onPointerUp={e => {
          handleTouchPickerUp(e, geom);
        }}
        onPointerCancel={handleTouchPickerCancel}
      >
        <div
          className={pickerClassName}
          role="radiogroup"
          aria-label="Bot for this chat"
          style={pickerStyle}
        >
          {pickerCells.map((b, cellIndex) => {
            if (!b) {
              if (
                hueFilterActive ||
                pickerBots.length < pickerSourceBots.length ||
                geom.threeBotStack ||
                geom.mobileColumnStack
              ) return null;
              return (
                <span
                  key={`blank-${cellIndex}`}
                  className={styles.chatBotTilePlaceholder}
                  aria-hidden="true"
                />
              );
            }
            const isSelected =
              sandboxGridSelectedBotId === b.id ||
              (view === "chat" && selectedId === null && selectedBotId === b.id);
            const isMarqueeSelected = canvasSelectedBotIds.has(b.id);
            const isProtected = isBotDeleteProtected(b.id);
            const isFavorite = favoriteBotIdSet.has(b.id);
            const tileTraits = [
              isFavorite ? "favorite" : null,
              isProtected ? "protected" : null,
            ].filter(Boolean);
            const rawColor = b.color?.trim();
            const accent = rawColor
              ? displayAccentForMode(rawColor, resolvedTheme, appWidePrivateMode)
              : null;
            const tileStyle = accent
              ? ({ "--bot-color": accent } as React.CSSProperties)
              : undefined;
            let tileClassName = styles.chatBotTile;
            if (isProtected) tileClassName += ` ${styles.chatBotTileProtected}`;
            if (isSelected) tileClassName += ` ${styles.chatBotTileSelected}`;
            if (isMarqueeSelected) tileClassName += ` ${styles.chatBotTileMarqueeSelected}`;
            if (geom.namedFlatTile || geom.flattenTile) {
              tileClassName += ` ${styles.chatBotTileFlat}`;
            }
            if (geom.solidSwatch) {
              tileClassName += ` ${styles.chatBotTileSolidSwatch}`;
            } else if (geom.hideGlyphByDefault) {
              tileClassName += ` ${styles.chatBotTileSwatchOnly}`;
            }
            const showPixelGridGlyph = geom.compactPixelGrid;
            const showSelectedDotGlyph = geom.selectedDotGlyph && isSelected;
            const showTileGlyph = !geom.hideGlyphByDefault || showPixelGridGlyph;
            const showFeaturedName =
              !geom.compactPixelGrid &&
              geom.tileSize >= PICKER_TILE_NAME_MIN_SIZE;
            const botTileTooltip = showFeaturedName ? undefined : b.name;
            if (showFeaturedName) {
              tileClassName += ` ${styles.chatBotTileWithName}`;
              if (
                geom.namedFlatTile ||
                geom.flattenTile ||
                geom.tileSize <= PICKER_TILE_COMPACT_NAME_MAX_SIZE
              ) {
                tileClassName += ` ${styles.chatBotTileNamedFlat}`;
              }
            }
            const tileGlyphSize = showPixelGridGlyph
              ? Math.max(
                  PICKER_PIXEL_GLYPH_MIN_SIZE,
                  Math.round(geom.tileSize * PICKER_PIXEL_GLYPH_RATIO)
                )
              : geom.glyphSize;
            const tileGlyphStroke = showPixelGridGlyph
              ? PICKER_PIXEL_GLYPH_STROKE
              : geom.glyphStroke;

            return (
              <button
                key={b.id}
                type="button"
                role="radio"
                aria-checked={isSelected}
                aria-label={tileTraits.length > 0 ? `${b.name}, ${tileTraits.join(", ")}` : b.name}
                className={tileClassName}
                data-bot-id={b.id}
                data-glyph-tooltip={botTileTooltip}
                data-favorite={isFavorite ? "true" : undefined}
                data-delete-protected={isProtected ? "true" : undefined}
                onPointerDown={e => {
                  lastBotPickerPointerTypeRef.current = e.pointerType;
                  startBotContextLongPress(e, b);
                }}
                onPointerUp={handleBotContextPointerEnd}
                onPointerCancel={handleBotContextPointerEnd}
                onPointerEnter={e => {
                  if (e.pointerType !== "mouse" || geom.compactPixelGrid) return;
                  updatePickerParallax(e);
                }}
                onPointerMove={e => {
                  handleBotContextPointerMove(e);
                  if (geom.compactPixelGrid) return;
                  updatePickerParallax(e);
                }}
                onContextMenu={(event) => {
                  event.preventDefault();
                  event.stopPropagation();
                  if (event.ctrlKey) {
                    toggleCanvasBotSelection(b.id);
                    return;
                  }
                  const multiSelectionIds =
                    canvasSelectedBotIds.size > 1 && canvasSelectedBotIds.has(b.id)
                      ? Array.from(canvasSelectedBotIds)
                      : [];
                  openBotContextMenu(b, event.clientX, event.clientY, multiSelectionIds);
                }}
                onClick={(e) => {
                  if (canvasBotMarqueeSuppressClickRef.current) {
                    canvasBotMarqueeSuppressClickRef.current = false;
                    e.preventDefault();
                    e.stopPropagation();
                    return;
                  }
                  if (botContextSuppressClickRef.current) {
                    botContextSuppressClickRef.current = false;
                    e.preventDefault();
                    e.stopPropagation();
                    return;
                  }
                  if (e.shiftKey || e.ctrlKey || e.metaKey) {
                    e.preventDefault();
                    e.stopPropagation();
                    toggleCanvasBotSelection(b.id);
                    return;
                  }
                  const isDesktopMousePixelClick =
                    geom.compactPixelGrid &&
                    e.detail > 0 &&
                    lastBotPickerPointerTypeRef.current === "mouse";
                  const shouldRelocateHue =
                    !emptyStateSearchActive &&
                    botHasFilterableColor(b) &&
                    (isDesktopMousePixelClick ||
                      (!hueFilterActive && pickerUsesHueNavigation(geom, viewportWidth)));
                  if (shouldRelocateHue) {
                    const { h } = hexToHsl(b.color!.trim());
                    const lensPosition = hueLensPositionForHue(h);
                    setHueFilterCenter(lensPosition);
                    if (isDesktopMousePixelClick) {
                      commitEmptyStateBotSelection(b.id);
                      return;
                    }
                    setSelectedBotId(null);
                    return;
                  }
                  commitEmptyStateBotSelection(b.id);
                }}
                style={tileStyle}
              >
                {showTileGlyph && (
                  <span className={styles.chatBotTileBotGlyph}>
                    {showSelectedDotGlyph ? (
                      <>
                        <span
                          className={styles.chatBotTileSelectedDotGlyph}
                          aria-hidden="true"
                        />
                        <BotGlyph
                          name={b.glyph}
                          size={tileGlyphSize}
                          strokeWidth={tileGlyphStroke}
                          className={styles.chatBotTileSelectedHoverGlyph}
                        />
                      </>
                    ) : (
                      <BotGlyph
                        name={b.glyph}
                        size={tileGlyphSize}
                        strokeWidth={tileGlyphStroke}
                      />
                    )}
                  </span>
                )}
                {showFeaturedName && (
                  <span className={styles.chatBotTileFeaturedName}>
                    {b.name}
                  </span>
                )}
              </button>
            );
          })}
        </div>
      </div>
    );
  };

  const disarmDelete = useCallback(() => {
    if (pendingDeleteTimerRef.current) {
      clearTimeout(pendingDeleteTimerRef.current);
      pendingDeleteTimerRef.current = null;
    }
    setPendingDeleteKey(null);
  }, []);

  const beginConversationGroupPointerDrag = useCallback((
    event: React.PointerEvent<HTMLElement>,
    groupKey: string
  ) => {
    if (event.button !== 0) return;
    if (conversationGroupPointerDragRef.current || draggingConversationGroupKey) return;
    conversationGroupPointerDragRef.current = {
      key: groupKey,
      pointerId: event.pointerId,
      startY: event.clientY,
      active: false,
    };
    try {
      event.currentTarget.setPointerCapture(event.pointerId);
    } catch {
      // Pointer capture is unavailable in some browser/test environments.
    }
  }, [draggingConversationGroupKey]);

  const updateConversationGroupPointerDrag = useCallback((
    event: React.PointerEvent<HTMLElement>
  ) => {
    const drag = conversationGroupPointerDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return;
    const deltaY = event.clientY - drag.startY;
    if (!drag.active) {
      if (Math.abs(deltaY) < 6) return;
      drag.active = true;
      disarmDelete();
      setExpandedConversationGroupKey((previous) =>
        previous === drag.key ? null : previous
      );
      setDraggingConversationGroupKey(drag.key);
      suppressConversationGroupClickRef.current = true;
    }

    event.preventDefault();
    const hoveredGroup = document
      .elementsFromPoint(event.clientX, event.clientY)
      .map((element) =>
        element instanceof HTMLElement
          ? element.closest<HTMLElement>("[data-conversation-group-key]")
          : null
      )
      .find((element) => element && element.dataset.conversationGroupKey !== drag.key);
    const targetKey = hoveredGroup?.dataset.conversationGroupKey;
    if (!hoveredGroup || !targetKey) return;
    const rect = hoveredGroup.getBoundingClientRect();
    const position: ConversationGroupDropPosition =
      event.clientY > rect.top + rect.height / 2 ? "after" : "before";
    moveConversationGroup(drag.key, targetKey, position);
  }, [disarmDelete, moveConversationGroup]);

  const endConversationGroupPointerDrag = useCallback((
    event: React.PointerEvent<HTMLElement>
  ) => {
    const drag = conversationGroupPointerDragRef.current;
    if (!drag || drag.pointerId !== event.pointerId) return;
    const wasActive = drag.active;
    try {
      event.currentTarget.releasePointerCapture(event.pointerId);
    } catch {
      // Non-fatal: capture may already be released.
    }
    clearConversationGroupDragState();
    if (wasActive) {
      event.preventDefault();
      window.setTimeout(() => {
        suppressConversationGroupClickRef.current = false;
      }, 0);
    }
  }, [clearConversationGroupDragState]);

  useEffect(() => {
    if (!draggingConversationGroupKey) return;
    const handleViewportLeave = (event: MouseEvent) => {
      if (event.relatedTarget !== null) return;
      abortConversationGroupPointerDrag();
    };
    const handleWindowBlur = () => {
      abortConversationGroupPointerDrag();
    };
    document.documentElement.addEventListener("mouseleave", handleViewportLeave);
    window.addEventListener("blur", handleWindowBlur);
    return () => {
      document.documentElement.removeEventListener("mouseleave", handleViewportLeave);
      window.removeEventListener("blur", handleWindowBlur);
    };
  }, [abortConversationGroupPointerDrag, draggingConversationGroupKey]);

  const armDelete = useCallback((key: string) => {
    if (pendingDeleteTimerRef.current) {
      clearTimeout(pendingDeleteTimerRef.current);
      pendingDeleteTimerRef.current = null;
    }
    setPendingDeleteKey(key);
    // DELETE_ALL_KEY / DELETE_ALL_BOTS_KEY are special: their confirm
    // surface is a centered modal, and the 3.5 s window that makes the
    // inline "Are you sure?" pill feel snappy would instead pull the
    // modal out from under the user mid-read. We skip auto-disarm for
    // them and rely on Cancel / backdrop / Esc to dismiss explicitly.
    if (
      key === DELETE_ALL_KEY ||
      key === DELETE_ALL_COFFEE_SESSIONS_KEY ||
      key === DELETE_ALL_BOTS_KEY ||
      key.startsWith(DELETE_COFFEE_GROUP_KEY_PREFIX)
    ) return;
    pendingDeleteTimerRef.current = setTimeout(() => {
      setPendingDeleteKey(null);
      pendingDeleteTimerRef.current = null;
    }, DELETE_CONFIRM_WINDOW_MS);
  }, []);

  // Clean up the pending-delete timer on unmount so an in-flight auto-disarm
  // doesn't call setState on a torn-down component.
  useEffect(() => () => {
    if (pendingDeleteTimerRef.current) {
      clearTimeout(pendingDeleteTimerRef.current);
    }
  }, []);

  // Right-click is suppressed app-wide for custom surfaces, but text-entry
  // controls should keep native OS context menus (copy/paste/spellcheck).
  // This preserves expected platform behavior in all textarea/input fields.
  const shouldAllowNativeContextMenu = useCallback((target: EventTarget | null): boolean => {
    if (!(target instanceof HTMLElement)) return false;
    return target.closest(
      [
        "textarea",
        "input:not([type='button']):not([type='submit']):not([type='reset'])",
        "[contenteditable='true']",
        "[contenteditable='']",
        "[role='textbox']",
      ].join(", ")
    ) !== null;
  }, []);

  const handleAppContextMenu = useCallback((event: React.MouseEvent<HTMLElement>) => {
    if (shouldAllowNativeContextMenu(event.target)) return;
    event.preventDefault();
  }, [shouldAllowNativeContextMenu]);

  /**
   * Right-click anywhere in the Coffee shell that isn't a seat / a button / a
   * field surfaces the same actions the Coffee header icons offer, in their
   * text-equivalent form. Mirrors `renderCanvasToolsContextMenu` for Chat.
   */
  const handleCoffeeShellContextMenu = useCallback(
    (event: React.MouseEvent<HTMLElement>) => {
      if (shouldAllowNativeContextMenu(event.target)) return;
      event.preventDefault();
      if (event.target instanceof HTMLElement) {
        // Defer to the seat-specific handler if the click landed on a Coffee seat.
        if (event.target.closest('[data-coffee-seat-context="true"]')) return;
      }
      const clamped = clampContextMenuPosition(
        event.clientX,
        event.clientY,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
      );
      setCoffeeShellContextMenu({ x: clamped.x, y: clamped.y });
      setCoffeeBotContextMenu(null);
      setCanvasToolsContextMenu(null);
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
    },
    [shouldAllowNativeContextMenu]
  );

  /**
   * Right-click on a seated bot — text shortcuts to that bot's customizer + memories.
   */
  const openCoffeeBotContextMenu = useCallback(
    (botId: string, x: number, y: number) => {
      const clamped = clampContextMenuPosition(
        x,
        y,
        BOT_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        BOT_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
      );
      setCoffeeBotContextMenu({ botId, x: clamped.x, y: clamped.y });
      setCoffeeShellContextMenu(null);
      setBotContextMenu(null);
      setCanvasToolsContextMenu(null);
      setConversationGroupContextMenu(null);
    },
    []
  );

  const handleStoryShellContextMenu = useCallback(
    (event: React.MouseEvent<HTMLElement>) => {
      event.preventDefault();
      const clamped = clampContextMenuPosition(
        event.clientX,
        event.clientY,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        260
      );
      setStoryShellContextMenu({ x: clamped.x, y: clamped.y });
      setCoffeeShellContextMenu(null);
      setCoffeeBotContextMenu(null);
      setCanvasToolsContextMenu(null);
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
    },
    []
  );

  const handleMessagesFrameContextMenu = useCallback(
    (event: React.MouseEvent<HTMLElement>) => {
      if (shouldAllowNativeContextMenu(event.target)) return;
      event.preventDefault();
      event.stopPropagation();
      if (botLibraryGroupDashboardActive) {
        closeMessageContextOverlay();
        setBotContextMenu(null);
        setConversationGroupContextMenu(null);
        setCanvasToolsContextMenu(null);
        setChatOverflowMenuOpen(false);
        return;
      }
      const clamped = clampContextMenuPosition(
        event.clientX,
        event.clientY,
        CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_WIDTH_PX,
        view === "chat"
          ? ZEN_CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
          : CANVAS_TOOLS_CONTEXT_MENU_ESTIMATED_HEIGHT_PX
      );
      setCanvasToolsContextMenu({ x: clamped.x, y: clamped.y });
      closeMessageContextOverlay();
      setBotContextMenu(null);
      setConversationGroupContextMenu(null);
      setChatOverflowMenuOpen(false);
    },
    [
      shouldAllowNativeContextMenu,
      botLibraryGroupDashboardActive,
      closeMessageContextOverlay,
      view,
    ]
  );

  // ── Hold-to-delete-all gesture ────────────────────────────────────────
  // `startHoldDelete` / `cancelHoldDelete` are called from pointer events
  // on every chat-clear affordance (sidebar × rows + header Delete). The
  // discrete React state change (holdingKey set/cleared) drives the CSS
  // `[data-holding="true"]` attribute, which owns the actual 900 ms morph
  // animation — we never re-render on intermediate progress, so even a
  // long hold doesn't thrash React's reconciler.
  const cancelHoldDelete = useCallback(() => {
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
      holdTimerRef.current = null;
    }
    setHoldingKey(null);
  }, []);

  const startHoldDelete = useCallback((key: string) => {
    // Refuse to start a new hold while anything is already armed: the
    // active confirm pill / modal deserves the user's attention first,
    // and a second gesture layering on top would be disorienting.
    if (pendingDeleteKey) return;
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
    }
    holdCompletedRef.current = false;
    setHoldingKey(key);
    // Route to the bots sentinel when the holding key is a bot × so the
    // confirmation modal asks the right question and the bulk action
    // wipes the right dataset. Any non-bot key (sidebar chat ×, header
    // Delete) stays on the original DELETE_ALL_KEY path.
    const allKey = key.startsWith(BOT_DELETE_KEY_PREFIX)
      ? DELETE_ALL_BOTS_KEY
      : DELETE_ALL_KEY;
    holdTimerRef.current = setTimeout(() => {
      // Threshold crossed — snap out of "holding" visuals and into the
      // armed-all state. The list-level data attribute flip takes the
      // ×'s from tilted-and-glowing straight into iOS jiggle, and
      // `armDelete` renders the confirmation modal.
      holdCompletedRef.current = true;
      setHoldingKey(null);
      holdTimerRef.current = null;
      armDelete(allKey);
    }, DELETE_ALL_HOLD_MS);
  }, [armDelete, pendingDeleteKey]);

  // Clean up the hold timer on unmount.
  useEffect(() => () => {
    if (holdTimerRef.current) {
      clearTimeout(holdTimerRef.current);
    }
  }, []);

  // Armed-all modal a11y: when the modal mounts, capture whatever had
  // focus (usually the × / header Delete the user was holding) so we can
  // restore focus to it on dismiss. While the modal is open, Escape
  // cancels — keeping the keyboard escape hatch consistent with every
  // other confirm surface in the app. Both the chat-scoped and bot-scoped
  // armed-all states share this contract so the two modals behave
  // identically from the keyboard / screen-reader side.
  const pendingCoffeeGroupDeleteIdForModal = parseCoffeeGroupDeleteKey(pendingDeleteKey);
  const isDeleteAllActive =
    pendingDeleteKey === DELETE_ALL_KEY ||
    pendingDeleteKey === DELETE_ALL_COFFEE_SESSIONS_KEY ||
    pendingDeleteKey === DELETE_ALL_BOTS_KEY ||
    pendingCoffeeGroupDeleteIdForModal !== null;
  useEffect(() => {
    if (!isDeleteAllActive) {
      // On close, return focus to the element that opened the modal
      // (if it still exists in the DOM and is focusable).
      const prev = preModalFocusRef.current;
      preModalFocusRef.current = null;
      if (prev && typeof prev.focus === "function" && document.contains(prev)) {
        // Use a microtask so React has flushed the modal-removal render
        // before we refocus — otherwise the browser may steal focus
        // back to <body> between our call and the reconciliation tick.
        queueMicrotask(() => {
          try { prev.focus({ preventScroll: true }); } catch { /* focus can fail on detached nodes */ }
        });
      }
      return;
    }
    // Modal is opening — remember where focus came from.
    const active = document.activeElement;
    preModalFocusRef.current =
      active instanceof HTMLElement ? active : null;

    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        disarmDelete();
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isDeleteAllActive, disarmDelete]);

  useEffect(() => {
    const id = parseCoffeeGroupDeleteKey(pendingDeleteKey);
    if (!id) return;
    if (!coffeeGroups.some((group) => group.id === id)) {
      disarmDelete();
    }
  }, [pendingDeleteKey, coffeeGroups, disarmDelete]);

  // Single-bot delete from the Bots panel header uses its own modal; if any
  // sidebar/header delete affordance arms, drop the header modal so only one
  // confirm surface is active.
  useEffect(() => {
    if (!pendingDeleteKey) return;
    setPanelBotDeleteConfirm(null);
    setSelectedBotDeleteConfirm(null);
  }, [pendingDeleteKey]);

  const isPanelBotDeleteModalOpen = panelBotDeleteConfirm !== null;
  useEffect(() => {
    if (!isPanelBotDeleteModalOpen) {
      const prev = prePanelBotDeleteModalFocusRef.current;
      prePanelBotDeleteModalFocusRef.current = null;
      if (prev && typeof prev.focus === "function" && document.contains(prev)) {
        queueMicrotask(() => {
          try { prev.focus({ preventScroll: true }); } catch { /* ignore */ }
        });
      }
      return;
    }
    const active = document.activeElement;
    prePanelBotDeleteModalFocusRef.current =
      active instanceof HTMLElement ? active : null;

    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        setPanelBotDeleteConfirm(null);
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isPanelBotDeleteModalOpen]);

  const isSweepConfirmModalOpen = sweepConfirmOpen;
  useEffect(() => {
    if (!isSweepConfirmModalOpen) {
      const prev = preSweepConfirmModalFocusRef.current;
      preSweepConfirmModalFocusRef.current = null;
      if (prev && typeof prev.focus === "function" && document.contains(prev)) {
        queueMicrotask(() => {
          try { prev.focus({ preventScroll: true }); } catch { /* ignore */ }
        });
      }
      return;
    }
    const active = document.activeElement;
    preSweepConfirmModalFocusRef.current =
      active instanceof HTMLElement ? active : null;

    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        setSweepConfirmOpen(false);
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isSweepConfirmModalOpen]);

  useEffect(() => {
    if (!sweepUndoToast) return;
    const remainingMs = Math.max(0, sweepUndoToast.expiresAt - Date.now());
    if (remainingMs <= 0) {
      setSweepUndoToast(null);
      return;
    }
    const timer = window.setTimeout(() => {
      setSweepUndoToast((current) =>
        current?.batchId === sweepUndoToast.batchId ? null : current
      );
    }, remainingMs);
    return () => window.clearTimeout(timer);
  }, [sweepUndoToast]);

  useEffect(() => {
    if (!devToolsOpen && !devToolsMinimized) return;
    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") {
        event.stopPropagation();
        closeDevTools();
      }
    }
    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [devToolsMinimized, devToolsOpen, closeDevTools]);

  // Clicking anywhere outside the delete / confirm affordance should disarm it.
  // This prevents the confirm pill from lingering in an awkward in-between
  // state after focus moves elsewhere in the sidebar.
  useEffect(() => {
    if (!pendingDeleteKey) {
      return;
    }

    function handlePointerDown(event: PointerEvent) {
      if (!isPrimaryPointerDismissal(event)) return;
      const target = event.target;
      // `Element` (not HTMLElement) is deliberate: clicks on inline SVG
      // glyphs have an SVGElement target, which is NOT an HTMLElement but
      // IS an Element (and has .closest). Narrowing to HTMLElement here
      // would treat glyph-icon taps as "outside" and collapse the
      // affordance the user just tried to act on.
      if (target instanceof Element && target.closest("[data-delete-affordance='true']")) {
        return;
      }
      disarmDelete();
    }

    document.addEventListener("pointerdown", handlePointerDown);
    return () => {
      document.removeEventListener("pointerdown", handlePointerDown);
    };
  }, [pendingDeleteKey, disarmDelete]);

  // Inline delete confirms (long-term rows + short-term card): disarm when leaving Memories.
  useEffect(() => {
    if (pendingDeleteKey === null) return;
    const memoryScoped =
      pendingDeleteKey.startsWith(LONG_TERM_MEMORY_ACTION_PREFIX) ||
      pendingDeleteKey.startsWith(MEMORY_CARD_DELETE_PREFIX) ||
      pendingDeleteKey.startsWith(ZEN_SESSION_MEMORY_DELETE_PREFIX);
    if (!memoryScoped) return;
    if (panel === "memories") return;
    disarmDelete();
  }, [panel, pendingDeleteKey, disarmDelete]);

  // Create mode: seed random color/glyph when the Bots panel opens only if
  // the compose form is still empty and the user hasn't picked a swatch/glyph
  // yet — so closing the panel mid-draft (or after a mis-tap) preserves work.
  useEffect(() => {
    if (panel !== "bots" || editingBotId) return;

    const draft = latestCreateBotDraftRef.current;
    if (
      createBotFormHasEnteredData(draft) ||
      createBotAppearanceTouchedRef.current
    ) {
      return;
    }

    setNewBotColor(randomHex(
      bots.map((bot) => bot.color?.trim() ?? "").filter((hex) => hex.length > 0)
    ));
    setNewBotGlyph(randomBotGlyph());
  }, [panel, editingBotId]);

  useEffect(() => {
    if (botProfileBuilderOpen && !editingBotId && !newBotName.trim()) {
      setBotProfileBuilderOpen(false);
    }
  }, [botProfileBuilderOpen, editingBotId, newBotName]);

	  useEffect(() => {
	    if (botAiParametersModalOpen && panel !== "bots") {
	      setBotAiParametersModalOpen(false);
	    }
	  }, [botAiParametersModalOpen, panel]);

  useEffect(() => {
    if (botAvatarCustomizerOpen && panel !== "bots") {
      closeBotAvatarCustomizer();
    }
  }, [botAvatarCustomizerOpen, closeBotAvatarCustomizer, panel]);

  // Close the color/glyph popover on any outside click or Escape. Only
  // one picker ever lives on screen (the top form in the Bots panel), so
  // a single `colorWheelOpen` flag is enough — no per-bot variant needed.
  useEffect(() => {
    if (!colorWheelOpen) return;
    function handlePointerDown(event: PointerEvent) {
      if (!isPrimaryPointerDismissal(event)) return;
      const target = event.target;
      // `Element` (not HTMLElement) is deliberate: a click inside the
      // glyph grid typically lands on an SVG <path>/<circle>, which is
      // an SVGElement — an Element subtype but NOT an HTMLElement. The
      // previous HTMLElement narrowing silently collapsed the popover
      // whenever the user hit an actual glyph icon (the whole point of
      // the grid), while clicks on gaps/padding worked fine.
      if (
        target instanceof Element &&
        target.closest("[data-color-affordance='true']")
      ) {
        return;
      }
      setColorWheelOpen(false);
    }
    function handleKey(event: KeyboardEvent) {
      if (event.key === "Escape") setColorWheelOpen(false);
    }
    document.addEventListener("pointerdown", handlePointerDown);
    document.addEventListener("keydown", handleKey);
    return () => {
      document.removeEventListener("pointerdown", handlePointerDown);
      document.removeEventListener("keydown", handleKey);
    };
  }, [colorWheelOpen]);

  async function deleteConversation(id: string) {
    setError(null);
    disarmDelete();
    // Optimistic update: drop the chat from the sidebar immediately and, if
    // it was open, clear the main pane. Roll everything back on failure.
    const previousConversations = conversations;
    const previousSelectedId = selectedId;
    const previousDetail = detail;
    const previousSessionOpinion = sessionOpinion;
    const previousBotOpinion = botOpinion;
    setConversations(list => list.filter(c => c.id !== id));
    if (selectedId === id) {
      setSelectedId(null);
      setDetail(null);
      setSessionOpinion(null);
      setBotOpinion(null);
    }
    try {
      await api(`/api/conversations/${id}`, { method: "DELETE" });
      // Resync from the server so updatedAt order / any server-side fixups
      // (e.g. race with another tab) are reflected.
      await refreshConversations();
    } catch (err) {
      setConversations(previousConversations);
      setSelectedId(previousSelectedId);
      setDetail(previousDetail);
      setSessionOpinion(previousSessionOpinion);
      setBotOpinion(previousBotOpinion);
      setError(err instanceof Error ? err.message : "Delete failed.");
    }
  }

  async function deleteConversationGroup(group: ConversationGroupSummary) {
    setError(null);
    disarmDelete();
    const previousConversations = conversations;
    const previousSelectedId = selectedId;
    const previousDetail = detail;
    const previousSessionOpinion = sessionOpinion;
    const previousBotOpinion = botOpinion;
    const previousUnreadIds = unreadConversationIds;
    const previousUnreadOrder = unreadConversationOrder;
    const previousExpandedGroupKey = expandedConversationGroupKey;
    const groupConversationIds = new Set(
      previousConversations
        .filter((conversation) => conversationGroupKey(conversation) === group.key)
        .map((conversation) => conversation.id)
    );
    const selectedGroupKey = previousDetail?.incognito
      ? null
      : previousDetail
        ? conversationGroupKey(previousDetail)
        : null;

    setConversations((list) =>
      list.filter((conversation) => conversationGroupKey(conversation) !== group.key)
    );
    setUnreadConversationIds((previous) => {
      const next = new Set(previous);
      for (const id of groupConversationIds) next.delete(id);
      return next;
    });
    setUnreadConversationOrder((previous) =>
      previous.filter((id) => !groupConversationIds.has(id))
    );
    setExpandedConversationGroupKey(null);
    if (selectedGroupKey === group.key) {
      setSelectedId(null);
      setDetail(null);
      setSessionOpinion(null);
      setBotOpinion(null);
    }

    const deleteConversationIds = group.conversations
      .filter(
        (conversation) =>
          !conversation.parentHubId || !groupConversationIds.has(conversation.parentHubId)
      )
      .map((conversation) => conversation.id);

    try {
      await Promise.all(
        deleteConversationIds.map((conversationId) =>
          api(`/api/conversations/${encodeURIComponent(conversationId)}`, {
            method: "DELETE",
          })
        )
      );
      await refreshConversations();
      await refreshOpenMemoryViews();
    } catch (err) {
      setConversations(previousConversations);
      setSelectedId(previousSelectedId);
      setDetail(previousDetail);
      setSessionOpinion(previousSessionOpinion);
      setBotOpinion(previousBotOpinion);
      setUnreadConversationIds(previousUnreadIds);
      setUnreadConversationOrder(previousUnreadOrder);
      setExpandedConversationGroupKey(previousExpandedGroupKey);
      setError(err instanceof Error ? err.message : "Delete conversation group failed.");
    }
  }

  // Bulk-clear every chat, triggered by the hold-to-delete-all gesture.
  // Optimistically wipes the sidebar + open pane so the UI matches the
  // user's intent instantly; on failure we roll back to the previous
  // snapshot and surface the error rather than silently recovering.
  async function deleteAllConversations() {
    setError(null);
    disarmDelete();
    const previousConversations = conversations;
    const previousSelectedId = selectedId;
    const previousDetail = detail;
    const previousSessionOpinion = sessionOpinion;
    const previousBotOpinion = botOpinion;
    // Nothing to clear — short-circuit rather than fire a no-op request.
    if (previousConversations.length === 0) return;
    setConversations([]);
    setSelectedId(null);
    setDetail(null);
    setSessionOpinion(null);
    setBotOpinion(null);
    try {
      await api("/api/conversations", { method: "DELETE" });
      await refreshConversations();
    } catch (err) {
      setConversations(previousConversations);
      setSelectedId(previousSelectedId);
      setDetail(previousDetail);
      setSessionOpinion(previousSessionOpinion);
      setBotOpinion(previousBotOpinion);
      setError(err instanceof Error ? err.message : "Delete all failed.");
    }
  }

  async function deleteAllCoffeeSessions() {
    setCoffeeError(null);
    setError(null);
    disarmDelete();
    const coffeeSessionIds = coffeeSessions.map((session) => session.id);
    if (coffeeSessionIds.length === 0) return;
    const coffeeSessionIdSet = new Set(coffeeSessionIds);
    try {
      await Promise.all(
        coffeeSessionIds.map((sessionId) =>
          api(`/api/conversations/${encodeURIComponent(sessionId)}`, { method: "DELETE" })
        )
      );
      if (
        (coffeeConversation && coffeeSessionIdSet.has(coffeeConversation.id)) ||
        (coffeeSelectedSessionId && coffeeSessionIdSet.has(coffeeSelectedSessionId))
      ) {
        resetCoffeeToPicker();
      }
      if (selectedId && coffeeSessionIdSet.has(selectedId)) {
        setSelectedId(null);
        setDetail(null);
        setSessionOpinion(null);
        setBotOpinion(null);
      }
      await refreshConversations();
    } catch (err) {
      setCoffeeError(err instanceof Error ? err.message : "Delete Coffee Sessions failed.");
      await refreshConversations().catch(() => undefined);
    }
  }

  async function deleteCoffeeGroupConfirmed(groupId: string) {
    setCoffeeError(null);
    setError(null);
    disarmDelete();
    try {
      await api(`/api/coffee/groups/${encodeURIComponent(groupId)}`, { method: "DELETE" });
      if (coffeeSelectedGroupId === groupId || coffeeConversation?.coffeeGroupId === groupId) {
        resetCoffeeToPicker();
      }
      await refreshCoffeeGroups();
      await refreshConversations();
    } catch (err) {
      setCoffeeError(err instanceof Error ? err.message : "Failed to delete Coffee Group.");
      await refreshCoffeeGroups().catch(() => undefined);
      await refreshConversations().catch(() => undefined);
    }
  }

  async function runConversationSweepActionConfirmed(): Promise<void> {
    if (sweepBusy) return;
    setError(null);
    setSweepBusy(true);
    try {
      const sweepResult = await api<ConversationSweepResponse>("/api/conversations/sweep", {
        method: "POST",
        body: JSON.stringify({
          mode: "sandbox",
        }),
      });
      const expiresAtMs = sweepResult.undoExpiresAt
        ? Date.parse(sweepResult.undoExpiresAt)
        : NaN;
      if (sweepResult.batchId && Number.isFinite(expiresAtMs)) {
        setSweepUndoToast({
          batchId: sweepResult.batchId,
          expiresAt: expiresAtMs,
        });
      } else {
        setSweepUndoToast(null);
      }
      const nextConversations = await refreshConversations();
      if (
        detailIdRef.current &&
        !nextConversations.some((conversation) => conversation.id === detailIdRef.current)
      ) {
        setSelectedId(null);
        setDetail(null);
        setSessionOpinion(null);
        setBotOpinion(null);
      }
      await refreshOpenMemoryViews();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Sweep action failed.");
    } finally {
      setSweepBusy(false);
    }
  }

  async function undoConversationSweepFromToast(batchId: string): Promise<void> {
    if (sweepBusy) return;
    setError(null);
    setSweepBusy(true);
    try {
      await api("/api/conversations/sweep/undo", {
        method: "POST",
        body: JSON.stringify({ batchId }),
      });
      setSweepUndoToast((current) => (current?.batchId === batchId ? null : current));
      const nextConversations = await refreshConversations();
      if (
        detailIdRef.current &&
        !nextConversations.some((conversation) => conversation.id === detailIdRef.current)
      ) {
        setSelectedId(null);
        setDetail(null);
        setSessionOpinion(null);
        setBotOpinion(null);
      }
      await refreshOpenMemoryViews();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Undo sweep failed.");
    } finally {
      setSweepBusy(false);
    }
  }

  function requestConversationSweepAction(): void {
    if (sweepBusy) return;
    if (!hasSweepEligibleConversations) return;
    setSweepConfirmOpen(true);
  }

  function buildRandomBotDraft(name = randomBotName(), lens = newBotAppliedLens) {
    const persona = buildRandomizerPersonaDraft({
      lens,
      fallbackName: name,
    });
    const faceStyle = persona.faceStyle ?? randomBotFaceStyle();
    const suggestedGlyph =
      persona.suggestedGlyph && isBotGlyphName(persona.suggestedGlyph)
        ? persona.suggestedGlyph
        : null;
    return {
      name: persona.name,
      profile: persona.profile,
      temperature: BOT_TEMPERATURE_DEFAULT,
      maxTokens: BOT_REPLY_LENGTH_DEFAULT_TOKENS,
      topP: BOT_TOP_P_DEFAULT,
      topK: BOT_TOP_K_DEFAULT,
      repetitionPenalty: BOT_REPETITION_PENALTY_DEFAULT,
      color: persona.suggestedColor ?? randomHex(
        bots.map((bot) => bot.color?.trim() ?? "").filter((hex) => hex.length > 0)
      ),
      glyph: suggestedGlyph ?? randomBotGlyph(),
      faceStyle,
      memorySeeds: persona.memories,
      lensId: persona.lensId,
      generationLabel: persona.generationLabel,
    };
  }

  function applyRandomBotDraft() {
    const draft = buildRandomBotDraft();
    setPanelNotice(null);
    setNewBotName(draft.name);
    setBotProfile(draft.profile);
    setNewBotSystemPrompt(serializeStoredBotPrompt(draft.profile, draft.name));
    setNewBotTemperature(draft.temperature);
    setNewBotMaxTokens(draft.maxTokens);
    setNewBotTopP(draft.topP);
    setNewBotTopK(draft.topK);
    setNewBotRepetitionPenalty(draft.repetitionPenalty);
    createBotAppearanceTouchedRef.current = true;
    setNewBotColor(draft.color);
    setNewBotGlyph(draft.glyph);
    setNewBotFaceEyesFont(draft.faceStyle.eyesFont);
    setNewBotFaceEyeCharacter(draft.faceStyle.eyeCharacter);
    setNewBotFaceMouthFont(draft.faceStyle.mouthFont);
    setNewBotFaceFontWeight(draft.faceStyle.weight);
    setNewBotFaceEyeScale(draft.faceStyle.eyeScale);
    setNewBotFaceEyeOffsetY(draft.faceStyle.eyeOffsetY);
    setNewBotProfilePictureImageId(null);
    setNewBotGeneratedMemorySeeds({
      lensId: draft.lensId,
      botName: draft.name,
      memories: draft.memorySeeds,
    });
    setColorWheelOpen(false);
    setBotProfileBuilderOpen(false);
    setBotProfileActivePage("purpose");
    setPanelNotice(
      draft.memorySeeds.length > 0
        ? `${draft.generationLabel}: ${draft.memorySeeds.length} memories ready to seed.`
        : draft.generationLabel
    );
  }

