  // Distribute random seed memories across every bot the user owns. Used
  // when the Memories panel is showing the All-memories view, so the
  // bubble cluster has something to chew on without having to wire each
  // bot up by hand.
  async function devToolsAddAllMemories() {
    const count = resolvedDevToolsBotQuantity;
    if (count <= 0) {
      setDevToolsMessage(randomDevToolsGhostMessage());
      return;
    }
    if (bots.length === 0) {
      setDevToolsMessage("Create at least one bot before seeding memories.");
      return;
    }

    setDevToolsMessage(null);
    setDevToolsBusy(true);
    try {
      const seedPayload: Record<string, unknown> = {
        count,
        source: devToolsMemorySeedSource,
      };
      if (devToolsMemorySeedSource !== "direct") {
        seedPayload.certainty = devToolsMemoryCertainty;
      }
      const result = await api<{ created?: number }>("/api/memories/dev-seed", {
        method: "POST",
        body: JSON.stringify(seedPayload),
      });
      await refreshMemories();
      const created = typeof result?.created === "number" ? result.created : count;
      setDevToolsMessage(
        created === 1
          ? `Added 1 ${devToolsMemorySeedSource} memory across bots.`
          : `Added ${created} ${devToolsMemorySeedSource} memories across ${bots.length} bots.`
      );
    } catch (err) {
      try { await refreshMemories(); } catch { /* best-effort refresh */ }
      setDevToolsMessage(
        err instanceof Error ? err.message : "Add memories failed."
      );
    } finally {
      setDevToolsBusy(false);
    }
  }

  // Seed memories for whichever bot is currently focused in the
  // Memories panel. Falls back to a clear status message if the panel
  // isn't on a specific bot — keeps the operator from accidentally
  // dumping memories on the wrong bot.
  async function devToolsAddBotMemories() {
    const targetBot = memoryPanelBot ?? activeBot;
    if (!targetBot?.id) {
      setDevToolsMessage("Open a bot's memories panel first to seed for that bot.");
      return;
    }
    const count = resolvedDevToolsBotQuantity;
    if (count <= 0) {
      setDevToolsMessage(randomDevToolsGhostMessage());
      return;
    }

    setDevToolsMessage(null);
    setDevToolsBusy(true);
    try {
      const seedPayload: Record<string, unknown> = {
        count,
        botId: targetBot.id,
        source: devToolsMemorySeedSource,
      };
      if (devToolsMemorySeedSource !== "direct") {
        seedPayload.certainty = devToolsMemoryCertainty;
      }
      const result = await api<{ created?: number }>("/api/memories/dev-seed", {
        method: "POST",
        body: JSON.stringify(seedPayload),
      });
      await refreshMemories();
      await refreshBotMemories(targetBot.id);
      const created = typeof result?.created === "number" ? result.created : count;
      setDevToolsMessage(
        created === 1
          ? `Added 1 ${devToolsMemorySeedSource} memory to ${targetBot.name}.`
          : `Added ${created} ${devToolsMemorySeedSource} memories to ${targetBot.name}.`
      );
    } catch (err) {
      try {
        await refreshMemories();
        await refreshBotMemories(targetBot.id);
      } catch { /* best-effort refresh */ }
      setDevToolsMessage(
        err instanceof Error ? err.message : "Add bot memories failed."
      );
    } finally {
      setDevToolsBusy(false);
    }
  }

  // Wipe every memory (global + bot-scoped) for the current user.
  // Server-side this is `DELETE /api/memories` — there's no per-bot
  // endpoint today, so this is intentionally a blunt instrument for
  // dev resets.
  async function devToolsClearAllMemories() {
    setDevToolsMessage(null);
    setDevToolsBusy(true);
    try {
      const result = await api<{ deleted?: number }>("/api/memories", {
        method: "DELETE",
      });
      await refreshMemories();
      if (memoryPanelBot?.id) {
        await refreshBotMemories(memoryPanelBot.id);
      }
      const deleted = typeof result?.deleted === "number" ? result.deleted : 0;
      setDevToolsMessage(
        deleted === 0
          ? "No memories to clear."
          : deleted === 1
            ? "Cleared 1 memory."
            : `Cleared ${deleted} memories.`
      );
    } catch (err) {
      try {
        await refreshMemories();
        if (memoryPanelBot?.id) {
          await refreshBotMemories(memoryPanelBot.id);
        }
      } catch { /* best-effort refresh */ }
      setDevToolsMessage(
        err instanceof Error ? err.message : "Clear memories failed."
      );
    } finally {
      setDevToolsBusy(false);
    }
  }

  async function devToolsSetBotDensityStage(stageId: PickerDensityStageId) {
    const liveViewportWidth =
      typeof window === "undefined" ? viewportWidth : window.innerWidth;
    const liveViewportHeight =
      typeof window === "undefined" ? viewportHeight : window.innerHeight;
    const stage = pickerDensityStageTargets(
      liveViewportWidth,
      liveViewportHeight
    ).find((target) => target.id === stageId);
    if (!stage) return;

    const targetCount = clampDevToolsBotQuantity(stage.targetCount);
    const delta = targetCount - bots.length;
    setDevToolsBotQuantity(targetCount);

    if (delta === 0) {
      setDevToolsMessage(
        `${stage.label} (${stage.description}) is already active at ${targetCount} bots for ${liveViewportWidth}x${liveViewportHeight}.`
      );
      return;
    }

    setDevToolsMessage(null);
    setDevToolsBusy(true);
    const previousBots = bots;
    const previousSelectedBotId = selectedBotId;

    try {
      if (delta > 0) {
        await devToolsCreateRandomBotBatch(delta);
        await refreshBots();
        setDevToolsMessage(
          `${stage.label} (${stage.description}) target: ${targetCount} bots for ${liveViewportWidth}x${liveViewportHeight}. Added ${delta} bots.`
        );
        return;
      }

      const deleteCount = Math.abs(delta);
      const optimisticDeletedIds = new Set(
        previousBots.slice(0, deleteCount).map((bot) => bot.id)
      );
      setBots((list) => list.filter((bot) => !optimisticDeletedIds.has(bot.id)));
      if (selectedBotId && optimisticDeletedIds.has(selectedBotId)) {
        setSelectedBotId(null);
      }

      const result = await api<{ deleted?: number }>(
        `/api/bots?limit=${deleteCount}`,
        { method: "DELETE" }
      );
      await refreshBots();
      const deleted = typeof result?.deleted === "number" ? result.deleted : deleteCount;
      setDevToolsMessage(
        `${stage.label} (${stage.description}) target: ${targetCount} bots for ${liveViewportWidth}x${liveViewportHeight}. Deleted ${deleted} bots.`
      );
    } catch (err) {
      setBots(previousBots);
      setSelectedBotId(previousSelectedBotId);
      try { await refreshBots(); } catch { /* best-effort refresh */ }
      setDevToolsMessage(
        err instanceof Error ? err.message : `Set ${stage.label} failed.`
      );
    } finally {
      setDevToolsBusy(false);
    }
  }

  // Load a specific bot into the top form for editing. The form itself
  // doesn't change shape — it just flips from "create" to "edit" mode
  // via editingBotId, and the name / prompt / color / glyph fields are
  // hydrated from the bot. Any other layered UI (armed delete pill, open
  // color picker) is collapsed so the user's attention rests squarely on
  // the one active form.
  //
  // We also stash the seeded values into editOriginalRef so the primary
  // button can ask "did the user change anything?" against the ACTUAL
  // starting state — this matters for bots with no stored color, where
  // we seed the picker with a random hex and would otherwise read as
  // "dirty" on the very first frame.
  //
  // Swapping targets (edit Bot A → click Bot B) just replaces the
  // hydrated values: the previous unsaved edits on Bot A are dropped,
  // which is one of the three advertised "cancel" paths (alongside the
  // panel backdrop and the × in the panel header).
  function startEditBot(bot: Bot) {
    disarmDelete();
    createBotAppearanceTouchedRef.current = false;
    setColorWheelOpen(false);
    const seededName = bot.name;
    const rawStoredPrompt = bot.system_prompt ?? "";
    const { fields: seededProfile } = parseStoredBotPrompt(rawStoredPrompt);
    const normalizedStoredPrompt = serializeStoredBotPrompt(seededProfile, seededName);
    setNewBotLensId("");
    setNewBotGeneratedMemorySeeds(null);
    setBotLensDropActive(false);
    const seededLocalModel = visibleConcreteModelChoiceForProvider(
      modelCatalog,
      settings,
      "local",
      bot.local_model ?? bot.model
    );
    const seededOnlineModel = visibleConcreteOnlineModelChoice(
      modelCatalog,
      settings,
      bot.online_model
    );
    const seededOnlineEnabled = bot.online_enabled !== 0;
    const seededDeleteProtected = isBotDeleteProtected(bot.id);
    const seededFlirtEnabled = bot.flirt_enabled === 1;
    const seededTemperature = normalizeBotTemperature(bot.temperature);
    const seededMaxTokens = normalizeBotMaxTokens(bot.max_tokens);
    const seededTopP = normalizeBotTopP(bot.top_p);
    const seededTopK = normalizeBotTopK(bot.top_k);
    const seededRepetitionPenalty = normalizeBotRepetitionPenalty(bot.repetition_penalty);
    const seededColor = bot.color?.trim() || randomHex(
      bots
        .filter((candidate) => candidate.id !== bot.id)
        .map((candidate) => candidate.color?.trim() ?? "")
        .filter((hex) => hex.length > 0)
    );
    const seededGlyph: BotGlyphName = isBotGlyphName(bot.glyph)
      ? bot.glyph
      : DEFAULT_BOT_GLYPH;
    const seededLocalImageModel = bot.local_image_model?.trim()
      ? bot.local_image_model.trim()
      : AUTO_MODEL_CHOICE;
    const seededOpenAiImageModel = bot.openai_image_model?.trim()
      ? bot.openai_image_model.trim()
      : AUTO_MODEL_CHOICE;
    const seededFaceStyle = resolveBotFaceStyleForBot(bot);
    const seededProfilePictureImageId = bot.profile_picture_image_id?.trim() || null;
    setNewBotName(seededName);
    setBotProfile(seededProfile);
    setNewBotSystemPrompt(rawStoredPrompt);
    setNewBotLocalModel(seededLocalModel);
    setNewBotOnlineModel(seededOnlineModel);
    setNewBotLocalImageModel(seededLocalImageModel);
    setNewBotOpenAiImageModel(seededOpenAiImageModel);
    setNewBotOnlineEnabled(seededOnlineEnabled);
    setNewBotDeleteProtected(seededDeleteProtected);
    setNewBotFlirtEnabled(seededFlirtEnabled);
    setNewBotTemperature(seededTemperature);
    setNewBotMaxTokens(seededMaxTokens);
    setNewBotTopP(seededTopP);
    setNewBotTopK(seededTopK);
    setNewBotRepetitionPenalty(seededRepetitionPenalty);
    setNewBotColor(seededColor);
    setNewBotGlyph(seededGlyph);
    setNewBotFaceEyesFont(seededFaceStyle.eyesFont);
    setNewBotFaceEyeCharacter(seededFaceStyle.eyeCharacter);
    setNewBotFaceMouthFont(seededFaceStyle.mouthFont);
    setNewBotFaceFontWeight(seededFaceStyle.weight);
    setNewBotFaceEyeScale(seededFaceStyle.eyeScale);
    setNewBotFaceEyeOffsetY(seededFaceStyle.eyeOffsetY);
	    setNewBotProfilePictureImageId(seededProfilePictureImageId);
	    setBotProfileBuilderOpen(false);
	    setBotAiParametersModalOpen(false);
    setBotProfileActivePage("purpose");
    setEditingBotId(bot.id);
    editOriginalRef.current = {
      name: seededName,
      prompt: normalizedStoredPrompt,
      rawPrompt: rawStoredPrompt,
      localModel: seededLocalModel,
      onlineModel: seededOnlineModel,
      localImageModel: seededLocalImageModel,
      openAiImageModel: seededOpenAiImageModel,
      onlineEnabled: seededOnlineEnabled,
      deleteProtected: seededDeleteProtected,
      flirtEnabled: seededFlirtEnabled,
      temperature: seededTemperature,
      maxTokens: seededMaxTokens,
      topP: seededTopP,
      topK: seededTopK,
      repetitionPenalty: seededRepetitionPenalty,
      color: seededColor,
      glyph: seededGlyph,
      faceEyesFont: seededFaceStyle.eyesFont,
      faceEyeCharacter: seededFaceStyle.eyeCharacter,
      faceMouthFont: seededFaceStyle.mouthFont,
      faceFontWeight: seededFaceStyle.weight,
      faceEyeScale: seededFaceStyle.eyeScale,
      faceEyeOffsetY: seededFaceStyle.eyeOffsetY,
      profilePictureImageId: seededProfilePictureImageId,
    };
    setPanelError(null);
  }

  function openActiveBotCustomizer() {
    if (!navbarCustomizerBot) return;
    openBotCustomizer(navbarCustomizerBot);
  }

  function openBotCustomizer(bot: Bot) {
    setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
    setSelectedBotPanelBotId(bot.id);
    setBotPanelView("customize");
    startEditBot(bot);
    openRightPanel("bots");
    setBotLibraryExpanded(false);
    setBotLibraryClosing(false);
  }

  function openBotSettings(bot: Bot) {
    setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
    setSelectedBotPanelBotId(bot.id);
    setBotPanelView("settings");
    startEditBot(bot);
    openRightPanel("bots");
    setBotLibraryExpanded(false);
    setBotLibraryClosing(false);
  }

  /** Leave single-bot edit mode and return to the bot library list (panel stays open). */
  function exitBotEditorToLibrary() {
    const returnBotId = selectedBotPanelBotId ?? editingBotId;
    disarmDelete();
    setPanelError(null);
    setPanelNotice(null);
    setPanelBotDeleteConfirm(null);
    setSelectedBotDeleteConfirm(null);
    setEditingBotId(null);
    resetBotForm();
    if (returnBotId && bots.some((bot) => bot.id === returnBotId)) {
      setSelectedBotPanelBotId(returnBotId);
      setBotPanelView("botHub");
      return;
    }
    setSelectedBotPanelBotId(null);
    setBotPanelView("library");
  }

  /** Opens the customizer focused on the Facts page so the Memories panel
   *  can hand off fact edits without duplicating the editor surface. */
  function openBotCustomizerFacts(bot: Bot) {
    openBotCustomizer(bot);
    setBotProfileActivePage("facts");
    setBotProfileBuilderOpen(true);
  }

  async function openMemoriesPanelForBot(bot: Bot) {
    setMemoryPanelScope("bot");
    setMemoryPanelBotId(bot.id);
    // Pre-select the PRISM family this bot belongs to so the bot-view
    // back button has a sensible destination (the family drill-down)
    // even when the user opened bot memories straight from the chat
    // header instead of drilling in through the directory.
    setMemoryPanelSelectedFamily(botPrismGroup(bot.color));
    setFocusedMemoryId(null);
    setBotMemories([]);
    setBotMemoryDossier(null);
    await runMemoryPanelLoad(`Loading ${bot.name} memories...`, async () => {
      await refreshBotMemories(bot.id);
    });
    openRightPanel("memories");
  }

  function openActiveBotMemoriesPanel() {
    if (!activeBot?.id) return;
    void openMemoriesPanelForBot(activeBot);
  }

  async function openDefaultMemoriesPanel() {
    setMemoryPanelScope("default");
    setMemoryPanelBotId(null);
    setMemoryPanelSelectedFamily(null);
    setFocusedMemoryId(null);
    setBotMemories([]);
    setBotMemoryDossier(null);
    await runMemoryPanelLoad(view === "chat" ? "Loading Prism memories..." : "Loading Prism shared memories...", async () => {
      await refreshPrismMemoryPanel();
    });
    openRightPanel("memories");
  }

  async function openAllMemoriesPanel() {
    setMemoryPanelScope("all");
    setMemoryPanelBotId(null);
    setMemoryPanelSelectedFamily(null);
    setFocusedMemoryId(null);
    setBotMemoryDossier(null);
    await runMemoryPanelLoad("Loading memory directories...", async () => {
      await refreshMemories();
    });
    openRightPanel("memories");
  }

  function openContextualMemoriesPanel() {
    const contextualBot = view === "chat" ? zenLivePresenceBot ?? zenPersonaBot ?? activeBot : activeBot;
    if (contextualBot) {
      void openMemoriesPanelForBot(contextualBot);
      return;
    }
    if (view === "chat") {
      void openDefaultMemoriesPanel();
      return;
    }
    void openAllMemoriesPanel();
  }

  function openConversationMemoriesPanel() {
    const targetBotId = detail?.hasAssistantReply
      ? detail.lastBotId
      : detail?.botId ?? selectedBotId ?? activeBot?.id ?? null;
    const targetBot = targetBotId
      ? bots.find((candidate) => candidate.id === targetBotId) ?? null
      : null;
    if (targetBot) {
      void openMemoriesPanelForBot(targetBot);
      return;
    }
    void openDefaultMemoriesPanel();
  }

  function handleHeaderHubClick() {
    pendingPrivateExitOnChatHomeRef.current = true;
    setSelectedId(null);
    setDetail(null);
    setSessionOpinion(null);
    setBotOpinion(null);
    setSelectedBotId(null);
    setSandboxGridSelectedBotId(null);
    setChatBotOverride(undefined);
    setZenPersonaBotId(null);
    setConversationStarterPrompts(null);
    navigateToView("chat");
  }

  function resetCurrentModeStartSurface(): void {
    setConversationStarterPrompts(null);
    if (view === "chat") {
      setChatAutoRestoreSuppressed(true);
      setForceNewConversationOnNextSend(true);
      setPendingZenSessionBreak(null);
      setPendingZenSessionResumeContext(null);
      persistZenSessionBreak(null);
      setZenSessionBreak(null);
      setSummaryDebug(null);
      setManualCompactionStatus(null);
      setZenWallpaperBusyConversationId(null);
      setZenWallpaperError(null);
      setZenAtmosphereLayerStates({});
      setZenAtmosphereGlobalParallaxY(0);
      setZenAtmosphereScrollBlendReadyKey(null);
    }
    setSelectedId(null);
    setDetail(null);
    setSelectedBotId(null);
    setChatBotOverride(undefined);
    setZenPersonaBotId(null);
    closeEmptyStateBotSearch();
    if (hueFilterCenter !== null) {
      startBotPickerReturnToAll();
    } else {
      setHueFilterCenter(null);
    }
    if (view === "chat") {
      setChatStartupSummary(DEFAULT_CHAT_STARTUP_SUMMARY);
      chatSummaryRefreshMarkerRef.current = null;
      rotateZenFallbackWallpaperSeed();
    }
  }

  function performShowAllBotsView(
    spotlightBotId: string | null = null,
    options: { suppressChatAutoRestore?: boolean } = {}
  ): void {
    const shouldAnimateSpotlightSwitch =
      spotlightBotId !== null &&
      view === "sandbox" &&
      !pendingReplyVisible &&
      activeConversationIsEmpty;
    if (shouldAnimateSpotlightSwitch) {
      setCanvasBotSwitchOverlayPhase("enter");
      canvasBotSwitchTransitionStartedAtRef.current = Date.now();
      pendingCanvasBotUnfoldRef.current = true;
      setCanvasBotSwitchTransitioning(true);
    }
    setSelectedId(null);
    setDetail(null);
    setChatBotOverride(undefined);
    setBotLibraryGroupFilterId(BOT_LIBRARY_GROUP_FILTER_ALL);
    setBotPanelGroup(BOT_LIBRARY_FILTER_ALL);
    closeEmptyStateBotSearch();
    startBotPickerReturnToAll();
    setSelectedBotId(spotlightBotId);
    if (view === "chat") {
      if (options.suppressChatAutoRestore) {
        setChatAutoRestoreSuppressed(true);
        setForceNewConversationOnNextSend(true);
      }
      setChatStartupSummary(null);
      chatSummaryRefreshMarkerRef.current = null;
      rotateZenFallbackWallpaperSeed();
      setZenPersonaBotId(spotlightBotId);
    }
    setSandboxGridSelectedBotId(spotlightBotId);
    setComposerPrimed(false);
    setConversationStarterPrompts(null);
    requestAnimationFrame(() => {
      const root = messagesScrollRef.current;
      if (!root) return;
      root.scrollTo({ top: root.scrollHeight, behavior: "smooth" });
    });
  }

  function handleChatHeaderWordmarkClick() {
    if (view !== "chat") return;
    if (showHeaderShowAllBotsLink) {
      performShowAllBotsView();
      return;
    }
    resetCurrentModeStartSurface();
  }

  function handleSandboxHeaderWordmarkClick() {
    if (view !== "sandbox") return;
    if (detail) {
      const spotlightBotId =
        chatBotOverride !== undefined
          ? chatBotOverride
          : (detail.lastBotId ?? detail.botId ?? selectedBotId ?? null);
      setConversationStarterPrompts(null);
      setSelectedId(null);
      setDetail(null);
      setSelectedBotId(spotlightBotId);
      setSandboxGridSelectedBotId(spotlightBotId);
      setChatBotOverride(undefined);
      closeEmptyStateBotSearch();
      if (hueFilterCenter !== null) {
        startBotPickerReturnToAll();
      } else {
        setHueFilterCenter(null);
      }
      return;
    }
    if (showHeaderShowAllBotsLink) {
      performShowAllBotsView();
      return;
    }
    if (!pendingReplyVisible && selectedBotId !== null) {
      resetCurrentModeStartSurface();
      return;
    }
    closeEmptyStateBotSearch();
    if (hueFilterCenter !== null) {
      startBotPickerReturnToAll();
    }
  }

  const memoryPanelBot = useMemo<Bot | null>(() => {
    if (memoryPanelScope !== "bot") return null;
    if (memoryPanelBotId) {
      const explicit = bots.find((bot) => bot.id === memoryPanelBotId) ?? null;
      if (explicit) return explicit;
    }
    return activeBot;
  }, [memoryPanelScope, memoryPanelBotId, bots, activeBot]);

  // Profile-owned facts for the active bot, displayed read-only in the
  // Memories panel. The Bot Customizer is the source of truth — editing
  // happens there via `openBotCustomizerFacts`, never in the Memories panel.
  const memoryPanelBotFacts = useMemo(() => {
    if (!memoryPanelBot) return [];
    const { fields } = parseStoredBotPrompt(memoryPanelBot.system_prompt ?? "");
    return listBotProfileFacts(fields.facts);
  }, [memoryPanelBot]);

  const activeBotMemoryDossier = useMemo(
    () =>
      memoryPanelBot?.id && botMemoryDossier?.botId === memoryPanelBot.id
        ? botMemoryDossier
        : null,
    [botMemoryDossier, memoryPanelBot?.id]
  );

  const botAboutYouMemories = activeBotMemoryDossier?.aboutYouMemories ?? [];
  const botMemoryDossierCurrentSessionOpinion = botMemoryDossierSessionOpinion(
    activeBotMemoryDossier,
    memoryPanelBot?.id
  );
  const botMemoryDossierSectionCounts = useMemo(
    () => resolveBotMemoryDossierSectionCounts(botMemories, botAboutYouMemories),
    [botAboutYouMemories, botMemories]
  );
  const botMemoryDossierStats = activeBotMemoryDossier
    ? botMemoryDossierStatItems(
        activeBotMemoryDossier.counts,
        botMemoryDossierSectionCounts
      )
    : [];

  const memoryPanelAccent = normalizeAccentForTheme(
    memoryPanelScope === "bot"
      ? memoryPanelBot?.color ?? PRISM_DEFAULT_ACCENT
      : PRISM_DEFAULT_ACCENT,
    resolvedTheme
  );
  const memoryPanelStyle = (() => {
    const base = deriveAccentStyle(memoryPanelAccent, resolvedTheme);
    const style: React.CSSProperties = {
      ["--memory-panel-color" as string]: memoryPanelAccent,
      ["--memory-panel-text" as string]: base["--accent-text" as keyof typeof base],
      ["--memory-panel-ink" as string]: base["--accent-ink" as keyof typeof base],
    };
    // Surface the active PRISM family's color so the left-edge bar in
    // the drill-down view can match the family being observed instead
    // of using the global rainbow gradient. We resolve the swatch from
    // PRISM_GROUPS directly to avoid forward-referencing
    // `selectedMemoryFamilyDirectory`, which is declared further down.
    if (memoryPanelScope === "all" && memoryPanelSelectedFamily) {
      const familyGroup = PRISM_GROUPS.find(
        (group) => group.id === memoryPanelSelectedFamily
      );
      if (familyGroup?.swatch) {
        (style as Record<string, string>)["--memory-family-bar-color"] =
          normalizeAccentForTheme(familyGroup.swatch, resolvedTheme);
      }
    }
    return style;
  })();

  const memoryFamilyDirectories = useMemo<MemoryFamilyDirectory[]>(() => {
    const memoryCounts: Record<PrismGroupId, number> = { p: 0, r: 0, i: 0, s: 0, m: 0 };
    const botCounts: Record<PrismGroupId, number> = { p: 0, r: 0, i: 0, s: 0, m: 0 };

    for (const bot of bots) {
      const family = botPrismGroup(bot.color);
      botCounts[family] += 1;
      memoryCounts[family] += directMemoryCountsByBotId[bot.id] ?? 0;
    }

    const itemCounts = PRISM_GROUPS.reduce<Record<PrismGroupId, number>>((acc, group) => {
      acc[group.id] = botCounts[group.id];
      return acc;
    }, { p: 0, r: 0, i: 0, s: 0, m: 0 });
    // Bubble size now reflects memory volume in the family (not bot count),
    // so a family with many bots but no memories collapses to the empty
    // size — visually matching the "No memories yet" drill-in state. The
    // numeric badge below still shows bot count for roster context.
    const maxCount = Math.max(defaultDirectMemoryCount, ...Object.values(memoryCounts));

    return PRISM_GROUPS.map((group, index) => {
      const itemCount = itemCounts[group.id];
      const memoryCount = memoryCounts[group.id];
      const size = ratioBubbleSize(memoryCount, maxCount);
      const slot = MEMORY_FAMILY_DIRECTORY_SLOTS[index % MEMORY_FAMILY_DIRECTORY_SLOTS.length];
      return {
        id: group.id,
        letter: group.letter,
        label: group.label,
        color: group.swatch,
        itemCount,
        memoryCount,
        innerBubbles: buildFamilyDirectoryBotInnerBubbles(group.id, itemCount, size),
        style: {
          ["--memory-family-x" as string]: `${slot[0]}%`,
          ["--memory-family-y" as string]: `${slot[1]}%`,
          ["--memory-family-size" as string]: `${size}px`,
          ["--memory-family-color" as string]: group.swatch,
          ["--memory-family-delay" as string]: `${(index * 0.18).toFixed(2)}s`,
        } as React.CSSProperties,
      };
    });
  }, [bots, defaultDirectMemoryCount, directMemoryCountsByBotId]);

  const defaultMemoryDirectoryStyle = useMemo(() => {
    // Share the family bubbles' memory-volume scale so the default Prism
    // orb is visually comparable (apples-to-apples) instead of being
    // measured against bot counts.
    const maxCount = Math.max(
      defaultDirectMemoryCount,
      ...memoryFamilyDirectories.map((family) => family.memoryCount)
    );
    const size = ratioBubbleSize(defaultDirectMemoryCount, maxCount);
    return {
      ["--memory-family-x" as string]: "50%",
      ["--memory-family-y" as string]: "50%",
      ["--memory-family-size" as string]: `${size}px`,
      ["--memory-family-color" as string]: PRISM_DEFAULT_ACCENT,
      ["--memory-family-delay" as string]: "0.42s",
    } as React.CSSProperties;
  }, [memoryFamilyDirectories, defaultDirectMemoryCount]);

  const showZenSessionMemoryInPrismPanel =
    view === "chat" && memoryPanelScope === "default";

  const selectedMemoryFamilyDirectory = useMemo(
    () => memoryFamilyDirectories.find((family) => family.id === memoryPanelSelectedFamily) ?? null,
    [memoryFamilyDirectories, memoryPanelSelectedFamily]
  );

  const selectedFamilyBotClusters = useMemo<MemoryFamilyBotCluster[]>(() => {
    if (!memoryPanelSelectedFamily) return [];
    const familyBots = bots.filter((bot) => botPrismGroup(bot.color) === memoryPanelSelectedFamily);
    // Family drill-down should show the full bot roster. Empty bots render as
    // small presence bubbles so the user can see who belongs here before they
    // have gathered memories.
    const baseClusters: Omit<MemoryFamilyBotCluster, "style" | "innerBubbles">[] = familyBots
      .map((bot) => ({
        id: bot.id,
        botId: bot.id,
        botName: bot.name,
        botGlyph: bot.glyph,
        color: normalizeAccentForTheme(bot.color ?? selectedMemoryFamilyDirectory?.color ?? PRISM_DEFAULT_ACCENT, resolvedTheme),
        memoryCount: directMemoryCountsByBotId[bot.id] ?? 0,
      }));

    const maxCount = Math.max(1, ...baseClusters.map((cluster) => cluster.memoryCount));
    const buildInnerBubbles = (
      clusterId: string,
      count: number,
      clusterSize: number
    ): MemoryClusterInnerBubble[] => {
      if (count <= 0) return [];
      // Inner motes are a direct preview of memories. Cap only at high counts
      // and scale dot count with the parent size so tiny clusters stay sparse.
      const sizeRatio = Math.max(0.12, clusterSize / MEMORY_RATIO_LARGE_MAX_SIZE);
      const density = Math.min(1, count / Math.max(1, maxCount));
      const bubbleCount = Math.max(1, Math.min(count, Math.round(20 * sizeRatio)));
      const placed: Array<{ x: number; y: number; radius: number }> = [];
      const bubbles: MemoryClusterInnerBubble[] = [];
      for (let i = 0; i < bubbleCount; i += 1) {
        // Larger memory families get slightly larger motes in addition to more
        // of them, so volume is readable at a glance.
        const size = 4.4 + density * 3.2 + ((i + count) % 3) * 1.15;
        const radius = size / 2;
        const minCenterRadius = 10 + radius;
        const maxCenterRadius = Math.max(minCenterRadius + 1, 32 - radius);
        let candidate: { x: number; y: number; radius: number } | null = null;
        for (let attempt = 0; attempt < 48; attempt += 1) {
          const angle = stableUnitValue(`${clusterId}:inner:${i}:a:${attempt}`) * Math.PI * 2;
          // Bias outward: most motes hug the outer ring while still permitting
          // occasional inner placements so the full orb stays alive.
          const radialSeed = stableUnitValue(`${clusterId}:inner:${i}:r:${attempt}`);
          const radialT = Math.pow(radialSeed, 0.36);
          const distance = minCenterRadius + radialT * (maxCenterRadius - minCenterRadius);
          const x = Math.cos(angle) * distance;
          const y = Math.sin(angle) * distance;
          const overlaps = placed.some((other) => {
            const dx = x - other.x;
            const dy = y - other.y;
            const minDistance = radius + other.radius + 2.2;
            return dx * dx + dy * dy < minDistance * minDistance;
          });
          if (!overlaps) {
            candidate = { x, y, radius };
            break;
          }
        }
        if (!candidate) {
          const fallbackAngle = ((i * 137.50776405) % 360) * (Math.PI / 180);
          const fallbackDistance = Math.min(maxCenterRadius, 14 + i * 1.7);
          candidate = {
            x: Math.cos(fallbackAngle) * fallbackDistance,
            y: Math.sin(fallbackAngle) * fallbackDistance,
            radius,
          };
        }
        placed.push(candidate);
        bubbles.push({
          id: `${clusterId}-inner-${i}`,
          style: {
            ["--memory-inner-x" as string]: `${candidate.x.toFixed(2)}px`,
            ["--memory-inner-y" as string]: `${candidate.y.toFixed(2)}px`,
            ["--memory-inner-size" as string]: `${size.toFixed(2)}px`,
            ["--memory-inner-dx" as string]: `${((stableUnitValue(`${clusterId}:inner:${i}:dx`) - 0.5) * 6).toFixed(2)}px`,
            ["--memory-inner-dy" as string]: `${((stableUnitValue(`${clusterId}:inner:${i}:dy`) - 0.5) * 6).toFixed(2)}px`,
            ["--memory-inner-duration" as string]: `${(2.8 + stableUnitValue(`${clusterId}:inner:${i}:dur`) * 2.2).toFixed(2)}s`,
            ["--memory-inner-delay" as string]: `${(i * 0.14).toFixed(2)}s`,
          } as React.CSSProperties,
        });
      }
      return bubbles;
    };

    const orderedClusters = baseClusters.sort(
      (a, b) => b.memoryCount - a.memoryCount || a.botName.localeCompare(b.botName)
    );
    const crowdScale = Math.min(1, Math.max(0.68, Math.sqrt(8 / Math.max(1, orderedClusters.length))));
    const placedClusters: Array<{ x: number; y: number; radiusPct: number }> = [];
    const pxToPct = 100 / 520;
    const placeWithoutOverlap = (
      clusterId: string,
      slotX: number,
      slotY: number,
      radiusPct: number
    ): { x: number; y: number } => {
      const minX = 8 + radiusPct;
      const maxX = 92 - radiusPct;
      const minY = 10 + radiusPct;
      const maxY = 90 - radiusPct;
      let bestCandidate = {
        x: Math.max(minX, Math.min(maxX, slotX)),
        y: Math.max(minY, Math.min(maxY, slotY)),
      };
      let bestPenalty = Number.POSITIVE_INFINITY;

      for (let attempt = 0; attempt < 140; attempt += 1) {
        const ring = Math.floor(attempt / 14);
        const step = 1.55 + radiusPct * 0.34;
        const angleSeed = stableUnitValue(`${clusterId}:layout:angle:${attempt}`);
        const angle = angleSeed * Math.PI * 2;
        const x = Math.max(minX, Math.min(maxX, slotX + Math.cos(angle) * ring * step));
        const y = Math.max(minY, Math.min(maxY, slotY + Math.sin(angle) * ring * step));
        let collision = false;
        let penalty = 0;
        for (const placed of placedClusters) {
          const dx = x - placed.x;
          const dy = y - placed.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const minDistance = radiusPct + placed.radiusPct + 0.9;
          if (distance < minDistance) {
            collision = true;
            penalty += minDistance - distance;
          }
        }
        if (!collision) return { x, y };
        if (penalty < bestPenalty) {
          bestPenalty = penalty;
          bestCandidate = { x, y };
        }
      }
      return bestCandidate;
    };

    // Pass 1: greedy placement. For each cluster, compute its size and a
    // best-effort non-overlapping initial position. The shrink-on-collision
    // heuristic is preserved as a cheap first pass, but with the new 72px
    // floor it rarely changes anything — the real overlap cleanup happens
    // in pass 2 below.
    const layouts: Array<{
      cluster: typeof orderedClusters[number];
      size: number;
      radiusPct: number;
    }> = [];
    for (let index = 0; index < orderedClusters.length; index += 1) {
      const cluster = orderedClusters[index];
      const slot = MEMORY_BUBBLE_CLOUD_SLOTS[index % MEMORY_BUBBLE_CLOUD_SLOTS.length];
      const slotLoop = Math.floor(index / MEMORY_BUBBLE_CLOUD_SLOTS.length);
      const baseSize = ratioBubbleSize(cluster.memoryCount, maxCount);
      let size = cluster.memoryCount === 0
        ? MEMORY_FAMILY_EMPTY_BOT_SIZE
        : Math.max(MEMORY_RATIO_MIN_SIZE, Math.round(baseSize * crowdScale));
      let radiusPct = (size / 2) * pxToPct;
      let baseX = slot[0] + ((slotLoop % 3) - 1) * 4 + (stableUnitValue(`${cluster.id}:x`) - 0.5) * 6;
      let baseY = slot[1] + ((slotLoop % 2) * 5 - 2.5) + (stableUnitValue(`${cluster.id}:y`) - 0.5) * 6;
      let placed = placeWithoutOverlap(cluster.id, baseX, baseY, radiusPct);

      for (let shrink = 0; shrink < 3; shrink += 1) {
        let collides = false;
        for (const existing of placedClusters) {
          const dx = placed.x - existing.x;
          const dy = placed.y - existing.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          if (distance < radiusPct + existing.radiusPct + 0.9) {
            collides = true;
            break;
          }
        }
        if (!collides) break;
        size = Math.max(MEMORY_RATIO_MIN_SIZE, Math.round(size * 0.9));
        radiusPct = (size / 2) * pxToPct;
        baseX = Math.max(8 + radiusPct, Math.min(92 - radiusPct, baseX));
        baseY = Math.max(10 + radiusPct, Math.min(90 - radiusPct, baseY));
        placed = placeWithoutOverlap(`${cluster.id}:shrink:${shrink}`, baseX, baseY, radiusPct);
      }

      placedClusters.push({ x: placed.x, y: placed.y, radiusPct });
      layouts.push({ cluster, size, radiusPct });
    }

    // Pass 2: relaxation. Iteratively push apart any overlapping pairs
    // along the connecting line until everyone settles. This catches the
    // cases where greedy placement landed two orbs in each other's space
    // because later orbs had to thread through gaps. The buffer (1.4%) is
    // wider than the placement buffer (0.9%) so neighbors get a small
    // breathing gap rather than touching edges.
    const RELAX_BUFFER_PCT = 1.4;
    const RELAX_ITERATIONS = 80;
    const RELAX_PUSH = 0.52;
    const RELAX_SETTLE_THRESHOLD = 0.04;
    for (let iter = 0; iter < RELAX_ITERATIONS; iter += 1) {
      let maxOverlap = 0;
      for (let i = 0; i < placedClusters.length; i += 1) {
        for (let j = i + 1; j < placedClusters.length; j += 1) {
          const a = placedClusters[i];
          const b = placedClusters[j];
          const dx = b.x - a.x;
          const dy = b.y - a.y;
          const rawDistance = Math.sqrt(dx * dx + dy * dy);
          const minDistance = a.radiusPct + b.radiusPct + RELAX_BUFFER_PCT;
          if (rawDistance < minDistance) {
            // Co-located orbs: pick a stable fallback direction so they
            // don't divide-by-zero into NaN positions.
            const distance = rawDistance > 0.0001 ? rawDistance : 0.0001;
            const nx = rawDistance > 0.0001 ? dx / distance : 1;
            const ny = rawDistance > 0.0001 ? dy / distance : 0;
            const overlap = minDistance - distance;
            maxOverlap = Math.max(maxOverlap, overlap);
            const push = overlap * RELAX_PUSH;
            a.x -= nx * push;
            a.y -= ny * push;
            b.x += nx * push;
            b.y += ny * push;
            a.x = Math.max(8 + a.radiusPct, Math.min(92 - a.radiusPct, a.x));
            a.y = Math.max(10 + a.radiusPct, Math.min(90 - a.radiusPct, a.y));
            b.x = Math.max(8 + b.radiusPct, Math.min(92 - b.radiusPct, b.x));
            b.y = Math.max(10 + b.radiusPct, Math.min(90 - b.radiusPct, b.y));
          }
        }
      }
      if (maxOverlap < RELAX_SETTLE_THRESHOLD) break;
    }

    return layouts.map(({ cluster, size }, index) => {
      const placed = placedClusters[index];
      const fill = mixHex(cluster.color, resolvedTheme === "dark" ? "#111114" : "#fbf3e6", 0.72);
      const border = ensureContrast(
        mixHex(cluster.color, resolvedTheme === "dark" ? "#ffffff" : "#20170f", resolvedTheme === "dark" ? 0.38 : 0.18),
        fill,
        2.1
      );
      const ink = pickReadableText(fill);
      return {
        ...cluster,
        style: {
          "--memory-bubble-size": `${size}px`,
          "--memory-cloud-x": `${placed.x.toFixed(2)}%`,
          "--memory-cloud-y": `${placed.y.toFixed(2)}%`,
          "--memory-bubble-color": fill,
          "--memory-bubble-border": border,
          "--memory-bubble-ink": ink,
          "--memory-bubble-source-color": cluster.color,
          "--memory-bubble-glow": cluster.color,
          "--memory-source-glyph-color": ensureContrast(cluster.color, fill, 2),
          "--memory-bubble-tilt": `${Math.round((stableUnitValue(`${cluster.id}:tilt`) - 0.5) * 8)}deg`,
          "--memory-bubble-z": `${20 + index}`,
        } as React.CSSProperties,
        innerBubbles: buildInnerBubbles(cluster.id, cluster.memoryCount, size),
      };
    });
  }, [
    memoryPanelSelectedFamily,
    bots,
    directMemoryCountsByBotId,
    selectedMemoryFamilyDirectory?.color,
    resolvedTheme,
  ]);

  const visibleMemoryBubbles = useMemo(() => {
    if (memoryPanelScope === "all") return [];
    const shortTermMemories = botMemories.filter((memory) => memoryTier(memory) === "short_term");
    const groupedByDedupKey = new Map<string, { representative: UserMemory; duplicateCount: number }>();
    for (const memory of shortTermMemories) {
      const dedupKey = normalizeMemoryBubbleDedupKey(memory.text);
      if (!dedupKey) continue;
      const currentGroup = groupedByDedupKey.get(dedupKey);
      if (!currentGroup) {
        groupedByDedupKey.set(dedupKey, {
          representative: memory,
          duplicateCount: 1,
        });
        continue;
      }
      const nextRepresentative = chooseMemoryBubbleRepresentative(currentGroup.representative, memory);
      groupedByDedupKey.set(dedupKey, {
        representative: nextRepresentative,
        duplicateCount: currentGroup.duplicateCount + 1,
      });
    }
    return Array.from(groupedByDedupKey.values()).map((group) =>
      applyDuplicateConfidenceBoost(group.representative, group.duplicateCount)
    );
  }, [memoryPanelScope, botMemories]);

  const visibleLongTermMemories = useMemo(
    () => {
      if (memoryPanelScope === "all") return [];
      const memories = botMemories.filter((memory) => memoryTier(memory) === "long_term");
      if (memoryPanelScope !== "bot") return memories;
      return [...memories, ...botAboutYouMemories];
    },
    [memoryPanelScope, botAboutYouMemories, botMemories]
  );
  const lastLearnedVisibleMemoryId = useMemo(() => {
    let lastLearnedMemory: UserMemory | null = null;
    let lastLearnedAtMs = Number.NEGATIVE_INFINITY;
    for (const memory of visibleMemoryBubbles) {
      const createdAtMs = Date.parse(memory.createdAt);
      const comparableCreatedAtMs = Number.isFinite(createdAtMs)
        ? createdAtMs
        : Number.NEGATIVE_INFINITY;
      if (
        !lastLearnedMemory ||
        comparableCreatedAtMs > lastLearnedAtMs ||
        (
          comparableCreatedAtMs === lastLearnedAtMs &&
          memory.id.localeCompare(lastLearnedMemory.id) > 0
        )
      ) {
        lastLearnedMemory = memory;
        lastLearnedAtMs = comparableCreatedAtMs;
      }
    }
    return lastLearnedMemory?.id ?? null;
  }, [visibleMemoryBubbles]);

  const longTermMemoryCounts = useMemo(() => {
    const counts: Record<MemoryCategory, number> = {
      general: 0,
      user: 0,
      bot_relation: 0,
    };
    for (const memory of visibleLongTermMemories) {
      counts[memoryLongTermCategory(memory)] += 1;
    }
    return counts;
  }, [visibleLongTermMemories]);

  const selectedLongTermMemories = useMemo(
    () => visibleLongTermMemories.filter((memory) => memoryLongTermCategory(memory) === longTermMemoryCategory),
    [longTermMemoryCategory, visibleLongTermMemories]
  );
  const memoryPanelWidthPx = Math.min(479, Math.max(0, viewportWidth - 32));
  const floatingMemoryCardAvailableStripPx = viewportWidth - memoryPanelWidthPx - 40;
  const showFloatingMemoryDetailCard = false;
  const memoryBubbleScopeKey = useMemo(() => {
    if (memoryPanelScope === "default") return "default";
    if (memoryPanelScope !== "bot") return null;
    if (!memoryPanelBot?.id) return null;
    return `bot:${memoryPanelBot.id}`;
  }, [memoryPanelScope, memoryPanelBot?.id]);
  const activeMemoryBubblePositions = useMemo(
    () => (memoryBubbleScopeKey ? memoryBubbleLayoutsByScope[memoryBubbleScopeKey] ?? {} : {}),
    [memoryBubbleLayoutsByScope, memoryBubbleScopeKey]
  );

  useEffect(() => {
    if (memoryBubbleLayoutsHydratedRef.current) return;
    const stored = readStoredMemoryBubbleLayouts();
    memoryBubbleLayoutsRef.current = stored;
    setMemoryBubbleLayoutsByScope(stored);
    memoryBubbleLayoutsHydratedRef.current = true;
  }, []);

  useEffect(() => {
    memoryBubbleLayoutsRef.current = memoryBubbleLayoutsByScope;
  }, [memoryBubbleLayoutsByScope]);

  const commitMemoryBubbleScopePositions = useCallback(
    (scopeKey: string, positions: Record<string, MemoryBubblePositionPct>) => {
      const nextLayouts = {
        ...memoryBubbleLayoutsRef.current,
        [scopeKey]: positions,
      };
      memoryBubbleLayoutsRef.current = nextLayouts;
      persistMemoryBubbleLayouts(nextLayouts);
      setMemoryBubbleLayoutsByScope(nextLayouts);
    },
    []
  );
  const commitMemoryBubbleScopePositionsRef = useRef(commitMemoryBubbleScopePositions);

  useEffect(() => {
    commitMemoryBubbleScopePositionsRef.current = commitMemoryBubbleScopePositions;
  }, [commitMemoryBubbleScopePositions]);

  useEffect(() => {
    if (!memoryBubbleLayoutsHydratedRef.current) return;
    if (!memoryBubbleLayoutsPersistReadyRef.current) {
      memoryBubbleLayoutsPersistReadyRef.current = true;
      if (Object.keys(memoryBubbleLayoutsByScope).length === 0) return;
    }
    persistMemoryBubbleLayouts(memoryBubbleLayoutsByScope);
  }, [memoryBubbleLayoutsByScope]);

  useEffect(() => {
    if (!memoryBubbleScopeKey) return;
    if (visibleMemoryBubbles.length === 0) return;
    const visibleIds = new Set(visibleMemoryBubbles.map((memory) => memory.id));
    setMemoryBubbleLayoutsByScope((current) => {
      const scoped = current[memoryBubbleScopeKey];
      if (!scoped) return current;
      let changed = false;
      const nextScoped: Record<string, MemoryBubblePositionPct> = {};
      for (const [memoryId, pos] of Object.entries(scoped)) {
        if (!visibleIds.has(memoryId)) {
          changed = true;
          continue;
        }
        nextScoped[memoryId] = pos;
      }
      if (!changed) return current;
      return { ...current, [memoryBubbleScopeKey]: nextScoped };
    });
  }, [memoryBubbleScopeKey, visibleMemoryBubbles]);

  useEffect(() => {
    if (!memoryBubbleScopeKey) return;
    const latest = readStoredMemoryBubbleLayouts();
    const latestScoped = latest[memoryBubbleScopeKey];
    if (!latestScoped) return;
    const currentScoped = memoryBubbleLayoutsRef.current[memoryBubbleScopeKey];
    if (JSON.stringify(currentScoped) === JSON.stringify(latestScoped)) return;
    const merged = {
      ...memoryBubbleLayoutsRef.current,
      [memoryBubbleScopeKey]: latestScoped,
    };
    memoryBubbleLayoutsRef.current = merged;
    setMemoryBubbleLayoutsByScope(merged);
  }, [memoryBubbleScopeKey]);

  const memoryBubbleLayoutById = useMemo(() => {
    const layoutById = new Map<string, { style: React.CSSProperties; uncertain: boolean }>();
    if (memoryPanelScope !== "bot" && memoryPanelScope !== "default") return layoutById;
    if (visibleMemoryBubbles.length === 0) return layoutById;

    const pxToPct = 100 / 520;
    const bounds = { minX: 6, maxX: 94, minY: 7, maxY: 93 };
    const shadePattern = [0.08, 0.16, 0.24, 0.12, 0.28, 0.2];
    const shadeTarget = resolvedTheme === "dark" ? "#ffffff" : "#000000";
    const placed: Array<{ x: number; y: number; radiusPct: number }> = [];

    const shortTermCount = visibleMemoryBubbles.length;
    const densityT = Math.max(0, Math.min(1, (shortTermCount - 6) / 30));
    // Dense short-term clouds need a steeper size falloff than the linear
    // curve so overlap reduces before we start hard-shrinking individual bubbles.
    const shortTermBubbleScale = Math.max(
      0.38,
      1 - densityT * 0.45 - densityT * densityT * 0.2
    );
    const bubbleMin = Math.round(MEMORY_BUBBLE_MIN_SIZE * shortTermBubbleScale);
    const bubbleMax = Math.round(MEMORY_BUBBLE_MAX_SIZE * shortTermBubbleScale);
    const uncertainMin = Math.round(MEMORY_UNCERTAIN_BUBBLE_MIN_SIZE * shortTermBubbleScale);
    const uncertainMax = Math.round(MEMORY_UNCERTAIN_BUBBLE_MAX_SIZE * shortTermBubbleScale);

    const entries = visibleMemoryBubbles.map((memory) => {
      const confidence = memoryBubbleSignalValue(memory);
      const uncertain = confidence <= MEMORY_UNCERTAIN_CONFIDENCE_MAX;
      const confidenceScale = uncertain
        ? Math.max(0, Math.min(1, confidence / MEMORY_UNCERTAIN_CONFIDENCE_MAX))
        : Math.max(0, Math.min(1, (confidence - MEMORY_UNCERTAIN_CONFIDENCE_MAX) / (1 - MEMORY_UNCERTAIN_CONFIDENCE_MAX)));
      // Use the visible confidence band, not raw 0..1, so normal direct
      // memories (roughly 0.62-0.92 in dev seeding) spread across the compact
      // size range instead of bunching into near-identical circles.
      const easedConfidence = Math.pow(confidenceScale, 0.82);
      const size = uncertain
        ? Math.round(uncertainMin + easedConfidence * (uncertainMax - uncertainMin))
        : Math.round(bubbleMin + easedConfidence * (bubbleMax - bubbleMin));
      return { memory, confidence, uncertain, size };
    });

    const sorted = [...entries].sort((a, b) => b.size - a.size);

    const findPlacement = (
      seed: string,
      anchorX: number,
      anchorY: number,
      radiusPct: number
    ): { x: number; y: number } => {
      const minX = bounds.minX + radiusPct;
      const maxX = bounds.maxX - radiusPct;
      const minY = bounds.minY + radiusPct;
      const maxY = bounds.maxY - radiusPct;

      let best = {
        x: Math.max(minX, Math.min(maxX, anchorX)),
        y: Math.max(minY, Math.min(maxY, anchorY)),
      };
      let bestPenalty = Number.POSITIVE_INFINITY;
      for (let attempt = 0; attempt < 220; attempt += 1) {
        const ring = Math.floor(attempt / 20);
        const step = 1.4 + radiusPct * 0.3;
        const angle = stableUnitValue(`${seed}:a:${attempt}`) * Math.PI * 2;
        const x = Math.max(minX, Math.min(maxX, anchorX + Math.cos(angle) * ring * step));
        const y = Math.max(minY, Math.min(maxY, anchorY + Math.sin(angle) * ring * step));

        let collision = false;
        let penalty = 0;
        for (const other of placed) {
          const dx = x - other.x;
          const dy = y - other.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const minDistance = radiusPct + other.radiusPct + 0.85;
          if (distance < minDistance) {
            collision = true;
            penalty += minDistance - distance;
          }
        }
        if (!collision) return { x, y };
        if (penalty < bestPenalty) {
          bestPenalty = penalty;
          best = { x, y };
        }
      }
      return best;
    };

    const layoutEntries: Array<{
      entry: (typeof sorted)[number];
      sortedIndex: number;
      size: number;
    }> = [];

    sorted.forEach((entry, sortedIndex) => {
      const slot = MEMORY_BUBBLE_CLOUD_SLOTS[sortedIndex % MEMORY_BUBBLE_CLOUD_SLOTS.length];
      const slotLoop = Math.floor(sortedIndex / MEMORY_BUBBLE_CLOUD_SLOTS.length);
      let size = entry.size;
      let radiusPct = (size / 2) * pxToPct;
      const saved = activeMemoryBubblePositions[entry.memory.id];
      let baseX = saved?.xPct ??
        (slot[0] + ((slotLoop % 3) - 1) * 4 + (stableUnitValue(`${entry.memory.id}:x`) - 0.5) * 7);
      let baseY = saved?.yPct ??
        (slot[1] + ((slotLoop % 2) * 5 - 2.5) + (stableUnitValue(`${entry.memory.id}:y`) - 0.5) * 7);
      let placedPoint = saved
        ? {
          x: Math.max(bounds.minX + radiusPct, Math.min(bounds.maxX - radiusPct, baseX)),
          y: Math.max(bounds.minY + radiusPct, Math.min(bounds.maxY - radiusPct, baseY)),
        }
        : findPlacement(entry.memory.id, baseX, baseY, radiusPct);

      for (let shrink = 0; shrink < 6; shrink += 1) {
        const overlaps = placed.some((other) => {
          const dx = placedPoint.x - other.x;
          const dy = placedPoint.y - other.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          return distance < radiusPct + other.radiusPct + 0.85;
        });
        if (!overlaps) break;
        size = Math.max(entry.uncertain ? uncertainMin : bubbleMin, Math.round(size * 0.9));
        radiusPct = (size / 2) * pxToPct;
        baseX = Math.max(bounds.minX + radiusPct, Math.min(bounds.maxX - radiusPct, baseX));
        baseY = Math.max(bounds.minY + radiusPct, Math.min(bounds.maxY - radiusPct, baseY));
        placedPoint = findPlacement(`${entry.memory.id}:shrink:${shrink}`, baseX, baseY, radiusPct);
      }

      placed.push({ x: placedPoint.x, y: placedPoint.y, radiusPct });
      layoutEntries.push({ entry, sortedIndex, size });
    });

    // A second relaxation pass keeps compact prose bubbles from piling up
    // after the greedy placement fallback chooses "least bad" positions.
    // The bubbles are small enough now that this can usually separate all
    // of them without additional shrinkage.
    const RELAX_BUFFER_PCT = 1.28;
    const RELAX_ITERATIONS = 100;
    const RELAX_PUSH = 0.56;
    const RELAX_SETTLE_THRESHOLD = 0.035;
    for (let iter = 0; iter < RELAX_ITERATIONS; iter += 1) {
      let maxOverlap = 0;
      for (let i = 0; i < placed.length; i += 1) {
        for (let j = i + 1; j < placed.length; j += 1) {
          const a = placed[i];
          const b = placed[j];
          const dx = b.x - a.x;
          const dy = b.y - a.y;
          const rawDistance = Math.sqrt(dx * dx + dy * dy);
          const minDistance = a.radiusPct + b.radiusPct + RELAX_BUFFER_PCT;
          if (rawDistance >= minDistance) continue;

          const distance = rawDistance > 0.0001 ? rawDistance : 0.0001;
          const nx = rawDistance > 0.0001 ? dx / distance : 1;
          const ny = rawDistance > 0.0001 ? dy / distance : 0;
          const overlap = minDistance - distance;
          maxOverlap = Math.max(maxOverlap, overlap);

          const push = overlap * RELAX_PUSH;
          a.x -= nx * push;
          a.y -= ny * push;
          b.x += nx * push;
          b.y += ny * push;

          a.x = Math.max(bounds.minX + a.radiusPct, Math.min(bounds.maxX - a.radiusPct, a.x));
          a.y = Math.max(bounds.minY + a.radiusPct, Math.min(bounds.maxY - a.radiusPct, a.y));
          b.x = Math.max(bounds.minX + b.radiusPct, Math.min(bounds.maxX - b.radiusPct, b.x));
          b.y = Math.max(bounds.minY + b.radiusPct, Math.min(bounds.maxY - b.radiusPct, b.y));
        }
      }
      if (maxOverlap < RELAX_SETTLE_THRESHOLD) break;
    }

    layoutEntries.forEach(({ entry, sortedIndex, size }, index) => {
      const placedPoint = placed[index];
      const bubbleAccent =
        memoryPanelScope === "default"
          ? resolvedTheme === "dark"
            ? "#cccccc"
            : "#444444"
          : memoryPanelAccent;
      const shade = mixHex(
        bubbleAccent,
        shadeTarget,
        shadePattern[sortedIndex % shadePattern.length]
      );
      const textLength = entry.memory.text.length;
      const fontDivisor = textLength > 92 ? 10.2 : textLength > 68 ? 9.2 : textLength > 46 ? 8.4 : 7.8;
      const fontSize = Math.max(11, Math.min(14, Math.round(size / fontDivisor)));
      const scoreInset = Math.max(6, Math.round(size * 0.16));
      const scoreMax = Math.max(12, size - scoreInset * 2);
      const scoreSize = Math.max(11, Math.min(scoreMax, Math.round(size * 0.22)));
      const lineCount = size >= Math.round(bubbleMax * 0.9) ? 4 : 3;
      layoutById.set(entry.memory.id, {
        uncertain: entry.uncertain,
        style: {
          "--memory-bubble-size": `${size}px`,
          "--memory-bubble-color": shade,
          "--memory-bubble-source-color": bubbleAccent,
          "--memory-bubble-ink": pickReadableText(shade),
          "--memory-bubble-font-size": `${fontSize}px`,
          "--memory-bubble-score-size": `${scoreSize}px`,
          "--memory-bubble-score-inset": `${scoreInset}px`,
          "--memory-bubble-line-count": lineCount,
          "--memory-cloud-x": `${placedPoint.x.toFixed(2)}%`,
          "--memory-cloud-y": `${placedPoint.y.toFixed(2)}%`,
          "--memory-bubble-tilt": `${Math.round((stableUnitValue(`${entry.memory.id}:tilt`) - 0.5) * 9)}deg`,
          "--memory-bubble-z": `${14 + sortedIndex}`,
        } as React.CSSProperties,
      });
    });
    return layoutById;
  }, [memoryPanelScope, visibleMemoryBubbles, memoryPanelAccent, resolvedTheme, activeMemoryBubblePositions]);

  const selectedVisibleMemory = useMemo(
    () => visibleMemoryBubbles.find((memory) => memory.id === focusedMemoryId) ?? null,
    [focusedMemoryId, visibleMemoryBubbles]
  );
  const memoryCardDeleteActionKey = selectedVisibleMemory
    ? memoryCardDeleteKey(selectedVisibleMemory.id)
    : null;
  const memoryCardDeleteArmed =
    memoryCardDeleteActionKey !== null &&
    pendingDeleteKey === memoryCardDeleteActionKey;

  useEffect(() => {
    if (pendingDeleteKey === null) return;
    if (!pendingDeleteKey.startsWith(MEMORY_CARD_DELETE_PREFIX)) return;
    const id = pendingDeleteKey.slice(MEMORY_CARD_DELETE_PREFIX.length);
    if (selectedVisibleMemory?.id === id) return;
    disarmDelete();
  }, [selectedVisibleMemory?.id, pendingDeleteKey, disarmDelete]);

  const memoryPanelSubjectLabel = useMemo(() => {
    const name = user?.displayName?.trim();
    return name && name.length > 0 ? name : "User";
  }, [user?.displayName]);
  const renderMemoryPanelText = useCallback(
    (memory: UserMemory) =>
      formatMemoryPanelText(memory.text, memoryPanelSubjectLabel, memoryCategory(memory)),
    [memoryPanelSubjectLabel]
  );
  const handleMemoryBubbleActivate = useCallback((memory: UserMemory) => {
    const actionKey = memoryCardDeleteKey(memory.id);
    if (pendingDeleteKey === actionKey) {
      disarmDelete();
      setMemoryBubbleDeletePrimedId(null);
      void deleteMemory(memory.id, memoryDeleteApiOptions(memory));
      return;
    }
    if (focusedMemoryId !== memory.id) {
      if (pendingDeleteKey?.startsWith(MEMORY_CARD_DELETE_PREFIX)) {
        disarmDelete();
      }
      setMemoryBubbleDeletePrimedId(null);
      setFocusedMemoryId(memory.id);
      return;
    }
    if (memoryBubbleDeletePrimedId === memory.id) {
      setMemoryBubbleDeletePrimedId(null);
      armDelete(actionKey);
      return;
    }
    setMemoryBubbleDeletePrimedId(memory.id);
  }, [
    armDelete,
    deleteMemory,
    disarmDelete,
    focusedMemoryId,
    memoryBubbleDeletePrimedId,
    pendingDeleteKey,
  ]);

  useEffect(() => {
    if (!memoryBubbleDeletePrimedId) return;
    if (focusedMemoryId === memoryBubbleDeletePrimedId) return;
    setMemoryBubbleDeletePrimedId(null);
  }, [focusedMemoryId, memoryBubbleDeletePrimedId]);

  const renderZenSessionMemorySection = (): React.JSX.Element => (
    <>
      <section
        className={styles.zenSessionPreviousCard}
        data-empty={zenPreviousContext ? undefined : "true"}
        aria-label="Previous context"
      >
        <div className={styles.zenSessionPreviousHeader}>
          <span>Previous Context</span>
          <strong>{zenPreviousContext ? zenPreviousContext.title : "Nothing stored yet"}</strong>
        </div>
        {zenPreviousContext ? (
          <>
            <p>{zenPreviousContext.summary}</p>
            <small>Non-expiring Zen context</small>
          </>
        ) : (
          <>
            <p>Once Zen has a compacted thread summary, it can appear here for later resuming.</p>
            <small>Not counted in the three checkpoint slots</small>
          </>
        )}
      </section>
      {zenSessionMemories.length > 0 ? (
        <ul className={styles.zenSessionMemoryList} aria-label="Session checkpoints">
          {zenSessionMemories.map((memory) => {
            const deleteKey = zenSessionMemoryDeleteKey(memory.id);
            const isArmed = pendingDeleteKey === deleteKey;
            return (
              <li key={memory.id} className={styles.zenSessionMemoryItem}>
                <div className={styles.zenSessionMemoryOrb} aria-hidden="true">
                  <span />
                </div>
                <div className={styles.zenSessionMemoryBody}>
                  <div className={styles.zenSessionMemoryMeta}>
                    <strong>{memory.title}</strong>
                    <span>{formatZenSessionMemoryExpiry(memory.expiresAt)}</span>
                  </div>
                  <p>{memory.text}</p>
                  {memory.trigger ? (
                    <small>Saved from: {memory.trigger}</small>
                  ) : null}
                </div>
                <button
                  type="button"
                  className={`${styles.zenSessionMemoryDelete} ${
                    isArmed ? styles.zenSessionMemoryDeleteArmed : ""
                  }`}
                  data-delete-affordance="true"
                  onClick={() => {
                    if (isArmed) {
                      void deleteZenSessionMemory(memory.id);
                      return;
                    }
                    armDelete(deleteKey);
                  }}
                  aria-label={
                    isArmed
                      ? `Confirm delete session memory: ${memory.title}`
                      : `Delete session memory: ${memory.title}`
                  }
                >
                  {isArmed ? "Confirm" : "Delete"}
                </button>
              </li>
            );
          })}
        </ul>
      ) : (
        <div className={styles.memoryEmptyState}>
          <strong>No session checkpoints</strong>
          <p>When you ask Zen to pause or finish something later, up to three short-lived checkpoints will appear here.</p>
        </div>
      )}
    </>
  );

  useEffect(() => {
    if (visibleLongTermMemories.length === 0) return;
    if (longTermMemoryCounts[longTermMemoryCategory] > 0) return;
    const nextCategory = LONG_TERM_MEMORY_CATEGORIES.find(
      (category) => longTermMemoryCounts[category.id] > 0
    )?.id;
    if (nextCategory) setLongTermMemoryCategory(nextCategory);
  }, [longTermMemoryCategory, longTermMemoryCounts, visibleLongTermMemories.length]);

  useEffect(() => {
    if (memoryPanelScope !== "bot" && memoryPanelScope !== "default") {
      setFocusedMemoryId(null);
      return;
    }
    if (focusedMemoryId && !visibleMemoryBubbles.some((memory) => memory.id === focusedMemoryId)) {
      setFocusedMemoryId(null);
    }
  }, [focusedMemoryId, memoryPanelScope, visibleMemoryBubbles]);

  const handleMemoryBubblePointerDown = useCallback(
    (event: React.PointerEvent<HTMLElement>, memoryId: string) => {
      if (focusedMemoryId) return;
      if (!memoryBubbleScopeKey) return;
      const cloud = memoryBubbleCloudRef.current;
      if (!cloud) return;
      if (
        event.pointerType === "mouse" &&
        event.button !== 0
      ) {
        return;
      }
      const cloudRect = cloud.getBoundingClientRect();
      if (cloudRect.width <= 0 || cloudRect.height <= 0) return;
      const positionsPx: Record<string, MemoryBubblePositionPx> = {};
      const radiiPx: Record<string, number> = {};
      for (const memory of visibleMemoryBubbles) {
        const layout = memoryBubbleLayoutById.get(memory.id);
        if (!layout) continue;
        const styleVars = layout.style as Record<string, string | number | undefined>;
        const xPctRaw = Number.parseFloat(String(styleVars["--memory-cloud-x"] ?? "50"));
        const yPctRaw = Number.parseFloat(String(styleVars["--memory-cloud-y"] ?? "50"));
        const sizeRaw = Number.parseFloat(String(styleVars["--memory-bubble-size"] ?? "72"));
        const xPct = Number.isFinite(xPctRaw) ? xPctRaw : 50;
        const yPct = Number.isFinite(yPctRaw) ? yPctRaw : 50;
        const sizePx = Number.isFinite(sizeRaw) ? sizeRaw : 72;
        positionsPx[memory.id] = {
          x: (xPct / 100) * cloudRect.width,
          y: (yPct / 100) * cloudRect.height,
        };
        radiiPx[memory.id] = Math.max(8, sizePx / 2);
      }
      const dragStart = positionsPx[memoryId];
      if (!dragStart) return;
      const originX = dragStart.x;
      const originY = dragStart.y;
      const nodeById: Record<string, HTMLElement> = {};
      for (const node of Array.from(cloud.querySelectorAll<HTMLElement>("[data-memory-physics-id]"))) {
        const id = node.dataset.memoryPhysicsId;
        if (!id?.startsWith("memory:")) continue;
        nodeById[id.slice("memory:".length)] = node;
      }

      const dragState: MemoryBubbleDragState = {
        pointerId: event.pointerId,
        memoryId,
        scopeKey: memoryBubbleScopeKey,
        startClientX: event.clientX,
        startClientY: event.clientY,
        cloudWidth: cloudRect.width,
        cloudHeight: cloudRect.height,
        boundsPx: {
          minX: cloudRect.width * 0.06,
          maxX: cloudRect.width * 0.94,
          minY: cloudRect.height * 0.07,
          maxY: cloudRect.height * 0.93,
        },
        positionsPx,
        radiiPx,
        nodeById,
        rafId: null,
        dragged: false,
      };

      const cleanup = () => {
        if (dragState.rafId !== null) {
          window.cancelAnimationFrame(dragState.rafId);
          dragState.rafId = null;
        }
        window.removeEventListener("pointermove", onMove);
        window.removeEventListener("pointerup", onUp);
        window.removeEventListener("pointercancel", onUp);
        memoryBubbleDragCleanupRef.current = null;
      };

      const paintPositions = () => {
        dragState.rafId = null;
        for (const [id, pos] of Object.entries(dragState.positionsPx)) {
          const node = dragState.nodeById[id];
          if (!node) continue;
          const xPct = Math.max(0, Math.min(100, (pos.x / dragState.cloudWidth) * 100));
          const yPct = Math.max(0, Math.min(100, (pos.y / dragState.cloudHeight) * 100));
          node.style.setProperty("--memory-cloud-x", `${xPct.toFixed(2)}%`);
          node.style.setProperty("--memory-cloud-y", `${yPct.toFixed(2)}%`);
        }
      };

      const onMove = (moveEvent: PointerEvent) => {
        if (!memoryBubbleDragStateRef.current) return;
        if (moveEvent.pointerId !== dragState.pointerId) return;
        const dx = moveEvent.clientX - dragState.startClientX;
        const dy = moveEvent.clientY - dragState.startClientY;
        if (!dragState.dragged && Math.hypot(dx, dy) >= 5) {
          dragState.dragged = true;
          setMemoryPhysicsActive(false);
        }
        if (!dragState.dragged) return;
        const active = dragState.positionsPx[dragState.memoryId];
        const radius = dragState.radiiPx[dragState.memoryId] ?? 16;
        active.x = originX + dx;
        active.y = originY + dy;
        active.x = Math.max(dragState.boundsPx.minX + radius, Math.min(dragState.boundsPx.maxX - radius, active.x));
        active.y = Math.max(dragState.boundsPx.minY + radius, Math.min(dragState.boundsPx.maxY - radius, active.y));
        resolveMemoryBubbleCollisionsPx(
          dragState.positionsPx,
          dragState.radiiPx,
          dragState.boundsPx,
          dragState.memoryId
        );
        if (dragState.rafId === null) {
          dragState.rafId = window.requestAnimationFrame(paintPositions);
        }
        setMemoryBubbleDraggingId(dragState.memoryId);
      };

      const onUp = (upEvent: PointerEvent) => {
        if (!memoryBubbleDragStateRef.current) return;
        if (upEvent.pointerId !== dragState.pointerId) return;
        if (dragState.dragged) {
          if (dragState.rafId !== null) {
            window.cancelAnimationFrame(dragState.rafId);
            dragState.rafId = null;
          }
          paintPositions();
          const finalPct = memoryBubblePositionsPxToPctMap(dragState);
          commitMemoryBubbleScopePositions(dragState.scopeKey, finalPct);
          memoryBubbleSuppressClickRef.current = dragState.memoryId;
          window.setTimeout(() => {
            if (memoryBubbleSuppressClickRef.current === dragState.memoryId) {
              memoryBubbleSuppressClickRef.current = null;
            }
          }, 120);
        }
        setMemoryBubbleDraggingId(null);
        memoryBubbleDragStateRef.current = null;
        cleanup();
      };

      if (memoryBubbleDragCleanupRef.current) {
        memoryBubbleDragCleanupRef.current();
      }
      memoryBubbleDragStateRef.current = dragState;
      memoryBubbleDragCleanupRef.current = cleanup;
      window.addEventListener("pointermove", onMove, { passive: true });
      window.addEventListener("pointerup", onUp);
      window.addEventListener("pointercancel", onUp);
    },
    [
      commitMemoryBubbleScopePositions,
      focusedMemoryId,
      memoryBubbleLayoutById,
      memoryBubbleScopeKey,
      visibleMemoryBubbles,
    ]
  );

  useEffect(() => {
    return () => {
      const dragState = memoryBubbleDragStateRef.current;
      if (dragState?.dragged) {
        commitMemoryBubbleScopePositionsRef.current(
          dragState.scopeKey,
          memoryBubblePositionsPxToPctMap(dragState)
        );
      }
      if (memoryBubbleDragCleanupRef.current) {
        memoryBubbleDragCleanupRef.current();
      }
    };
  }, []);

  useEffect(() => {
    if (!memoryBubbleScopeKey) {
      const dragState = memoryBubbleDragStateRef.current;
      if (dragState?.dragged) {
        commitMemoryBubbleScopePositions(
          dragState.scopeKey,
          memoryBubblePositionsPxToPctMap(dragState)
        );
      }
      setMemoryBubbleDraggingId(null);
      if (memoryBubbleDragCleanupRef.current) {
        memoryBubbleDragCleanupRef.current();
      }
      memoryBubbleDragStateRef.current = null;
      return;
    }
    const dragScope = memoryBubbleDragStateRef.current?.scopeKey;
    if (dragScope && dragScope !== memoryBubbleScopeKey) {
      const dragState = memoryBubbleDragStateRef.current;
      if (dragState?.dragged) {
        commitMemoryBubbleScopePositions(
          dragState.scopeKey,
          memoryBubblePositionsPxToPctMap(dragState)
        );
      }
      if (memoryBubbleDragCleanupRef.current) {
        memoryBubbleDragCleanupRef.current();
      }
      memoryBubbleDragStateRef.current = null;
      setMemoryBubbleDraggingId(null);
    }
  }, [commitMemoryBubbleScopePositions, memoryBubbleScopeKey]);

  useEffect(() => {
    if (panel !== "memories") return;
    const root = memoryPanelRef.current;
    if (!root) return;

    const startPhysics = () => {
      const cloud = root.querySelector<HTMLElement>(`.${styles.memoryBubbleCloud}`);
      if (!cloud) return;
      const nodes = Array.from(
        cloud.querySelectorAll<HTMLElement>("[data-memory-physics-id]")
      );
      if (nodes.length === 0) return;

      // Keep hit targets stable on narrow/drawer layouts. The one-shot
      // drawer inertia effect slightly moves absolute-positioned orb bounds,
      // which can cause pointer/default cursor flapping when a pointer sits
      // near an edge. Desktop keeps the physics flourish.
      if (viewportWidth <= SIDEBAR_DRAWER_BREAKPOINT) {
        for (const node of nodes) {
          node.style.setProperty("--memory-physics-x", "0px");
          node.style.setProperty("--memory-physics-y", "0px");
        }
        setMemoryPhysicsActive(false);
        return;
      }

      if (memoryPhysicsFrameRef.current !== null) {
        window.cancelAnimationFrame(memoryPhysicsFrameRef.current);
        memoryPhysicsFrameRef.current = null;
      }

      // Reset every body's offset BEFORE measuring so getBoundingClientRect
      // reads the true layout target — not a residual physics offset from a
      // previous open. Without this, reopening the drawer measures stale
      // positions and the next sim looks "pre-scripted" / glitchy.
      for (const node of nodes) {
        node.style.setProperty("--memory-physics-x", "0px");
        node.style.setProperty("--memory-physics-y", "0px");
      }

      const cloudRect = cloud.getBoundingClientRect();
      // Unified drawer-inertia impulse. The right-hand panel slides in from
      // off-screen-right and decelerates to a stop, so its children feel a
      // simultaneous leftward "g-force" — like passengers in a car that
      // just braked. Random per-item jitter (in BOTH starting offset and
      // velocity) keeps it from feeling like a synchronized swim while
      // preserving the shared direction cue.
      const drawerDirX = MEMORY_PHYSICS_DRAWER_DIR_X;
      const bodies = nodes.map((node) => {
        const rect = node.getBoundingClientRect();
        const radiusX = rect.width / 2;
        const radiusY = rect.height / 2;
        const targetX = rect.left - cloudRect.left + radiusX;
        const targetY = rect.top - cloudRect.top + radiusY;
        const minX = radiusX;
        const maxX = Math.max(minX, cloudRect.width - radiusX);
        const minY = radiusY;
        const maxY = Math.max(minY, cloudRect.height - radiusY);
        // Initial offset: tiny — items lag the drawer's leftward slide
        // by a few px so they appear to "still be catching up" the moment
        // the drawer parks.
        const offsetX = -drawerDirX * 6 + (Math.random() - 0.5) * MEMORY_PHYSICS_OFFSET_JITTER_X;
        const offsetY = (Math.random() - 0.5) * MEMORY_PHYSICS_OFFSET_JITTER_Y;
        // Velocity: the bulk leftward kick + symmetric jitter. Y component
        // has more spread because there's no shared vertical impulse, so
        // the noise reads as natural unsettling.
        const vx =
          drawerDirX * MEMORY_PHYSICS_DRAWER_VELOCITY +
          (Math.random() - 0.5) * MEMORY_PHYSICS_VELOCITY_JITTER_X;
        const vy = (Math.random() - 0.5) * MEMORY_PHYSICS_VELOCITY_JITTER_Y;
        node.style.setProperty("--memory-physics-x", `${offsetX.toFixed(2)}px`);
        node.style.setProperty("--memory-physics-y", `${offsetY.toFixed(2)}px`);
        return {
          node,
          targetX,
          targetY,
          minX,
          maxX,
          minY,
          maxY,
          x: offsetX,
          y: offsetY,
          vx,
          vy,
        };
      });

      setMemoryPhysicsActive(true);

      let lastTime: number | null = null;
      let elapsed = 0;
      const step = (time: number) => {
        if (lastTime === null) lastTime = time;
        const dt = Math.min(0.033, (time - lastTime) / 1000);
        lastTime = time;
        elapsed += dt * 1000;

        for (const body of bodies) {
          const ax = -body.x * MEMORY_PHYSICS_SPRING - body.vx * MEMORY_PHYSICS_DAMPING;
          const ay = -body.y * MEMORY_PHYSICS_SPRING - body.vy * MEMORY_PHYSICS_DAMPING;
          body.vx += ax * dt;
          body.vy += ay * dt;
          body.x += body.vx * dt;
          body.y += body.vy * dt;

          const worldX = body.targetX + body.x;
          const worldY = body.targetY + body.y;
          if (worldX < body.minX) {
            body.x = body.minX - body.targetX;
            body.vx = Math.abs(body.vx) * MEMORY_PHYSICS_WALL_RESTITUTION;
          }
          if (worldX > body.maxX) {
            body.x = body.maxX - body.targetX;
            body.vx = -Math.abs(body.vx) * MEMORY_PHYSICS_WALL_RESTITUTION;
          }
          if (worldY < body.minY) {
            body.y = body.minY - body.targetY;
            body.vy = Math.abs(body.vy) * MEMORY_PHYSICS_WALL_RESTITUTION;
          }
          if (worldY > body.maxY) {
            body.y = body.maxY - body.targetY;
            body.vy = -Math.abs(body.vy) * MEMORY_PHYSICS_WALL_RESTITUTION;
          }

          body.node.style.setProperty("--memory-physics-x", `${body.x.toFixed(2)}px`);
          body.node.style.setProperty("--memory-physics-y", `${body.y.toFixed(2)}px`);
        }

        const stillMoving = bodies.some((body) =>
          Math.abs(body.x) > 0.35 ||
          Math.abs(body.y) > 0.35 ||
          Math.abs(body.vx) > 2 ||
          Math.abs(body.vy) > 2
        );
        if (elapsed < MEMORY_PHYSICS_DURATION_MS && stillMoving) {
          memoryPhysicsFrameRef.current = window.requestAnimationFrame(step);
          return;
        }
        for (const body of bodies) {
          body.node.style.setProperty("--memory-physics-x", "0px");
          body.node.style.setProperty("--memory-physics-y", "0px");
        }
        memoryPhysicsFrameRef.current = null;
        setMemoryPhysicsActive(false);
      };

      memoryPhysicsFrameRef.current = window.requestAnimationFrame(step);
    };

    // Time the physics kick to coincide with the panelIn animation's
    // settle (the panel slides for ~200ms then snaps to rest). Firing
    // ~140ms in lets the drawer reach its decelerating tail before the
    // contents register the "stop", so the leftward overshoot reads as
    // a consequence of the drawer braking — not as the bubbles moving on
    // their own. Two rAFs after the timeout guarantee layout has stabilized
    // before we measure each node's target position.
    const startTimeout = window.setTimeout(() => {
      const firstFrame = window.requestAnimationFrame(() => {
        window.requestAnimationFrame(startPhysics);
      });
      memoryPhysicsFrameRef.current = firstFrame;
    }, 140);
    return () => {
      window.clearTimeout(startTimeout);
      if (memoryPhysicsFrameRef.current !== null) {
        window.cancelAnimationFrame(memoryPhysicsFrameRef.current);
        memoryPhysicsFrameRef.current = null;
      }
      setMemoryPhysicsActive(false);
    };
  }, [panel, memoryPhysicsSeed, viewportWidth]);

  function renderComposeUtilityActions(): React.JSX.Element {
    return (
      <div className={styles.composeUtilityActions}>
      </div>
    );
  }

  async function saveDefaultBot(): Promise<boolean> {
    const defaultBotName = "Default";
    const defaultBotProfile = parseStoredBotPrompt("").fields;
    const defaultBotPrompt = serializeStoredBotPrompt(defaultBotProfile, defaultBotName);
    const editPristine = editOriginalRef.current;
    const hasChanges = editPristine
      ? newBotFaceEyesFont !== editPristine.faceEyesFont
        || newBotFaceEyeCharacter !== editPristine.faceEyeCharacter
        || newBotFaceMouthFont !== editPristine.faceMouthFont
        || newBotFaceFontWeight !== editPristine.faceFontWeight
        || newBotFaceEyeScale !== editPristine.faceEyeScale
        || newBotFaceEyeOffsetY !== editPristine.faceEyeOffsetY
      : true;
    if (!hasChanges) return true;

    setBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      await withBotAvatarSaveTimeout((signal) =>
        api<{ defaultBot?: Record<string, unknown> }>("/api/default-bot", {
          method: "PATCH",
          body: JSON.stringify({
            faceEyesFont: newBotFaceEyesFont,
            faceEyeCharacter: newBotFaceEyeCharacter,
            faceMouthFont: newBotFaceMouthFont,
            faceFontWeight: newBotFaceFontWeight,
            faceEyeScale: newBotFaceEyeScale,
            faceEyeOffsetY: newBotFaceEyeOffsetY,
          }),
          signal,
        })
      );
      setNewBotName(defaultBotName);
      setBotProfile(defaultBotProfile);
      setNewBotSystemPrompt("");
      setNewBotTemperature(BOT_TEMPERATURE_DEFAULT);
      setNewBotMaxTokens(BOT_REPLY_LENGTH_DEFAULT_TOKENS);
      setNewBotTopP(BOT_TOP_P_DEFAULT);
      setNewBotTopK(BOT_TOP_K_DEFAULT);
      setNewBotRepetitionPenalty(BOT_REPETITION_PENALTY_DEFAULT);
      editOriginalRef.current = {
        name: defaultBotName,
        prompt: defaultBotPrompt,
        rawPrompt: "",
        localModel: DEFAULT_BOT_CHAT_MODEL_CHOICE,
        onlineModel: DEFAULT_BOT_CHAT_MODEL_CHOICE,
        localImageModel: AUTO_MODEL_CHOICE,
        openAiImageModel: AUTO_MODEL_CHOICE,
        onlineEnabled: true,
        deleteProtected: false,
        flirtEnabled: false,
        temperature: BOT_TEMPERATURE_DEFAULT,
        maxTokens: BOT_REPLY_LENGTH_DEFAULT_TOKENS,
        topP: BOT_TOP_P_DEFAULT,
        topK: BOT_TOP_K_DEFAULT,
        repetitionPenalty: BOT_REPETITION_PENALTY_DEFAULT,
        color: DEFAULT_PRISM_BOT_CUSTOMIZER_COLOR,
        glyph: DEFAULT_PRISM_BOT_GLYPH,
        faceEyesFont: newBotFaceEyesFont,
        faceEyeCharacter: newBotFaceEyeCharacter,
        faceMouthFont: newBotFaceMouthFont,
        faceFontWeight: newBotFaceFontWeight,
        faceEyeScale: newBotFaceEyeScale,
        faceEyeOffsetY: newBotFaceEyeOffsetY,
        profilePictureImageId: null,
      };
      setSettings((previous) =>
        previous
          ? {
              ...previous,
              prismDefaultBotName: "",
              prismDefaultBotSystemPrompt: "",
              prismDefaultBotColor: "",
              prismDefaultBotGlyph: "",
              prismDefaultBotFaceEyesFont: newBotFaceEyesFont,
              prismDefaultBotFaceEyeCharacter: newBotFaceEyeCharacter,
              prismDefaultBotFaceMouthFont: newBotFaceMouthFont,
              prismDefaultBotFaceFontWeight: newBotFaceFontWeight,
              prismDefaultBotFaceEyeScale: newBotFaceEyeScale,
              prismDefaultBotFaceEyeOffsetY: newBotFaceEyeOffsetY,
              prismDefaultBotTemperature: BOT_TEMPERATURE_DEFAULT,
              prismDefaultBotMaxTokens: BOT_REPLY_LENGTH_DEFAULT_TOKENS,
              prismDefaultBotTopP: BOT_TOP_P_DEFAULT,
              prismDefaultBotTopK: BOT_TOP_K_DEFAULT,
              prismDefaultBotRepetitionPenalty: BOT_REPETITION_PENALTY_DEFAULT,
            }
          : previous
      );
      setColorWheelOpen(false);
      setPanelNotice("Default avatar updated.");
      return true;
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Save failed.");
      return false;
    } finally {
      setBusy(false);
    }
  }

  async function flushBotAvatarAutosaveQueue(id: string): Promise<boolean> {
    if (!botAvatarAutosavePatchHasFields(botAvatarAutoSaveQueuedPatchRef.current)) {
      return botAvatarAutoSaveFlushPromiseRef.current ?? true;
    }
    if (botAvatarAutoSaveInFlightRef.current) {
      return botAvatarAutoSaveFlushPromiseRef.current ?? true;
    }

    const flushPromise = (async (): Promise<boolean> => {
      botAvatarAutoSaveInFlightRef.current = true;
      setBotAvatarAutoSaving(true);
      setBotAvatarAutoSavingBotId(id);
      setPanelError(null);
      setPanelNotice(null);

      let saved = true;
      try {
        while (botAvatarAutosavePatchHasFields(botAvatarAutoSaveQueuedPatchRef.current)) {
          const patch = botAvatarAutoSaveQueuedPatchRef.current;
          botAvatarAutoSaveQueuedPatchRef.current = {};
          const result = await withBotAvatarSaveTimeout((signal) =>
            api<{ bot?: Bot }>(`/api/bots/${encodeURIComponent(id)}`, {
              method: "PATCH",
              body: JSON.stringify(patch),
              signal,
            })
          );
          if (editOriginalRef.current) {
            editOriginalRef.current = applyBotAvatarAutosavePatchToSnapshot(
              editOriginalRef.current,
              patch
            );
          }
          if (result.bot?.id) {
            setBots((list) => replaceBotRowById(list, result.bot as Bot));
          } else {
            await refreshBots();
          }
        }
      } catch (err) {
        saved = false;
        setPanelError(err instanceof Error ? err.message : "Avatar save failed.");
      } finally {
        botAvatarAutoSaveInFlightRef.current = false;
      }

      if (botAvatarAutosavePatchHasFields(botAvatarAutoSaveQueuedPatchRef.current)) {
        const nextSaved = await flushBotAvatarAutosaveQueue(id);
        return saved && nextSaved;
      }

      setBotAvatarAutoSaving(false);
      setBotAvatarAutoSavingBotId(null);
      return saved;
    })();

    botAvatarAutoSaveFlushPromiseRef.current = flushPromise;
    try {
      return await flushPromise;
    } finally {
      if (botAvatarAutoSaveFlushPromiseRef.current === flushPromise) {
        botAvatarAutoSaveFlushPromiseRef.current = null;
      }
    }
  }

  function queueBotAvatarAutosave(id: string | null, patch: BotCustomizerSavePatch): void {
    if (!id) return;
    const normalizedPatch = normalizeBotAvatarAutosavePatch(patch);
    if (!botAvatarAutosavePatchHasFields(normalizedPatch)) return;
    botAvatarAutoSaveQueuedPatchRef.current = mergeBotAvatarAutosavePatch(
      botAvatarAutoSaveQueuedPatchRef.current,
      normalizedPatch
    );
    void flushBotAvatarAutosaveQueue(id);
  }

  async function saveBot(id: string): Promise<boolean> {
    const trimmedName = newBotName.trim();
    if (!trimmedName) return false;
    const avatarSaved = await flushBotAvatarAutosaveQueue(id);
    if (!avatarSaved) return false;
    const storedSystemPrompt = botEditorAdvancedMode
      ? newBotSystemPrompt
      : serializeStoredBotPrompt(botProfile, trimmedName);
    const localModel = visibleConcreteModelChoiceForProvider(
      modelCatalog,
      settings,
      "local",
      newBotLocalModel
    );
    const onlineModel = visibleConcreteOnlineModelChoice(
      modelCatalog,
      settings,
      newBotOnlineModel
    );
    const localImageStored =
      newBotLocalImageModel === AUTO_MODEL_CHOICE ? "" : newBotLocalImageModel.trim();
    const openaiImageStored =
      newBotOpenAiImageModel === AUTO_MODEL_CHOICE
        ? ""
        : normalizeOnlineImageModelPreference(newBotOpenAiImageModel);
    const patch = buildBotCustomizerSavePatch(
      {
        name: trimmedName,
        storedSystemPrompt,
        advancedMode: botEditorAdvancedMode,
        localModel,
        onlineModel,
        localModelForStorage: localModel === AUTO_MODEL_CHOICE ? "" : localModel,
        onlineModelForStorage: onlineModel === AUTO_MODEL_CHOICE ? "" : onlineModel,
        localImageModel: newBotLocalImageModel,
        openAiImageModel: newBotOpenAiImageModel,
        localImageModelForStorage: localImageStored,
        openAiImageModelForStorage: openaiImageStored,
        onlineEnabled: newBotOnlineEnabled,
        deleteProtected: newBotDeleteProtected,
        flirtEnabled: newBotFlirtEnabled,
        temperature: newBotTemperature,
        maxTokens: newBotMaxTokens,
        topP: newBotTopP,
        topK: newBotTopK,
        repetitionPenalty: newBotRepetitionPenalty,
        color: newBotColor,
        glyph: newBotGlyph,
        faceEyesFont: newBotFaceEyesFont,
        faceEyeCharacter: newBotFaceEyeCharacter,
        faceMouthFont: newBotFaceMouthFont,
        faceFontWeight: newBotFaceFontWeight,
        faceEyeScale: newBotFaceEyeScale,
        faceEyeOffsetY: newBotFaceEyeOffsetY,
        profilePictureImageId: newBotProfilePictureImageId,
      },
      editOriginalRef.current
    );
    if (Object.keys(patch).length === 0) return true;
    setBusy(true);
    setPanelError(null);
    setPanelNotice(null);
    try {
      const result = await withBotAvatarSaveTimeout((signal) =>
        api<{ bot?: Bot }>(`/api/bots/${id}`, {
          method: "PATCH",
          body: JSON.stringify(patch),
          signal,
        })
      );
      setNewBotLocalModel(localModel);
      setNewBotOnlineModel(onlineModel);
      setBotProfile(parseStoredBotPrompt(storedSystemPrompt).fields);
      setNewBotSystemPrompt(storedSystemPrompt);
      setNewBotLocalImageModel(
        localImageStored ? localImageStored : AUTO_MODEL_CHOICE
      );
      setNewBotOpenAiImageModel(
        openaiImageStored ? openaiImageStored : AUTO_MODEL_CHOICE
      );
      editOriginalRef.current = {
        name: trimmedName,
        prompt: serializeStoredBotPrompt(
          parseStoredBotPrompt(storedSystemPrompt).fields,
          trimmedName
        ),
        rawPrompt: storedSystemPrompt,
        localModel,
        onlineModel,
        localImageModel: localImageStored ? localImageStored : AUTO_MODEL_CHOICE,
        openAiImageModel: openaiImageStored ? openaiImageStored : AUTO_MODEL_CHOICE,
        onlineEnabled: newBotOnlineEnabled,
        deleteProtected: newBotDeleteProtected,
	        flirtEnabled: newBotFlirtEnabled,
	        temperature: newBotTemperature,
	        maxTokens: newBotMaxTokens,
	        topP: newBotTopP,
	        topK: newBotTopK,
	        repetitionPenalty: newBotRepetitionPenalty,
	        color: newBotColor,
        glyph: newBotGlyph,
        faceEyesFont: newBotFaceEyesFont,
        faceEyeCharacter: newBotFaceEyeCharacter,
        faceMouthFont: newBotFaceMouthFont,
        faceFontWeight: newBotFaceFontWeight,
        faceEyeScale: newBotFaceEyeScale,
        faceEyeOffsetY: newBotFaceEyeOffsetY,
        profilePictureImageId: newBotProfilePictureImageId,
      };
      setEditingBotId(id);
      setColorWheelOpen(false);
      const updatedBot = result.bot;
      if (updatedBot?.id) {
        setBots((list) => replaceBotRowById(list, updatedBot));
      } else {
        await refreshBots();
      }
      return true;
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Save failed.");
      return false;
    } finally {
      setBusy(false);
    }
  }

  // Single submit handler for the top form: routes to createBot or
  // saveBot based on whether editingBotId is set. Keeps the JSX's
  // onSubmit one line and lets mode-switch logic live next to the API
  // calls it dispatches to.
  async function submitBotForm(event: React.FormEvent) {
    event.preventDefault();
    if (!newBotName.trim()) return;
    if (botPanelView === "defaultCustomize") {
      await saveDefaultBot();
    } else if (editingBotId) {
      await saveBot(editingBotId);
    } else {
      await createBot();
    }
  }

  function registerImageGenAbort(scopeKey: string, controller: AbortController) {
    const m = imageGenAbortControllersByScopeRef.current;
    const list = m.get(scopeKey) ?? [];
    list.push(controller);
    m.set(scopeKey, list);
  }

  function unregisterImageGenAbort(scopeKey: string, controller: AbortController) {
    const m = imageGenAbortControllersByScopeRef.current;
    const list = m.get(scopeKey);
    if (!list) return;
    const idx = list.indexOf(controller);
    if (idx >= 0) list.splice(idx, 1);
    if (list.length === 0) m.delete(scopeKey);
    else m.set(scopeKey, list);
  }

  function abortImageGenForScope(scopeKey: string) {
    const list = imageGenAbortControllersByScopeRef.current.get(scopeKey);
    if (!list?.length) return;
    for (const ac of [...list]) {
      ac.abort();
    }
  }

  const visibleLocalImageCandidateOrEmpty = (
    modelId: string | null | undefined
  ): string => {
    if (modelChoiceIsDisabled(modelId)) return "";
    const visible = visibleLocalImageModelIdOrEmpty(modelId);
    return modelChoiceIsDisabled(visible) ? "" : visible;
  };

  const visibleOpenAiImageCandidateOrEmpty = (
    modelId: string | null | undefined
  ): ReturnType<typeof normalizeOpenAiImageModelId> | "" =>
    modelChoiceIsDisabled(modelId) ? "" : visibleOpenAiImageModelIdOrEmpty(modelId);

  function imagesPanelImageLaneDisabled(provider: "local" | "openai"): boolean {
    if (provider === "local") {
      return (
        modelChoiceIsDisabled(imageGenModelChoiceByProvider.local) ||
        modelChoiceIsDisabled(settings?.preferredLocalImageModel)
      );
    }
    return (
      modelChoiceIsDisabled(imageGenModelChoiceByProvider.openai) ||
      modelChoiceIsDisabled(settings?.preferredOpenAiImageModel)
    );
  }

  function zenWallpaperImageLaneDisabled(provider: "local" | "openai"): boolean {
    if (provider === "local") {
      return (
        modelChoiceIsDisabled(imageGenModelChoiceByProvider.local) ||
        modelChoiceIsDisabled(settings?.preferredZenWallpaperLocalImageModel) ||
        modelChoiceIsDisabled(settings?.preferredLocalImageModel)
      );
    }
    return (
      modelChoiceIsDisabled(imageGenModelChoiceByProvider.openai) ||
      modelChoiceIsDisabled(settings?.preferredZenWallpaperOpenAiImageModel) ||
      modelChoiceIsDisabled(settings?.preferredOpenAiImageModel)
    );
  }

  /** Effective image model for generate + overlay: picker (unless Auto) → bot → account Settings → catalog. */
  function resolveImagesPanelImageModels(): {
    localModelId: string;
    openAiModelId: string;
  } {
    const scopeBotId = imagesPanelAttributionBotId;
    const scopeBot =
      scopeBotId && bots.length > 0
        ? bots.find((b) => b.id === scopeBotId) ?? null
        : null;
    const botLocalImage = scopeBot?.local_image_model?.trim() ?? "";
    const botOpenAiImage = scopeBot?.openai_image_model?.trim() ?? "";

    const headerLocalRaw = imageGenModelChoiceByProvider.local?.trim() ?? "";
    const headerLocal =
      headerLocalRaw === AUTO_MODEL_CHOICE || headerLocalRaw === ""
        ? ""
        : visibleLocalImageCandidateOrEmpty(headerLocalRaw);

    const localModelId = imagesPanelImageLaneDisabled("local")
      ? ""
      : headerLocal ||
        visibleLocalImageCandidateOrEmpty(botLocalImage) ||
        visibleLocalImageCandidateOrEmpty(settings?.preferredLocalImageModel) ||
        localImageModelCatalogEntries[0]?.id ||
        "";

    const headerOpenAiRaw = imageGenModelChoiceByProvider.openai?.trim() ?? "";
    const headerOpenAi =
      headerOpenAiRaw === AUTO_MODEL_CHOICE || headerOpenAiRaw === ""
        ? ""
        : visibleOpenAiImageCandidateOrEmpty(headerOpenAiRaw);
    const fallbackOpenAiImageModel =
      visibleOpenAiImageCandidateOrEmpty(availableOpenAiImageModelCatalogEntries[0]?.id);

    const openAiModelCandidates: Array<
      ReturnType<typeof normalizeOpenAiImageModelId> | ""
    > = [
      ...(imagesPanelImageLaneDisabled("openai")
        ? []
        : [
            headerOpenAi,
            visibleOpenAiImageCandidateOrEmpty(botOpenAiImage),
            visibleOpenAiImageCandidateOrEmpty(settings?.preferredOpenAiImageModel),
            fallbackOpenAiImageModel,
          ]),
    ];
    const openAiModelId =
      openAiModelCandidates.find(
        (modelId): modelId is ReturnType<typeof normalizeOpenAiImageModelId> =>
          modelId !== ""
      ) ?? "";

    return { localModelId, openAiModelId };
  }

  function zenWallpaperImageGenerationAvailable(): boolean {
    if (!settings) return false;
    if (effectivePreferredProvider !== "local") {
      if (hasRunnableOnlineImageModels && !zenWallpaperImageLaneDisabled("openai")) {
        return true;
      }
      return localImageModelCatalogEntries.length > 0 && !zenWallpaperImageLaneDisabled("local");
    }
    return localImageModelCatalogEntries.length > 0 && !zenWallpaperImageLaneDisabled("local");
  }

  function resolveZenWallpaperImageModels(): {
    localModelId: string;
    openAiModelId: string;
  } {
    const conversationBot =
      detail?.botId && bots.length > 0
        ? bots.find((bot) => bot.id === detail.botId) ?? null
        : null;
    const botLocalImage = conversationBot?.local_image_model?.trim() ?? "";
    const botOpenAiImage = conversationBot?.openai_image_model?.trim() ?? "";
    const headerLocalRaw = imageGenModelChoiceByProvider.local?.trim() ?? "";
    const headerLocal =
      headerLocalRaw === AUTO_MODEL_CHOICE || headerLocalRaw === ""
        ? ""
        : visibleLocalImageCandidateOrEmpty(headerLocalRaw);
    const localModelId = zenWallpaperImageLaneDisabled("local")
      ? ""
      : headerLocal ||
        visibleLocalImageCandidateOrEmpty(botLocalImage) ||
        visibleLocalImageCandidateOrEmpty(settings?.preferredZenWallpaperLocalImageModel) ||
        visibleLocalImageCandidateOrEmpty(settings?.preferredLocalImageModel) ||
        localImageModelCatalogEntries[0]?.id ||
        "";
    const headerOpenAiRaw = imageGenModelChoiceByProvider.openai?.trim() ?? "";
    const headerOpenAi =
      headerOpenAiRaw === AUTO_MODEL_CHOICE || headerOpenAiRaw === ""
        ? ""
        : visibleOpenAiImageCandidateOrEmpty(headerOpenAiRaw);
    const fallbackOpenAiImageModel =
      visibleOpenAiImageCandidateOrEmpty(availableOpenAiImageModelCatalogEntries[0]?.id);
    const openAiModelCandidates: Array<
      ReturnType<typeof normalizeOpenAiImageModelId> | ""
    > = [
      ...(zenWallpaperImageLaneDisabled("openai")
        ? []
        : [
            headerOpenAi,
            visibleOpenAiImageCandidateOrEmpty(botOpenAiImage),
            visibleOpenAiImageCandidateOrEmpty(settings?.preferredZenWallpaperOpenAiImageModel),
            visibleOpenAiImageCandidateOrEmpty(settings?.preferredOpenAiImageModel),
            fallbackOpenAiImageModel,
          ]),
    ];
    const openAiModelId =
      openAiModelCandidates.find(
        (modelId): modelId is ReturnType<typeof normalizeOpenAiImageModelId> =>
          modelId !== ""
      ) ?? "";
    return { localModelId, openAiModelId };
  }

  function applyZenWallpaperMetadata(
    conversationId: string,
    zenWallpaper: ZenWallpaperMetadata
  ): void {
    setDetail((current) =>
      current?.id === conversationId
        ? { ...current, zenWallpaper }
        : current
    );
    setConversations((current) =>
      current.map((conversation) =>
        conversation.id === conversationId
          ? { ...conversation, zenWallpaper }
          : conversation
      )
    );
  }

  async function requestZenWallpaperUpdate(
    conversationId: string,
    options: {
      enabled: boolean;
      force?: boolean;
      generate?: boolean;
      promptOverride?: string;
    }
  ): Promise<void> {
    const generationRequested = options.generate !== false;
    if (options.enabled && generationRequested && !zenWallpaperImageGenerationAvailable()) {
      setZenWallpaperError("Configure an image generation model before enabling Atmosphere.");
      return;
    }
    if (zenWallpaperGenerationInFlightRef.current.has(conversationId)) return;
    zenWallpaperGenerationInFlightRef.current.add(conversationId);
    setZenWallpaperBusyConversationId(conversationId);
    setZenWallpaperError(null);
    try {
      const { localModelId, openAiModelId } = resolveZenWallpaperImageModels();
      const body: Record<string, unknown> = {
        enabled: options.enabled,
        force: options.force === true,
      };
      if (!generationRequested) {
        body.generate = false;
      }
      if (options.promptOverride?.trim()) {
        body.promptOverride = options.promptOverride.trim();
      }
      if (options.enabled && generationRequested) {
        if (effectivePreferredProvider === "local") {
        body.preferredProvider = "local";
        if (localModelId) body.model = localModelId;
      } else {
          if (zenWallpaperImageLaneDisabled("openai")) {
            if (zenWallpaperImageLaneDisabled("local") || !localModelId) {
              throw new Error("Online Atmosphere images are disabled. Choose a local image model before generating.");
            }
            body.preferredProvider = "local";
            body.model = localModelId;
          } else {
            body.preferredProvider = "openai";
            if (!openAiModelId) {
              throw new Error("Add an OpenAI key in Settings to enable online image models.");
            }
            body.model = openAiModelId;
          }
        }
      }
      const data = await api<ZenWallpaperApiResponse>(
        `/api/conversations/${encodeURIComponent(conversationId)}/zen-wallpaper`,
        {
          method: "POST",
          body: JSON.stringify(body),
        }
      );
      applyZenWallpaperMetadata(conversationId, data.zenWallpaper);
    } catch (err) {
      setZenWallpaperError(
        err instanceof Error ? err.message : "Zen Atmosphere failed to update."
      );
      setDetail((current) =>
        current?.id === conversationId && current.zenWallpaper
          ? {
              ...current,
              zenWallpaper: { ...current.zenWallpaper, status: "error" },
            }
          : current
      );
    } finally {
      zenWallpaperGenerationInFlightRef.current.delete(conversationId);
      setZenWallpaperBusyConversationId((current) =>
        current === conversationId ? null : current
      );
    }
  }

  useEffect(() => {
    const zenWallpaper = detail?.zenWallpaper;
    if (view !== "chat") return;
    if (!detail || detail.mode !== "zen") return;
    if (!zenWallpaper?.enabled) return;
    if (zenWallpaper.status === "generating" || zenWallpaper.status === "error") return;
    if (zenWallpaperBusyConversationId === detail.id) return;
    if (!zenWallpaperImageGenerationAvailable()) return;
    const messageCount = detail.messages.length;
    if (messageCount === 0) return;
    const suppressedMessageCount =
      zenWallpaperToggleAutoGenerationSuppressedRef.current.get(detail.id);
    if (suppressedMessageCount !== undefined) {
      if (suppressedMessageCount === messageCount) return;
      zenWallpaperToggleAutoGenerationSuppressedRef.current.delete(detail.id);
    }
    const lastGeneratedAt = zenWallpaper.generationMessageCount ?? 0;
    if (!zenWallpaper.imageId) {
      void requestZenWallpaperUpdate(detail.id, {
        enabled: true,
        force: true,
      });
      return;
    }
    const shouldGenerateForIdleEra =
      zenLatestIdleEraBoundaryMessageCount !== null &&
      lastGeneratedAt < zenLatestIdleEraBoundaryMessageCount;
    const preGenerationInterval = Math.max(
      1,
      zenWallpaperRegenMessageInterval - ZEN_WALLPAPER_PREGEN_MESSAGE_LEAD
    );
    const shouldPreGenerateNext =
      !shouldGenerateForIdleEra &&
      messageCount - lastGeneratedAt >= preGenerationInterval;
    if (!shouldGenerateForIdleEra && !shouldPreGenerateNext) return;
    void requestZenWallpaperUpdate(detail.id, {
      enabled: true,
      force: shouldGenerateForIdleEra || shouldPreGenerateNext,
    });
  }, [
    view,
    detail?.id,
    detail?.mode,
    detail?.messages.length,
    detail?.zenWallpaper?.enabled,
    detail?.zenWallpaper?.imageId,
    detail?.zenWallpaper?.generationMessageCount,
    detail?.zenWallpaper?.status,
    zenLatestIdleEraBoundaryMessageCount,
    zenWallpaperBusyConversationId,
    zenWallpaperRegenMessageInterval,
    settings,
    effectivePreferredProvider,
    localImageModelCatalogEntries.length,
    imageGenModelChoiceByProvider.local,
    imageGenModelChoiceByProvider.openai,
  ]);

  function addImageKeywordTags(kind: "positive" | "negative", draftTags: string[]): void {
    const normalizedDrafts = draftTags
      .map((tag) => tag.replace(/\s+/g, " ").trim())
      .filter((tag) => tag.length > 0);
    if (normalizedDrafts.length === 0) return;
    const scope = imagePanelScopeRef.current;
    const scopeBotId = scope === "bot" ? imagePanelBotIdRef.current : null;
    if (scopeBotId) {
      setImageBotKeywordsByBotId((current) => {
        const existing = current[scopeBotId] ?? EMPTY_SCOPED_IMAGE_KEYWORDS;
        const nextList =
          kind === "positive" ? existing.positive.slice() : existing.negative.slice();
        let changed = false;
        for (const draft of normalizedDrafts) {
          if (!nextList.some((tag) => tag.toLowerCase() === draft.toLowerCase())) {
            nextList.push(draft);
            changed = true;
          }
        }
        if (!changed) return current;
        return {
          ...current,
          [scopeBotId]:
            kind === "positive"
              ? { positive: nextList, negative: existing.negative }
              : { positive: existing.positive, negative: nextList },
        };
      });
    } else if (kind === "positive") {
      setImageGlobalPositiveKeywords((current) => {
        const next = current.slice();
        let changed = false;
        for (const draft of normalizedDrafts) {
          if (!next.some((tag) => tag.toLowerCase() === draft.toLowerCase())) {
            next.push(draft);
            changed = true;
          }
        }
        return changed ? next : current;
      });
    } else {
      setImageGlobalNegativeKeywords((current) => {
        const next = current.slice();
        let changed = false;
        for (const draft of normalizedDrafts) {
          if (!next.some((tag) => tag.toLowerCase() === draft.toLowerCase())) {
            next.push(draft);
            changed = true;
          }
        }
        return changed ? next : current;
      });
    }
  }

  function commitImageKeywordDraft(kind: "positive" | "negative"): void {
    const draftRaw =
      kind === "positive" ? imagePositiveKeywordDraft : imageNegativeKeywordDraft;
    const draft = draftRaw.replace(/\s+/g, " ").trim();
    if (!draft) return;
    addImageKeywordTags(kind, [draft]);
    if (kind === "positive") {
      setImagePositiveKeywordDraft("");
    } else {
      setImageNegativeKeywordDraft("");
    }
  }

  function applyImageKeywordPaste(kind: "positive" | "negative", text: string): void {
    if (!text.includes(",")) return;
    const chunks = text.split(",");
    const endsWithComma = /,\s*$/.test(text);
    const finalized = (endsWithComma ? chunks : chunks.slice(0, -1))
      .map((part) => part.replace(/\s+/g, " ").trim())
      .filter((part) => part.length > 0);
    if (finalized.length > 0) {
      addImageKeywordTags(kind, finalized);
    }
    const trailingDraft = endsWithComma
      ? ""
      : (chunks[chunks.length - 1] ?? "").replace(/\s+/g, " ").trim();
    if (kind === "positive") {
      setImagePositiveKeywordDraft(trailingDraft);
    } else {
      setImageNegativeKeywordDraft(trailingDraft);
    }
  }

  function removeImageKeywordTags(kind: "positive" | "negative", tagsToRemove: string[]): void {
    if (tagsToRemove.length === 0) return;
    const uniqueTagsToRemove = Array.from(new Set(tagsToRemove));
    const tagsToRemoveSet = new Set(uniqueTagsToRemove);
    setImageKeywordSelectedTagsByKind((current) => ({
      ...current,
      [kind]: current[kind].filter((tag) => !tagsToRemoveSet.has(tag)),
    }));
    const scope = imagePanelScopeRef.current;
    const scopeBotId = scope === "bot" ? imagePanelBotIdRef.current : null;
    if (scopeBotId) {
      setImageBotKeywordsByBotId((current) => {
        const existing = current[scopeBotId] ?? EMPTY_SCOPED_IMAGE_KEYWORDS;
        const next =
          kind === "positive"
            ? {
                positive: existing.positive.filter((item) => !tagsToRemoveSet.has(item)),
                negative: existing.negative,
              }
            : {
                positive: existing.positive,
                negative: existing.negative.filter((item) => !tagsToRemoveSet.has(item)),
              };
        if (next.positive.length === 0 && next.negative.length === 0) {
          const { [scopeBotId]: _removed, ...rest } = current;
          return rest;
        }
        return {
          ...current,
          [scopeBotId]: next,
        };
      });
      return;
    }
    if (kind === "positive") {
      setImageGlobalPositiveKeywords((current) =>
        current.filter((item) => !tagsToRemoveSet.has(item))
      );
      return;
    }
    setImageGlobalNegativeKeywords((current) =>
      current.filter((item) => !tagsToRemoveSet.has(item))
    );
  }

  function removeImageKeywordTag(kind: "positive" | "negative", tag: string): void {
    removeImageKeywordTags(kind, [tag]);
  }

  function setImageKeywordTagSelected(
    kind: "positive" | "negative",
    tag: string,
    selected: boolean
  ): void {
    setImageKeywordSelectedTagsByKind((current) => {
      const existing = current[kind];
      const hasTag = existing.includes(tag);
      if (selected && hasTag) return current;
      if (!selected && !hasTag) return current;
      return {
        ...current,
        [kind]: selected ? [...existing, tag] : existing.filter((item) => item !== tag),
      };
    });
  }

  function applyImageKeywordDragSelectionFromTarget(
    kind: "positive" | "negative",
    mode: ImageKeywordDragMode,
    target: EventTarget | null
  ): void {
    if (!(target instanceof Element)) return;
    const chipElement = target.closest<HTMLElement>("[data-image-keyword-tag]");
    const tag = chipElement?.dataset.imageKeywordTag;
    if (!tag) return;
    setImageKeywordTagSelected(kind, tag, mode === "add");
  }

  async function runImageGeneration(promptTrimmed: string) {
    if (!promptTrimmed) return;
    const scopeBotId = imagesPanelAttributionBotId;
    const scopeKey = imageGenerationScopeKey(
      sandboxImageGenConversationId,
      scopeBotId
    );
    const originScope = imagePanelScopeRef.current;
    const originScopeBotId = imagePanelBotIdRef.current;
    // Keep loading-overlay identity scoped to the Images panel itself:
    // - Bot scope: use that bot's chrome.
    // - All/general scopes: force Prism default (no persona tint), even if
    //   another chat bot is currently active elsewhere in the app.
    const originOverlayBotId = originScope === "bot" ? originScopeBotId : null;
    setImageGenUiContextByScope((prev) => ({
      ...prev,
      [scopeKey]: {
        overlayBotId: originOverlayBotId,
        provider: effectivePreferredProvider,
      },
    }));
    setImageGenInflightByScope((prev) => ({
      ...prev,
      [scopeKey]: (prev[scopeKey] ?? 0) + 1,
    }));
    setImageToolsDockHideCount((count) => count + 1);
    setPanelError(null);
    let succeeded = false;
    const abortController = new AbortController();
    registerImageGenAbort(scopeKey, abortController);
    try {
      const inferredVariant = inferImageGenerationVariantFromPrompt(promptTrimmed);
      const effectiveVariant = imageVariantManualOverride
        ? imageGenerationVariant
        : inferredVariant;
      const requestedSize = IMAGE_GENERATION_SIZE_BY_VARIANT[effectiveVariant];
      if (!imageVariantManualOverride && effectiveVariant !== imageGenerationVariant) {
        setImageGenerationVariant(effectiveVariant);
      }
      const body: Record<string, unknown> = {
        prompt: composeImagePromptWithKeywordDirectives({
          basePrompt: promptTrimmed,
          positiveKeywords: imagePositiveKeywords,
          negativeKeywords: imageNegativeKeywords,
        }),
        size: requestedSize,
      };
      if (sandboxImageGenConversationId) {
        body.conversationId = sandboxImageGenConversationId;
      }
      if (scopeBotId) {
        body.botId = scopeBotId;
      }
      const { localModelId, openAiModelId } = resolveImagesPanelImageModels();
      // Image generation has only LOCAL/OpenAI lanes. Anthropic chat mode maps
      // to the OpenAI image lane while keeping chat replies on Anthropic.
      // Uses the EFFECTIVE provider so the body honors the offline-only lock
      // when the active chat bot is protected.
      if (effectivePreferredProvider !== "local") {
        if (imagesPanelImageLaneDisabled("openai")) {
          if (imagesPanelImageLaneDisabled("local") || !localModelId) {
            throw new Error("Online image generation is disabled. Choose a local image model before generating.");
          }
          body.preferredProvider = "local";
          body.model = localModelId;
        } else {
          body.preferredProvider = "openai";
          if (!openAiModelId) {
            throw new Error("Add an OpenAI key in Settings to enable online image models.");
          }
          body.model = openAiModelId;
        }
      } else if (settings) {
        if (imagesPanelImageLaneDisabled("local")) {
          throw new Error("Local image generation is disabled. Choose a local image model before generating.");
        }
        body.preferredProvider = "local";
        if (localModelId) {
          body.model = localModelId;
        }
      }
      const data = await api<ImageGenerateApiResponse>("/api/images/generate", {
        method: "POST",
        body: JSON.stringify(body),
        signal: abortController.signal,
      });
      const imageId = data.image?.id ?? "";
      const privateImageForRun = imagePrivateMode || (view === "chat" && privateChatActive);
      if (privateImageForRun && imageId) {
        setImagePrivateGeneratedIds((current) =>
          current.includes(imageId) ? current : [...current, imageId]
        );
      }
      await refreshImageBotDirectorySnapshot();
      const p = panelRef.current;
      const scope = imagePanelScopeRef.current;
      const panelBot = imagePanelBotIdRef.current;
      let suppressNotice = false;
      if (p === "images") {
        if (scope === "all") {
          await (view === "chat" ? refreshImagesChatGallery() : refreshImages(null));
          suppressNotice = true;
        } else if (scope === "general") {
          await refreshImages("general");
          suppressNotice = true;
        } else if (
          scope === "bot" &&
          panelBot &&
          scopeBotId &&
          panelBot === scopeBotId
        ) {
          await refreshImages(panelBot);
          suppressNotice = true;
        }
      }
      if (suppressNotice) {
        setImageReadyNotice(null);
      } else if (imageId) {
        const rawAccent =
          PRISM_NOTICE_PALETTE[
            Math.floor(Math.random() * PRISM_NOTICE_PALETTE.length)
          ];
        const accentHex = normalizeAccentForTheme(
          rawAccent,
          resolvedThemeRef.current
        );
        setImageReadyNotice((prev) => ({
          items: [...(prev?.items ?? []), { botId: scopeBotId, imageId }],
          accentHex: prev?.accentHex ?? accentHex,
        }));
      }
      succeeded = true;
    } catch (err) {
      if (isAbortLikeError(err)) {
        // User cancelled; overlay clears via `finally` — no error line.
      } else if (panelRef.current === "images") {
        setPanelError(err instanceof Error ? err.message : "Image gen failed.");
      } else {
        console.warn(
          "[prism] Image generation failed while Images panel was not focused:",
          err
        );
      }
    } finally {
      unregisterImageGenAbort(scopeKey, abortController);
      setImageToolsDockHideCount((count) => (count <= 0 ? 0 : count - 1));
      setImageGenInflightByScope((prev) => {
        const next = { ...prev };
        const cur = next[scopeKey] ?? 1;
        const n = cur - 1;
        if (n <= 0) {
          delete next[scopeKey];
          if (succeeded) {
            queueMicrotask(() => {
              setImagePrompt("");
              setImageVariantManualOverride(false);
              setImageGenerationVariant("letterbox");
            });
          }
        } else {
          next[scopeKey] = n;
        }
        return next;
      });
    }
  }

  async function generateImg(e: React.FormEvent) {
    e.preventDefault();
    if (view === "chat" && privateChatActive && !imagePrivateMode) {
      setImagePrivateMode(true);
    }
    await runImageGeneration(imagePrompt.trim());
  }

  async function randomizeImagePrompt() {
    setImageRandomPromptBusy(true);
    setPanelError(null);
    try {
      const scopeBotId = imagesPanelAttributionBotId;
      const body: Record<string, unknown> = {};
      if (scopeBotId) {
        body.botId = scopeBotId;
      }
      const data = await api<{ ok: boolean; prompt?: string }>(
        "/api/images/random-prompt",
        {
          method: "POST",
          body: JSON.stringify(body),
        }
      );
      const p = data.prompt?.trim();
      if (p) {
        setImagePrompt(p);
        setImageVariantManualOverride(false);
        setImageGenerationVariant(inferImageGenerationVariantFromPrompt(p));
      } else {
        setPanelError(
          "Could not generate a prompt. Check that Ollama is running and the auxiliary model is available."
        );
      }
    } catch (err) {
      setPanelError(err instanceof Error ? err.message : "Random prompt failed.");
    } finally {
      setImageRandomPromptBusy(false);
    }
  }

  const secondaryOllamaUiStatus: SecondaryOllamaUiStatus =
    !secondaryOllamaDraftHost
      ? "unconfigured"
      : secondaryOllamaStatusChecking
          ? "checking"
          : secondaryOllamaStatus?.reachable
            ? secondaryOllamaStatus.modelCount > 0
              ? "connected"
              : "empty"
            : "error";
  const secondaryOllamaStatusText =
    secondaryOllamaUiStatus === "connected"
      ? `Connected · ${secondaryOllamaStatus?.modelCount ?? 0} model${
          secondaryOllamaStatus?.modelCount === 1 ? "" : "s"
        }`
      : secondaryOllamaUiStatus === "empty"
        ? "Connected · no models"
        : secondaryOllamaUiStatus === "checking"
          ? "Checking..."
          : secondaryOllamaUiStatus === "error"
              ? "Not reachable"
              : "Optional";
  const dualOllamaWorkloadText =
    dualOllamaWorkloadStatus?.enabled
      ? `Dual routing ready · ${dualOllamaWorkloadStatus.sharedModelIds.length} paired model${
          dualOllamaWorkloadStatus.sharedModelIds.length === 1 ? "" : "s"
        }`
      : dualOllamaWorkloadStatus?.reason === "model_mismatch"
        ? "Dual routing paused · no shared models detected"
        : dualOllamaWorkloadStatus?.reason === "empty_catalog"
          ? "Dual routing paused · one host has no detected models"
          : dualOllamaWorkloadStatus?.reason === "secondary_unreachable"
            ? "Dual routing paused · paired host is not reachable"
            : dualOllamaWorkloadStatus?.reason === "primary_unreachable"
              ? "Dual routing paused · primary host is not reachable"
              : "Dual routing waits for a paired Ollama host";

  const comfyUiUiStatus: SecondaryOllamaUiStatus =
    !comfyUiDraftHost
      ? "unconfigured"
      : comfyUiStatusChecking
          ? "checking"
          : comfyUiStatus?.reachable
            ? comfyUiStatus.modelCount > 0
              ? "connected"
              : "empty"
            : "error";
  const comfyUiStatusText =
    comfyUiUiStatus === "connected"
      ? `Connected · ${comfyUiStatus?.modelCount ?? 0} workflow${
          comfyUiStatus?.modelCount === 1 ? "" : "s"
        }`
      : comfyUiUiStatus === "empty"
        ? "Connected · no workflows"
        : comfyUiUiStatus === "checking"
          ? "Checking..."
          : comfyUiUiStatus === "error"
              ? "Not reachable"
              : "Optional";
  const openAiKeyPillStatus = providerKeyPillStatus(
    settings?.hasOpenAiApiKey === true,
    openAiKey.trim().length > 0,
    providerKeyStatusChecking,
    providerKeyStatus?.openai
  );
  const anthropicKeyPillStatus = providerKeyPillStatus(
    settings?.hasAnthropicApiKey === true,
    anthropicKey.trim().length > 0,
    providerKeyStatusChecking,
    providerKeyStatus?.anthropic
  );
  const openAiKeyPillText = providerKeyPillText(
    "OpenAI",
    settings?.hasOpenAiApiKey === true,
    openAiKey.trim().length > 0,
    providerKeyStatusChecking,
    providerKeyStatus?.openai
  );
  const anthropicKeyPillText = providerKeyPillText(
    "Anthropic",
    settings?.hasAnthropicApiKey === true,
    anthropicKey.trim().length > 0,
    providerKeyStatusChecking,
    providerKeyStatus?.anthropic
  );
  const shouldShowPreAuthChecklist = !user && !hasAnyAccounts && !preAuthChecklistComplete;
  const shouldShowAuthForm = !user && (hasAnyAccounts || preAuthChecklistComplete);

  if (!user && backendUnavailable) {
    return (
      <main className={`${styles.authLayout} ${themeClass}`}>
        {renderBackendUnavailableNotice("full")}
        <GlyphTooltipLayer />
      </main>
    );
  }

  if (clientAccessState !== "allowed") {
    const isChecking = clientAccessState === "checking";
    return (
      <main className={`${styles.authLayout} ${themeClass}`}>
        <div className={styles.card}>
          <div className={styles.brandLockup}>
            <div className={styles.brandIconShell} aria-hidden="true">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img src="/icon.jpg" alt="" aria-hidden="true" className={styles.brandIcon} />
              <PrismTriangleMark className={styles.brandIconLight} />
            </div>
            <PrismWordmarkWithVersion className={styles.brandWordmark} />
          </div>
          <p className={styles.muted}>Local-first AI playground. ChatGPT Gov fidelity, FL Studio creativity.</p>
          <h2 className={styles.authHeading}>
            {isChecking ? "Connecting to Prism" : "Open Prism in the app"}
          </h2>
          <p className={styles.muted}>
            {isChecking
              ? "Checking app access..."
              : "Prism Desktop opens directly without pairing codes."}
          </p>
        </div>
        <GlyphTooltipLayer />
      </main>
    );
  }

  function renderModeTutorialOverlay(): React.JSX.Element | null {
    if (!activeTutorialMode) return null;
    const tutorialContent: Record<
      TutorialMode,
      { title: string; steps: Array<{ heading: string; body: string }> }
    > = {
      zen: {
        title: "Zen walkthrough",
        steps: [
          {
            heading: "Stay with PRISM",
            body: "Zen is one continuous PRISM-only conversation. There are no bot or model pickers here.",
          },
          {
            heading: "Let context breathe",
            body: "Recent messages stay visible while older continuity is carried through summaries and memory.",
          },
          {
            heading: "Use Atmosphere gently",
            body: "Turn Atmosphere on from the header when you want the conversation backdrop to evolve.",
          },
        ],
      },
      chat: {
        title: "Chat mode walkthrough",
        steps: [
          {
            heading: "Start with a bot",
            body: "Pick a bot from the panel, then send your first message to start the conversation.",
          },
          {
            heading: "Use quick tools",
            body: "Right-click in the canvas for shortcuts to settings, memories, images, and bot actions.",
          },
          {
            heading: "Fix and refine",
            body: "Use message actions like Edit and Resend to tune replies without losing your flow.",
          },
        ],
      },
      coffee: {
        title: "Coffee mode walkthrough",
        steps: [
          {
            heading: "Pick your table",
            body: "Choose a Coffee Group and seat bots to set the conversation vibe before starting.",
          },
          {
            heading: "Guide the session",
            body: "Use settings and transcript controls to steer pacing, topic flow, and recap visibility.",
          },
          {
            heading: "Return anytime",
            body: "You can reset Coffee tutorials from Settings if you want another guided pass later.",
          },
        ],
      },
    };
    const content = tutorialContent[activeTutorialMode];
    const safeStepIndex = Math.min(activeTutorialStepIndex, content.steps.length - 1);
    const step = content.steps[safeStepIndex];
    const isLastStep = safeStepIndex >= content.steps.length - 1;
    return (
      <div className={styles.modeTutorialOverlay} role="dialog" aria-modal="true">
        <div className={styles.modeTutorialCard}>
          <p className={styles.modeTutorialEyebrow}>
            {content.title} · Step {safeStepIndex + 1} of {content.steps.length}
          </p>
          <h3>{step.heading}</h3>
          <p>{step.body}</p>
          <div className={styles.modeTutorialTimeline} aria-hidden="true">
            {content.steps.map((_, index) => (
              <span
                key={`${activeTutorialMode}-step-${index}`}
                data-state={
                  index < safeStepIndex ? "done" : index === safeStepIndex ? "active" : "pending"
                }
              />
            ))}
          </div>
          <div className={styles.modeTutorialActions}>
            <button
              type="button"
              className={styles.linkButton}
              onClick={() =>
                setActiveTutorialStepIndex((current) => Math.max(0, current - 1))
              }
              disabled={safeStepIndex === 0}
            >
              Back
            </button>
            <button
              type="button"
              className={styles.linkButton}
              onClick={() => markTutorialComplete(activeTutorialMode)}
            >
              Skip tutorial
            </button>
            <button
              type="button"
              className={styles.accountLogoutButton}
              onClick={() => {
                if (isLastStep) {
                  markTutorialComplete(activeTutorialMode);
                  return;
                }
                setActiveTutorialStepIndex((current) =>
                  Math.min(content.steps.length - 1, current + 1)
                );
              }}
            >
              {isLastStep ? "Finish" : "Next"}
            </button>
          </div>
        </div>
      </div>
    );
  }

  function renderDesktopFirstRunChecklist(): React.JSX.Element | null {
    if (!desktopFirstRunChecklistOpen) return null;
    const qdrantState = desktopFirstRunHealth?.services?.qdrant ?? "unknown";
    const ollamaState = desktopFirstRunHealth?.services?.ollama ?? "unknown";
    const qdrantReady = qdrantState === "ready" || qdrantState === "configured";
    const ollamaReady = ollamaState === "ready" || ollamaState === "configured";
    const onlineKeyConfigured = Boolean(
      settings &&
        (settings.openAiApiKeySource !== "none" ||
          settings.anthropicApiKeySource !== "none")
    );
    const backupConfigured = Boolean(
      settings?.secondaryOllamaHost?.trim() || settings?.comfyUiHost?.trim()
    );
    const steps = [
      {
        id: "account",
        title: "Account",
        subtitle: "Create or sign in to your Prism account.",
        state: user ? "done" : "pending",
      },
      {
        id: "ollama",
        title: "Local AI engine",
        subtitle: "Confirm Ollama is reachable.",
        state: ollamaReady ? "done" : "pending",
      },
      {
        id: "qdrant",
        title: "Memory engine",
        subtitle: "Confirm Qdrant is reachable.",
        state: qdrantReady ? "done" : "pending",
      },
      {
        id: "api-keys",
        title: "API key (optional)",
        subtitle: "Add an OpenAI or Anthropic key for online models.",
        state: onlineKeyConfigured ? "done" : "optional",
      },
      {
        id: "extras",
        title: "Extra servers (optional)",
        subtitle: "Use paired Ollama models or add ComfyUI for local image workflows.",
        state: backupConfigured ? "done" : "optional",
      },
    ] as const;
    const activeStepIndex = Math.min(
      desktopFirstRunChecklistStepIndex,
      steps.length - 1
    );
    const activeStep = steps[activeStepIndex];
    const completedCount = steps.filter((step) => step.state === "done").length;
    const progressPercent = (completedCount / steps.length) * 100;
    const canCompleteChecklist = user !== null && qdrantReady && ollamaReady;
    return (
      <div className={styles.desktopChecklistOverlay} role="dialog" aria-modal="true">
        <div className={styles.desktopChecklistCard}>
          <h3>First-time setup checklist</h3>
          <p className={styles.muted}>
            Walk through each setup step. Completed steps get checkmarks in the timeline.
          </p>
          <div className={styles.desktopChecklistProgressRow} aria-live="polite">
            <p className={styles.desktopChecklistProgressLabel}>
              {completedCount} of {steps.length} completed
            </p>
            <div className={styles.desktopChecklistProgressBar} aria-hidden="true">
              <span
                className={styles.desktopChecklistProgressFill}
                style={{ width: `${progressPercent}%` }}
              />
            </div>
          </div>
          <ol className={styles.desktopChecklistList}>
            {steps.map((step, index) => (
              <li
                key={step.id}
                className={styles.desktopChecklistItem}
                data-active={index === activeStepIndex ? "true" : undefined}
              >
                <div className={styles.desktopChecklistItemBody}>
                  <span className={styles.desktopChecklistItemTitle}>{step.title}</span>
                  <span className={styles.desktopChecklistItemHint}>{step.subtitle}</span>
                </div>
                <strong className={styles.desktopChecklistStatus} data-state={step.state}>
                  {step.state === "done" ? "✓ Done" : step.state === "optional" ? "Optional" : "Pending"}
                </strong>
              </li>
            ))}
          </ol>
          <section className={styles.desktopChecklistStepCard}>
            <p className={styles.desktopChecklistStepEyebrow}>
              Step {activeStepIndex + 1} of {steps.length}
            </p>
            <h4>{activeStep.title}</h4>
            <p>{activeStep.subtitle}</p>
            <div className={styles.desktopChecklistStepActions}>
              {activeStep.id === "api-keys" || activeStep.id === "extras" ? (
                <button
                  type="button"
                  className={styles.linkButton}
                  onClick={() => openSettingsPanel("connections")}
                >
                  Open Settings
                </button>
              ) : null}
              {(activeStep.id === "ollama" || activeStep.id === "qdrant") && (
                <button
                  type="button"
                  className={styles.linkButton}
                  onClick={() => void refreshDesktopFirstRunHealth()}
                  disabled={desktopFirstRunChecklistBusy}
                >
                  {desktopFirstRunChecklistBusy ? "Checking..." : "Refresh checks"}
                </button>
              )}
              {activeStep.id === "account" && !user && (
                <button
                  type="button"
                  className={styles.linkButton}
                  onClick={completeDesktopFirstRunChecklist}
                >
                  Continue to login
                </button>
              )}
            </div>
          </section>
          <div className={styles.desktopChecklistActions}>
            <button
              type="button"
              className={styles.linkButton}
              onClick={() =>
                setDesktopFirstRunChecklistStepIndex((current) =>
                  Math.max(0, current - 1)
                )
              }
              disabled={activeStepIndex === 0}
            >
              Previous step
            </button>
            <button
              type="button"
              className={styles.linkButton}
              onClick={() => void runDesktopFirstRunAutoSetup()}
              disabled={desktopFirstRunAutoSetupBusy}
            >
              {desktopFirstRunAutoSetupBusy ? "Running auto-setup..." : "Run automatic setup"}
            </button>
            <button
              type="button"
              className={styles.linkButton}
              onClick={() =>
                setDesktopFirstRunChecklistStepIndex((current) =>
                  Math.min(steps.length - 1, current + 1)
                )
              }
              disabled={activeStepIndex >= steps.length - 1}
            >
              Next step
            </button>
            <button
              type="button"
              className={styles.accountLogoutButton}
              onClick={completeDesktopFirstRunChecklist}
              disabled={!canCompleteChecklist}
            >
              Continue to Prism
            </button>
          </div>
        </div>
      </div>
    );
  }

  function renderMessageContextMenu(): React.JSX.Element | null {
    if (!messageContextMenu) return null;
    const msg = messageContextMenu.message;
    const isUser = msg.role === "user";
    const showFork = !detail?.incognito;
    const branchZenDelete = shouldBranchZenDelete(msg);
    return (
      <>
        <button
          type="button"
          className={styles.messageContextBackdrop}
          aria-label="Close message actions"
          data-msg-focus-overlay={mobileFocusedMessageId ? "true" : undefined}
          tabIndex={-1}
          aria-hidden="true"
        />
        <div
          ref={messageActionsMenuRef}
          className={styles.messageContextMenu}
          data-anchor={messageContextMenu.anchor}
          style={{
            left: `${messageContextMenu.x}px`,
            top: `${messageContextMenu.y}px`,
            "--message-context-accent": deriveMobileMessageFocusAccent(msg),
          } as React.CSSProperties}
          role="menu"
          aria-label="Message actions"
        >
          <button
            type="button"
            role="menuitem"
            onClick={() => {
              closeMessageContextOverlay();
              void copyMessageToClipboard(msg);
            }}
          >
            <span className={styles.contextMenuItemLabel}>
              <span className={styles.contextMenuGlyph} aria-hidden="true">⧉</span>
              <span>Copy</span>
            </span>
          </button>
          {isUser && (
            <>
              <button
                key={`default:${memoryPhysicsSeed}`}
                type="button"
                role="menuitem"
                onClick={() => beginEditMessage(msg)}
              >
                <span className={styles.contextMenuItemLabel}>
                  <span className={styles.contextMenuGlyph} aria-hidden="true">✎</span>
                  <span>Edit</span>
                </span>
              </button>
              <button
                type="button"
                role="menuitem"
                onClick={() => {
                  void resendUserMessage(msg);
                }}
              >
                <span className={styles.contextMenuItemLabel}>
                  <span className={styles.contextMenuGlyph} aria-hidden="true">↻</span>
                  <span>Resend</span>
                </span>
              </button>
            </>
          )}
          {showFork && !isUser && (
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeMessageContextOverlay();
                void forkChat(msg.id);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⑂</span>
                <span>Fork</span>
              </span>
            </button>
          )}
          <button
            type="button"
            role="menuitem"
            onClick={() => {
              void deleteMessageFromHistory(msg);
            }}
          >
            <span className={styles.contextMenuItemLabel}>
              <span className={styles.contextMenuGlyph} aria-hidden="true">
                {branchZenDelete ? "⑂" : "⌫"}
              </span>
              <span>{branchZenDelete ? "Branch without this" : "Delete"}</span>
            </span>
          </button>
        </div>
      </>
    );
  }

  function renderBotContextMenu(): React.JSX.Element | null {
    if (!botContextMenu) return null;
    const bot = bots.find((candidate) => candidate.id === botContextMenu.botId);
    if (!bot) return null;
    const selectedBotIds =
      botContextMenu.selectedBotIds.length > 1
        ? botContextMenu.selectedBotIds.filter((id) => bots.some((candidate) => candidate.id === id))
        : [];
    const multiSelectedBots =
      selectedBotIds.length > 1
        ? selectedBotIds
            .map((id) => bots.find((candidate) => candidate.id === id) ?? null)
            .filter((candidate): candidate is Bot => Boolean(candidate))
        : [];
    const isMultiSelectionMenu = multiSelectedBots.length > 1;
    const multiSelectedBotIds = multiSelectedBots.map((candidate) => candidate.id);
    const multiSelectionGroupActions = isMultiSelectionMenu
      ? resolveBotLibraryMultiSelectionActions(multiSelectedBotIds)
      : null;
    const botLibraryGroupContext = botContextMenu.groupId
      ? botLibraryGroups.find((group) => group.id === botContextMenu.groupId) ?? null
      : null;
    const botLibraryGroupContextIsFavorites =
      botLibraryGroupContext?.id === BOT_LIBRARY_FAVORITES_GROUP_ID;
    const singleBotIsGridSelected = canvasSelectedBotIds.has(bot.id);
    const hasMultipleCanvasSelectedBots = canvasSelectedBotIds.size > 1;
    const singleBotAddToGroupOptions =
      !isMultiSelectionMenu
        ? botLibraryAddToGroupOptionsForBot(bot.id)
        : [];
    const botIsFavorite = favoriteBotIdSet.has(bot.id);
    const favoriteLabel = botIsFavorite ? "Remove from Favorites" : "Add to Favorites";
    const renderFavoriteMenuItem = (): React.JSX.Element => (
      <button
        type="button"
        role="menuitem"
        onClick={() => {
          closeBotContextMenu();
          toggleBotFavorite(bot.id);
        }}
      >
        <span className={styles.contextMenuItemLabel}>
          <span className={styles.contextMenuGlyph} aria-hidden="true">
            {botIsFavorite ? "★" : "☆"}
          </span>
          <span>{favoriteLabel}</span>
        </span>
      </button>
    );
    const menuStyle = {
      left: `${botContextMenu.x}px`,
      top: `${botContextMenu.y}px`,
      maxHeight:
        typeof botContextMenu.maxHeight === "number"
          ? `${botContextMenu.maxHeight}px`
          : undefined,
      "--bot-color": normalizeAccentForTheme(bot.color ?? PRISM_DEFAULT_ACCENT, resolvedTheme),
    } as React.CSSProperties;
    if (botContextMenu.groupId && !botLibraryGroupContext) return null;
    if (botLibraryGroupContext) {
      return (
        <div
          ref={botContextMenuRef}
          className={`${styles.messageContextMenu} ${styles.botContextMenu}`}
          style={menuStyle}
          role="menu"
          aria-label={`${bot.name} group actions`}
        >
          {!hasMultipleCanvasSelectedBots ? (
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                openBotPanelHub(bot);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">✎</span>
                <span>Edit bot</span>
              </span>
            </button>
          ) : null}
          {renderFavoriteMenuItem()}
          <button
            type="button"
            role="menuitem"
            onClick={() => {
              closeBotContextMenu();
              void exportBotProfile(bot);
            }}
          >
            <span className={styles.contextMenuItemLabel}>
              <span className={styles.contextMenuGlyph} aria-hidden="true">⇪</span>
              <span>Export bot</span>
            </span>
          </button>
          {!botLibraryGroupContextIsFavorites && !hasMultipleCanvasSelectedBots ? (
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                removeBotsFromLibraryGroup(botLibraryGroupContext.id, [bot.id]);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⊖</span>
                <span>Remove bot from group</span>
              </span>
            </button>
          ) : null}
        </div>
      );
    }
    return (
      <div
        ref={botContextMenuRef}
        className={`${styles.messageContextMenu} ${styles.botContextMenu}`}
        style={menuStyle}
        role="menu"
        aria-label={isMultiSelectionMenu ? "Selected bot actions" : `${bot.name} actions`}
      >
        {isMultiSelectionMenu ? (
          <>
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                void exportBotsAsCollection(multiSelectedBots);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⇪</span>
                <span>Export bots</span>
              </span>
            </button>
            {multiSelectionGroupActions?.canCreateGroup ? (
              <button
                type="button"
                role="menuitem"
                onClick={() => {
                  closeBotContextMenu();
                  groupSelectedBots(multiSelectedBotIds);
                }}
              >
                <span className={styles.contextMenuItemLabel}>
                  <span className={styles.contextMenuGlyph} aria-hidden="true">⊕</span>
                  <span>Add to group</span>
                </span>
              </button>
            ) : null}
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                const protectedCount = multiSelectedBots.filter(
                  (candidate) => isBotDeleteProtected(candidate.id)
                ).length;
                setSelectedBotDeleteConfirm({
                  ids: multiSelectedBots.map((candidate) => candidate.id),
                  protectedCount,
                });
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⌫</span>
                <span>Delete selected bots</span>
              </span>
            </button>
          </>
        ) : (
          <>
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                if (singleBotIsGridSelected) {
                  toggleCanvasBotSelection(bot.id);
                } else {
                  selectCanvasBot(bot.id);
                }
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">
                  {singleBotIsGridSelected ? "−" : "✓"}
                </span>
                <span>{singleBotIsGridSelected ? "Deselect" : "Select"}</span>
              </span>
            </button>
            {renderFavoriteMenuItem()}
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                void exportBotProfile(bot);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⇪</span>
                <span>Export bot</span>
              </span>
            </button>
            {singleBotAddToGroupOptions.length > 0 ? (
              <button
                type="button"
                role="menuitem"
                onClick={() => {
                  closeBotContextMenu();
                  openAddBotToGroupDialog(bot.id);
                }}
              >
                <span className={styles.contextMenuItemLabel}>
                  <span className={styles.contextMenuGlyph} aria-hidden="true">⊕</span>
                  <span>Add to group</span>
                </span>
              </button>
            ) : null}
            <button
              type="button"
              role="menuitem"
              onClick={() => void cloneBot(bot)}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⧉</span>
                <span>Clone bot</span>
              </span>
            </button>
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                openBotCustomizer(bot);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">✎</span>
                <span>Edit bot</span>
              </span>
            </button>
            <button
              type="button"
              role="menuitem"
              onClick={() => {
                closeBotContextMenu();
                void openMemoriesPanelForBot(bot);
              }}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">◉</span>
                <span>View memories</span>
              </span>
            </button>
            {!isBotDeleteProtected(bot.id) ? (
              <button
                type="button"
                role="menuitem"
                onClick={() => {
                  closeBotContextMenu();
                  setPanelBotDeleteConfirm({
                    id: bot.id,
                    name: bot.name,
                    hadUnsavedChanges: false,
                  });
                }}
              >
                <span className={styles.contextMenuItemLabel}>
                  <span className={styles.contextMenuGlyph} aria-hidden="true">⌫</span>
                  <span>Delete bot</span>
                </span>
              </button>
            ) : null}
          </>
        )}
      </div>
    );
  }

  function renderConversationGroupContextMenu(): React.JSX.Element | null {
    if (!conversationGroupContextMenu) return null;
    const group = conversationGroupsByKey.get(conversationGroupContextMenu.groupKey);
    if (!group) return null;
    const rowAccent = group.color
      ? normalizeAccentForTheme(group.color, resolvedTheme)
      : neutralRowColor(resolvedTheme);
    const menuStyle = {
      left: `${conversationGroupContextMenu.x}px`,
      top: `${conversationGroupContextMenu.y}px`,
      "--bot-color": rowAccent,
    } as React.CSSProperties;
    const deleteLabel = `Delete ${group.name} chats`;
    return (
      <div
        ref={conversationGroupContextMenuRef}
        className={`${styles.messageContextMenu} ${styles.botContextMenu}`}
        style={menuStyle}
        role="menu"
        aria-label={`${group.name} conversations`}
      >
        <button
          type="button"
          role="menuitem"
          disabled={group.count === 0}
          onClick={() => {
            closeConversationGroupContextMenu();
            if (group.count === 0) return;
            const confirmed = window.confirm(
              `Delete all ${group.count} chat(s) in ${group.name}? This cannot be undone.`
            );
            if (confirmed) void deleteConversationGroup(group);
          }}
        >
          <span className={styles.contextMenuItemLabel}>
            <span className={styles.contextMenuGlyph} aria-hidden="true">⌫</span>
            <span>{deleteLabel}</span>
          </span>
        </button>
      </div>
    );
  }

  // ── Pre-auth onboarding checklist gate ──
  if (shouldShowPreAuthChecklist) {
    const qdrantState = desktopFirstRunHealth?.services?.qdrant ?? "unknown";
    const ollamaState = desktopFirstRunHealth?.services?.ollama ?? "unknown";
    const qdrantReady = qdrantState === "ready" || qdrantState === "configured";
    const ollamaReady = ollamaState === "ready" || ollamaState === "configured";
    const setupChecksReady = qdrantReady && ollamaReady;
    const completedChecks = Number(ollamaReady) + Number(qdrantReady);
    const totalChecks = 2;
    const progressPercent = (completedChecks / totalChecks) * 100;
    const progressLabel = setupChecksReady
      ? "System checks complete"
      : desktopFirstRunChecklistBusy
        ? "Checking local services..."
        : `${completedChecks} of ${totalChecks} services ready`;
    return (
      <main className={`${styles.authLayout} ${themeClass}`}>
        <div className={`${styles.card} ${styles.authCard}`}>
          <div className={`${styles.brandLockup} ${styles.authBrandLockup}`}>
            <div className={styles.brandIconShell} aria-hidden="true">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src="/icon.jpg"
                alt=""
                aria-hidden="true"
                className={styles.brandIcon}
              />
              <PrismTriangleMark className={styles.brandIconLight} />
            </div>
            <div className={styles.authBrandTextBlock}>
              <PrismWordmarkWithVersion
                className={styles.brandWordmark}
                pillTestId="auth-app-version"
              />
              <p className={`${styles.muted} ${styles.authTagline}`}>
                Private by default. Creative by design.
              </p>
            </div>
          </div>
          <div className={styles.authFormHeader}>
            <h2 className={styles.authHeading}>Let&apos;s get Prism ready</h2>
            <p className={`${styles.muted} ${styles.desktopChecklistIntro}`}>
              Quick local checks first, then account creation.
            </p>
          </div>
          <div className={styles.desktopChecklistProgressRow} aria-live="polite">
            <p className={styles.desktopChecklistProgressLabel}>{progressLabel}</p>
            <div className={styles.desktopChecklistProgressBar} aria-hidden="true">
              <span
                className={styles.desktopChecklistProgressFill}
                style={{ width: `${progressPercent}%` }}
              />
            </div>
          </div>
          <ol className={styles.desktopChecklistList}>
            <li className={styles.desktopChecklistItem}>
              <div className={styles.desktopChecklistItemBody}>
                <span className={styles.desktopChecklistItemTitle}>Local AI engine</span>
                <span className={styles.desktopChecklistItemHint}>Ollama connection</span>
              </div>
              <strong
                className={styles.desktopChecklistStatus}
                data-state={ollamaReady ? "done" : desktopFirstRunChecklistBusy ? "checking" : "pending"}
              >
                {ollamaReady ? "Ready" : desktopFirstRunChecklistBusy ? "Checking..." : "Needs setup"}
              </strong>
            </li>
            <li className={styles.desktopChecklistItem}>
              <div className={styles.desktopChecklistItemBody}>
                <span className={styles.desktopChecklistItemTitle}>Memory engine</span>
                <span className={styles.desktopChecklistItemHint}>Qdrant connection</span>
              </div>
              <strong
                className={styles.desktopChecklistStatus}
                data-state={qdrantReady ? "done" : desktopFirstRunChecklistBusy ? "checking" : "pending"}
              >
                {qdrantReady ? "Ready" : desktopFirstRunChecklistBusy ? "Checking..." : "Needs setup"}
              </strong>
            </li>
            <li className={styles.desktopChecklistItem}>
              <div className={styles.desktopChecklistItemBody}>
                <span className={styles.desktopChecklistItemTitle}>Create your account</span>
                <span className={styles.desktopChecklistItemHint}>Unlocked after local checks</span>
              </div>
              <strong
                className={styles.desktopChecklistStatus}
                data-state={setupChecksReady ? "done" : "next"}
              >
                {setupChecksReady ? "Ready" : "Up next"}
              </strong>
            </li>
          </ol>
          <div className={styles.desktopChecklistMeta}>
            <p className={styles.muted}>
              Auto-checks every {DESKTOP_FIRST_RUN_CHECKLIST_AUTO_REFRESH_MS / 1000} seconds.
            </p>
            {desktopFirstRunAutoSetupSteps.length > 0 && (
              <p className={styles.muted}>
                Automation: {desktopFirstRunAutoSetupSteps[desktopFirstRunAutoSetupSteps.length - 1]}
              </p>
            )}
          </div>
          <div className={styles.desktopChecklistActions}>
            <button
              type="button"
              className={styles.desktopChecklistPrimaryAction}
              onClick={continueFromPreAuthChecklist}
              disabled={!setupChecksReady}
            >
              Continue to account creation
            </button>
            <div className={styles.desktopChecklistSecondaryActions}>
              <button
                type="button"
                className={styles.linkButton}
                onClick={() => void runDesktopFirstRunAutoSetup()}
                disabled={desktopFirstRunAutoSetupBusy}
              >
                {desktopFirstRunAutoSetupBusy ? "Running auto-setup..." : "Run automatic setup"}
              </button>
              <button
                type="button"
                className={styles.linkButton}
                onClick={() => void refreshDesktopFirstRunHealth()}
                disabled={desktopFirstRunChecklistBusy}
              >
                {desktopFirstRunChecklistBusy ? "Checking..." : "Refresh now"}
              </button>
              {!setupChecksReady && (
                <button
                  type="button"
                  className={styles.linkButton}
                  onClick={continueFromPreAuthChecklist}
                >
                  Continue anyway
                </button>
              )}
            </div>
          </div>
          {error && <p className={styles.error}>{error}</p>}
        </div>
        <GlyphTooltipLayer />
      </main>
    );
  }

  // ── Auth screen ──
  if (shouldShowAuthForm) {
    return (
      <main className={`${styles.authLayout} ${themeClass}`}>
        <div className={`${styles.card} ${styles.authCard}`}>
          <div className={`${styles.brandLockup} ${styles.authBrandLockup}`}>
            {/* Auth lockup keeps the boxed Prism icon in dark mode and swaps to
                the hollow triangle in light mode for high-contrast parity. */}
            <div className={styles.brandIconShell} aria-hidden="true">
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src="/icon.jpg"
                alt=""
                aria-hidden="true"
                className={styles.brandIcon}
              />
              <PrismTriangleMark className={styles.brandIconLight} />
            </div>
            <div className={styles.authBrandTextBlock}>
              <PrismWordmarkWithVersion
                className={styles.brandWordmark}
                pillTestId="auth-app-version"
              />
              <p className={`${styles.muted} ${styles.authTagline}`}>
                Private by default. Creative by design.
              </p>
            </div>
          </div>
          <div className={styles.authFormHeader}>
            <h2 className={styles.authHeading}>{authMode === "register" ? "Create your account" : "Welcome back"}</h2>
            <div className={styles.authControls}>
              {hasAnyAccounts && (
                <div className={styles.authToggle}>
                  <a
                    href="?mode=register"
                    className={authMode === "register" ? styles.selected : ""}
                    onClick={() => setError(null)}
                  >
                    Register
                  </a>
                  <a
                    href="?mode=login"
                    className={authMode === "login" ? styles.selected : ""}
                    onClick={() => setError(null)}
                  >
                    Login
                  </a>
                </div>
              )}
              <button
                type="button"
                className={styles.themeToggleButton}
                onClick={() => void cycleThemeMode()}
                aria-label={
                  effectiveThemeMode === "system"
                    ? `Theme: Auto, currently ${THEME_LABEL[resolvedTheme]}. Click to switch to ${THEME_LABEL[nextThemeMode(effectiveThemeMode)]}.`
                    : `Theme: ${THEME_LABEL[effectiveThemeMode]}. Click to switch to ${THEME_LABEL[nextThemeMode(effectiveThemeMode)]}.`
                }
                data-title={
                  effectiveThemeMode === "system"
                    ? `Theme: Auto (${THEME_LABEL[resolvedTheme]})`
                    : `Theme: ${THEME_LABEL[effectiveThemeMode]}`
                }
                data-glyph-tooltip={
                  effectiveThemeMode === "system"
                    ? `Theme: Auto (${THEME_LABEL[resolvedTheme]})`
                    : `Theme: ${THEME_LABEL[effectiveThemeMode]}`
                }
              >
                <ThemeGlyph mode={effectiveThemeMode} />
              </button>
            </div>
          </div>
          <form onSubmit={submitAuth} className={styles.form}>
            <input required value={username} onChange={e => setUsername(e.target.value)} placeholder="Username" />
            <input required type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" />
            {authMode === "register" && (
              <input
                required
                type="password"
                value={confirmPassword}
                onChange={e => setConfirmPassword(e.target.value)}
                placeholder="Confirm password"
              />
            )}
            <button disabled={busy} type="submit">{busy ? "Working..." : authMode === "register" ? "Create account" : "Log in"}</button>
            {error && <p className={styles.error}>{error}</p>}
          </form>
        </div>
        <GlyphTooltipLayer />
      </main>
    );
  }

  // ── Sidebar row delete button ───────────────────────────────────────
  const renderChatDeleteButton = (c: ConversationSummary) => {
    const deleteKey = conversationRowDeleteKey(c.id);
    const isArmed = pendingDeleteKey === deleteKey;
    const className = [
      styles.conversationDelete,
      isArmed ? styles.conversationDeleteArmed : "",
    ]
      .filter(Boolean)
      .join(" ");
    return (
      <button
        type="button"
        className={className}
        data-delete-affordance="true"
        aria-label={
          isArmed ? `Confirm delete ${c.title}` : `Delete ${c.title}`
        }
        data-glyph-tooltip={
          isArmed ? `Confirm delete ${c.title}` : "Delete chat"
        }
        onClick={(e) => {
          e.stopPropagation();
          if (isArmed) {
            disarmDelete();
            void deleteConversation(c.id);
            return;
          }
          armDelete(deleteKey);
        }}
      >
        {isArmed && (
          <span className={styles.conversationDeletePrompt}>Are you sure?</span>
        )}
        <span className={styles.conversationDeleteGlyph}>
          {isArmed ? "✓" : "×"}
        </span>
      </button>
    );
  };

  const renderConversationDeleteAllButton = (): React.JSX.Element => {
    const isHoldingDeleteAll = holdingKey === DELETE_ALL_KEY;
    return (
      <button
        type="button"
        className={styles.conversationDeleteAllButton}
        data-delete-affordance="true"
        data-holding={isHoldingDeleteAll ? "true" : undefined}
        onPointerDown={(event) => {
          if (event.button !== 0) return;
          try {
            event.currentTarget.setPointerCapture(event.pointerId);
          } catch {
            // Pointer capture is missing in some test environments.
          }
          startHoldDelete(DELETE_ALL_KEY);
        }}
        onPointerUp={cancelHoldDelete}
        onPointerCancel={cancelHoldDelete}
        onClick={(event) => {
          event.stopPropagation();
          if (holdCompletedRef.current) {
            holdCompletedRef.current = false;
            return;
          }
          armDelete(DELETE_ALL_KEY);
        }}
        aria-label="Delete all chats"
        data-glyph-tooltip="Delete all chats"
      >
        <span className={styles.conversationDeleteAllButtonGlyph}>
          <IconTrash />
        </span>
      </button>
    );
  };

  const renderConversationSweepButton = (): React.JSX.Element => {
    const actionLabel = hasSweepEligibleConversations
      ? "Sweep chats"
      : "Need at least 2 chats in one bot group";
    return (
      <button
        type="button"
        className={styles.conversationSweepButton}
        aria-label={actionLabel}
        data-glyph-tooltip={actionLabel}
        disabled={sweepBusy || !hasSweepEligibleConversations}
        onClick={(event) => {
          event.stopPropagation();
          requestConversationSweepAction();
        }}
      >
        <span className={styles.conversationSweepButtonGlyph}>
          <IconSparkles />
        </span>
      </button>
    );
  };

  const conversationRowStyle = (
    c: ConversationSummary,
    index: number
  ): React.CSSProperties => {
    const rawRowColor = resolveRowColor(c, bots);
    const normalRowAccent = rawRowColor
      ? normalizeAccentForTheme(rawRowColor, resolvedTheme)
      : !c.incognito
        ? neutralRowColor(resolvedTheme)
        : null;
    const rowAccent =
      rawRowColor && appWidePrivateMode
        ? privateModeAccentHex(rawRowColor, resolvedTheme) ?? normalRowAccent
        : normalRowAccent;
    const privateRowTint =
      appWidePrivateMode && rowAccent
        ? mixHex(
            rowAccent,
            resolvedTheme === "dark" ? "#b9b0a5" : "#2c251e",
            resolvedTheme === "dark" ? 0.72 : 0.6
          )
        : rowAccent;
    return {
      ...conversationRowGlowStyle(index),
      ...(privateRowTint
        ? {
            "--row-color": privateRowTint,
            "--row-glyph-color": rowAccent ?? privateRowTint,
            "--row-border-mix": `${rowBorderMixPercent(privateRowTint, resolvedTheme)}%`,
            "--row-selected-text-color": appWidePrivateMode
              ? (rowAccent ?? privateRowTint)
              : selectedRowTextColor(privateRowTint, resolvedTheme),
            ...(appWidePrivateMode
              ? { "--row-text-color": rowAccent ?? privateRowTint }
              : {}),
          }
        : {}),
    } as React.CSSProperties;
  };

  const conversationGroupStyle = (
    group: ConversationGroupSummary,
    index: number
  ): React.CSSProperties => {
    const rawRowColor = group.color;
    const normalRowAccent = rawRowColor
      ? normalizeAccentForTheme(rawRowColor, resolvedTheme)
      : neutralRowColor(resolvedTheme);
    const rowAccent =
      rawRowColor && appWidePrivateMode
        ? privateModeAccentHex(rawRowColor, resolvedTheme) ?? normalRowAccent
        : normalRowAccent;
    const privateRowTint = appWidePrivateMode
      ? mixHex(
          rowAccent,
          resolvedTheme === "dark" ? "#b9b0a5" : "#2c251e",
          resolvedTheme === "dark" ? 0.72 : 0.6
        )
      : rowAccent;
    return {
      ...conversationRowGlowStyle(index),
      "--row-color": privateRowTint,
      "--row-glyph-color": rowAccent,
      "--row-border-mix": `${rowBorderMixPercent(privateRowTint, resolvedTheme)}%`,
    } as React.CSSProperties;
  };

  function currentZenConversationIdForPersonaSwitch(): string | null {
    if (detail?.mode === "zen" && detail.id !== "pending") {
      return detail.id;
    }
    const selectedConversation = selectedId
      ? conversations.find((conversation) => conversation.id === selectedId) ?? null
      : null;
    if (selectedConversation?.mode === "zen") {
      return selectedConversation.id;
    }
    return (
      conversations.find(
        (conversation) =>
          conversation.mode === "zen" &&
          !conversation.incognito &&
          !conversation.parentHubId
      )?.id ??
      conversations.find(
        (conversation) => conversation.mode === "zen" && !conversation.incognito
      )?.id ??
      null
    );
  }

  function selectZenPersonaFromSidebar(botId: string): void {
    setSelectedBotId(botId);
    setSandboxGridSelectedBotId(botId);
    setZenPersonaBotId(botId);
    setChatBotOverride(undefined);
    setConversationStarterPrompts(null);
    closeEmptyStateBotSearch();
    const targetConversationId = currentZenConversationIdForPersonaSwitch();
    if (targetConversationId) {
      clearConversationUnread(targetConversationId);
      void refreshConversation(targetConversationId, {
        zenPersonaBotIdOverride: botId,
      });
    } else {
      setChatAutoRestoreSuppressed(true);
      setForceNewConversationOnNextSend(false);
      setSelectedId(null);
      setDetail(null);
      setSessionOpinion(null);
      setBotOpinion(null);
    }
    focusDraftInput();
  }

  const renderConversationRow = (
    c: ConversationSummary,
    index: number,
    nested = false,
    parentGroupBotId: string | null = null
  ): React.JSX.Element => {
    const isSelected = c.id === selectedId;
    const isUnread = unreadConversationIds.has(c.id);
    const zenPersonaBotIdForRow =
      view === "chat" && c.mode === "zen"
        ? conversationEffectiveBotId(c) ?? parentGroupBotId
        : undefined;
    const rowSelectionComplete =
      !isSelected ||
      zenPersonaBotIdForRow === undefined ||
      zenPersonaBotId === zenPersonaBotIdForRow;
    return (
      <li
        key={c.id}
        className={[styles.conversationRow, nested ? styles.conversationRowNested : ""]
          .filter(Boolean)
          .join(" ")}
        data-private={c.incognito ? "true" : undefined}
        data-unread={isUnread ? "true" : undefined}
        data-current={isSelected ? "true" : undefined}
        style={conversationRowStyle(c, index)}
      >
        <button
          type="button"
          className={`${styles.conversationTitleButton} ${isSelected ? styles.selected : ""}`}
          disabled={rowSelectionComplete && isSelected}
          aria-current={isSelected ? "page" : undefined}
          title={isSelected ? "Current chat" : undefined}
          onClick={() => {
            if (rowSelectionComplete && isSelected) return;
            disarmDelete();
            clearConversationUnread(c.id);
            if (view === "chat" && c.mode !== "zen" && parentGroupBotId) {
              selectZenPersonaFromSidebar(parentGroupBotId);
              return;
            }
            void refreshConversation(c.id, {
              ...(zenPersonaBotIdForRow !== undefined
                ? { zenPersonaBotIdOverride: zenPersonaBotIdForRow }
                : {}),
            });
          }}
        >
          {c.title}
        </button>
        {!isSelected && renderChatDeleteButton(c)}
      </li>
    );
  };

  function renderConversationGroupDeleteButton(group: ConversationGroupSummary): React.JSX.Element {
    const deleteKey = conversationGroupDeleteKey(group.key);
    const isArmedSingle = pendingDeleteKey === deleteKey;
    const className = [
      styles.conversationDelete,
      isArmedSingle ? styles.conversationDeleteArmed : "",
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <button
        type="button"
        className={className}
        data-delete-affordance="true"
        aria-label={
          isArmedSingle
            ? `Confirm delete ${group.name} conversations`
            : `Delete ${group.name} conversations`
        }
        data-glyph-tooltip={
          isArmedSingle
            ? `Confirm delete ${group.name} conversations`
            : `Delete ${group.name} chats`
        }
        onClick={(event) => {
          event.stopPropagation();
          if (isArmedSingle) {
            void deleteConversationGroup(group);
          } else {
            armDelete(deleteKey);
          }
        }}
      >
        {isArmedSingle && (
          <span className={styles.conversationDeletePrompt}>Are you sure?</span>
        )}
        <span className={styles.conversationDeleteGlyph}>
          {isArmedSingle ? "✓" : <IconTrash />}
        </span>
      </button>
    );
  }

  const renderConversationGroupTile = (
    group: ConversationGroupSummary,
    headerGlowIndex: number
  ): React.JSX.Element => {
    const isExpanded = expandedConversationGroupKey === group.key;
    const nestedListId = conversationGroupNestedListId(group.key);
    const headerButtonId = conversationGroupHeaderButtonId(group.key);
    const groupNameLabelId = `${headerButtonId}-name`;
    const isDragging = draggingConversationGroupKey === group.key;
    const hubConversation =
      group.conversations.find(
        (conversation) =>
          !conversation.parentHubId &&
          (conversation.hubRole === "hub" || conversation.mode === "zen")
      ) ?? group.conversations[0] ?? null;

    return (
      <li
        key={group.key}
        className={styles.conversationGroupAccordionItem}
        data-conversation-group-key={group.key}
        data-dragging={isDragging ? "true" : undefined}
      >
        <div
          className={styles.conversationRow}
          data-unread={group.unread ? "true" : undefined}
          data-group-neutral={group.color ? undefined : "true"}
          style={conversationGroupStyle(group, headerGlowIndex)}
        >
          <button
            type="button"
            className={styles.conversationGroupTile}
            id={headerButtonId}
            aria-expanded={isExpanded}
            aria-controls={nestedListId}
            onPointerDown={(event) => beginConversationGroupPointerDrag(event, group.key)}
            onPointerMove={updateConversationGroupPointerDrag}
            onPointerUp={endConversationGroupPointerDrag}
            onPointerCancel={endConversationGroupPointerDrag}
            onContextMenu={(event) => {
              event.preventDefault();
              event.stopPropagation();
              openConversationGroupContextMenu(group.key, event.clientX, event.clientY);
            }}
            onClick={() => {
              if (suppressConversationGroupClickRef.current) {
                suppressConversationGroupClickRef.current = false;
                return;
              }
              disarmDelete();
              if (!isExpanded) {
                setConversationListScrollTop(0);
              }
              setExpandedConversationGroupKey(group.key);
              if (view === "chat" && group.botId) {
                selectZenPersonaFromSidebar(group.botId);
              } else if (hubConversation) {
                clearConversationUnread(hubConversation.id);
                void refreshConversation(hubConversation.id, {
                  ...(view === "chat" && hubConversation.mode === "zen"
                    ? { zenPersonaBotIdOverride: group.botId }
                    : {}),
                });
              } else if (group.botId) {
                performShowAllBotsView(group.botId, { suppressChatAutoRestore: true });
              } else {
                performShowAllBotsView(group.botId);
              }
            }}
            aria-label={`Select and expand ${group.name} conversations`}
          >
            <span
              className={styles.conversationGroupChevronHitbox}
              data-conversation-group-chevron="true"
              aria-hidden="true"
            >
              <span
                className={[
                  styles.conversationGroupChevron,
                  isExpanded ? styles.conversationGroupChevronExpanded : "",
                ]
                  .filter(Boolean)
                  .join(" ")}
              />
            </span>
            <span className={styles.conversationGroupGlyph} aria-hidden="true">
              <BotGlyph name={group.glyph} size={22} strokeWidth={1.5} />
            </span>
            <span className={styles.conversationGroupText}>
              <span className={styles.conversationGroupName} id={groupNameLabelId}>
                {group.name}
              </span>
              <span className={styles.conversationGroupCount}>
                {group.count}
              </span>
            </span>
          </button>
          {isExpanded ? renderConversationGroupDeleteButton(group) : null}
        </div>
        <div
          className={[
            styles.conversationGroupCollapse,
            isExpanded ? styles.conversationGroupCollapseExpanded : "",
          ]
            .filter(Boolean)
            .join(" ")}
        >
          <div className={styles.conversationGroupCollapseInner}>
            <ul
              id={nestedListId}
              className={styles.conversationGroupNestedList}
              role="group"
              aria-labelledby={groupNameLabelId}
            >
              {group.conversations.map((conversation, childIndex) =>
                renderConversationRow(
                  conversation,
                  headerGlowIndex + 1 + childIndex,
                  true,
                  group.botId
                )
              )}
            </ul>
          </div>
        </div>
      </li>
    );
  };

  const renderConversationListContents = (): React.JSX.Element[] => {
    const rows: React.JSX.Element[] = [];
    if (showPrivateConversationEmptyState) {
      rows.push(
        <li key="private-empty" className={styles.conversationListEmptyState}>
          Private chats aren&apos;t saved.
        </li>
      );
    }
    let glowRowIndex = 0;
    sidebarConversationItems.forEach((item) => {
      if (item.kind === "group") {
        rows.push(renderConversationGroupTile(item.group, glowRowIndex));
        glowRowIndex += 1;
        if (expandedConversationGroupKey === item.group.key) {
          glowRowIndex += item.group.conversations.length;
        }
      } else {
        rows.push(renderConversationRow(item.conversation, glowRowIndex));
        glowRowIndex += 1;
      }
    });
    return rows;
  };

  // ── Delete-all confirmation modal ─────────────────────────────────────
  // Rendered whenever `pendingDeleteKey` points at one of the bulk-delete
  // sentinels: the sidebar Conversations × for chats, or the existing
  // hold gesture for bots.
  // The modal is the definitive commit surface for the delete-all action
  // — the button under the user's finger never "becomes" the confirm pill
  // in this flow, because at-scale deletion deserves a dedicated
  // alertdialog with a real Cancel + a real Delete-all button.
  //
  // Focus: the Cancel button is auto-focused on mount (safer default;
  // Enter confirms it). On dismiss, the effect at `isDeleteAllActive`
  // restores focus to the element that opened the modal.
  //
  // Escape: handled globally in the same effect, so any focus target can cancel.
  const renderDeleteAllModal = () => {
    const pendingCoffeeGroupDeleteId = parseCoffeeGroupDeleteKey(pendingDeleteKey);
    const isCoffeeGroupDelete = pendingCoffeeGroupDeleteId !== null;
    const groupForDelete =
      isCoffeeGroupDelete && pendingCoffeeGroupDeleteId
        ? coffeeGroups.find((group) => group.id === pendingCoffeeGroupDeleteId)
        : undefined;

    const isChats = pendingDeleteKey === DELETE_ALL_KEY;
    const isCoffeeSessions = pendingDeleteKey === DELETE_ALL_COFFEE_SESSIONS_KEY;
    const isBots = pendingDeleteKey === DELETE_ALL_BOTS_KEY;
    if (!isChats && !isCoffeeSessions && !isBots && !isCoffeeGroupDelete) return null;
    if (isCoffeeGroupDelete && !groupForDelete) return null;

    const protectedBotCount = isBots
      ? bots.filter((bot) => isBotDeleteProtected(bot.id)).length
      : 0;
    const count = isCoffeeGroupDelete
      ? 1
      : isChats
        ? conversations.length
        : isCoffeeSessions
          ? coffeeSessions.length
          : Math.max(0, bots.length - protectedBotCount);
    const noun = isCoffeeGroupDelete
      ? "Coffee Group"
      : isChats
        ? count === 1 ? "conversation" : "conversations"
        : isCoffeeSessions
          ? count === 1 ? "Coffee Session" : "Coffee Sessions"
          : count === 1 ? "bot" : "bots";
    const title = isCoffeeGroupDelete
      ? `Delete “${groupForDelete!.name}”?`
      : isChats
        ? "Delete all chats?"
        : isCoffeeSessions
          ? "Delete all Coffee Sessions?"
          : "Delete all unprotected bots?";
    const body = isCoffeeGroupDelete
      ? "This permanently removes the saved Coffee Group from your sidebar — the named group card, table layout, group shortcuts, and every Coffee Session that belongs to this group."
      : isChats
        ? count === 1
          ? "This will permanently remove your only conversation."
          : `This will permanently remove all ${count} conversations.`
        : isCoffeeSessions
          ? count === 1
            ? "This will permanently remove your only Coffee Session."
            : `This will permanently remove all ${count} Coffee Sessions.`
          : count === 1
            ? "This will permanently remove your only unprotected bot."
            : `This will permanently remove all ${count} unprotected ${noun}.`;
    const coda = isCoffeeGroupDelete
      ? " Other Coffee Groups, chats, bots, images, and memories stay."
      : isChats
        ? " Images and memories stay."
        : isCoffeeSessions
          ? " Coffee Groups and other chats stay; only session transcripts are removed."
          : `${protectedBotCount > 0 ? " Protected bots will be kept." : ""} Chats using deleted bots stay (they fall back to Default).`;
    const onConfirm = () => {
      if (isCoffeeGroupDelete && pendingCoffeeGroupDeleteId) {
        void deleteCoffeeGroupConfirmed(pendingCoffeeGroupDeleteId);
      } else if (isChats) void deleteAllConversations();
      else if (isCoffeeSessions) void deleteAllCoffeeSessions();
      else void deleteAllBots();
    };
    const confirmLabel = isCoffeeGroupDelete ? "Delete group" : "Delete all";
    const confirmAria = isCoffeeGroupDelete
      ? `Delete Coffee Group ${groupForDelete!.name}`
      : `Delete all ${noun}`;
    return (
      <div
        className={styles.deleteAllModalBackdrop}
        data-delete-affordance="true"
        onClick={(event) => {
          // Clicks that originate on the backdrop itself dismiss; clicks
          // that bubble up from the panel have a stopPropagation guard
          // on the panel, so they never reach here.
          if (event.target === event.currentTarget) disarmDelete();
        }}
      >
        <div
          className={styles.deleteAllModalPanel}
          role="alertdialog"
          aria-modal="true"
          aria-labelledby="delete-all-title"
          aria-describedby="delete-all-desc"
          onClick={(event) => event.stopPropagation()}
        >
          <h2 id="delete-all-title" className={styles.deleteAllModalTitle}>
            {title}
          </h2>
          <p id="delete-all-desc" className={styles.deleteAllModalBody}>
            {body}{coda}
          </p>
          <div className={styles.deleteAllModalActions}>
            <button
              type="button"
              className={styles.deleteAllModalCancel}
              ref={(node) => {
                // Autofocus in a microtask so the modal's scale-in has
                // begun before the browser pulls focus, avoiding a
                // one-frame flash of unfocused Cancel.
                if (node) queueMicrotask(() => {
                  try { node.focus({ preventScroll: true }); } catch { /* ignore */ }
                });
              }}
              onClick={disarmDelete}
            >
              Cancel
            </button>
            <button
              type="button"
              className={styles.deleteAllModalConfirm}
              onClick={onConfirm}
              aria-label={confirmAria}
            >
              {confirmLabel}
            </button>
          </div>
        </div>
      </div>
    );
  };

  /** Centered alertdialog for deleting the bot currently loaded in the Bots editor. */
