  const renderAppSwitcher = (className?: string): React.JSX.Element => {
    const applets = prismTopLevelSwitcherApplets();
    const currentAppletId: PrismAppletId = view === "coffee" ? "coffee" : "chat";
    const appSwitcherMenuId = "prism-app-switcher-menu";
    const classes = [styles.appSwitcher, className].filter(Boolean).join(" ");
    const appletGlyph = (appletId: PrismAppletId): React.ReactNode => {
      if (appletId === "coffee") return <GlyphCoffee size={22} />;
      return <GlyphChat size={22} />;
    };
    const appletIsSelected = (appletId: PrismAppletId): boolean => {
      if (appletId === "coffee") return view === "coffee";
      if (appletId === "chat") return view === "chat";
      return false;
    };
    const switchToApplet = (appletId: PrismAppletId): void => {
      setAppSwitcherOpen(false);
      if (appletId === "coffee") {
        if (view !== "coffee") navigateToView("coffee");
        return;
      }
      if (appletId === "chat") {
        if (view === "coffee") {
          void exitCoffeeToChat();
        } else if (view !== "chat") {
          navigateToView("chat");
        }
      }
    };

    return (
      <div className={classes} ref={appSwitcherRef} data-open={appSwitcherOpen ? "true" : undefined}>
        <button
          type="button"
          className={styles.appSwitcherButton}
          onClick={() => setAppSwitcherOpen((open) => !open)}
          aria-haspopup="menu"
          aria-expanded={appSwitcherOpen}
          aria-controls={appSwitcherMenuId}
        >
          <span className={styles.appSwitcherGlyph} aria-hidden="true">
            {appletGlyph(currentAppletId)}
          </span>
          <span className={styles.appSwitcherName}>{PRISM_APPLETS[currentAppletId].name}</span>
          <ChevronDown
            size={14}
            strokeWidth={2.2}
            className={styles.appSwitcherChevron}
            aria-hidden="true"
          />
        </button>
        {appSwitcherOpen ? (
          <div
            id={appSwitcherMenuId}
            className={styles.appSwitcherMenu}
            role="menu"
            aria-label="Switch Prism app"
          >
            {applets.map((applet) => {
              const selected = appletIsSelected(applet.id);
              return (
                <button
                  key={applet.id}
                  type="button"
                  role="menuitem"
                  className={styles.appSwitcherMenuItem}
                  data-selected={selected ? "true" : undefined}
                  aria-current={selected ? "page" : undefined}
                  disabled={selected}
                  onClick={() => switchToApplet(applet.id)}
                >
                  <span className={styles.appSwitcherMenuGlyph} aria-hidden="true">
                    {appletGlyph(applet.id)}
                  </span>
                  <span className={styles.appSwitcherMenuCopy}>
                    <span>{applet.name}</span>
                    <small>{prismAppletVersionLabel(applet.id)}</small>
                  </span>
                  {selected ? <Check size={14} strokeWidth={2.2} aria-hidden="true" /> : null}
                </button>
              );
            })}
          </div>
        ) : null}
      </div>
    );
  };

  const renderUniversalNavbarButtons = ({
    disabled = false,
    showAtmosphere = view === "chat",
    showHub = false,
    onBeforeAction,
    onHub,
    imageReadyChip = null,
    toolStyles = {},
  }: {
    disabled?: boolean;
    showAtmosphere?: boolean;
    showHub?: boolean;
    onBeforeAction?: () => void;
    onHub?: () => void;
    imageReadyChip?: React.ReactNode;
    toolStyles?: {
	      memories?: React.CSSProperties;
	      refresh?: React.CSSProperties;
	      atmosphere?: React.CSSProperties;
	      images?: React.CSSProperties;
	      bots?: React.CSSProperties;
	      usage?: React.CSSProperties;
      theme?: React.CSSProperties;
    };
  } = {}): React.ReactNode => {
    const runAction = (action: () => void): void => {
      onBeforeAction?.();
      action();
    };
    const runAsyncAction = (action: () => Promise<void>): void => {
      onBeforeAction?.();
      void action();
    };
    const openNavbarImages = async (): Promise<void> => {
      const inflightKey = resolveActiveImageGenInflightScopeKey();
      if (inflightKey) {
        await openImagesPanelForScopeKey(inflightKey);
        return;
      }
      if (navbarCustomizerBot) {
        await openImagesPanelForBot(navbarCustomizerBot);
        return;
      }
      await openAllImagesPanel();
    };
    const openNavbarMemories = (): void => {
      if (view === "hub") {
        void openAllMemoriesPanel();
        return;
      }
      openContextualMemoriesPanel();
    };
    const openNavbarBots = (): void => {
      if (navbarCustomizerBot) {
        openBotCustomizer(navbarCustomizerBot);
        return;
      }
      openFreshBotCustomizer();
    };
    const zenWallpaper = detail?.zenWallpaper;
    const zenAtmosphereHasConversation = Boolean(
      detail && detail.mode === "zen" && selectedId
    );
    const zenAtmosphereBusy = Boolean(
      detail &&
        (zenWallpaperBusyConversationId === detail.id ||
          zenWallpaper?.status === "generating")
    );
    const zenAtmosphereEnabled = Boolean(zenWallpaper?.enabled);
    const zenAtmosphereError =
      zenWallpaper?.status === "error" && zenWallpaperError
        ? zenWallpaperError
        : null;
    const zenAtmosphereDisabled =
      disabled ||
      zenAtmosphereBusy ||
      !zenAtmosphereHasConversation;
    const zenAtmosphereTooltip = !zenAtmosphereHasConversation
      ? "Send a Zen message before enabling Atmosphere"
      : zenAtmosphereBusy
          ? "Generating Zen Atmosphere"
          : zenAtmosphereError
            ? `Atmosphere failed: ${zenAtmosphereError}`
          : zenAtmosphereEnabled
            ? "Turn off Zen Atmosphere"
            : "Turn on Zen Atmosphere";
    const zenAtmosphereState = zenAtmosphereBusy
      ? "generating"
      : zenAtmosphereEnabled
          ? "on"
          : "off";
    const toggleZenAtmosphere = (): void => {
      if (!detail || detail.mode !== "zen" || zenAtmosphereDisabled) return;
      const nextEnabled = !zenAtmosphereEnabled;
      if (nextEnabled) {
        zenWallpaperToggleAutoGenerationSuppressedRef.current.set(
          detail.id,
          detail.messages.length
        );
      } else {
        zenWallpaperToggleAutoGenerationSuppressedRef.current.delete(detail.id);
      }
      void requestZenWallpaperUpdate(detail.id, {
        enabled: nextEnabled,
        generate: false,
      });
    };
    const themeAriaLabel =
      effectiveThemeMode === "system"
        ? `Theme: Auto, currently ${THEME_LABEL[resolvedTheme]}. Click to switch to ${THEME_LABEL[nextThemeMode(effectiveThemeMode)]}.`
        : `Theme: ${THEME_LABEL[effectiveThemeMode]}. Click to switch to ${THEME_LABEL[nextThemeMode(effectiveThemeMode)]}.`;
    const themeTooltip =
      effectiveThemeMode === "system"
        ? `Theme: Auto (${THEME_LABEL[resolvedTheme]})`
        : `Theme: ${THEME_LABEL[effectiveThemeMode]}`;
    const botsTooltip = navbarCustomizerBot ? "Edit bot" : "Bots";
    const botsAriaLabel = navbarCustomizerBot
      ? `Edit ${navbarCustomizerBot.name}`
      : "Open bot customizer";
    const imagesButton = (
      <button
        type="button"
        className={styles.headerIconButton}
        onClick={() => runAsyncAction(openNavbarImages)}
        aria-label="Images"
        data-glyph-tooltip="Images"
        disabled={disabled}
        style={toolStyles.images}
      >
        <ImagesGlyph />
      </button>
    );

    return (
      <>
        <button
          type="button"
          className={styles.headerIconButton}
          onClick={() => runAction(() => openRightPanel("command-center"))}
          aria-label="Open Prompt Center"
          data-glyph-tooltip="Prompt Center"
          disabled={disabled}
        >
          <SlashCommandGlyph />
        </button>
        <button
          type="button"
          className={styles.headerIconButton}
          onClick={() => runAction(refreshPrismFromNavbar)}
          aria-label="Refresh Prism"
          data-glyph-tooltip="Refresh"
          disabled={disabled}
          style={toolStyles.refresh}
        >
          <Recycle size={18} strokeWidth={2.2} aria-hidden="true" />
        </button>
        <button
          type="button"
          className={styles.headerIconButton}
          onClick={() => runAction(() => openSettingsPanel())}
          aria-label="Open settings"
          data-glyph-tooltip="Settings"
          disabled={disabled}
        >
          <WrenchGlyph />
        </button>
        <button
          type="button"
          className={styles.headerIconButton}
          onClick={() => runAction(() => openRightPanel("usage"))}
          aria-label="Usage"
          data-glyph-tooltip="Usage"
          disabled={disabled}
          style={toolStyles.usage}
        >
          <BarChart3 size={18} strokeWidth={2.2} aria-hidden="true" />
        </button>
        <button
          type="button"
          className={styles.headerIconButton}
          onClick={() => runAction(openNavbarMemories)}
          aria-label="Memories"
          data-glyph-tooltip="Memories"
          disabled={disabled}
          style={toolStyles.memories}
        >
          <BookmarkGlyph />
        </button>
        {showAtmosphere ? (
          <button
            type="button"
            className={`${styles.headerIconButton} ${styles.atmosphereHeaderButton}`}
            onClick={() => runAction(toggleZenAtmosphere)}
            aria-label={zenAtmosphereTooltip}
            aria-pressed={zenAtmosphereEnabled}
            data-glyph-tooltip={zenAtmosphereTooltip}
            data-atmosphere-state={zenAtmosphereState}
            disabled={zenAtmosphereDisabled}
            style={toolStyles.atmosphere}
          >
            <AtmosphereGlyph />
          </button>
        ) : null}
        {imageReadyChip ? (
          <span className={styles.imagesHeaderAffordance}>
            {imagesButton}
            {imageReadyChip}
          </span>
        ) : (
          imagesButton
        )}
        <button
          type="button"
          className={styles.headerIconButton}
          onClick={() => runAction(openNavbarBots)}
          aria-label={botsAriaLabel}
          data-glyph-tooltip={botsTooltip}
          disabled={disabled}
          style={toolStyles.bots}
        >
          <BotsGlyph />
        </button>
        <button
          type="button"
          className={styles.themeToggleButton}
          onClick={() => runAsyncAction(cycleThemeMode)}
          aria-label={themeAriaLabel}
          data-title={themeTooltip}
          data-glyph-tooltip={themeTooltip}
          disabled={disabled}
          style={toolStyles.theme}
        >
          <ThemeGlyph mode={effectiveThemeMode} />
        </button>
        {showHub ? (
          <button
            type="button"
            className={styles.headerIconButton}
            onClick={() => runAction(onHub ?? handleHeaderHubClick)}
            aria-label="Open Chat"
            data-glyph-tooltip="Open Chat"
            disabled={disabled}
          >
            <HomeGlyph />
          </button>
        ) : null}
      </>
    );
  };

  /** Conversation tools — Settings / Memories / Edit bot / Export / Delete.
   *  Desktop renders inline in the chat header bar.
   *  Mobile floats a wrench gear at top-right that opens the menu as a popout. */
  const renderChatOverflowGear = (): React.JSX.Element | null => {
    const sandboxDefaultBotView =
      view !== "chat" && !privateChatActive && selectedBotId === null && !activeBot;
    const showSettingsOnly =
      !detail &&
      !activeBot &&
      !privateChatActive &&
      view !== "chat" &&
      !defaultConversationUsesPrismIdentity &&
      !sandboxDefaultBotView;
    const showToolbarMemoriesButton = view === "chat" || view === "sandbox";
    const showChatThemeButton = view === "chat" || view === "sandbox";
    const showSandboxHubButton = false;
    const isZenSurface = view === "chat";
    const gearHidden = panel !== null;
    const deleteArmed = pendingDeleteKey === HEADER_DELETE_KEY;
    const canBotActions = true;
    const canMemoryActions = true;
    const canFavoriteActions = !isZenSurface && Boolean(activeBot);
    const canExport = !isZenSurface && Boolean(detail && selectedId);
    const selectedBotCanDelete = Boolean(
      !isZenSurface && activeBot && !isBotDeleteProtected(activeBot.id)
    );
    const canDelete = Boolean(!isZenSurface && ((detail && selectedId) || selectedBotCanDelete));
    /** Always allow header tools (Sandbox non-zen was the only case that disabled during first reply / pending). */
    const headerActionsDisabled = false;
    const isPhoneGear =
      FLOATING_SHELL_APPLETS_ENABLED && viewportWidth <= PHONE_MENU_BREAKPOINT;
    const useHeaderToolsMenu = isPhoneGear || chatHeaderToolsWrapped;
    const privateDefaultHeaderMode = privateChatActive && !privateCustomBotActive;
    const privateFocusedBotHeaderMode = privateChatActive && privateCustomBotActive;
    const privateFocusedBotBase =
      (activeBot?.color ?? headerIdentity?.color ?? PRISM_DEFAULT_ACCENT).trim();
    const privateFocusedBotHeaderTint =
      privateModeAccentHex(privateFocusedBotBase, resolvedTheme) ??
      normalizeAccentForTheme(privateFocusedBotBase, resolvedTheme);
    const privateHeaderToolTints = PRISM_WORDMARK_PALETTE.map(
      (color) => privateModeAccentHex(color, resolvedTheme) ?? color
    );
    const privateDefaultMemoriesStyle = privateDefaultHeaderMode
      ? ({ color: privateHeaderToolTints[0] } as React.CSSProperties)
      : privateFocusedBotHeaderMode
        ? ({ color: privateFocusedBotHeaderTint } as React.CSSProperties)
        : undefined;
    const privateDefaultAtmosphereStyle = privateDefaultHeaderMode
      ? ({ color: privateHeaderToolTints[1] } as React.CSSProperties)
      : privateFocusedBotHeaderMode
        ? ({ color: privateFocusedBotHeaderTint } as React.CSSProperties)
        : undefined;
    const privateDefaultImagesStyle = privateDefaultHeaderMode
      ? ({ color: privateHeaderToolTints[2] } as React.CSSProperties)
      : privateFocusedBotHeaderMode
        ? ({ color: privateFocusedBotHeaderTint } as React.CSSProperties)
        : undefined;
    const privateDefaultBotsStyle = privateDefaultHeaderMode
      ? ({ color: privateHeaderToolTints[3] } as React.CSSProperties)
      : privateFocusedBotHeaderMode
        ? ({ color: privateFocusedBotHeaderTint } as React.CSSProperties)
        : undefined;
    const privateDefaultThemeStyle = privateDefaultHeaderMode
      ? ({ color: privateHeaderToolTints[4] } as React.CSSProperties)
      : privateFocusedBotHeaderMode
        ? ({ color: privateFocusedBotHeaderTint } as React.CSSProperties)
        : undefined;
    const imageReadySurface = THEME_SURFACE_BG[resolvedTheme];
    const chatToolbarImageReadyChip =
      showToolbarMemoriesButton &&
      imageReadyNotice &&
      imageReadyNotice.items.length > 0 ? (
        <button
          type="button"
          className={`${styles.imageReadyNoticeChip} ${
            isPhoneGear ? styles.imageReadyNoticeChipFloating : ""
          }`}
          style={{
            backgroundColor: imageReadyNotice.accentHex,
            color: pickReadableText(imageReadyNotice.accentHex),
            borderColor: ensureContrast(
              imageReadyNotice.accentHex,
              imageReadySurface,
              3
            ),
          }}
          aria-label="Dismiss image ready notification"
          onClick={() => setImageReadyNotice(null)}
        >
          {imageReadyNotice.items.length > 1 ? imageReadyNotice.items.length : "\u200b"}
        </button>
      ) : null;

    const closeMenu = () => setChatOverflowMenuOpen(false);
    const zenWallpaper = detail?.zenWallpaper;
    const showZenAtmosphereButton = view === "chat";
    const zenAtmosphereHasConversation = Boolean(
      detail && detail.mode === "zen" && selectedId
    );
    const zenAtmosphereBusy = Boolean(
      detail &&
      (zenWallpaperBusyConversationId === detail.id ||
        zenWallpaper?.status === "generating")
    );
    const zenAtmosphereEnabled = Boolean(zenWallpaper?.enabled);
    const zenAtmosphereError =
      zenWallpaper?.status === "error" && zenWallpaperError
        ? zenWallpaperError
        : null;
    const zenAtmosphereDisabled =
      headerActionsDisabled ||
      zenAtmosphereBusy ||
      !zenAtmosphereHasConversation;
    const zenAtmosphereTooltip = !zenAtmosphereHasConversation
      ? "Send a Zen message before enabling Atmosphere"
      : zenAtmosphereBusy
          ? "Generating Zen Atmosphere"
          : zenAtmosphereError
            ? `Atmosphere failed: ${zenAtmosphereError}`
          : zenAtmosphereEnabled
            ? "Turn off Zen Atmosphere"
            : "Turn on Zen Atmosphere";
    const zenAtmosphereState = zenAtmosphereBusy
      ? "generating"
      : zenAtmosphereEnabled
          ? "on"
          : "off";
    const toggleZenAtmosphere = () => {
      if (!detail || detail.mode !== "zen" || zenAtmosphereDisabled) return;
      const nextEnabled = !zenAtmosphereEnabled;
      if (nextEnabled) {
        zenWallpaperToggleAutoGenerationSuppressedRef.current.set(
          detail.id,
          detail.messages.length
        );
      } else {
        zenWallpaperToggleAutoGenerationSuppressedRef.current.delete(detail.id);
      }
      void requestZenWallpaperUpdate(detail.id, {
        enabled: nextEnabled,
        generate: false,
      });
    };

    const handleSettings = () => {
      closeMenu();
      openSettingsPanel();
    };
    const handleImages = () => {
      closeMenu();
      const inflightKey = resolveActiveImageGenInflightScopeKey();
      if (inflightKey) {
        void openImagesPanelForScopeKey(inflightKey);
        return;
      }
      if (navbarCustomizerBot) {
        void openImagesPanelForBot(navbarCustomizerBot);
        return;
      }
      void openAllImagesPanel();
    };
    const handleMemories = () => {
      closeMenu();
      openContextualMemoriesPanel();
    };
    const activeBotIsFavorite = Boolean(
      activeBot &&
      favoriteBotIdSet.has(activeBot.id)
    );
	    const handleToggleFavorite = () => {
	      if (!activeBot) return;
	      closeMenu();
	      toggleBotFavorite(activeBot.id);
	    };
	    const handleOpenCommandCenter = () => {
	      closeMenu();
	      openRightPanel("command-center");
	    };
	    const handleRefreshPage = () => {
	      closeMenu();
	      refreshPrismFromNavbar();
	    };
	    const handleEditBot = () => {
	      closeMenu();
	      if (navbarCustomizerBot) {
        openActiveBotCustomizer();
      } else {
        openFreshBotCustomizer();
      }
    };
    const handleExport = () => {
      closeMenu();
      if (detail && selectedId) {
        void exportChat();
      }
    };
    const exportTitle = "Export chat as Markdown";
    const exportButtonText = "Export chat";
    const handleDelete = () => {
      if (!deleteArmed) {
        armDelete(HEADER_DELETE_KEY);
        return;
      }
      if (detail && selectedId) {
        disarmDelete();
        void deleteConversation(selectedId);
        closeMenu();
        return;
      }
      if (activeBot && !isBotDeleteProtected(activeBot.id)) {
        disarmDelete();
        void deleteBot(activeBot.id);
        closeMenu();
        return;
      }
      disarmDelete();
      closeMenu();
    };
    const deleteLabel =
      deleteArmed
        ? detail && selectedId
          ? "Confirm delete this chat"
          : activeBot
            ? `Confirm delete ${activeBot.name}`
            : "Confirm delete"
        : detail && selectedId
          ? "Delete this chat"
          : activeBot
            ? isBotDeleteProtected(activeBot.id)
              ? "Delete is disabled for protected bots"
              : "Delete this bot"
            : "Delete";
    const deleteButtonText =
      deleteArmed
        ? "Are you sure?"
        : detail && selectedId
          ? "Delete chat"
          : activeBot
            ? "Delete bot"
            : "Delete";
    const swallowMenuPointerDown = (
      event: React.PointerEvent<HTMLElement>
    ) => {
      event.stopPropagation();
    };
    const swallowMenuEvent = (
      event:
        | React.MouseEvent<HTMLElement>
        | React.SyntheticEvent<HTMLElement>
    ) => {
      event.preventDefault();
      event.stopPropagation();
    };

    if (!useHeaderToolsMenu) {
      // Desktop: header is now a row of glyph-only icon buttons. The old
      // SETTINGS / IMAGES / MEMORIES accordion was removed in favor of
      // direct-action icons; the gear glyph opens Settings instead of toggling
      // an overflow menu. Edit-bot, Export, Delete still live on the message
      // context menu and bot card affordances elsewhere.
      return (
        <div
          ref={(node) => {
            chatOverflowMenuRef.current = node;
            chatHeaderInlineActionsRef.current = node;
          }}
          className={`${styles.chatHeaderActions} ${
            gearHidden ? styles.chatHeaderActionsHidden : ""
          } ${
            headerActionsDisabled ? styles.chatHeaderActionsDisabled : ""
          }`}
          aria-label="Conversation tools"
          aria-disabled={headerActionsDisabled}
        >
          {!isZenSurface ? renderMemoryToasts() : null}
          {!isZenSurface ? (
            <button
              type="button"
              className={styles.headerIconButton}
              onClick={handleToggleFavorite}
              aria-label={
                activeBot
                  ? activeBotIsFavorite
                    ? `Remove ${activeBot.name} from favorites`
                    : `Add ${activeBot.name} to favorites`
                  : "Favorites unavailable until a bot is selected"
              }
              aria-pressed={activeBot ? activeBotIsFavorite : undefined}
              data-favorite={activeBotIsFavorite ? "true" : undefined}
              data-glyph-tooltip={
                activeBot
                  ? activeBotIsFavorite
                    ? "Remove from Favorites"
                    : "Add to Favorites"
                  : "Select a bot to favorite"
              }
              disabled={headerActionsDisabled || !canFavoriteActions}
            >
              <StarGlyph />
            </button>
          ) : null}
          {renderUniversalNavbarButtons({
            disabled: headerActionsDisabled,
            showAtmosphere: showZenAtmosphereButton,
            showHub: showSandboxHubButton,
            onBeforeAction: closeMenu,
            imageReadyChip: chatToolbarImageReadyChip,
            toolStyles: {
              memories: privateDefaultMemoriesStyle,
              atmosphere: privateDefaultAtmosphereStyle,
              images: privateDefaultImagesStyle,
              bots: privateDefaultBotsStyle,
              theme: privateDefaultThemeStyle,
            },
          })}
        </div>
      );
    }

    return (
      <div
        ref={(node) => {
          chatOverflowMenuRef.current = node;
          chatHeaderInlineActionsRef.current = null;
        }}
        className={`${styles.chatGearAnchor} ${gearHidden ? styles.chatGearAnchorHidden : ""}`}
      >
        <div className={styles.chatHeaderGearAnchor}>
          <button
            type="button"
            className={styles.chatGearButton}
            aria-expanded={chatOverflowMenuOpen}
            aria-haspopup="menu"
            aria-label={isPhoneGear ? "Conversation tools menu" : "Navigation menu"}
            data-glyph-tooltip={isPhoneGear ? "Conversation tools" : "Navigation menu"}
            onPointerDownCapture={swallowMenuPointerDown}
            onClick={(event) => {
              swallowMenuEvent(event);
              setChatOverflowMenuOpen(open => !open);
            }}
          >
            {isPhoneGear ? (
              <WrenchGlyph />
            ) : (
              <MenuIcon className={styles.headerIconGlyph} aria-hidden="true" />
            )}
          </button>
          {chatOverflowMenuOpen && (
            <div
              className={styles.chatOverflowMenu}
              role="menu"
              aria-label="Conversation tools"
              onPointerDownCapture={swallowMenuPointerDown}
              onContextMenu={swallowMenuEvent}
            >
            <button
              type="button"
              role="menuitem"
              className={styles.chatOverflowMenuItem}
              onClick={(event) => {
                swallowMenuEvent(event);
                handleSettings();
              }}
            >
              Settings
            </button>
            {!isZenSurface ? (
              <button
                type="button"
                role="menuitem"
                className={styles.chatOverflowMenuItem}
                disabled={headerActionsDisabled || !canFavoriteActions}
                onClick={(event) => {
                  swallowMenuEvent(event);
                  handleToggleFavorite();
                }}
              >
                {activeBot
                  ? activeBotIsFavorite
                    ? `Remove ${activeBot.name} from Favorites`
                    : `Add ${activeBot.name} to Favorites`
                  : "Select a bot to favorite"}
              </button>
            ) : null}
            <button
              type="button"
              role="menuitem"
              className={styles.chatOverflowMenuItem}
              disabled={headerActionsDisabled}
              onClick={(event) => {
                swallowMenuEvent(event);
                handleOpenCommandCenter();
              }}
	            >
	              Prompt Center
	            </button>
	            <button
	              type="button"
	              role="menuitem"
	              className={styles.chatOverflowMenuItem}
	              disabled={headerActionsDisabled}
	              onClick={(event) => {
	                swallowMenuEvent(event);
		                handleRefreshPage();
	              }}
	            >
	              Refresh
	            </button>
	            {showZenAtmosphereButton ? (
              <button
                type="button"
                role="menuitem"
                className={styles.chatOverflowMenuItem}
                disabled={zenAtmosphereDisabled}
                onClick={(event) => {
                  swallowMenuEvent(event);
                  toggleZenAtmosphere();
                }}
                title={zenAtmosphereTooltip}
              >
                {zenAtmosphereBusy
                  ? "Generating Atmosphere"
                  : zenAtmosphereEnabled
                    ? "Turn off Atmosphere"
                    : "Turn on Atmosphere"}
              </button>
            ) : null}
            {showToolbarMemoriesButton ? (
              <button
                type="button"
                role="menuitem"
                className={styles.chatOverflowMenuItem}
                disabled={headerActionsDisabled}
                onClick={(event) => {
                  swallowMenuEvent(event);
                  handleImages();
                }}
              >
                Images
              </button>
            ) : null}
            {canBotActions && (
              <button
                type="button"
                role="menuitem"
                className={styles.chatOverflowMenuItem}
                onClick={(event) => {
                  swallowMenuEvent(event);
                  handleEditBot();
                }}
              >
                {navbarCustomizerBot ? `Edit ${navbarCustomizerBot.name}` : "Bots"}
              </button>
            )}
            {!showSettingsOnly && !isZenSurface && (
              <button
                type="button"
                role="menuitem"
                className={styles.chatOverflowMenuItem}
                disabled={!canExport || privateChatActive}
                onClick={(event) => {
                  swallowMenuEvent(event);
                  handleExport();
                }}
                title={privateChatActive ? "Unavailable in private chats" : exportTitle}
              >
                {exportButtonText}
              </button>
            )}
            {!showSettingsOnly && view !== "chat" && (
              <button
                type="button"
                role="menuitem"
                className={`${styles.chatOverflowMenuItem} ${deleteArmed ? styles.chatOverflowMenuItemDanger : ""}`}
                disabled={!canDelete || privateChatActive}
                data-delete-affordance="true"
                aria-label={deleteLabel}
                title={privateChatActive ? "Unavailable in private chats" : deleteLabel}
                onClick={(event) => {
                  swallowMenuEvent(event);
                  handleDelete();
                }}
              >
                {deleteButtonText}
              </button>
            )}
            {/* Glyph row at the bottom of the popout — replaces the floating
                Memories / Theme buttons that used to sit beside the
                gear and overlap the PRISM wordmark at narrow widths. */}
            {(showToolbarMemoriesButton
              || showChatThemeButton
              || showSandboxHubButton) && (
              <div
                className={styles.chatOverflowMenuGlyphRow}
                role="group"
                aria-label="Header tools"
              >
                {showToolbarMemoriesButton ? (
                  <button
                    type="button"
                    role="menuitem"
                    className={styles.headerIconButton}
                    onClick={(event) => {
                      swallowMenuEvent(event);
                      handleMemories();
                    }}
                    aria-label="Memories"
                    data-glyph-tooltip="Memories"
                    disabled={headerActionsDisabled || !canMemoryActions}
                  >
                    <BookmarkGlyph />
                  </button>
                ) : null}
                {showChatThemeButton ? (
                  <button
                    type="button"
                    role="menuitem"
                    className={styles.themeToggleButton}
                    onClick={(event) => {
                      swallowMenuEvent(event);
                      void cycleThemeMode();
                    }}
                    aria-label={
                      effectiveThemeMode === "system"
                        ? `Theme: Auto, currently ${THEME_LABEL[resolvedTheme]}. Click to switch to ${THEME_LABEL[nextThemeMode(effectiveThemeMode)]}.`
                        : `Theme: ${THEME_LABEL[effectiveThemeMode]}. Click to switch to ${THEME_LABEL[nextThemeMode(effectiveThemeMode)]}.`
                    }
                    data-title={
                      effectiveThemeMode === "system"
                        ? `Theme: Auto (${THEME_LABEL[resolvedTheme]})`
                        : `Theme: ${THEME_LABEL[effectiveThemeMode]}`
                    }
                    data-glyph-tooltip={
                      effectiveThemeMode === "system"
                        ? `Theme: Auto (${THEME_LABEL[resolvedTheme]})`
                        : `Theme: ${THEME_LABEL[effectiveThemeMode]}`
                    }
                  >
                    <ThemeGlyph mode={effectiveThemeMode} />
                  </button>
                ) : null}
                {showSandboxHubButton ? (
                  <button
                    type="button"
                    role="menuitem"
                    className={styles.headerIconButton}
                    onClick={(event) => {
                      swallowMenuEvent(event);
                      handleHeaderHubClick();
                    }}
                    aria-label="Open Chat"
                    data-glyph-tooltip="Open Chat"
                  >
                    <HomeGlyph />
                  </button>
                ) : null}
              </div>
            )}
            </div>
          )}
        </div>
        {showToolbarMemoriesButton ? chatToolbarImageReadyChip : null}
      </div>
    );
  };

  /** Right-click on `messagesFrame`: Sandbox mirrors the full header tool stack;
   *  Zen keeps a compact canvas menu so the calm surface stays light. */
  function renderCanvasToolsContextMenu(): React.JSX.Element | null {
    if (!canvasToolsContextMenu) return null;
    const sandboxDefaultBotView =
      view !== "chat" && !privateChatActive && selectedBotId === null && !activeBot;
    const showSettingsOnly =
      !detail &&
      !activeBot &&
      !privateChatActive &&
      view !== "chat" &&
      !defaultConversationUsesPrismIdentity &&
      !sandboxDefaultBotView;
    const showToolbarMemoriesButton = view === "chat" || view === "sandbox";
    const showChatThemeButton = view === "chat" || view === "sandbox";
    const showSandboxHubButton = false;
    const isZenSurface = view === "chat";
    const canFavoriteActions = !isZenSurface && Boolean(activeBot);
    const activeBotIsFavorite = Boolean(
      activeBot &&
      favoriteBotIdSet.has(activeBot.id)
    );
    const canMemoryActions = true;
    /** Keep in sync with `renderChatOverflowGear` — header tools stay enabled during pending / first reply. */
    const headerActionsDisabled = false;

    const menuStyle = {
      left: `${canvasToolsContextMenu.x}px`,
      top: `${canvasToolsContextMenu.y}px`,
      "--bot-color": normalizeAccentForTheme(
        activeBot?.color ?? PRISM_DEFAULT_ACCENT,
        resolvedTheme
      ),
    } as React.CSSProperties;

    const runAndClose = (fn: () => void) => {
      closeCanvasToolsContextMenu();
      fn();
    };

    const memoriesDisabled = headerActionsDisabled || !canMemoryActions;
    const zenWallpaper = detail?.zenWallpaper;
    const showZenAtmosphereButton = view === "chat";
    const zenAtmosphereHasConversation = Boolean(
      detail && detail.mode === "zen" && selectedId
    );
    const zenAtmosphereBusy = Boolean(
      detail &&
      (zenWallpaperBusyConversationId === detail.id ||
        zenWallpaper?.status === "generating")
    );
    const zenAtmosphereEnabled = Boolean(zenWallpaper?.enabled);
    const zenAtmosphereDisabled =
      headerActionsDisabled ||
      zenAtmosphereBusy ||
      !zenAtmosphereHasConversation;
    const editBotsLabel = navbarCustomizerBot
      ? `Edit ${navbarCustomizerBot.name}`
      : "Bots";
    const themeLabel =
      effectiveThemeMode === "system"
        ? `Theme: Auto (${THEME_LABEL[resolvedTheme]})`
        : `Theme: ${THEME_LABEL[effectiveThemeMode]}`;

    if (isZenSurface) {
      return (
        <div
          ref={canvasToolsContextMenuRef}
          className={`${styles.messageContextMenu} ${styles.botContextMenu} ${styles.canvasToolsContextMenu}`}
          style={menuStyle}
          role="menu"
          aria-label="Zen canvas tools"
        >
          <button
            type="button"
            role="menuitem"
            onClick={() => runAndClose(() => openSettingsPanel())}
          >
            <span className={styles.contextMenuItemLabel}>
              <span className={styles.contextMenuGlyph} aria-hidden="true">⚙</span>
              <span>Settings</span>
            </span>
          </button>
          {showZenAtmosphereButton ? (
            <button
              type="button"
              role="menuitem"
              disabled={zenAtmosphereDisabled}
              onClick={() => {
                if (zenAtmosphereDisabled || !detail) return;
                runAndClose(() => {
                  const nextEnabled = !zenAtmosphereEnabled;
                  if (nextEnabled) {
                    zenWallpaperToggleAutoGenerationSuppressedRef.current.set(
                      detail.id,
                      detail.messages.length
                    );
                  } else {
                    zenWallpaperToggleAutoGenerationSuppressedRef.current.delete(detail.id);
                  }
                  void requestZenWallpaperUpdate(detail.id, {
                    enabled: nextEnabled,
                    generate: false,
                  });
                });
              }}
            >
              {zenAtmosphereBusy
                ? "Generating Atmosphere"
                : zenAtmosphereEnabled
                  ? "Turn off Atmosphere"
                  : "Turn on Atmosphere"}
            </button>
          ) : null}
          {showChatThemeButton ? (
            <button
              type="button"
              role="menuitem"
              onClick={() =>
                runAndClose(() => {
                  void cycleThemeMode();
                })
              }
            >
              {themeLabel}
            </button>
          ) : null}
          {showSandboxHubButton ? (
            <button
              type="button"
              role="menuitem"
              onClick={() => runAndClose(handleHeaderHubClick)}
            >
              <span className={styles.contextMenuItemLabel}>
                <span className={styles.contextMenuGlyph} aria-hidden="true">⌂</span>
                <span>Open Chat</span>
              </span>
            </button>
          ) : null}
        </div>
      );
    }

    return (
      <div
        ref={canvasToolsContextMenuRef}
        className={`${styles.messageContextMenu} ${styles.botContextMenu} ${styles.canvasToolsContextMenu}`}
        style={menuStyle}
        role="menu"
        aria-label="Conversation tools"
      >
        <button
          type="button"
          role="menuitem"
          onClick={() => runAndClose(() => openSettingsPanel())}
        >
          <span className={styles.contextMenuItemLabel}>
            <span className={styles.contextMenuGlyph} aria-hidden="true">⚙</span>
            <span>Settings</span>
          </span>
        </button>
        {!isZenSurface ? (
          <button
            type="button"
            role="menuitem"
            disabled={!canFavoriteActions}
            onClick={() =>
              runAndClose(() => {
                if (!activeBot) return;
                toggleBotFavorite(activeBot.id);
              })
            }
          >
            {activeBot
              ? activeBotIsFavorite
                ? `Remove ${activeBot.name} from Favorites`
                : `Add ${activeBot.name} to Favorites`
              : "Select a bot to favorite"}
          </button>
        ) : null}
        <button
          type="button"
          role="menuitem"
          onClick={() => runAndClose(() => openRightPanel("command-center"))}
        >
          <span className={styles.contextMenuItemLabel}>
            <span className={styles.contextMenuGlyph} aria-hidden="true">⌘</span>
            <span>Prompt Center</span>
          </span>
        </button>
        {showToolbarMemoriesButton ? (
          <button
            type="button"
            role="menuitem"
            disabled={memoriesDisabled}
            onClick={() => {
              if (memoriesDisabled) return;
              runAndClose(() => {
                openContextualMemoriesPanel();
              });
            }}
          >
            Memories
          </button>
        ) : null}
        {showZenAtmosphereButton ? (
          <button
            type="button"
            role="menuitem"
            disabled={zenAtmosphereDisabled}
            onClick={() => {
              if (zenAtmosphereDisabled || !detail) return;
              runAndClose(() => {
                const nextEnabled = !zenAtmosphereEnabled;
                if (nextEnabled) {
                  zenWallpaperToggleAutoGenerationSuppressedRef.current.set(
                    detail.id,
                    detail.messages.length
                  );
                } else {
                  zenWallpaperToggleAutoGenerationSuppressedRef.current.delete(detail.id);
                }
                void requestZenWallpaperUpdate(detail.id, {
                  enabled: nextEnabled,
                  generate: false,
                });
              });
            }}
          >
            {zenAtmosphereBusy
              ? "Generating Atmosphere"
              : zenAtmosphereEnabled
                ? "Turn off Atmosphere"
                : "Turn on Atmosphere"}
          </button>
        ) : null}
        {showToolbarMemoriesButton ? (
          <button
            type="button"
            role="menuitem"
            disabled={headerActionsDisabled}
            onClick={() => {
              if (headerActionsDisabled) return;
              runAndClose(() => {
                const inflightKey = resolveActiveImageGenInflightScopeKey();
                if (inflightKey) {
                  void openImagesPanelForScopeKey(inflightKey);
                  return;
                }
                if (activeBot) {
                  void openImagesPanelForBot(activeBot);
                  return;
                }
                void openAllImagesPanel();
              });
            }}
          >
            Images
          </button>
        ) : null}
        {!showSettingsOnly ? (
          <button
            type="button"
            role="menuitem"
            disabled={headerActionsDisabled}
            onClick={() => {
              if (headerActionsDisabled) return;
              runAndClose(() => {
                if (navbarCustomizerBot) {
                  openActiveBotCustomizer();
                } else {
                  openFreshBotCustomizer();
                }
              });
            }}
          >
            {editBotsLabel}
          </button>
        ) : null}
        <button
          type="button"
          role="menuitem"
          title="Import Bot[s]"
          onClick={() => runAndClose(openImportBotModal)}
        >
          <span className={styles.contextMenuItemLabel}>
            <span className={styles.contextMenuGlyph} aria-hidden="true">⇩</span>
            <span>Import Bot[s]</span>
          </span>
        </button>
        {showChatThemeButton ? (
          <button
            type="button"
            role="menuitem"
            onClick={() =>
              runAndClose(() => {
                void cycleThemeMode();
              })
            }
          >
            {themeLabel}
          </button>
        ) : null}
        {showSandboxHubButton ? (
          <button
            type="button"
            role="menuitem"
            onClick={() => runAndClose(handleHeaderHubClick)}
          >
            <span className={styles.contextMenuItemLabel}>
              <span className={styles.contextMenuGlyph} aria-hidden="true">⌂</span>
              <span>Open Chat</span>
            </span>
          </button>
        ) : null}
      </div>
    );
  }

  function renderBotTransferOverlay(): React.JSX.Element | null {
    if (!botTransferOverlay) return null;
    const transfer = botTransferOverlay;
    const progress =
      transfer.totalSteps && transfer.totalSteps > 0
        ? clampUnitInterval(transfer.completedSteps / transfer.totalSteps)
        : null;
    const progressPercent = progress !== null ? Math.round(progress * 100) : null;
    const etaSeconds = estimateBotTransferEtaSeconds(transfer, botTransferOverlayNowMs);
    const etaLabel = etaSeconds !== null ? formatBotTransferEta(etaSeconds) : "Calculating ETA";
    const botCount =
      typeof transfer.stats.totalBots === "number"
        ? `${transfer.stats.completedBots ?? 0}/${transfer.stats.totalBots} bots`
        : null;
    const memoryCount =
      typeof transfer.stats.totalMemories === "number" && transfer.stats.totalMemories > 0
        ? `${transfer.stats.completedMemories ?? 0}/${transfer.stats.totalMemories} memories`
        : null;
    const resultCounts = [
      transfer.stats.imported ? `${transfer.stats.imported} imported` : null,
      transfer.stats.exported ? `${transfer.stats.exported} exported` : null,
      transfer.stats.generated ? `${transfer.stats.generated} generated` : null,
      transfer.stats.overwritten ? `${transfer.stats.overwritten} overwritten` : null,
      transfer.stats.skipped ? `${transfer.stats.skipped} skipped` : null,
      transfer.stats.failed ? `${transfer.stats.failed} failed` : null,
    ].filter((item): item is string => Boolean(item));
    const progressStyle = {
      ["--bot-transfer-progress" as string]: `${progressPercent ?? 44}%`,
      ...(transfer.accentColor
        ? {
            ["--import-bot-accent" as string]: normalizeAccentForTheme(
              transfer.accentColor,
              resolvedTheme
            ),
          }
        : {}),
    } as React.CSSProperties;
    return (
      <div
        className={styles.importBotLoadingBackdrop}
        aria-busy="true"
      >
        <div
          className={styles.importBotLoadingCard}
          style={progressStyle}
          role="status"
          aria-live="polite"
          data-mode={transfer.mode}
          data-determinate={progress !== null ? "true" : undefined}
        >
          <div className={styles.importBotLoadingOrb} aria-hidden="true">
            <div className={styles.importBotLoadingOrbFill} />
            <span className={styles.importBotLoadingGlyph}>
              <BotGlyph name={transfer.glyph} size={30} strokeWidth={1.95} />
            </span>
          </div>
          <p className={styles.importBotLoadingName}>{transfer.subject}</p>
          <h4>{transfer.title}</h4>
          <p>{transfer.detail}</p>
          <div
            className={styles.botTransferProgressBlock}
            aria-label={
              progressPercent !== null
                ? `${progressPercent}% complete. ${etaLabel}.`
                : `${transfer.currentStepLabel}. ${etaLabel}.`
            }
          >
            <div className={styles.botTransferProgressMeta}>
              <span>{transfer.currentStepLabel}</span>
              <strong>{progressPercent !== null ? `${progressPercent}%` : "Working"}</strong>
            </div>
            <div
              className={styles.botTransferProgressTrack}
              data-indeterminate={progress === null ? "true" : undefined}
            >
              <span className={styles.botTransferProgressFill} />
            </div>
            <div className={styles.botTransferProgressFoot}>
              <span>{botCount ?? "Preparing work"}</span>
              <span>{etaLabel}</span>
            </div>
          </div>
          {memoryCount || resultCounts.length > 0 ? (
            <div className={styles.botTransferStats} aria-hidden="true">
              {memoryCount ? <span>{memoryCount}</span> : null}
              {resultCounts.map((item) => (
                <span key={item}>{item}</span>
              ))}
            </div>
          ) : null}
        </div>
      </div>
    );
  }

